window.BELLRINGER_STANDARDS = [{"code":"C.K.1","subject":"English Language Arts","grade":"K","text":"Compose OPINION PIECES , using a combination of drawing, dictating, writing and digital resources, to state the topic and an opinion . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, strengthen writing through peer collaboration and adding details through writing and/or pictures as needed . b. Introduce the topic . c. Provide reasons with details to support the opinion . d. Use grade-appropriate TRANSITIONS to connect sentences . e. Provide a concluding idea . f. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.K.2","subject":"English Language Arts","grade":"K","text":"Compose INFORMATIVE AND/OR EXPLANATORY TEXTS , using writing and digital resources, to establish a topic and provide information about the topic . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, strengthen writing through peer collaboration and adding details through writing and/or pictures as needed . b. Introduce the topic . c. Supply information with detail to develop the topic . d. Use grade-appropriate CONJUNCTIONS to develop text structure within sentences . e. Use grade-appropriate TRANSITIONS to combine sentences within a paragraph (or piece) . f. Provide a concluding idea . g. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.K.3","subject":"English Language Arts","grade":"K","text":"Compose NARRATIVES , using a combination of drawing, dictating, writing and digital resources, to develop real or imagined experiences or multiple events or ideas , using effective technique, descriptive details and clear sequences . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, produce writing in which the development and organization are appropriate to task and purpose . b. Recount a single event . c. Include details which describe actions, thoughts and/or emotions . d. Create a sense of closure . e. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.K.4","subject":"English Language Arts","grade":"K","text":"With guidance and support from adults, explore a VARIETY OF DIGITAL RESOURCES to create and publish products, including in collaboration with peers . Composition, Kindergarten, Standard 5"},{"code":"C.K.5","subject":"English Language Arts","grade":"K","text":"With guidance and support, participate in shared RESEARCH and writing projects ."},{"code":"C.K.6","subject":"English Language Arts","grade":"K","text":"With guidance and support, collect information from real-world experiences or provided sources to answer or generate questions . Composition, Kindergarten, Standard 7"},{"code":"HW.K.1","subject":"English Language Arts","grade":"K","text":"Handwriting, Kindergarten, Standard 1 Additionally, the guiding principles are signified by the graduation cap as they are broad statements about the expectations for students as they prepare for life after high school."},{"code":"L.K.1","subject":"English Language Arts","grade":"K","text":"When writing or speaking , demonstrate appropriate use of: a. COMMON NOUNS AND VERBS . b. REGULAR PLURAL NOUNS BY ADDING /S/ OR /ES/ . c. INTERROGATIVE SENTENCES USING WHO, WHAT, WHERE, WHEN, WHY AND HOW . d. SENTENCES USING COMMON PREPOSITIONS . a. COMPLETE SENTENCES ."},{"code":"L.K.2","subject":"English Language Arts","grade":"K","text":"When writing : a. Capitalize THE FIRST WORD IN A SENTENCE AND THE PRONOUN I . b. Recognize and name END PUNCTUATION . c. Write a GRAPHEME FOR MOST CONSONANT AND SHORT-VOWEL PHONEMES . d. Spell CONSONANT-VOWEL-CONSONANT (CVC) words, and attempt to spell simple words drawing on knowledge of PHONEME-GRAPHEME CORRESPONDENCES ."},{"code":"L.K.4","subject":"English Language Arts","grade":"K","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on kindergarten reading and content. a. Identify HOMOPHONES . b. Identify COMMON AFFIXES and how they change the meaning of a word . c. Use words and phrases acquired through conversations, reading and being read to and responding to texts ."},{"code":"L.K.5","subject":"English Language Arts","grade":"K","text":"With guidance and support from adults, explore word relationships and nuances in word meanings . a. Sort common objects into categories (e.g., shapes, foods) to gain a sense of the concepts the categories represent . b. Demonstrate an understanding of VERBS AND ADJECTIVES and their ANTONYMS . c. Demonstrate an understanding of VERBS AND ADJECTIVES and their SYNONYMS ."},{"code":"RF.K.1","subject":"English Language Arts","grade":"K","text":"Demonstrate understanding of the organization and basic features of print to aid in comprehension. a. Follow words from left to right, top to bottom and page by page. b. Recognize that spoken words are represented in written language by specific sequences of letters (graphemes). c. Recognize that words are separated by spaces in print. d. Recognize and name all upper- and lowercase letters of the alphabet. Phonological Awareness"},{"code":"RF.K.2","subject":"English Language Arts","grade":"K","text":"Demonstrate understanding of spoken words, syllables and sounds (phonemes). a. Recognize and orally produce rhyming words. b. Count, pronounce, blend and segment syllables in spoken words. c. Blend and segment onsets and rimes of single-syllable spoken words. d. Isolate and pronounce the initial, medial vowel and final sounds (phonemes) in three-phoneme words. e. Add or substitute individual sounds (phonemes) in simple, one-syllable words to make new words. Phonics and Word Recognition"},{"code":"RF.K.3","subject":"English Language Arts","grade":"K","text":"Know and apply grade-level phonics and word analysis skills in decoding and encoding words. a. Demonstrate basic knowledge of one-to-one letter-sound correspondences by producing the primary sound or many of the most frequent sounds (phonemes) for each consonant. b. Associate the long and short sounds (phonemes) with common spellings (graphemes) for the five major vowels. c. Distinguish between similarly spelled words by analyzing the phoneme-grapheme correspondence. d. Decode consonant-vowel-consonant (CVC) words. e. Encode consonant-vowel-consonant (CVC) words. Fluency"},{"code":"RF.K.3c","subject":"English Language Arts","grade":"K","text":"Reading Foundational Skills, Kindergarten, Standard 3, Substandard c Handwriting HW"},{"code":"RF.K.4","subject":"English Language Arts","grade":"K","text":"Read fluently (accuracy, speed and prosody) on grade-level to support comprehension. a. Read decodable text with purpose and understanding. b. Read irregularly spelled high-frequency words with automaticity and accuracy. c. Read common high-frequency words with automaticity."},{"code":"RI.K.1","subject":"English Language Arts","grade":"K","text":"With prompting and support, ask and answer explicit questions about KEY CONCEPTS AND DETAILS , and make logical inferences to construct meaning from the text."},{"code":"RI.K.10","subject":"English Language Arts","grade":"K","text":"With prompting and support through listening comprehension, routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT ."},{"code":"RI.K.2","subject":"English Language Arts","grade":"K","text":"With prompting and support, orally recognize KEY DETAILS from an informational text to demonstrate understanding of the CENTRAL IDEA of a text."},{"code":"RI.K.3","subject":"English Language Arts","grade":"K","text":"With prompting and support, identify the INDIVIDUALS, EVENTS, IDEAS OR PIECES OF INFORMATION presented over the course of a text ."},{"code":"RI.K.4","subject":"English Language Arts","grade":"K","text":"With prompting and support, ask and answer questions about UNKNOWN WORDS in a text."},{"code":"RI.K.5","subject":"English Language Arts","grade":"K","text":"Identify the FRONT COVER, BACK COVER AND TITLE PAGE of a book ."},{"code":"RI.K.6","subject":"English Language Arts","grade":"K","text":"With prompting and support, identify THE AUTHOR AND ILLUSTRATOR OF A TEXT and define THE ROLE OF EACH in presenting the ideas or information in a text ."},{"code":"RI.K.7","subject":"English Language Arts","grade":"K","text":"With prompting and support, describe the relationship between VISUALS AND THE TEXT ."},{"code":"RI.K.8","subject":"English Language Arts","grade":"K","text":"With prompting and support, identify the CLAIM and the REASONS an author gives to support the CLAIM in a text."},{"code":"RI.K.9","subject":"English Language Arts","grade":"K","text":"With prompting and support, identify information from TWO OR MORE TEXTS ON SIMILAR THEMES OR TOPICS ."},{"code":"RL.K.1","subject":"English Language Arts","grade":"K","text":"With prompting and support, ask and answer explicit questions about KEY IDEAS AND DETAILS and make logical inferences to construct meaning from the text."},{"code":"RL.K.10","subject":"English Language Arts","grade":"K","text":"With prompting and support through listening comprehension, routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand GRADE-APPROPRIATE, COMPLEX LITERARY TEXT ."},{"code":"RL.K.2","subject":"English Language Arts","grade":"K","text":"With prompting and support, orally recognize key details from a literary text to demonstrate understanding of the LESSON in the story ."},{"code":"RL.K.3","subject":"English Language Arts","grade":"K","text":"With prompting and support, identify CHARACTERS, SETTINGS and MAJOR EVENTS IN A STORY in order to make meaning of the story development ."},{"code":"RL.K.4","subject":"English Language Arts","grade":"K","text":"With prompting and support, identify words and phrases in stories or poems that SUGGEST FEELINGS OR APPEAL TO THE SENSES ."},{"code":"RL.K.5","subject":"English Language Arts","grade":"K","text":"With prompting and support, identify STRUCTURES OF common LITERARY TEXT (E.G., STORIES, POEMS AND DRAMAS) ."},{"code":"RL.K.6","subject":"English Language Arts","grade":"K","text":"With prompting and support, identify THE AUTHOR AND ILLUSTRATOR OF A STORY and explain how each tells the story ."},{"code":"RL.K.7","subject":"English Language Arts","grade":"K","text":"With prompting and support, describe the relationship between ILLUSTRATIONS AND THE STORY IN WHICH THEY APPEAR ."},{"code":"RL.K.8","subject":"English Language Arts","grade":"K","text":"Not applicable to literature"},{"code":"RL.K.9","subject":"English Language Arts","grade":"K","text":"With prompting and support, compare and contrast the adventures and experiences of CHARACTERS in stories."},{"code":"KY.K.CC.1","subject":"Mathematics","grade":"K","text":"Count a. Count to 100 by ones and by tens. b. Count backwards from 30 by ones."},{"code":"KY.K.CC.2","subject":"Mathematics","grade":"K","text":"Count forward beginning from a given number within the known sequence within 100 (instead of having to begin at 1)."},{"code":"KY.K.CC.3","subject":"Mathematics","grade":"K","text":"Represent numbers. a. Write numbers from 0 to 20. b. Represent a number of objects with a written numeral 0-20 (with 0 representing a count of no objects)."},{"code":"KY.K.CC.4","subject":"Mathematics","grade":"K","text":"Understand the relationship between numbers and quantities; connect counting to cardinality. a. When counting objects, say the number names in the standard order, pairing each object with one and only one number name and each number name with one and only one object. b. Understand that the last number name said tells the number of objects counted. The number of objects is the same regardless of their arrangement or the order in which they were counted. c. Understand that each successive number name refers to a quantity that is one larger."},{"code":"KY.K.CC.5","subject":"Mathematics","grade":"K","text":"Given a number from 1-20, count out that many objects. a. Count to answer \u201chow many?\u201d questions with as many as 20 things arranged in a line, a rectangular array, or a circle. b. Count to answer \u201chow many?\u201d questions with as many as 10 things in a scattered configuration."},{"code":"KY.K.CC.6","subject":"Mathematics","grade":"K","text":"Identify whether the number of objects in one group is greater than, less than, or equal to the number of objects in another group."},{"code":"KY.K.CC.7","subject":"Mathematics","grade":"K","text":"Compare two numbers between 1 and 10 presented as written numerals."},{"code":"KY.K.G.1","subject":"Mathematics","grade":"K","text":"Name and describe shapes in the environment. a. Describe objects in the environment using names of shapes. b. Describe the relative positions of these objects using terms above, below, in front of, behind and next to."},{"code":"KY.K.G.2","subject":"Mathematics","grade":"K","text":"Correctly name shapes regardless of orientations or overall size."},{"code":"KY.K.G.3","subject":"Mathematics","grade":"K","text":"Identify shapes as two-dimensional or three-dimensional."},{"code":"KY.K.G.4","subject":"Mathematics","grade":"K","text":"Describe the similarities, differences and attributes of two and three dimensional shapes using different sizes and orientations."},{"code":"KY.K.G.5","subject":"Mathematics","grade":"K","text":"Model shapes in the world by building figures from components and drawing shapes."},{"code":"KY.K.G.6","subject":"Mathematics","grade":"K","text":"Compose simple shapes to form larger shapes."},{"code":"KY.K.MD.1","subject":"Mathematics","grade":"K","text":"Describe measurable attributes (length, height, weight, width, depth) of an object or a set of objects using appropriate vocabulary."},{"code":"KY.K.MD.2","subject":"Mathematics","grade":"K","text":"Directly compare two objects with a measurable attribute in common, to see which object has \u201cmore of\u201d/ \u201cless of\u201d the attribute and describe the difference."},{"code":"KY.K.MD.3","subject":"Mathematics","grade":"K","text":"Classify and sort objects or people by attributes. Limit objects or people in each category to be less than or equal to 10."},{"code":"KY.K.MD.4","subject":"Mathematics","grade":"K","text":"Recognize and identify coins by name (penny, nickel, dime, quarter)."},{"code":"KY.K.NBT.1","subject":"Mathematics","grade":"K","text":"Compose and decompose numbers from 11 to 19 using quantities (numbers with units) of ten ones and some further ones. Understand that these numbers are composed of ten ones and one, two, three, four, five, six, seven, eight, or nine ones."},{"code":"KY.K.OA.1","subject":"Mathematics","grade":"K","text":"Represent addition and subtraction with objects, fingers, mental images, drawings, sounds, acting out situations, verbal explanations, expressions, or equations."},{"code":"KY.K.OA.2","subject":"Mathematics","grade":"K","text":"Solve addition and subtraction word problems and add and subtract within 10 by using objects or drawings to represent the problem."},{"code":"KY.K.OA.3","subject":"Mathematics","grade":"K","text":"Decompose numbers less than or equal to 10. a. Decompose numbers into two groups in more than one way by using objects or drawings and record each decomposition by a drawing or equation. b. Use objects or drawings to demonstrate equality as the balancing of quantities."},{"code":"KY.K.OA.4","subject":"Mathematics","grade":"K","text":"For any number from 1 to 9, find the number that makes 10 when added to the given number by using objects or drawings and record the answer with a drawing or equation."},{"code":"KY.K.OA.5","subject":"Mathematics","grade":"K","text":"Fluently add and subtract within 5."},{"code":"K-2-ETS1-1","subject":"Science","grade":"K","text":"Ask questions, make observations, and gather information about a situation that people want to change to define a simple problem that can be solved through the development of a new or improved object or tool. *"},{"code":"K-2-ETS1-2","subject":"Science","grade":"K","text":"Develop a simple sketch, drawing, or physical model to illustrate how the shape of an object helps it function as needed to solve a given problem. *"},{"code":"K-2-ETS1-3","subject":"Science","grade":"K","text":"Analyze data from tests of two objects designed to solve the same problem to compare the strengths and weaknesses of how each performs. *"},{"code":"K-ESS2-1","subject":"Science","grade":"K","text":"Use and share observations of local weather conditions to describe patterns over time."},{"code":"K-ESS2-2","subject":"Science","grade":"K","text":"Construct an argument supported by evidence for how plants and animals (including humans) can change the environment to meet their needs."},{"code":"K-ESS3-1","subject":"Science","grade":"K","text":"Use a model to represent the relationship between the needs of different plants or animals (including humans) and the places they live."},{"code":"K-ESS3-2","subject":"Science","grade":"K","text":"Ask questions to obtain information about the purpose of weather forecasting to prepare for, and respond to, severe weather.*"},{"code":"K-ESS3-3","subject":"Science","grade":"K","text":"Communicate solutions that will reduce the impact of humans on the land, water, air, and/or other living things in the local environment.*"},{"code":"K-LS1-1","subject":"Science","grade":"K","text":"Use observations to describe patterns of what plants and animals (including humans) need to survive."},{"code":"K-PS2-1","subject":"Science","grade":"K","text":"Plan and conduct an investigation to compare the effects of different strengths or different directions of pushes and pulls on the motion of an object."},{"code":"K-PS2-2","subject":"Science","grade":"K","text":"Analyze data to determine if a design solution works as intended to change the speed or direction of an object with a push or a pull. *"},{"code":"K-PS3-1","subject":"Science","grade":"K","text":"Make observations to determine the effect of sunlight on Earth\u2019s surface."},{"code":"K-PS3-2","subject":"Science","grade":"K","text":"Use tools and materials to design and build a structure that will reduce the warming effect of sunlight on an area.*"},{"code":"K.C.CP.1","subject":"Social Studies","grade":"K","text":"Explain the purpose of lo cal government."},{"code":"K.C.CV.1","subject":"Social Studies","grade":"K","text":"Explain ways people can work together effectively to make decisions."},{"code":"K.C.KGO.1","subject":"Social Studies","grade":"K","text":"Identify leade rs in the local community, and explain their roles and responsibilities."},{"code":"K.C.KGO.2","subject":"Social Studies","grade":"K","text":"Identify local and Kentucky state symbols and events."},{"code":"K.C.PR.1","subject":"Social Studies","grade":"K","text":"Identify example s of rules that apply in the school and community, and explain why they exist."},{"code":"K.C.PR.2","subject":"Social Studies","grade":"K","text":"Describe consequences of following or not following rules."},{"code":"K.C.RR.1","subject":"Social Studies","grade":"K","text":"Identify roles a nd responsibilities of self and others at home, in school and neighborhood settings."},{"code":"K.C.RR.2","subject":"Social Studies","grade":"K","text":"Identify symbols and events that represent American patriotism."},{"code":"K.E.IC.1","subject":"Social Studies","grade":"K","text":"Differentiate b etween needs and wants."},{"code":"K.E.KE.1","subject":"Social Studies","grade":"K","text":"Explain how variou s jobs affect communities."},{"code":"K.E.MA.1","subject":"Social Studies","grade":"K","text":"Identify places in c ommunities that provide goods and services."},{"code":"K.E.MI.1","subject":"Social Studies","grade":"K","text":"Describe why pe ople purchase goods and services."},{"code":"K.E.ST.1","subject":"Social Studies","grade":"K","text":"Demonstrate way s trade can be used to obtain goods and services."},{"code":"K.G.GR.1","subject":"Social Studies","grade":"K","text":"Create maps of familiar a reas, such as the classroom, school and community."},{"code":"K.G.HE.1","subject":"Social Studies","grade":"K","text":"Identify ways h umans interact with their environment."},{"code":"K.G.HI.1","subject":"Social Studies","grade":"K","text":"Identify and des cribe the culture of communities."},{"code":"K.G.KGE.1","subject":"Social Studies","grade":"K","text":"Identify physical and environmental characteristics of communities."},{"code":"K.G.MM.1","subject":"Social Studies","grade":"K","text":"Identify why a nd how people and goods move to and within communities."},{"code":"K.H.CE.1","subject":"Social Studies","grade":"K","text":"Identify the c ause and effect of an event in a community."},{"code":"K.H.CH.1","subject":"Social Studies","grade":"K","text":"Identify and de scribe how communities change over time."},{"code":"K.H.CH.2","subject":"Social Studies","grade":"K","text":"Compare traditions found in communities over time, including those from diverse backgrounds."},{"code":"K.H.CO.1","subject":"Social Studies","grade":"K","text":"Describe inte ractions that occur between individuals/groups in families, classrooms and communities."},{"code":"K.H.KH.1","subject":"Social Studies","grade":"K","text":"Compare life in the past to life today in communities."},{"code":"K.I.CC.1","subject":"Social Studies","grade":"K","text":"Construct an ex planation about their community\u2019s civic life, history, geography and/or economy."},{"code":"K.I.CC.2","subject":"Social Studies","grade":"K","text":"Construct an argument to address a problem in the classroom or school."},{"code":"K.I.CC.3","subject":"Social Studies","grade":"K","text":"Identify ways to civically engage at school."},{"code":"K.I.CC.4","subject":"Social Studies","grade":"K","text":"U se listening skills to decide on and take action in their classrooms."},{"code":"K.I.Q.1","subject":"Social Studies","grade":"K","text":"Ask compelling questions about their community. \u201cWhy do I have to be res ponsible?\u201d Teachers can pose this question to students to facilitate exploration about why this standard applies to them and/or their school, city and local communities."},{"code":"K.I.UE.1","subject":"Social Studies","grade":"K","text":"Identify information from two or more sources to investigate characteristics of a community."},{"code":"K.I.UE.2","subject":"Social Studies","grade":"K","text":"Construct responses to compelling questions about oneself and one\u2019s community."},{"code":"C.1.1","subject":"English Language Arts","grade":"1","text":"Compose OPINION PIECES , using a combination of drawing, dictating, writing and digital resources, to state the topic and an opinion . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, strengthen writing through peer collaboration and adding details through writing and/or pictures as needed . b. Introduce the topic . c. Provide reasons with details to support the opinion . d. Use grade-appropriate TRANSITIONS . e. Provide a concluding idea . f. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.1.2","subject":"English Language Arts","grade":"1","text":"Compose INFORMATIVE AND/OR EXPLANATORY TEXTS , using a combination of drawing, dictating, writing and digital resources, to establish a topic and provide information about the topic . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, strengthen writing through peer collaboration and adding details through writing and/or pictures as needed . b. Introduce the topic . c. Supply information with detail to develop the topic . d. Use grade-appropriate CONJUNCTIONS to connect sentences and paragraphs . e. Use grade-appropriate TRANSITION WORDS AND PHRASES to develop text structure in sentences and paragraphs . f. Provide a concluding section . g. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.1.3","subject":"English Language Arts","grade":"1","text":"Compose NARRATIVES , using a combination of drawing, dictating, writing and digital resources, to develop real or imagined experiences or multiple events or ideas using effective technique, descriptive details and clear sequences . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, produce writing in which the development and organization are appropriate to task and purpose . b. Recount a single event or multiple events, memories or ideas . c. Include details which describe actions, thoughts and/or emotions . d. Use temporal words and phrases to signal event order . e. Create a sense of closure . f. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.1.4","subject":"English Language Arts","grade":"1","text":"With guidance and support from adults, use a VARIETY OF DIGITAL RESOURCES to create and publish products, including in collaboration with peers ."},{"code":"C.1.5","subject":"English Language Arts","grade":"1","text":"With guidance and support, participate in shared RESEARCH and writing projects ."},{"code":"C.1.6","subject":"English Language Arts","grade":"1","text":"With guidance and support, collect information from real-world experiences or provided sources to answer or generate questions ."},{"code":"HW.1.1","subject":"English Language Arts","grade":"1","text":"Print all upper- and lowercase letters and numerals. Legibly print all upper- and lowercase letters and numerals with correct form."},{"code":"L.1.1","subject":"English Language Arts","grade":"1","text":"When writing or speaking , demonstrate appropriate use of: a. COMMON, PROPER AND POSSESSIVE NOUNS in a sentence. b. SINGULAR AND PLURAL NOUNS WITH MATCHING VERBS in basic sentences. c. PERSONAL, POSSESSIVE AND INDEFINITE PRONOUNS in a sentence. d. VERBS TO CONVEY A SENSE OF PAST, PRESENT AND FUTURE in a sentence. e. FREQUENTLY OCCURRING ADJECTIVES in a sentence. f. FREQUENTLY OCCURRING CONJUNCTIONS in a sentence. g. FREQUENTLY OCCURRING PREPOSITIONS in a sentence. h. DECLARATIVE, INTERROGATIVE, IMPERATIVE AND EXCLAMATORY SENTENCES in response to prompts."},{"code":"L.1.2","subject":"English Language Arts","grade":"1","text":"When writing : a. Capitalize PROPER NOUNS , including but not limited to DATES AND NAMES OF PEOPLE . b. Demonstrate appropriate use of END PUNCTUATION . c. With prompting and support, produce and write COMMAS IN DATES AND TO SEPARATE SINGLE WORDS IN A SERIES . d. Use conventional spelling for words with COMMON SPELLING PATTERNS (GRAPHEMES) and for FREQUENTLY OCCURRING IRREGULAR WORDS . e. With adult support, spell untaught words phonetically, using PHONEMIC AWARENESS AND SYLLABICATION ."},{"code":"L.1.4","subject":"English Language Arts","grade":"1","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grade 1 reading and content, choosing flexibly from an array of strategies . a. Use SENTENCE-LEVEL CONTEXT as a clue to the meaning of a word or phrase . b. Identify COMMON AFFIXES and how they change the meaning of a word . c. With guidance and support, identify frequently occurring ROOT WORDS and their inflectional forms . d. Use words and phrases acquired through conversations, reading and being read to and responding to texts, including using frequently occurring CONJUNCTIONS to signal simple relationships ."},{"code":"L.1.5","subject":"English Language Arts","grade":"1","text":"With guidance and support from adults, demonstrate understanding of word relationships and nuances in word meanings . a. Sort words into categories to classify relationships and to gain a sense of the concepts the categories represent . b. Define words by category and by one or more key attributes (e.g., a duck is a bird that swims; a tiger is a large cat with stripes). c. Demonstrate understanding of words by relating them to their SYNONYMS and ANTONYMS . d. Define or act out the shades of meaning among verbs (e.g., look, peek, glance) and adjectives differing in intensity (e.g., large, gigantic)."},{"code":"RF.1.1","subject":"English Language Arts","grade":"1","text":"Demonstrate understanding of the organization and basic features of print to aid in comprehension. a. Recognize the distinguishing features of a sentence including first word, capitalization, spacing and ending punctuation. Phonological Awareness"},{"code":"RF.1.2","subject":"English Language Arts","grade":"1","text":"Demonstrate understanding of spoken words, syllables and sounds (phonemes). a. Distinguish long from short vowel sounds (phonemes) in spoken single-syllable words. b. Orally produce single-syllable words by blending sounds (phonemes), including consonant blends. c. Construct and deconstruct spoken single syllable words into initial, medial vowel and final sounds (phonemes). Phonics and Word Recognition"},{"code":"RF.1.3","subject":"English Language Arts","grade":"1","text":"Know and apply grade-level phonics and word analysis skills in decoding and encoding words. a. Know the phoneme-grapheme correspondences for common consonant digraphs. b. Decode regularly spelled one-syllable words. c. Know final \u2013e and common vowel team conventions for representing long vowel sounds (phonemes). d. Demonstrate knowledge that every syllable must have a vowel sound to determine the number of syllables in a printed word. e. With adult support, decode two-syllable words by breaking the words into syllables. f. With adult support, encode two-syllable words by breaking the words into syllables. g. Read words with inflectional endings. Fluency"},{"code":"RF.1.4","subject":"English Language Arts","grade":"1","text":"Read fluently (accuracy, speed and prosody) on grade-level to support comprehension. a. Read a variety of grade-level texts (including but not limited to decodables) with purpose and understanding. b. Orally read grade-level text fluently on successive readings. c. Use context to confirm or self-correct word recognition and understanding, rereading as necessary. d. Read irregularly spelled high-frequency words with automaticity and accuracy."},{"code":"RI.1.1","subject":"English Language Arts","grade":"1","text":"With prompting and support, ask and answer explicit questions about KEY CONCEPTS AND DETAILS and make and support logical inferences to construct meaning from the text."},{"code":"RI.1.10","subject":"English Language Arts","grade":"1","text":"With prompting and support through listening comprehension, routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT ."},{"code":"RI.1.2","subject":"English Language Arts","grade":"1","text":"With prompting and support, recognize KEY DETAILS from an informational text to demonstrate understanding of the CENTRAL IDEA of a text."},{"code":"RI.1.3","subject":"English Language Arts","grade":"1","text":"With prompting and support, identify the connection between INDIVIDUALS, EVENTS, IDEAS OR PIECES OF INFORMATION over the course of a text ."},{"code":"RI.1.4","subject":"English Language Arts","grade":"1","text":"Ask and answer questions to help determine or clarify the meaning of words and phrases in a GRADE-LEVEL TEXT ."},{"code":"RI.1.5","subject":"English Language Arts","grade":"1","text":"Know and use various TEXT FEATURES , including but not limited to HEADINGS, TABLES OF CONTENTS, GLOSSARIES, CAPTIONS, BOLD PRINT, SUBHEADINGS, INDEXES, ELECTRONIC MENUS AND ICONS to locate key facts or information in a text."},{"code":"RI.1.6","subject":"English Language Arts","grade":"1","text":"Distinguish between INFORMATION PROVIDED BY PICTURES or other illustrations and INFORMATION PROVIDED BY THE WORDS in a text ."},{"code":"RI.1.7","subject":"English Language Arts","grade":"1","text":"Use the visuals and details in a text to describe its KEY IDEAS ."},{"code":"RI.1.8","subject":"English Language Arts","grade":"1","text":"Identify the CLAIM and the REASONS an author gives to support the CLAIM in a text."},{"code":"RI.1.9","subject":"English Language Arts","grade":"1","text":"Identify information from TWO OR MORE TEXTS ON SIMILAR THEMES OR TOPICS ."},{"code":"RL.1.1","subject":"English Language Arts","grade":"1","text":"With prompting and support, ask and answer explicit questions about KEY IDEAS AND DETAILS and make and support logical inferences to construct meaning from the text."},{"code":"RL.1.10","subject":"English Language Arts","grade":"1","text":"With prompting and support through listening comprehension, routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand GRADE-APPROPRIATE, COMPLEX LITERARY TEXT ."},{"code":"RL.1.2","subject":"English Language Arts","grade":"1","text":"With prompting and support, recognize key details from a literary text to demonstrate understanding of the AUTHOR\u2019S MESSAGE, LESSON LEARNED AND/OR MORAL ."},{"code":"RL.1.3","subject":"English Language Arts","grade":"1","text":"Describe CHARACTERS, SETTINGS and MAJOR EVENTS IN A STORY , using key details in order to make meaning of the story development ."},{"code":"RL.1.4","subject":"English Language Arts","grade":"1","text":"Identify words and phrases in stories or poems that SUGGEST FEELINGS OR APPEAL TO THE SENSES in order to construct meaning ."},{"code":"RL.1.5","subject":"English Language Arts","grade":"1","text":"Identify differences between the STRUCTURES OF STORIES, POEMS AND DRAMAS ."},{"code":"RL.1.6","subject":"English Language Arts","grade":"1","text":"With prompting and support, identify WHO IS TELLING THE STORY at various points in a text ."},{"code":"RL.1.7","subject":"English Language Arts","grade":"1","text":"Use a story\u2019s illustrations and details to describe its CHARACTERS, SETTING AND EVENTS ."},{"code":"RL.1.8","subject":"English Language Arts","grade":"1","text":"Not applicable to literature."},{"code":"RL.1.9","subject":"English Language Arts","grade":"1","text":"Compare and contrast the adventures and experiences of CHARACTERS in stories."},{"code":"KY.1.G.1","subject":"Mathematics","grade":"1","text":"Distinguish between defining attributes versus non-defining attributes; build and draw shapes to possess defining attributes."},{"code":"KY.1.G.2","subject":"Mathematics","grade":"1","text":"Compose shapes. a. Compose two-dimensional shapes to create rectangles, squares, trapezoids, triangles, half-circles, quarter-circles and composite shapes to compose new shapes from the composite shapes. b. Use three-dimensional shapes (cubes, right rectangular prisms, right circular cones and right circular cylinders) to create a composite shape and compose new shapes from the composite shapes."},{"code":"KY.1.G.3","subject":"Mathematics","grade":"1","text":"Partition circles and rectangles into two and four equal shares, describe the shares using the words halves, fourths and quarters, and use the phrases half of, fourth of and quarter of. Describe the whole as two of or four of the shares. Understand for these examples that decomposing into more equal shares creates smaller shares."},{"code":"KY.1.MD.1","subject":"Mathematics","grade":"1","text":"Order three objects by length; compare the lengths of two objects indirectly by using a third object."},{"code":"KY.1.MD.2","subject":"Mathematics","grade":"1","text":"Express the length of an object as a whole number of same- size length units, by laying multiple copies of a shorter object (the length unit) end to end with no gaps or overlaps."},{"code":"KY.1.MD.3","subject":"Mathematics","grade":"1","text":"Assign values to time and money. a. Tell and write time in hours and half-hours using analog and digital clocks. b. Identify the coins by values (penny, nickel, dime, quarter)."},{"code":"KY.1.MD.4","subject":"Mathematics","grade":"1","text":"Investigate questions involving categorical data. a. Pose a question that can be answered by gathering data. b. Determine strategy for gathering data from peers. c. Organize and represent data in a table/chart with up to three categories. d. Interpret data to answer questions about the table/chart that connects to the question posed, including total number of data points, how many in each category and how many more or less are in one category than in another."},{"code":"KY.1.NBT.1","subject":"Mathematics","grade":"1","text":"Count and represent numbers. a. Count forward to and backward from 120, starting at any number less than 120. b. In this range, read and write numerals and represent a number of objects with a written numeral."},{"code":"KY.1.NBT.2","subject":"Mathematics","grade":"1","text":"Understand the two-digits of a two-digit number represent amounts of tens and ones. Understand the following as special cases: a. 10 can be thought of as a bundle of ten ones \u2014 called a \u201cten.\u201d b. The numbers from 11 to 19 are composed of a ten and one, two, three, four, five, six, seven, eight or nine ones. c. The numbers 10, 20, 30, 40, 50, 60, 70, 80, 90 refer to one, two, three, four, five, six, seven, eight or nine tens (and 0 ones)."},{"code":"KY.1.NBT.3","subject":"Mathematics","grade":"1","text":"Compare two two-digit numbers based on meanings of the tens and ones digits, recording the results of comparisons with the symbols >, =, and <. MP. 2 Students use tools such as objects on place value charts, tens frames, hundreds charts and number lines to compare two two-digit numbers. Students describe the comparisons using terms such as greater than, more than, less than, fewer than, equal to and same as. Students justify their reasoning. Students compare two two-digit numbers written as numerals."},{"code":"KY.1.NBT.4","subject":"Mathematics","grade":"1","text":"Add within 100 including adding a two-digit number and a one-digit number. Add a two-digit number and a multiple of 10. a. Add within 100 using\u2026 \u2022 concrete models or drawings; \u2022 strategies based on place value; \u2022 properties of operations; \u2022 the relationship between addition and subtraction. b. Relate the addition strategy to a written method and explain the reasoning used. Understand that in adding two-digit numbers, one adds tens and tens, ones and ones; and sometimes it is necessary to compose a ten."},{"code":"KY.1.NBT.5","subject":"Mathematics","grade":"1","text":"Given a two-digit number, mentally find 10 more or 10 less than the number, without having to count; explain the reasoning used."},{"code":"KY.1.NBT.6","subject":"Mathematics","grade":"1","text":"Subtract multiples of 10 in the range 10-90 from multiples of 10 in the range 10-90 (positive or zero differences). a. Subtract using: \u2022 concrete models or drawings; \u2022 strategies based on place value; \u2022 properties of operations; \u2022 the relationship between addition and subtraction b. Relate the subtraction strategy to a written method and explain the reasoning used. Students use strategies to subtract groups of ten from more tens. 80 \u2013 30 can be expressed at 8 tens with 3 tens taken away which leaves 5 tens. Students explore using hundreds chart, base ten blocks, number lines and other tools."},{"code":"KY.1.OA.1","subject":"Mathematics","grade":"1","text":"Use addition and subtraction within 20 to solve word problems involving situations of adding to, taking from, putting together, taking apart and comparing, with unknowns in all positions. MP. 1,"},{"code":"KY.1.OA.2","subject":"Mathematics","grade":"1","text":"Solve word problems that call for addition of three whole numbers whose sum is less than or equal to 20, by using objects, drawings and equations with a symbol for one unknown number to represent the problem. MP. 1,"},{"code":"KY.1.OA.3","subject":"Mathematics","grade":"1","text":"Apply properties of operations as strategies to add and subtract. MP. 2,"},{"code":"KY.1.OA.4","subject":"Mathematics","grade":"1","text":"Understand subtraction as an unknown-addend problem. MP. 2,"},{"code":"KY.1.OA.5","subject":"Mathematics","grade":"1","text":"Relate counting to addition and subtraction."},{"code":"KY.1.OA.6","subject":"Mathematics","grade":"1","text":"Add and subtract within 20. a. Fluently add and subtract within 10. b. Add and subtract within 20, demonstrating fluency for addition and subtraction within 10. Use strategies such as counting on; making 10; decomposing a number leading to a 10; using the relationship between addition and subtraction; creating equivalent but easier or known sums."},{"code":"KY.1.OA.7","subject":"Mathematics","grade":"1","text":"Understand the meaning of the equal sign and determine if equations involving addition and subtraction are true or false. MP. 2,"},{"code":"KY.1.OA.8","subject":"Mathematics","grade":"1","text":"Determine the unknown whole number in an addition or subtraction equation relating three whole numbers. MP. 1,"},{"code":"1-ESS1-1","subject":"Science","grade":"1","text":"Use observations of the sun, moon, and stars to describe patterns that can be predicted."},{"code":"1-ESS1-2","subject":"Science","grade":"1","text":"Make observations at different times of year to relate the amount of daylight to the time of year."},{"code":"1-LS1-1","subject":"Science","grade":"1","text":"Use materials to design a solution to a human problem by mimicking how plants and/or animals use their external parts to help them survive, grow, and meet their needs.*"},{"code":"1-LS1-2","subject":"Science","grade":"1","text":"Read texts and use media to determine patterns in the behavior of parents and offspring that help offspring survive."},{"code":"1-LS3-1","subject":"Science","grade":"1","text":"Make observations to construct an evidence-based account that young plants and animals are like, but not exactly like, their parents."},{"code":"1-PS4-1","subject":"Science","grade":"1","text":"Plan and conduct investigations to provide evidence that vibrating materials can make sound and that sound can make materials vibrate."},{"code":"1-PS4-2","subject":"Science","grade":"1","text":"Make observations to construct an evidence-based account that objects can be seen only when illuminated."},{"code":"1-PS4-3","subject":"Science","grade":"1","text":"Plan and conduct an investigation to determine the effect of placing objects made with different materials in the path of a beam of light."},{"code":"1-PS4-4","subject":"Science","grade":"1","text":"Use tools and materials to design and build a device that uses light or sound to solve the problem of communicating over a distance.*"},{"code":"1.C.CP.1","subject":"Social Studies","grade":"1","text":"Describe t he purpose of Kentucky government."},{"code":"1.C.CV.1","subject":"Social Studies","grade":"1","text":"Describe basic d emocratic principles."},{"code":"1.C.CV.2","subject":"Social Studies","grade":"1","text":"Describe civic virtues."},{"code":"1.C.KGO.1","subject":"Social Studies","grade":"1","text":"Identify Kent ucky leaders, and explain their roles and responsibilities."},{"code":"1.C.KGO.2","subject":"Social Studies","grade":"1","text":"Investigate how civic identity is shaped by symbolic figures, places and events."},{"code":"1.C.PR.1","subject":"Social Studies","grade":"1","text":"Investigat e rules and laws in Kentucky to understand their purpose."},{"code":"1.C.RR.1","subject":"Social Studies","grade":"1","text":"Identify the r ights and responsibilities of citizens."},{"code":"1.E.IC.1","subject":"Social Studies","grade":"1","text":"Predict a person\u2019s change in behavior in response to incentives and opportunity costs."},{"code":"1.E.IC.2","subject":"Social Studies","grade":"1","text":"Explain how choices are made as a result of scarcity."},{"code":"1.E.KE.1","subject":"Social Studies","grade":"1","text":"Identify and describe what goods and services are produced in different places and regions in Kentucky."},{"code":"1.E.MA.1","subject":"Social Studies","grade":"1","text":"Describe ho w different jobs, as well as public and private institutions, help people in the community."},{"code":"1.E.MI.1","subject":"Social Studies","grade":"1","text":"Differentiate b etween buyers (consumers) and sellers (producers)."},{"code":"1.E.MI.2","subject":"Social Studies","grade":"1","text":"Give an example of a cost or benefit of an event."},{"code":"1.E.ST.1","subject":"Social Studies","grade":"1","text":"Explain why the good s and services people in a community produce are traded with those produced in other communities."},{"code":"1.E.ST.2","subject":"Social Studies","grade":"1","text":"Investigate how people can benefit themselves and others by developing special skills, strengths and goods."},{"code":"1.G.GR.1","subject":"Social Studies","grade":"1","text":"Create geog raphic representations to identify the location of familiar places, and organize information regarding familiar places at different scales."},{"code":"1.G.HE.1","subject":"Social Studies","grade":"1","text":"Describe way s people modify their environment."},{"code":"1.G.HI.1","subject":"Social Studies","grade":"1","text":"Describe how c ulture and experience influence the cultural landscape of places and regions within their community and state."},{"code":"1.G.KGE.1","subject":"Social Studies","grade":"1","text":"Compare the physical and human characteristics of communities in Kentucky."},{"code":"1.G.MM.1","subject":"Social Studies","grade":"1","text":"Explain why and how people and goods move to and within communities."},{"code":"1.H.CE.1","subject":"Social Studies","grade":"1","text":"Predict the c auses and effects of events in their community and state."},{"code":"1.H.CH.1","subject":"Social Studies","grade":"1","text":"Describe how e vents, people and innovation of the past affect their present lives, community and state."},{"code":"1.H.CO.1","subject":"Social Studies","grade":"1","text":"Describe in teractions that occur between individuals as members of groups, the community and/or state."},{"code":"1.H.KH.1","subject":"Social Studies","grade":"1","text":"Compare li fe in Kentucky in the past to life in Kentucky today."},{"code":"1.H.KH.2","subject":"Social Studies","grade":"1","text":"Identify Kentucky symbols, songs and traditions."},{"code":"1.I.CC.1","subject":"Social Studies","grade":"1","text":"Construct an ex planation about a specific community in Kentucky."},{"code":"1.I.CC.2","subject":"Social Studies","grade":"1","text":"Construct an argument with reasons to address how to improve the local community and Kentucky."},{"code":"1.I.CC.3","subject":"Social Studies","grade":"1","text":"Identify ways to civically engage in the local community."},{"code":"1.I.CC.4","subject":"Social Studies","grade":"1","text":"Use listening and voting procedures to decide on and take action in their school, local community or Kentucky."},{"code":"1.I.Q.1","subject":"Social Studies","grade":"1","text":"Ask compelling questions about communities in Kentucky. \u201cWhat makes a commun ity healthy?\u201d Teachers can pose this question to students to facilitate exploration about why this standard applies to them and/or their community and state."},{"code":"1.I.Q.2","subject":"Social Studies","grade":"1","text":"Identify supporting questions to investigate compelling questions about communities in Kentucky."},{"code":"1.I.UE.1","subject":"Social Studies","grade":"1","text":"Identify information from two or more sources to describe multiple perspectives about communities in Kentucky."},{"code":"1.I.UE.2","subject":"Social Studies","grade":"1","text":"Construct responses to compelling and supporting questions about communities in Kentucky."},{"code":"C.2.1","subject":"English Language Arts","grade":"2","text":"Compose OPINION PIECES , using a combination of writing and digital resources, on topics or texts , with supporting reasons . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, strengthen writing through peer collaboration and adding details through writing and/or pictures as needed . b. Introduce the topic , followed by an OPINION STATEMENT , and create an organizational structure . c. Provide reasons with details to support the opinion . d. Use grade-appropriate TRANSITIONS to connect sentences and paragraphs . e. Provide a concluding section . f. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.2.2","subject":"English Language Arts","grade":"2","text":"Compose INFORMATIVE AND/OR EXPLANATORY TEXTS , using writing and digital resources, to establish a topic and provide information about the topic . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, strengthen writing through peer collaboration and adding details through writing and/or pictures as needed . b. Introduce the topic . c. Supply information with detail to develop the topic . d. Use grade-appropriate CONJUNCTIONS to develop text structure within sentences . e. Use grade-appropriate TRANSITIONS to develop text structure in sentences and paragraphs . f. Provide a concluding section . g. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.2.3","subject":"English Language Arts","grade":"2","text":"Compose NARRATIVES , using writing and digital resources, to develop real or imagined experiences or multiple events or ideas , using effective technique, descriptive details and clear sequences . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, produce writing in which the development and organization are appropriate to task and purpose . b. Recount a single event or multiple events, memories or ideas . c. Include details which describe actions, thoughts and/or emotions . d. Use temporal words and phrases to signal event order . e. Create a sense of closure . f. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.2.4","subject":"English Language Arts","grade":"2","text":"With guidance and support from adults, use a VARIETY OF DIGITAL RESOURCES to create and publish products, including in collaboration with peers ."},{"code":"C.2.5","subject":"English Language Arts","grade":"2","text":"Conduct shared RESEARCH and writing projects that build knowledge about a topic ."},{"code":"C.2.6","subject":"English Language Arts","grade":"2","text":"Collect information from real-world experiences or provided sources to answer or generate questions ."},{"code":"HW.2.1","subject":"English Language Arts","grade":"2","text":"Print all upper- and lowercase letters and numerals. Legibly print all upper- and lowercase letters and numerals with correct form. Introduce formation of all upper- and lowercase cursive letters."},{"code":"L.2.1","subject":"English Language Arts","grade":"2","text":"In writing or speaking , demonstrate appropriate use of: a. COLLECTIVE NOUNS . b. FREQUENTLY OCCURRING IRREGULAR NOUNS . c. REFLEXIVE PRONOUNS . d. PAST TENSE OF FREQUENTLY OCCURRING IRREGULAR VERBS . e. ADJECTIVES AND ADVERBS in sentence formation. f. producing, expanding and rearranging COMPLETE SIMPLE AND COMPOUND SENTENCES ."},{"code":"L.2.2","subject":"English Language Arts","grade":"2","text":"When writing : a. Capitalize PROPER NOUNS , including but not limited to HOLIDAYS, PRODUCT NAMES AND GEOGRAPHIC NAMES . b. Demonstrate appropriate use of COMMAS IN VARIED COMMUNICATION FORMATS (e.g., letter, email, blog). c. Use APOSTROPHE to form CONTRACTIONS AND POSSESSIVES . d. Generalize SPELLING PATTERNS (GRAPHEMES) . e. Use reference materials to self-check and correct spelling ."},{"code":"L.2.3","subject":"English Language Arts","grade":"2","text":"Use knowledge of language and its conventions when writing, speaking, reading or listening . a. Compare ACADEMIC AND NON-ACADEMIC uses of language ."},{"code":"L.2.4","subject":"English Language Arts","grade":"2","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grade 2 reading and content, choosing flexibly from an array of strategies . a. Use SENTENCE-LEVEL CONTEXT as a clue to the meaning of a word or phrase . b. Determine the meaning of the new word formed when a known PREFIX is added to a known word . c. Use a known ROOT WORD as a clue to the meaning of an unknown word with the same root . d. Use knowledge of the meaning of individual words to predict the meaning of compound words . e. Use glossaries and beginning dictionaries to determine or clarify the meaning of words and phrases . f. Use words and phrases acquired through conversations, reading and being read to and responding to texts, including using ADJECTIVES AND ADVERBS to describe ."},{"code":"L.2.5","subject":"English Language Arts","grade":"2","text":"Demonstrate understanding of word relationships and nuances in word meanings . a. Demonstrate understanding of words by relating them to their SYNONYMS and ANTONYMS . b. Distinguish the shades of meaning among closely related verbs (e.g., toss, throw, hurl) and closely related adjectives (e.g., thin, slender) ."},{"code":"RF.2.3","subject":"English Language Arts","grade":"2","text":"Know and apply grade-level phonics and word analysis skills in decoding and encoding words. a. Distinguish long and short vowels when reading regularly spelled one-syllable words. b. Know phoneme-grapheme correspondences for additional common vowel teams. c. Decode regularly spelled two-syllable words with long vowels. d. Encode regularly spelled two-syllable words with long vowels. e. Identify, decode, encode and know the meaning of words with the most common prefixes and derivational suffixes. f. Identify words with inconsistent but common phoneme-grapheme correspondences. Fluency"},{"code":"RF.2.4","subject":"English Language Arts","grade":"2","text":"Read fluently (accuracy, speed and prosody) on grade-level to support comprehension. a. Read a variety of grade-level texts (including but not limited to decodables) with purpose and understanding. b. Orally read grade-level text fluently on successive readings. c. Use context to confirm or self-correct word recognition and understanding, rereading as necessary. d. Read irregularly spelled high-frequency words with automaticity and accuracy."},{"code":"RI.2.1","subject":"English Language Arts","grade":"2","text":"Ask and answer such QUESTIONS AS WHO, WHAT, WHERE, WHEN, WHY AND HOW and make and support logical inferences to construct meaning from the text."},{"code":"RI.2.10","subject":"English Language Arts","grade":"2","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT independently ."},{"code":"RI.2.2","subject":"English Language Arts","grade":"2","text":"Identify implicit and explicit information from an informational text to determine the CENTRAL IDEA of a text."},{"code":"RI.2.3","subject":"English Language Arts","grade":"2","text":"Describe the connection between INDIVIDUALS, HISTORICAL EVENTS, SCIENTIFIC IDEAS OR CONCEPTS OR STEPS IN TECHNICAL PROCEDURES over the course of a text ."},{"code":"RI.2.4","subject":"English Language Arts","grade":"2","text":"Determine the meaning of general ACADEMIC WORDS AND PHRASES and how those words and phrases shape meaning in a GRADE-LEVEL TEXT ."},{"code":"RI.2.5","subject":"English Language Arts","grade":"2","text":"Identify and describe INFORMATIONAL TEXT STRUCTURES , including SEQUENCE/CHRONOLOGICAL AND DESCRIPTIVE STRUCTURES , and describe the logical connection between particular sentences and paragraphs in a text and how they contribute to the overall structure ."},{"code":"RI.2.6","subject":"English Language Arts","grade":"2","text":"Identify the MAIN PURPOSE of a text, including what the author wants to ANSWER, EXPLAIN OR DESCRIBE , and how that purpose shapes the content of the text ."},{"code":"RI.2.7","subject":"English Language Arts","grade":"2","text":"Identify information gained from VISUALS AND WORDS in the text and explain how that information contributes to understanding of the text."},{"code":"RI.2.8","subject":"English Language Arts","grade":"2","text":"Describe how REASONS support specific CLAIMS the author makes in a text."},{"code":"RI.2.9","subject":"English Language Arts","grade":"2","text":"Describe the relationship between information from TWO OR MORE TEXTS ON THE SAME THEME OR TOPIC ."},{"code":"RL.2.1","subject":"English Language Arts","grade":"2","text":"Ask and answer such QUESTIONS AS WHO, WHAT, WHERE, WHEN, WHY AND HOW and make and support logical inferences to construct meaning from the text."},{"code":"RL.2.10","subject":"English Language Arts","grade":"2","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.2.2","subject":"English Language Arts","grade":"2","text":"Identify implicit and explicit information from a literary text to determine the AUTHOR'S MESSAGE, LESSON LEARNED AND/OR MORAL , including but not limited to FABLES AND FOLKTALES FROM DIVERSE CULTURES ."},{"code":"RL.2.3","subject":"English Language Arts","grade":"2","text":"Describe how CHARACTERS in a story respond to MAJOR EVENTS AND CHALLENGES in order to make meaning of the story development ."},{"code":"RL.2.4","subject":"English Language Arts","grade":"2","text":"Describe how words and phrases , including but not limited to REGULAR BEATS, ALLITERATION, RHYMES and/or REPEATED LINES , supply rhythm and shape meaning in a story, poem or song."},{"code":"RL.2.5","subject":"English Language Arts","grade":"2","text":"Describe how parts of the text contribute to the overall STRUCTURES OF STORIES, POEMS AND DRAMAS (E.G., BEGINNING, MIDDLE AND END OF STORIES; LINES AND STANZAS IN POEMS; AND ACTS/SCENES IN DRAMAS) ."},{"code":"RL.2.6","subject":"English Language Arts","grade":"2","text":"With prompting and support, acknowledge differences in the PERSPECTIVES OF CHARACTERS , including by speaking in a different voice for each character when reading dialogue aloud , and how those PERSPECTIVES shape the content of the text ."},{"code":"RL.2.7","subject":"English Language Arts","grade":"2","text":"Use a story\u2019s illustrations and words in PRINT/NON-PRINT TEXTS to demonstrate understanding of CHARACTERS, SETTING AND PLOT ."},{"code":"RL.2.8","subject":"English Language Arts","grade":"2","text":"Not applicable to literature"},{"code":"RL.2.9","subject":"English Language Arts","grade":"2","text":"Compare and contrast TWO OR MORE VERSIONS of the same story by DIFFERENT AUTHORS OR FROM DIFFERENT CULTURES ."},{"code":"KY.2.G.1","subject":"Mathematics","grade":"2","text":"Recognize and draw shapes having specified attributes, such as a given number of angles or sides. Identify triangles, quadrilaterals, pentagons, hexagons and cubes (identify number of faces)."},{"code":"KY.2.G.2","subject":"Mathematics","grade":"2","text":"Partition a rectangle into rows and columns of same-size squares and count to find the total number of them."},{"code":"KY.2.G.3","subject":"Mathematics","grade":"2","text":"Partition circles and rectangles into two, three, or four equal shares; describe the shares using the words halves, thirds, half of, a third of, etc.; and describe the whole as two halves, three thirds, four fourths. Recognize that equal shares of identical wholes need not have the same shape."},{"code":"KY.2.MD.1","subject":"Mathematics","grade":"2","text":"Measure the length of an object by selecting and using appropriate tools such as rulers, yardsticks, meter sticks and measuring tapes."},{"code":"KY.2.MD.10","subject":"Mathematics","grade":"2","text":"Create a pictograph and a bar graph (with single-unit scale) to represent a data set with up to four categories. Solve simple put together, take-apart and compare problems using information presented in a bar graph."},{"code":"KY.2.MD.2","subject":"Mathematics","grade":"2","text":"Measure the length of an object twice, using length units of different lengths for the two measurements; describe how the two measurements relate to the size of the unit chosen."},{"code":"KY.2.MD.3","subject":"Mathematics","grade":"2","text":"Estimate lengths using units of inches, feet, yards, centimeters and meters."},{"code":"KY.2.MD.4","subject":"Mathematics","grade":"2","text":"Measure to determine how much longer one object is than another, expressing the length difference in terms of either a customary or metric standard length unit."},{"code":"KY.2.MD.5","subject":"Mathematics","grade":"2","text":"Use addition and subtraction within 100 to solve word problems involving lengths that are given in the same units by using drawings and equations with a symbol for the unknown number to represent the problem."},{"code":"KY.2.MD.6","subject":"Mathematics","grade":"2","text":"Represent whole numbers as lengths from 0 on a number line with equally spaced points corresponding to the numbers 0, 1, 2,... and represent whole-number sums and differences within 100 on a number line."},{"code":"KY.2.MD.7","subject":"Mathematics","grade":"2","text":"Tell and write time from analog and digital clocks to the nearest five minutes, using a.m. and p.m."},{"code":"KY.2.MD.8","subject":"Mathematics","grade":"2","text":"Solve word problems with adding and subtracting within 100, (not using dollars and cents simultaneously) using the \uff04and \uffe0 symbols appropriately (not including decimal notation)."},{"code":"KY.2.MD.9","subject":"Mathematics","grade":"2","text":"Investigate questions involving measurements. a. Identify a statistical question focused on measurements. b. Generate measurement data by measuring lengths of several objects to the nearest whole unit, or by making repeated measurements of the same object. c. Show the measurements by making a dot plot, where the horizontal scale is marked off in whole-number units."},{"code":"KY.2.NBT.1","subject":"Mathematics","grade":"2","text":"Understand that the three digits of a three-digit number represent amounts of hundreds, tens and ones. Understand the following as special cases: a. 100 can be thought of as a bundle of ten tens \u2014 called a \u201chundred.\u201d b. The numbers 100, 200, 300, 400, 500, 600, 700, 800, 900 refer to one, two, three, four, five, six, seven, eight, or nine hundreds (and 0 tens and 0 ones)."},{"code":"KY.2.NBT.2","subject":"Mathematics","grade":"2","text":"Count forwards and backwards within 1000; skip-count by 5s, 10s and 100s."},{"code":"KY.2.NBT.3","subject":"Mathematics","grade":"2","text":"Read and write numbers to 1000 using base-ten numerals, number names and expanded form."},{"code":"KY.2.NBT.4","subject":"Mathematics","grade":"2","text":"Compare two three-digit numbers based on meanings of the hundreds, tens and ones digits, using >, =, and < symbols to record the results of comparisons."},{"code":"KY.2.NBT.5","subject":"Mathematics","grade":"2","text":"Fluently add and subtract within 100 using strategies based on place value, properties of operations and/or the relationship between addition and subtraction."},{"code":"KY.2.NBT.6","subject":"Mathematics","grade":"2","text":"Add up to four two-digit numbers using strategies based on place value and properties of operations."},{"code":"KY.2.NBT.7","subject":"Mathematics","grade":"2","text":"Add and subtract within 1000. a. Represent and solve addition and subtraction problems using\u2026 \u2022 concrete models or drawings; \u2022 strategies based on place value; \u2022 properties of operations; \u2022 the relationship between addition and subtraction and; \u2022 relate drawings and strategies to expressions or equations. b. Understand that in adding or subtracting three-digit numbers, one adds or subtracts hundreds and hundreds, tens and tens, ones and ones; and sometimes it is necessary to compose or decompose tens or hundreds."},{"code":"KY.2.NBT.8","subject":"Mathematics","grade":"2","text":"Mentally add 10 or 100 to a given number 100\u2013900 and mentally subtract 10 or 100 from a given number 100\u2013900."},{"code":"KY.2.NBT.9","subject":"Mathematics","grade":"2","text":"Explain why addition and subtraction strategies work, using place value and the properties of operations."},{"code":"KY.2.OA.1","subject":"Mathematics","grade":"2","text":"Use addition and subtraction within 100 to solve one- and two-step word problems involving situations of adding to, taking from, putting together, taking apart and comparing, with unknowns in all positions, by using drawings and equations with a symbol for the unknown number to represent the problem."},{"code":"KY.2.OA.2","subject":"Mathematics","grade":"2","text":"Fluently add and subtract within 20 using mental strategies."},{"code":"KY.2.OA.3","subject":"Mathematics","grade":"2","text":"Determine whether a group of objects (up to 20) has an odd or even number of members; write an equation to express an even number as a sum of two equal addends."},{"code":"KY.2.OA.4","subject":"Mathematics","grade":"2","text":"Use addition to find the total number of objects arranged in rectangular arrays with up to 5 rows and up to 5 columns; write an equation to express the total as a sum of equal addends."},{"code":"2-ESS1-1","subject":"Science","grade":"2","text":"Use information from several sources to provide evidence that Earth events can occur quickly or slowly."},{"code":"2-ESS2-1","subject":"Science","grade":"2","text":"Compare multiple solutions designed to slow or prevent wind or water from changing the shape of the land.*"},{"code":"2-ESS2-2","subject":"Science","grade":"2","text":"Develop a model to represent the shapes and kinds of land and bodies of water in an area."},{"code":"2-ESS2-3","subject":"Science","grade":"2","text":"Obtain information to identify where water is found on Earth and that it can be solid or liquid."},{"code":"2-LS2-1","subject":"Science","grade":"2","text":"Plan and conduct an investigation to determine if plants need sunlight and water to grow."},{"code":"2-LS2-2","subject":"Science","grade":"2","text":"Develop a simple model that mimics the function of an animal in dispersing seeds or pollinating plants.*"},{"code":"2-LS4-1","subject":"Science","grade":"2","text":"Make observations of plants and animals to compare the diversity of life in different habitats."},{"code":"2-PS1-1","subject":"Science","grade":"2","text":"Plan and conduct an investigation to describe and classify different kinds of materials by their observable properties."},{"code":"2-PS1-2","subject":"Science","grade":"2","text":"Analyze data obtained from testing different materials to determine which materials have the properties that are best suited for an intended purpose. *"},{"code":"2-PS1-3","subject":"Science","grade":"2","text":"Make observations to construct an eviden ce-based account of how an object made of a small set of pieces can be disassembled and made into a new object."},{"code":"2-PS1-4","subject":"Science","grade":"2","text":"Construct an argument with evidence that some changes caused by heating or cooling can be reversed and some cannot."},{"code":"2.C.CP.1","subject":"Social Studies","grade":"2","text":"Explain the need for civ ic and political structures in North America."},{"code":"2.C.CP.2","subject":"Social Studies","grade":"2","text":"Explain that the functions of effective government are to create order, establish justice and meet the needs of their citizens."},{"code":"2.C.CV.1","subject":"Social Studies","grade":"2","text":"Evaluate how civic v irtues guide governments, societies and communities."},{"code":"2.C.CV.2","subject":"Social Studies","grade":"2","text":"Evaluate how democratic principles guide governments, societies and communities."},{"code":"2.C.KGO.1","subject":"Social Studies","grade":"2","text":"Describe how Ke ntucky\u2019s laws change over time."},{"code":"2.C.PR.1","subject":"Social Studies","grade":"2","text":"Describe how so cieties changed and continue to change through processes, rules and laws in North America."},{"code":"2.C.RR.1","subject":"Social Studies","grade":"2","text":"Describe the impo rtance of civic participation."},{"code":"2.C.RR.2","subject":"Social Studies","grade":"2","text":"Compare the rights and responsibilities of citizens in North America."},{"code":"2.E.IC.1","subject":"Social Studies","grade":"2","text":"Categorize d ifferent limited resources as renewable and non- renewable resources."},{"code":"2.E.KE.1","subject":"Social Studies","grade":"2","text":"Provide examples of each of the factors of production in Kentucky."},{"code":"2.E.MA.1","subject":"Social Studies","grade":"2","text":"Identify the cost of e veryday, common goods."},{"code":"2.E.MA.2","subject":"Social Studies","grade":"2","text":"Explain the role of prices in an economic market."},{"code":"2.E.MI.1","subject":"Social Studies","grade":"2","text":"Describe how ex amples of capital, human, and natural resources are related to goods and services."},{"code":"2.E.MI.2","subject":"Social Studies","grade":"2","text":"Describe how people are both producers and consumers."},{"code":"2.E.ST.1","subject":"Social Studies","grade":"2","text":"Explain why people specialize in the production of goods and services."},{"code":"2.G.GR.1","subject":"Social Studies","grade":"2","text":"Examine geog raphic features of places in North America, using a variety of geographic data, including maps, photos, and other geographic tools."},{"code":"2.G.HE.1","subject":"Social Studies","grade":"2","text":"Explain the ways human activities impact the physical environment of North America."},{"code":"2.G.HI.1","subject":"Social Studies","grade":"2","text":"Compare the ways various cultural groups connect and interact within North America."},{"code":"2.G.KGE.1","subject":"Social Studies","grade":"2","text":"Analyze reason s for similarities and differences in the settlement patterns of North America and Kentucky."},{"code":"2.G.MM.1","subject":"Social Studies","grade":"2","text":"Explain patt erns of human settlement in North America."},{"code":"2.H.CE.1","subject":"Social Studies","grade":"2","text":"Describe events in N orth America shaped by multiple cause and effect relationships."},{"code":"2.H.CE.2","subject":"Social Studies","grade":"2","text":"Describe the events and innovations that had effects on North America."},{"code":"2.H.CH.1","subject":"Social Studies","grade":"2","text":"Identify an d compare the diverse North American cultural groups of the past and today."},{"code":"2.H.CO.1","subject":"Social Studies","grade":"2","text":"Describe events in N orth America that illustrate how people from diverse cultural groups attempted to work through conflicts to solve a problem."},{"code":"2.H.KH.1","subject":"Social Studies","grade":"2","text":"Explain how events in North America impacted Kentucky."},{"code":"2.I.CC.1","subject":"Social Studies","grade":"2","text":"Construct an ex planation, using correct sequence and relevant information, to provide information on a community in North America."},{"code":"2.I.CC.2","subject":"Social Studies","grade":"2","text":"Construct an argument with reasons and details to address a civic issue on a community in North America."},{"code":"2.I.CC.3","subject":"Social Studies","grade":"2","text":"Identify ways to civically engage in Kentucky."},{"code":"2.I.CC.4","subject":"Social Studies","grade":"2","text":"Use listening and consensus-building procedures to discuss how to take action in the local community or Kentucky."},{"code":"2.I.Q.1","subject":"Social Studies","grade":"2","text":"Ask compelling questions about communities found in North America. \u201cHow do diverse groups build good relationships?\u201d Teachers can pose this question to students to facilitate exploration about why this standard applies to communities in North America."},{"code":"2.I.Q.2","subject":"Social Studies","grade":"2","text":"Identify supporting questions that help answer compelling questions about communities found in North America."},{"code":"2.I.UE.1","subject":"Social Studies","grade":"2","text":"Identify characteristics of primary and secondary sources."},{"code":"2.I.UE.2","subject":"Social Studies","grade":"2","text":"Determine whether the evidence in primary and secondary sources is fact or opinion."},{"code":"2.I.UE.3","subject":"Social Studies","grade":"2","text":"Identify a primary and secondary source, and explain who created it, when they created it, where they created it and why they created it."},{"code":"2.I.UE.4","subject":"Social Studies","grade":"2","text":"Construct responses to compelling and supporting questions, using reasoning, examples and details, about the diversity of communities in North America."},{"code":"C.3.1","subject":"English Language Arts","grade":"3","text":"Compose OPINION PIECES , using a combination of writing and digital resources, on topics or texts , with supporting reasons . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, produce writing in which the development and organization are appropriate to task and purpose . b. Introduce the topic , followed by opinion statement, and create an organizational structure . c. Provide reasons with elaborate details to support the opinion . d. Use grade-appropriate TRANSITIONS to connect sentences and paragraphs . e. Provide a concluding section . f. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.3.2","subject":"English Language Arts","grade":"3","text":"Compose informative and/or explanatory texts, using writing and digital resources, to examine a topic and provide information. a. With guidance and support from adults, produce writing in which the development and organization are appropriate to task and purpose. b. Introduce a topic and group related information together; include illustrations when useful to aiding comprehension. c. Develop the topic with facts, definitions and details. d. Use grade-appropriate conjunctions to develop text structure within sentences. e. Use grade-appropriate transitions to develop text structure in sentences and paragraphs. f. Provide a concluding section. g. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing."},{"code":"C.3.3","subject":"English Language Arts","grade":"3","text":"Compose NARRATIVES , using writing and digital resources, to develop real or imagined experiences or multiple events or ideas , using effective technique, descriptive details and clear sequences . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. With guidance and support from adults, produce writing in which the development and organization are appropriate to task and purpose . b. Establish a situation, and introduce a narrator and/or characters; organize an event sequence that reflects linear, nonlinear and/or circular structure . c. Use dialogue and descriptions of actions, thoughts and feelings to develop experiences and events or show the response of characters to situations . d. Use temporal words and phrases to signal event order . e. Create a sense of closure that follows the narrated experiences or events . f. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising and editing ."},{"code":"C.3.4","subject":"English Language Arts","grade":"3","text":"With guidance and support from adults, use DIGITAL RESOURCES to create and publish products as well as to interact and collaborate with others ."},{"code":"C.3.5","subject":"English Language Arts","grade":"3","text":"Conduct short RESEARCH projects that build knowledge about a topic ."},{"code":"C.3.6","subject":"English Language Arts","grade":"3","text":"Summarize information from experiences or gather information from print and digital sources; take brief notes on information from various print/digital sources and analyze by sorting into appropriate categories ."},{"code":"C.3.7","subject":"English Language Arts","grade":"3","text":"Compose routinely over extended time frames and shorter time frames for a variety of tasks, purposes and audiences ."},{"code":"HW.3.1","subject":"English Language Arts","grade":"3","text":"Legibly print all upper- and lowercase letters and numerals with correct form. Introduce formation of all upper- and lowercase cursive letters. Legibly form cursive letters, words and sentences with accepted norms."},{"code":"L.3.1","subject":"English Language Arts","grade":"3","text":"When writing or speaking , demonstrate command of the conventions of General American English grammar and usage . a. Explain the function OF NOUNS, PRONOUNS, VERBS, ADJECTIVES AND ADVERBS in a GRADE-LEVEL TEXT . b. Form and use REGULAR AND IRREGULAR PLURAL NOUNS . c. Use ABSTRACT NOUNS . d. Form and use REGULAR AND IRREGULAR VERBS . e. Use VERB TENSES . f. Ensure SUBJECT-VERB AND PRONOUN-ANTECEDENT AGREEMENT . g. Form and use COMPARATIVE AND SUPERLATIVE ADJECTIVES AND ADVERBS , and choose between them depending on what is to be modified . h. Use COORDINATING AND SUBORDINATING CONJUNCTIONS . i. Produce SIMPLE, COMPOUND AND COMPLEX SENTENCES ."},{"code":"L.3.2","subject":"English Language Arts","grade":"3","text":"When writing : a. Capitalize APPROPRIATE WORDS IN TITLES . b. Use COMMAS IN ADDRESSES . c. Use COMMAS AND QUOTATION MARKS IN DIALOGUE . d. Use POSSESSIVES . e. Use conventional spelling for HIGH-FREQUENCY WORDS WHERE SUFFIXES ARE ADDED TO BASE WORDS . f. Use spelling patterns (graphemes) and generalizations in writing MULTISYLLABIC WORDS . g. Consult reference materials as needed to check and correct spellings ."},{"code":"L.3.3","subject":"English Language Arts","grade":"3","text":"Use knowledge of language and its conventions when writing, speaking, reading or listening . a. Choose words and phrases for effect . b. Recognize and observe differences between THE CONVENTIONS OF SPOKEN AND WRITTEN GENERAL AMERICAN ENGLISH ."},{"code":"L.3.4","subject":"English Language Arts","grade":"3","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grade 3 reading and content, choosing flexibly from an array of strategies . a. Use SENTENCE-LEVEL CONTEXT as a clue to the meaning of a word or phrase . b. Determine the meaning of the new word formed when a known AFFIX is added to a known word . c. Use a known ROOT WORD as a clue to the meaning of an unknown word with the same root . d. Use glossaries or beginning dictionaries to determine or clarify the precise meaning of key words and phrases . e. Acquire and use accurately GRADE-APPROPRIATE CONVERSATIONAL, GENERAL ACADEMIC AND DOMAIN-SPECIFIC words and phrases, including THOSE THAT SIGNAL SPATIAL AND TEMPORAL RELATIONSHIPS ."},{"code":"L.3.5","subject":"English Language Arts","grade":"3","text":"Demonstrate understanding of word relationships and nuances in word meanings . a. Distinguish the LITERAL AND NONLITERAL MEANINGS OF WORDS AND PHRASES in context . b. Demonstrate understanding of words by relating them to their SYNONYMS and ANTONYMS . c. Distinguish shades of meaning among RELATED WORDS THAT DESCRIBE DEGREES OF CERTAINTY ."},{"code":"RF.3.3","subject":"English Language Arts","grade":"3","text":"Know and apply grade-level phonics and word analysis skills in decoding and encoding words. a. Identify, decode, encode and know the meaning of words with the most common prefixes and derivational suffixes, including Latin suffixes. b. Decode and encode multisyllabic words. Fluency"},{"code":"RF.3.4","subject":"English Language Arts","grade":"3","text":"Read fluently (accuracy, speed and prosody) on grade-level to support comprehension. a. Read grade-level text with purpose and understanding. b. Fluently read grade-level prose and poetry orally on successive readings. c. Use context to confirm or self-correct word recognition and understanding, rereading as necessary. d. Read grade-appropriate irregularly spelled words."},{"code":"RI.3.1","subject":"English Language Arts","grade":"3","text":"Ask and answer QUESTIONS , and make and support logical inferences to construct meaning from the text."},{"code":"RI.3.10","subject":"English Language Arts","grade":"3","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT independently ."},{"code":"RI.3.2","subject":"English Language Arts","grade":"3","text":"Identify implicit and cite explicit information from an informational text to determine the CENTRAL IDEA of a text."},{"code":"RI.3.3","subject":"English Language Arts","grade":"3","text":"Describe the relationship between INDIVIDUALS, A SERIES OF HISTORICAL EVENTS, SCIENTIFIC IDEAS OR CONCEPTS OR STEPS IN TECHNICAL PROCEDURES over the course of a text ."},{"code":"RI.3.4","subject":"English Language Arts","grade":"3","text":"Determine the meaning of GENERAL ACADEMIC WORDS AND PHRASES in a GRADE-LEVEL TEXT and describe how those words and phrases shape meaning ."},{"code":"RI.3.5","subject":"English Language Arts","grade":"3","text":"Identify and describe INFORMATIONAL TEXT STRUCTURES, including COMPARISON, CAUSE/EFFECT AND PROBLEM/SOLUTION STRUCTURES , and describe the logical connection between particular sentences and paragraphs in a text and how they contribute to the overall structure ."},{"code":"RI.3.6","subject":"English Language Arts","grade":"3","text":"Distinguish their own PERSPECTIVE from that of the author of a text and describe how various perspectives shape the content and style of a text."},{"code":"RI.3.7","subject":"English Language Arts","grade":"3","text":"Identify and explain how specific VISUALS , including but not limited to DIAGRAMS, GRAPHS, PHOTOGRAPHS AND SIDE BARS , contribute to the meaning and clarity of a text ."},{"code":"RI.3.8","subject":"English Language Arts","grade":"3","text":"Describe how REASONS AND EVIDENCE support specific CLAIMS the author makes in a text."},{"code":"RI.3.9","subject":"English Language Arts","grade":"3","text":"Explain the relationship between information from TWO OR MORE TEXTS ON THE SAME THEME OR TOPIC ."},{"code":"RL.3.1","subject":"English Language Arts","grade":"3","text":"Ask and answer QUESTIONS and make and support logical inferences to construct meaning from the text."},{"code":"RL.3.10","subject":"English Language Arts","grade":"3","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.3.2","subject":"English Language Arts","grade":"3","text":"Identify implicit and cite explicit information from a literary text to determine the theme , LESSON LEARNED AND/OR MORAL, including but not limited to FABLES, FOLKTALES AND MYTHS FROM DIVERSE CULTURES ."},{"code":"RL.3.3","subject":"English Language Arts","grade":"3","text":"Describe CHARACTERS in a story, including but not limited to their TRAITS, MOTIVATIONS, ACTIONS OR FEELINGS , and how they affect the plot ."},{"code":"RL.3.4","subject":"English Language Arts","grade":"3","text":"Determine the meaning of words and phrases as they are used in a text, distinguishing LITERAL FROM NONLITERAL LANGUAGE , including but not limited to IDIOMS and HYPERBOLES , and describe how those words and phrases shape meaning ."},{"code":"RL.3.5","subject":"English Language Arts","grade":"3","text":"Describe THE STRUCTURE and provide evidence of how the parts of the text contribute to the whole IN A STORY, POEM OR DRAMA (E.G., HOW A CHAPTER, STANZA OR ACT/SCENE MIGHT BUILD ON ANOTHER PART OF THE TEXT) ."},{"code":"RL.3.6","subject":"English Language Arts","grade":"3","text":"Distinguish their own PERSPECTIVE from that of the narrator or those of the characters , and describe how various PERSPECTIVES shape the content of the text ."},{"code":"RL.3.7","subject":"English Language Arts","grade":"3","text":"Explain how the specific aspects of a text\u2019s illustrations contribute to an effect , including but not limited to creating MOOD, CHARACTER AND SETTING ."},{"code":"RL.3.8","subject":"English Language Arts","grade":"3","text":"Not applicable to literature"},{"code":"RL.3.9","subject":"English Language Arts","grade":"3","text":"Compare and contrast the THEMES, SETTINGS AND PLOTS of stories written by THE SAME AUTHOR ABOUT THE SAME OR SIMILAR CHARACTERS ."},{"code":"KY.3.G.1","subject":"Mathematics","grade":"3","text":"Classify polygons by attributes. a. Recognize and classify polygons based on the number of sides and vertices (triangles, quadrilaterals, pentagons and hexagons). b. Recognize and classify quadrilaterals (rectangles, squares, parallelograms, rhombuses, trapezoids) by side lengths and understanding shapes in different categories may share attributes and the shared attributes can define a larger category. c. Identify shapes that do not belong to a given category or subcategory."},{"code":"KY.3.G.2","subject":"Mathematics","grade":"3","text":"Partition shapes into parts with equal areas. Express the area of each part as a unit fraction of the whole."},{"code":"KY.3.MD.1","subject":"Mathematics","grade":"3","text":"Tell and write time to the nearest minute and measure elapsed time intervals in minutes. Solve word problems involving addition and subtraction of time intervals within and across the hour in minutes."},{"code":"KY.3.MD.2","subject":"Mathematics","grade":"3","text":"Measure and solve problems involving mass and liquid volume. a. Measure and estimate masses and liquid volumes of objects using standard units of grams (g), kilograms (kg) and liters (L). b. Add, subtract, multiply, or divide to solve one-step word problems involving masses or volumes that are given in the same units."},{"code":"KY.3.MD.3","subject":"Mathematics","grade":"3","text":"Investigate questions involving categorical data. a. Identify a statistical question focused on categorical data and gather data; b. Create a scaled pictograph and a scaled bar graph to represent a data set (using technology or by hand); c. Make observations from the graph about the question posed, including \u201chow many more\u201d and \u201chow many less\u201d questions."},{"code":"KY.3.MD.4","subject":"Mathematics","grade":"3","text":"Investigate questions involving numerical data. a. Identify a statistical question focused on numerical data; b. Generate measurement data by measuring lengths using rulers marked with halves and fourths of an inch. c. Show the data by making a dot plot where the horizontal scale is marked off in appropriate units \u2013 whole numbers, halves, or quarters. d. Make observations from the graph about the question posed, including questions about the shape of the data and compare responses."},{"code":"KY.3.MD.5","subject":"Mathematics","grade":"3","text":"Recognize area as an attribute of plane figures and understand concepts of area measurement."},{"code":"KY.3.MD.6","subject":"Mathematics","grade":"3","text":"Measure areas by counting unit squares (square cm, square m, square in, square ft. and improvised units)."},{"code":"KY.3.MD.7","subject":"Mathematics","grade":"3","text":"Relate area to the operations of multiplication and addition. a. Find the area of a rectangle with whole-number side lengths by tiling it and show the area is the same as would be found by multiplying the side lengths. b. Multiply side lengths to find areas of rectangles with whole- number side lengths in the context of solving real world and mathematical problems and represent whole-number products as rectangular areas in mathematical reasoning. c. Use tiling to show in a concrete case the area of a rectangle with whole-number side lengths a and b + c is the sum of a \u00d7 b d."},{"code":"KY.3.MD.8","subject":"Mathematics","grade":"3","text":"Solve real world and mathematical problems involving perimeters of polygons. a. Find the perimeter given the side lengths of a polygon. b. Find an unknown side length, given the perimeter and some lengths. c. Draw rectangles with the same perimeter and different areas or with the same area and different perimeters."},{"code":"KY.3.NBT.1","subject":"Mathematics","grade":"3","text":"Use place value understanding to round whole numbers to the nearest 10 or 100."},{"code":"KY.3.NBT.2","subject":"Mathematics","grade":"3","text":"Fluently add and subtract within 1000 using strategies and algorithms based on place value, properties of operations and/or the relationship between addition and subtraction."},{"code":"KY.3.NBT.3","subject":"Mathematics","grade":"3","text":"Multiply one-digit whole numbers by multiples of 10 in the range of 10\u201390 using strategies based on place value and properties of operations."},{"code":"KY.3.NF.1","subject":"Mathematics","grade":"3","text":"Understand a fraction 1 \ud835\udc4f\ud835\udc4f as the quantity formed by 1 part when a whole is partitioned into b equal parts; understand a fraction \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f as the quantity formed by a parts of size 1 \ud835\udc4f\ud835\udc4f."},{"code":"KY.3.NF.2","subject":"Mathematics","grade":"3","text":"Understand a fraction as a number on the number line; represent fractions on a number line. a. Represent a fraction 1 \ud835\udc4f\ud835\udc4f (unit fraction) on a number line by defining the interval from 0 to 1 as the whole and partitioning it into b equal parts. \u2022 Recognize each part has size 1 \ud835\udc4f\ud835\udc4f. \u2022 a unit fraction, 1 \ud835\udc4f\ud835\udc4f is located 1 \ud835\udc4f\ud835\udc4f of a whole unit from 0 on the number line. b. Represent a non-unit fraction \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f on a number line by marking off a lengths of 1 \ud835\udc4f\ud835\udc4f (unit fractions) from 0. Recognize that the resulting interval has size \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f and that its endpoint locates the non-unit fraction \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f on the number line."},{"code":"KY.3.NF.3","subject":"Mathematics","grade":"3","text":"Explain equivalence of fractions in special cases and compare fractions by reasoning about their size. a. Understand two fractions as equivalent (equal) if they are the same size, or same point on a number line. b. Recognize and generate simple equivalent fractions. Explain why the fractions are equivalent through writing or drawing. c. Express whole numbers as fractions and recognize fractions that are equivalent to whole numbers. d. Compare two fractions with the same numerator or the same denominator by reasoning about their size. Recognize that comparisons are valid only when the two fractions refer to the same whole. Record the results of comparisons with the symbols >, =, or <, and justify the conclusions."},{"code":"KY.3.OA.1","subject":"Mathematics","grade":"3","text":"Interpret and demonstrate products of whole numbers."},{"code":"KY.3.OA.2","subject":"Mathematics","grade":"3","text":"Interpret and demonstrate whole-number quotients of whole numbers, where objects are partitioned into equal shares."},{"code":"KY.3.OA.3","subject":"Mathematics","grade":"3","text":"Use multiplication and division within 100 to solve word problems in situations involving equal groups, arrays and measurement quantities, by using drawings and equations with a symbol for the unknown number to represent the problem."},{"code":"KY.3.OA.4","subject":"Mathematics","grade":"3","text":"Determine the unknown whole number in a multiplication or division equation relating three whole numbers."},{"code":"KY.3.OA.5","subject":"Mathematics","grade":"3","text":"Apply properties of operations as strategies to multiply and divide."},{"code":"KY.3.OA.6","subject":"Mathematics","grade":"3","text":"Understand division as an unknown-factor problem."},{"code":"KY.3.OA.7","subject":"Mathematics","grade":"3","text":"Fluently multiply and divide within 100, using strategies such as the relationship between multiplication and division or properties of operations."},{"code":"KY.3.OA.8","subject":"Mathematics","grade":"3","text":"Use various strategies to solve two-step word problems using the four operations (involving only whole numbers with whole number answers). Represent these problems using equations with a letter standing for the unknown quantity. Assess the reasonableness of answers using mental computation and estimation strategies including rounding."},{"code":"KY.3.OA.9","subject":"Mathematics","grade":"3","text":"Identify arithmetic patterns (including patterns in the addition table or multiplication table) and explain them using properties of operations."},{"code":"3-5-ETS1-1","subject":"Science","grade":"3","text":"Define a simple design problem reflecting a need or a want that includes specified criteria for success and constraints on materials, time, or cost. *"},{"code":"3-5-ETS1-2","subject":"Science","grade":"3","text":"Generate and compare multiple possible solutions to a problem based on how well each is likely to meet the criteria and constraints of the problem. *"},{"code":"3-5-ETS1-3","subject":"Science","grade":"3","text":"Plan and carry out fair tests in which variables are controlled and failure points are considered to identify aspects of a model or prototype that can be improved. *"},{"code":"3-ESS2-1","subject":"Science","grade":"3","text":"Represent data in tables and graphical displays to describe typical weather conditions expected during a particular season."},{"code":"3-ESS2-2","subject":"Science","grade":"3","text":"Obtain and combine information to describe climates in different regions of the world."},{"code":"3-ESS3-1","subject":"Science","grade":"3","text":"Make a claim about the merit of a design solution that reduces the impacts of a weather -related hazard. *"},{"code":"3-LS1-1","subject":"Science","grade":"3","text":"Develop models to describe that organisms have unique and diverse life cycles but all have in common birth, growth, reproduction, and death."},{"code":"3-LS2-1","subject":"Science","grade":"3","text":"Construct an argument that some animals form groups that help members survive."},{"code":"3-LS3-1","subject":"Science","grade":"3","text":"Analyze and interpret data to provide evidence that plants and animals have traits inherited from parents and that variation of these traits exists in a group of similar organisms."},{"code":"3-LS3-2","subject":"Science","grade":"3","text":"Use evidence to support the explanation that traits can be influenced by the environment."},{"code":"3-LS4-2","subject":"Science","grade":"3","text":"Use evidence to construct an explanation for how the variations in characteristics among individuals of the same species may provide advantages in surviving, finding mates, and reproducing."},{"code":"3-LS4-3","subject":"Science","grade":"3","text":"Construct an argument with evidence that in a particular habitat some organisms can survive well, some survive less well, and some cannot survive at all."},{"code":"3-LS4-4","subject":"Science","grade":"3","text":"Make a claim about the merit of a solution to a problem caused when the environment changes and the types of plants and animals that live there may change.*"},{"code":"3-PS2-1","subject":"Science","grade":"3","text":"Plan and conduct an investigation to provide evidence of the effects of balanced and unbalanced forces on the motion of an object."},{"code":"3-PS2-2","subject":"Science","grade":"3","text":"Make observations and/or measurements of an object\u2019s motion to provide evidence that a pattern can be used to predict future motion."},{"code":"3-PS2-3","subject":"Science","grade":"3","text":"Ask questions to determine cause-and-effect relationships of electric or magnetic interactions between two objects not in contact with each other."},{"code":"3-PS2-4","subject":"Science","grade":"3","text":"Define a simple design problem that can be solved by applying scientific ideas about magnets.*"},{"code":"3.C.CP.1","subject":"Social Studies","grade":"3","text":"Explain the basic purposes and functions of differing governing bodies in the world."},{"code":"3.C.CP.2","subject":"Social Studies","grade":"3","text":"Explain the basic purposes and functions of differing governing bodies in the world."},{"code":"3.C.CV.1","subject":"Social Studies","grade":"3","text":"Compare civic vir tues and democratic principles within a variety of diverse world communities."},{"code":"3.C.PR.1","subject":"Social Studies","grade":"3","text":"Explain how pro cesses, rules and laws influence how individuals are governed and how diverse world communities address problems."},{"code":"3.C.RR.1","subject":"Social Studies","grade":"3","text":"Examine how the go vernment maintains order, keeps people safe, and makes and enforces rules and laws in diverse world communities."},{"code":"3.E.IC.1","subject":"Social Studies","grade":"3","text":"Explain how people use incentives and opportunity costs to inform economic decisions. (continued) Opportunity cost is the benefit missed when an economic actor like a consumer, business, government or investor chooses one alternative over another."},{"code":"3.E.KE.1","subject":"Social Studies","grade":"3","text":"Explain how t rade between people and groups can benefit Kentucky."},{"code":"3.E.MA.1","subject":"Social Studies","grade":"3","text":"Differentiate be tween private property and public property."},{"code":"3.E.MA.2","subject":"Social Studies","grade":"3","text":"Investigate how the cost of things changes over time."},{"code":"3.E.MI.1","subject":"Social Studies","grade":"3","text":"Explain how produce rs and consumers interact to determine the prices of goods and services in markets."},{"code":"3.E.MI.2","subject":"Social Studies","grade":"3","text":"Describe the relationship between supply and demand."},{"code":"3.E.ST.1","subject":"Social Studies","grade":"3","text":"Describe examp les of economic interdependence."},{"code":"3.G.GR.1","subject":"Social Studies","grade":"3","text":"Explain how physical and cultural characteristics of world regions affect people, using a variety of maps, photos and other geographic representations."},{"code":"3.G.HE.1","subject":"Social Studies","grade":"3","text":"Explain how t he culture of places and regions influence how people modify and adapt to their environments."},{"code":"3.G.HI.1","subject":"Social Studies","grade":"3","text":"Explain how t he cultural aspects of a region spread beyond its borders."},{"code":"3.G.KGE.1","subject":"Social Studies","grade":"3","text":"Describe the impact of cultural diffusion and blending on Kentucky in the past and today."},{"code":"3.G.MM.1","subject":"Social Studies","grade":"3","text":"Analyze how hum an settlement and movement impact diverse groups of people."},{"code":"3.H.CE.1","subject":"Social Studies","grade":"3","text":"Compare diverse wor ld communities in terms of members, customs and traditions to the local community."},{"code":"3.H.CH.1","subject":"Social Studies","grade":"3","text":"Create and use chro nological reasoning to learn about significant figures, traditions and events of diverse world communities."},{"code":"3.H.CH.2","subject":"Social Studies","grade":"3","text":"Identify contributions made by inventors in diverse world communities."},{"code":"3.H.CO.1","subject":"Social Studies","grade":"3","text":"Evaluate the effec ts of people, goods and ideas that have diffused from one world community into other world communities and the effects of the people, goods and ideas on these communities."},{"code":"3.H.KH.1","subject":"Social Studies","grade":"3","text":"Explain how world e vents impact Kentucky, both in the past and today."},{"code":"3.I.CC.1","subject":"Social Studies","grade":"3","text":"Construct an explanation, using relevant information, to address a local, regional or global problem."},{"code":"3.I.CC.2","subject":"Social Studies","grade":"3","text":"Construct an argument with reasons and supporting evidence, to address a local, regional or global problem."},{"code":"3.I.CC.3","subject":"Social Studies","grade":"3","text":"Identify strategies to address local, regional or global problems."},{"code":"3.I.CC.4","subject":"Social Studies","grade":"3","text":"Use listening, consensus-building and voting procedures to determine the best strategies to take to address local, regional and global problems."},{"code":"3.I.Q.1","subject":"Social Studies","grade":"3","text":"Ask compelling questions about the interactions of diverse groups of people. \u201cHow does where we live affect how we live?\u201d Teachers can pose this question to students to facilitate exploration about why this standard applies to diverse groups of people in the world."},{"code":"3.I.Q.2","subject":"Social Studies","grade":"3","text":"Develop supporting questions that help answer compelling questions about the interactions of diverse groups of people."},{"code":"3.I.UE.1","subject":"Social Studies","grade":"3","text":"Describe how multiple perspectives shape the content and style of a primary and secondary source."},{"code":"3.I.UE.2","subject":"Social Studies","grade":"3","text":"Explain the relationship between two or more sources on the same theme or topic."},{"code":"3.I.UE.3","subject":"Social Studies","grade":"3","text":"Construct responses to compelling and supporting questions about the interactions of diverse groups of people using evidence and reasoning."},{"code":"C.4.1","subject":"English Language Arts","grade":"4","text":"Compose OPINIONS , using writing and digital resources, on topics or texts , supporting an author\u2019s perspective with reasons and information . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. Produce clear and coherent writing in which the development and organization are appropriate to task, purpose and audience . b. Introduce a topic or text clearly , state an opinion and create an organizational structure in which related ideas are grouped to support the writer\u2019s purpose . c. Provide reasons that are supported by facts and details . d. Use grade-appropriate TRANSITIONS to connect sentences and paragraphs . e. Provide a concluding section . f. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising , editing and rewriting ."},{"code":"C.4.2","subject":"English Language Arts","grade":"4","text":"Compose informative and/or explanatory texts, using writing and digital resources, to examine a topic and convey ideas and information clearly. a. Produce clear and coherent writing in which the development and organization are appropriate to task, purpose and audience. b. Introduce a topic clearly, and group related information in paragraphs and sections; include formatting, illustrations and multimedia when useful to aiding comprehension. c. Develop the topic with facts, definitions, concrete details, quotations or other information and examples related to the topic. d. Use grade-appropriate conjunctions to connect sentences and paragraphs. e. Use grade-appropriate transitions to develop text structure in sentences and paragraphs. f. Use precise language and domain-specific vocabulary to inform about or explain the topic. g. Provide a concluding section. h. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising, editing and rewriting."},{"code":"C.4.3","subject":"English Language Arts","grade":"4","text":"Compose narratives, using writing and digital resources, to develop real or imagined experiences or multiple events or ideas, using effective technique, descriptive details and clear sequences. a. Produce clear and coherent writing in which the development and organization are appropriate to task, purpose and audience. b. Orient the reader by establishing a situation and introducing a narrator and/or characters; organize an event sequence that reflects linear, nonlinear or circular structure. c. Use dialogue and description to develop experiences and events or show the responses of characters to situations. d. Use a variety of conjunctions and transitional words and phrases to manage the sequence of events. e. Use concrete words and phrases and sensory details to convey experiences and events precisely. f. Provide a conclusion that follows the narrated experiences or events. g. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising, editing and rewriting."},{"code":"C.4.4","subject":"English Language Arts","grade":"4","text":"With some guidance and support from adults, use DIGITAL RESOURCES to create and publish products as well as to interact and collaborate with others ."},{"code":"C.4.5","subject":"English Language Arts","grade":"4","text":"Conduct short RESEARCH projects that build knowledge through investigation of different aspects of a topic ."},{"code":"C.4.6","subject":"English Language Arts","grade":"4","text":"Summarize relevant information from experiences, or gather relevant information from various print and digital sources; take notes , categorize information and provide a list of sources ."},{"code":"C.4.7","subject":"English Language Arts","grade":"4","text":"Compose routinely over extended time frames and shorter time frames for a variety of tasks, purposes and audiences ."},{"code":"L.4.1","subject":"English Language Arts","grade":"4","text":"When writing or speaking , demonstrate command of the conventions of General American English grammar and usage . a. Use RELATIVE PRONOUNS AND RELATIVE ADVERBS . b. Use the PROGRESSIVE VERB TENSES . c. Use MODAL AUXILIARIES to convey various conditions , such as can, may and must. d. Order ADJECTIVES within sentences according to conventional patterns . e. Use PREPOSITIONAL PHRASES . f. Produce COMPLETE SENTENCES , recognizing and correcting inappropriate fragments and run-ons . g. Use FREQUENTLY CONFUSED WORDS , such as to, too, two; there, their, they\u2019re."},{"code":"L.4.2","subject":"English Language Arts","grade":"4","text":"When writing : a. Demonstrate appropriate use of CAPITALIZATION RULES . b. Use COMMAS AND QUOTATION MARKS TO INDICATE DIRECT SPEECH AND QUOTATIONS for a text. c. Use a COMMA BEFORE A COORDINATING CONJUNCTION IN A COMPOUND SENTENCE . d. Consult reference materials as needed to check and correct spellings ."},{"code":"L.4.3","subject":"English Language Arts","grade":"4","text":"Use knowledge of language and its conventions when writing, speaking, reading or listening . a. Choose words and phrases to convey ideas precisely . b. Choose punctuation for effect . c. Differentiate between ACADEMIC AND NON-ACADEMIC DISCOURSE PATTERNS based on context ."},{"code":"L.4.4","subject":"English Language Arts","grade":"4","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grade 4 reading and content, choosing flexibly from an array of strategies . a. Use context (e.g., DEFINITIONS, EXAMPLES OR RESTATEMENTS in text) as a clue to the meaning of a word or phrase . b. Use common AFFIXES AND ROOTS as clues to the meaning of a word . c. Consult print and digital reference materials to find the pronunciation and determine or clarify the precise meaning of key words and phrases . d. Acquire and use accurately GRADE-APPROPRIATE GENERAL ACADEMIC AND DOMAIN-SPECIFIC words and phrases, including THOSE THAT SIGNAL PRECISE ACTIONS and that are basic to a particular topic ."},{"code":"L.4.5","subject":"English Language Arts","grade":"4","text":"Demonstrate understanding of figurative language, word relationships and nuances in word meanings . a. Explain the meaning of simple SIMILES AND METAPHORS in context . b. Recognize and explain the meaning of common IDIOMS, ADAGES AND PROVERBS . c. Demonstrate understanding of words by relating them to their SYNONYMS and ANTONYMS ."},{"code":"RF.4.3","subject":"English Language Arts","grade":"4","text":"Know and apply grade-level phonics and word analysis skills in decoding and encoding words. a. Use combined knowledge of all phoneme-grapheme correspondences, syllabication patterns and morphology to accurately decode and encode unfamiliar multisyllabic words. Fluency"},{"code":"RF.4.4","subject":"English Language Arts","grade":"4","text":"Read fluently (accuracy, speed and prosody) on grade-level text to support comprehension. a. Read grade-level text with purpose and understanding. b. Fluently read grade-level prose and poetry orally on successive readings. c. Use context to confirm or self-correct word recognition and understanding, rereading as necessary."},{"code":"RI.4.1","subject":"English Language Arts","grade":"4","text":"REFER TO DETAILS AND EXAMPLES in a text when explaining what the text says explicitly and when drawing inferences from the text."},{"code":"RI.4.10","subject":"English Language Arts","grade":"4","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT independently ."},{"code":"RI.4.2","subject":"English Language Arts","grade":"4","text":"Analyze how the CENTRAL IDEAS are reflected in a text, and cite relevant implicit and explicit evidence from the text."},{"code":"RI.4.3","subject":"English Language Arts","grade":"4","text":"Explain the INDIVIDUALS, EVENTS, PROCEDURES, IDEAS OR CONCEPTS IN A HISTORICAL, SCIENTIFIC OR TECHNICAL TEXT , including what happened and why , based on specific information over the course of a text ."},{"code":"RI.4.4","subject":"English Language Arts","grade":"4","text":"Determine the meaning of GENERAL ACADEMIC AND DOMAIN-SPECIFIC WORDS OR PHRASES in a GRADE-LEVEL TEXT , and describe and explain how those words and phrases shape meaning ."},{"code":"RI.4.5","subject":"English Language Arts","grade":"4","text":"Describe the overall STRUCTURE , in a text or part of the text, the author uses to organize the events, ideas, concepts or information ."},{"code":"RI.4.6","subject":"English Language Arts","grade":"4","text":"Compare and contrast a FIRSTHAND AND SECONDHAND ACCOUNT of the same event or topic ."},{"code":"RI.4.7","subject":"English Language Arts","grade":"4","text":"Interpret information presented in PRINT AND NON-PRINT FORMATS and explain how the information contributes to an understanding of the text in which it appears ."},{"code":"RI.4.8","subject":"English Language Arts","grade":"4","text":"Explain how an author uses REASONS and EVIDENCE to support particular CLAIMS the author makes in a text."},{"code":"RI.4.9","subject":"English Language Arts","grade":"4","text":"Integrate information from TWO OR MORE TEXTS ON THE SAME THEME OR TOPIC ."},{"code":"RL.4.1","subject":"English Language Arts","grade":"4","text":"REFER TO DETAILS AND EXAMPLES in a text when explaining what the text says explicitly and when drawing inferences from the text."},{"code":"RL.4.10","subject":"English Language Arts","grade":"4","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.4.2","subject":"English Language Arts","grade":"4","text":"Analyze how the THEME is reflected in a text , and cite relevant implicit and explicit evidence from the text, including but not limited to poems, stories and dramas."},{"code":"RL.4.3","subject":"English Language Arts","grade":"4","text":"Describe in depth a CHARACTER\u2019S THOUGHTS, WORDS and/or ACTIONS, the SETTING or EVENT(S) IN A STORY OR DRAMA , drawing on specific details to analyze their interaction over the course of the text ."},{"code":"RL.4.4","subject":"English Language Arts","grade":"4","text":"Determine the meaning of words and phrases as they are used in a text, including but not limited to FIGURATIVE LANGUAGE such as METAPHORS and SIMILES , and describe and explain how those words and phrases shape meaning ."},{"code":"RL.4.5","subject":"English Language Arts","grade":"4","text":"Analyze THE STRUCTURE the author uses IN A STORY, POEM OR DRAMA , considering how the parts of the text contribute to the whole ."},{"code":"RL.4.6","subject":"English Language Arts","grade":"4","text":"Compare and contrast the POINT OF VIEW of first and third person narrators and the effect they have on the reader ."},{"code":"RL.4.7","subject":"English Language Arts","grade":"4","text":"Make connections between the TEXT OF A STORY OR DRAMA AND A VISUAL OR ORAL PRESENTATION , including making connections with what they \u201csee\u201d and \u201chear\u201d when reading the text to what they perceive when they listen or watch ."},{"code":"RL.4.8","subject":"English Language Arts","grade":"4","text":"Not applicable to literature"},{"code":"RL.4.9","subject":"English Language Arts","grade":"4","text":"Compare and contrast THEMES, TOPICS AND PATTERNS OF EVENTS in STORIES, MYTHS AND TRADITIONAL LITERATURE FROM DIFFERENT CULTURES ."},{"code":"KY.4.G.1","subject":"Mathematics","grade":"4","text":"Draw points, lines, line segments, rays, angles (right, acute, obtuse) and perpendicular and parallel lines. Identify these in two- dimensional figures."},{"code":"KY.4.G.2","subject":"Mathematics","grade":"4","text":"Classify two-dimensional figures based on the presence or absence of parallel or perpendicular lines, or the presence of absence of angles of a specified size. Recognize right triangles as a category and identify right triangles."},{"code":"KY.4.G.3","subject":"Mathematics","grade":"4","text":"Identify lines of symmetry. a. Recognize a line of symmetry for a two-dimensional figure. b. Identify line-symmetric figures and draw lines of symmetry. MP. 5,"},{"code":"KY.4.MD.1","subject":"Mathematics","grade":"4","text":"Know relative size of measurement units (mass, weight, liquid volume, length, time) within one system of units (metric system, U.S. standard system and time). a. Understand the relationship of measurement units within any given measurement system. b. Within any given measurement system, express measurements in a larger unit in terms of a smaller unit. c. Record measurement equivalents in a two-column table."},{"code":"KY.4.MD.2","subject":"Mathematics","grade":"4","text":"Use the four operations to solve word problems involving distances, intervals of time, liquid volumes, masses of objects and money. a. Solve measurement problems involving whole number, simple fractions or decimals. b. Solve problems that require converting a given measurement from a larger unit to a smaller unit within a common measurement system, such as 2 km = 2,000 m. c. Visually display measurement quantities using representations such as number lines that feature a measurement scale."},{"code":"KY.4.MD.3","subject":"Mathematics","grade":"4","text":"Apply the area and perimeter formulas for rectangles in real world and mathematical problems."},{"code":"KY.4.MD.4","subject":"Mathematics","grade":"4","text":"Use dot plots to analyze data to a statistical question. a. Identify a statistical question focused on numerical data. b. Make a dot plot to display a data set of measurements in fractions of a unit ( 1 2, 1 4, 1 8). c. Solve problems involving addition and subtraction of fractions by using information presented in dot plots."},{"code":"KY.4.MD.5","subject":"Mathematics","grade":"4","text":"Recognize angles as geometric shapes that are formed wherever two rays share a common endpoint and understand concepts of angle measurement."},{"code":"KY.4.MD.6","subject":"Mathematics","grade":"4","text":"Measure angles in whole-number degrees using a protractor. Sketch angles of specified measure."},{"code":"KY.4.MD.7","subject":"Mathematics","grade":"4","text":"Recognize angle measure as additive. When an angle is decomposed into non-overlapping parts, the angle measure of the whole is the sum of the angle measures of the parts. Solve addition and subtraction problems to find unknown angles on a diagram in real world and mathematical problems."},{"code":"KY.4.NBT.1","subject":"Mathematics","grade":"4","text":"Recognize in a multi-digit whole number, a digit in one place represents ten times what it represents in the place to its right."},{"code":"KY.4.NBT.2","subject":"Mathematics","grade":"4","text":"Represent and compare multi-digit whole numbers. a. Read and write multi-digit whole numbers using base-ten numerals, number names and expanded form. b. Compare two multi-digit numbers based on meanings of the digit in each place, using >, =, and < symbols to record the results of comparisons."},{"code":"KY.4.NBT.3","subject":"Mathematics","grade":"4","text":"Use place value understanding to round multi-digit whole numbers to any place."},{"code":"KY.4.NBT.4","subject":"Mathematics","grade":"4","text":"Fluently add and subtract multi-digit whole numbers using an algorithm."},{"code":"KY.4.NBT.5","subject":"Mathematics","grade":"4","text":"Multiply whole numbers \u25cf Up to four digit number by a one-digit number \u25cf Two-digit number by two-digit number Multiply using strategies based on place value and the properties of operations. Illustrate and explain the calculation by using equations, rectangular arrays and/or area models."},{"code":"KY.4.NBT.6","subject":"Mathematics","grade":"4","text":"Divide up to four-digit dividends by one-digit divisors. Find whole number quotients and remainders using \u25cf strategies based on place value \u25cf the properties of operations \u25cf the relationship between multiplication and division Illustrate and explain the calculation by using equations, rectangular arrays and/or area models."},{"code":"KY.4.NF.1","subject":"Mathematics","grade":"4","text":"Understand and generate equivalent fractions. a. Use visual fraction models to recognize and generate equivalent fractions that have different numerators/denominators even though they are the same size. b. Explain why a fraction \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f is equivalent to a fraction (\ud835\udc5b\ud835\udc5b \u00d7 \ud835\udc4e\ud835\udc4e) (\ud835\udc5b\ud835\udc5b \u00d7 \ud835\udc4f\ud835\udc4f)."},{"code":"KY.4.NF.2","subject":"Mathematics","grade":"4","text":"Compare two fractions with different numerators and different denominators using the symbols <, =, or >. Recognize comparisons are valid only when the two fractions refer to the same whole. Justify the conclusions."},{"code":"KY.4.NF.3","subject":"Mathematics","grade":"4","text":"Understand a fraction \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f with a > 1 as a sum of fractions 1 \ud835\udc4f\ud835\udc4f. a. Understand addition and subtraction of fractions as joining and separating parts referring to the same whole. b. Decomposing a fraction into a sum of fractions with the same denominator in more than one way, recording each decomposition by an equation. Justify decompositions. c. Add and subtract mixed numbers with like denominators. d. Solve word problems involving addition and subtraction of fractions referring to the same whole and having like denominators."},{"code":"KY.4.NF.4","subject":"Mathematics","grade":"4","text":"Apply and extend previous understandings of multiplication to multiply a fraction by a whole number. a. Understand a fraction \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f as a multiple of 1 \ud835\udc4f\ud835\udc4f. b. Understand a multiple of \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f as a multiple of 1 \ud835\udc4f\ud835\udc4f and use this understanding to multiply a fraction by a whole number. c. Solve word problems involving multiplication of a fraction by a whole number."},{"code":"KY.4.NF.5","subject":"Mathematics","grade":"4","text":"Convert and add fractions with denominators of 10 and 100. a. Convert a fraction with a denominator of 10 to an equivalent fraction with a denominator of 100. b. Add two fractions with respective denominators 10 and 100."},{"code":"KY.4.NF.6","subject":"Mathematics","grade":"4","text":"Use decimal notation for fractions with denominators 10 or 100."},{"code":"KY.4.NF.7","subject":"Mathematics","grade":"4","text":"Compare two decimals to hundredths. a. Compare two decimals to hundredths by reasoning about their size. b. Recognize that comparisons are valid only when the two decimals refer to the same whole. c. Record the results of comparisons with the symbols >, =, or < and justify the conclusions."},{"code":"KY.4.OA.1","subject":"Mathematics","grade":"4","text":"Interpret a multiplication equation as a comparison. Represent verbal statements of multiplicative comparisons as multiplication equations."},{"code":"KY.4.OA.2","subject":"Mathematics","grade":"4","text":"Multiply or divide to solve word problems involving multiplicative comparisons by using drawings and equations with a symbol for the unknown number to represent the problem, distinguishing multiplicative comparison from additive comparison."},{"code":"KY.4.OA.3","subject":"Mathematics","grade":"4","text":"Solve multistep problems. a. Students use their knowledge of order of operations even when"},{"code":"KY.4.OA.4","subject":"Mathematics","grade":"4","text":"Find factors and multiples of numbers in the range 1-100. a. Find all factor pairs for a given whole number. b. Recognize that a whole number is a multiple of each of its factors. c. Determine whether a given whole number is a multiple of a given one-digit number. d. Determine whether a given whole number is prime or composite."},{"code":"KY.4.OA.5","subject":"Mathematics","grade":"4","text":"Generate a number or shape pattern that follows a given rule. Identify apparent features of the pattern not explicit in the rule itself."},{"code":"4-ESS1-1","subject":"Science","grade":"4","text":"Identify evidence from patterns in rock formations and fossils in rock layers to support an explanation for changes in a landscape over time."},{"code":"4-ESS2-1","subject":"Science","grade":"4","text":"Make observations and/or measurements to provide evidence of the effects of weathering or the rate of erosion by water, ice, wind, or vegetation."},{"code":"4-ESS2-2","subject":"Science","grade":"4","text":"Analyze and interpret data from maps to describe patterns of Earth\u2019s features."},{"code":"4-ESS3-1","subject":"Science","grade":"4","text":"Obtain and combine information to describe that energy and fuels are derived from natural resources and that their uses affect the environment."},{"code":"4-ESS3-2","subject":"Science","grade":"4","text":"Generate and compare multiple solutions to reduce the impacts of natural Earth processes on humans. *"},{"code":"4-LS1-1","subject":"Science","grade":"4","text":"Construct an argument that plants and animals have internal and external structures that function to support survival, growth, behavior, and reproduction."},{"code":"4-LS1-2","subject":"Science","grade":"4","text":"Use a model to describe that animals receive different types of information through their senses, process the information in their brain, and respond to the information in different ways."},{"code":"4-LS4-1","subject":"Science","grade":"4","text":"Analyze and interpret data from fossils to provide evidence of the organisms and the environments in which they lived long ago."},{"code":"4-PS3-1","subject":"Science","grade":"4","text":"Use evidence to construct an explanation relating the speed of an object to the energy of that object."},{"code":"4-PS3-2","subject":"Science","grade":"4","text":"Make observations to provide evidence that energy can be transferred from place to place by sound, light, heat, and electric currents."},{"code":"4-PS3-3","subject":"Science","grade":"4","text":"Ask questions and predict outcomes about the changes in energy that occur when objects collide."},{"code":"4-PS3-4","subject":"Science","grade":"4","text":"Apply scientific ideas to design, test, and refine a device that converts energy from one form to another. *"},{"code":"4-PS4-1","subject":"Science","grade":"4","text":"Develop a model of waves to describe patterns in terms of amplitude and wavelength and that waves can cause objects to move."},{"code":"4-PS4-2","subject":"Science","grade":"4","text":"Develop a model to describe that light reflecting from objects and entering the eye allows objects to be seen."},{"code":"4-PS4-3","subject":"Science","grade":"4","text":"Generate and compare multiple solutions that use patterns to transfer information.*"},{"code":"4.C.CP.1","subject":"Social Studies","grade":"4","text":"Describe dive rse forms of self-government used by various groups in Colonial America."},{"code":"4.C.CP.2","subject":"Social Studies","grade":"4","text":"Compare the political form of monarchy with the self- governing system developed in Colonial America."},{"code":"4.C.CV.1","subject":"Social Studies","grade":"4","text":"Assess the ability of vario us forms of government to foster civic virtues and uphold democratic principles."},{"code":"4.C.KGO.1","subject":"Social Studies","grade":"4","text":"Explain how the dev elopment of rules improves communities and attempts to meet the needs of citizens."},{"code":"4.C.PR.1","subject":"Social Studies","grade":"4","text":"Describe the pr ocesses people use to change rules and laws."},{"code":"4.C.RR.1","subject":"Social Studies","grade":"4","text":"Describe the impo rtance of civic participation, and locate examples in past and current events."},{"code":"4.E.IC.1","subject":"Social Studies","grade":"4","text":"Describe an d evaluate the relationship between resource availability, opportunity costs, migration and settlement."},{"code":"4.E.KE.1","subject":"Social Studies","grade":"4","text":"Predict how producers in colonial Kentucky used the factors of production to make goods, deliver services and earn profits."},{"code":"4.E.MA.1","subject":"Social Studies","grade":"4","text":"Compare and cont rast different ways that the government interacts with the economy."},{"code":"4.E.MI.1","subject":"Social Studies","grade":"4","text":"Explain the role of pro ducers, consumers, products and labor in economic markets."},{"code":"4.E.MI.2","subject":"Social Studies","grade":"4","text":"Investigate the relationship between supply and demand."},{"code":"4.E.ST.1","subject":"Social Studies","grade":"4","text":"Explain how t rade leads to increasing economic interdependence."},{"code":"4.G.GR.1","subject":"Social Studies","grade":"4","text":"Analyze how lo cation and regional landforms affect human settlement, movement and use of various national resources, using maps, photos and other geographic representations."},{"code":"4.G.HE.1","subject":"Social Studies","grade":"4","text":"Analyze how ge ographic features created challenges and opportunities for the development of Colonial America."},{"code":"4.G.HI.1","subject":"Social Studies","grade":"4","text":"Explain how c ultural, economic and environmental characteristics affect the interactions of people, goods and ideas from European Exploration to the Thirteen Colonies."},{"code":"4.G.KGE.1","subject":"Social Studies","grade":"4","text":"Compare ho w the movement of people, goods and ideas in Colonial America and modern Kentucky were affected by technology."},{"code":"4.G.MM.1","subject":"Social Studies","grade":"4","text":"Compare the di stinctive cultural characteristics of groups that immigrated or were brought forcibly to the United States from other nations from European exploration to the Thirteen Colonies."},{"code":"4.H.CE.1","subject":"Social Studies","grade":"4","text":"Utilize chrono logical sequences of events to explain causes and effects of historical developments from European Exploration to the Thirteen Colonies."},{"code":"4.H.CH.1","subject":"Social Studies","grade":"4","text":"Describe how migrati on and settlement impacted diverse groups of people as they encountered one another from European Exploration to the Thirteen Colonies."},{"code":"4.H.CH.2","subject":"Social Studies","grade":"4","text":"Describe the impact innovation and human ingenuity had on the development of the United States from European Exploration to the Thirteen Colonies."},{"code":"4.H.CO.1","subject":"Social Studies","grade":"4","text":"Explain example s of conflict and collaboration among various groups of people from European Exploration to the Thirteen Colonies as they encountered one another."},{"code":"4.H.KH.1","subject":"Social Studies","grade":"4","text":"Identify and describe the significance of diverse groups of people in Kentucky from European Exploration to the Thirteen Colonies."},{"code":"4.I.CC.1","subject":"Social Studies","grade":"4","text":"Construct an explanation, using reasoning and relevant information, to examine the causes and effects of an issues around migration and settlement."},{"code":"4.I.CC.2","subject":"Social Studies","grade":"4","text":"Construct an argument with reasons and supporting evidence on the challenges and opportunities people face when transitioning to a new community."},{"code":"4.I.CC.3","subject":"Social Studies","grade":"4","text":"Describe different strategies that can be taken to address issues of migration and settlement."},{"code":"4.I.CC.4","subject":"Social Studies","grade":"4","text":"Use listening and consensus-building to determine ways to support people in transitioning to a new community."},{"code":"4.I.Q.1","subject":"Social Studies","grade":"4","text":"Ask compelling questions about migration and settlement. \u201cWhy do diverse groups of people settle in new areas?\u201d Teachers can pose this question to st udents to facilitate exploration about why this standard applies to migration and settlement."},{"code":"4.I.Q.2","subject":"Social Studies","grade":"4","text":"Develop supporting questions to answer compelling questions about migration and settlement."},{"code":"4.I.UE.1","subject":"Social Studies","grade":"4","text":"Integrate evidence from two or more sources to answer compelling and supporting questions."},{"code":"4.I.UE.2","subject":"Social Studies","grade":"4","text":"Determine the value and limitations of primary and secondary sources."},{"code":"4.I.UE.3","subject":"Social Studies","grade":"4","text":"Develop claims with evidence to answer compelling and supporting questions."},{"code":"C.5.1","subject":"English Language Arts","grade":"5","text":"Compose OPINION PIECES , using writing and digital resources, on topics or texts , supporting the writer\u2019s perspective with reasons and information . (NOTE: Students must have the opportunity throughout the year to utilize digital resources, but not every writing experience must utilize digital resources.) a. Produce clear and coherent writing in which the development and organization are appropriate to task, purpose and audience . b. Introduce a topic or text clearly , state an opinion and create an organizational structure in which ideas are logically grouped to support the writer\u2019s purpose . c. Provide logically ordered reasons that are supported by facts and details . d. Use grade-appropriate TRANSITIONS to connect sentences and paragraphs . e. Provide a concluding section . f. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising , editing , rewriting or trying a new approach ."},{"code":"C.5.2","subject":"English Language Arts","grade":"5","text":"Compose informative and/or explanatory texts, using writing and digital resources, to examine a topic and convey ideas and information clearly. a. Produce clear and coherent writing in which the development and organization are appropriate to task, purpose and audience. b. Introduce a topic clearly, provide a general observation and focus and group related information logically; include formatting, illustrations and multimedia when useful to aiding comprehension. c. Develop the topic with facts, definitions, concrete details, quotations or other information and examples related to the topic. d. Use grade-appropriate conjunctions to develop text structure within sentences. e. Use grade-appropriate transitions to develop text structure in sentences and paragraphs. f. Use precise language and domain-specific vocabulary to inform about or explain the topic. g. Provide a concluding section. h. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach."},{"code":"C.5.3","subject":"English Language Arts","grade":"5","text":"Compose narratives, using writing and digital resources, to develop real or imagined experiences or multiple events or ideas, using effective technique, descriptive details and clear sequences. a. Produce clear and coherent writing in which the development and organization are appropriate to task, purpose and audience. b. Orient the reader by establishing a situation and introducing a narrator and/or characters; organize an event sequence that reflects linear, nonlinear or circular structure. c. Use narrative techniques, such as dialogue, description and pacing, to develop experiences and events or show the responses of characters to situations. d. Use a variety of conjunctions and transitional words, phrases and clauses to manage the sequence of events. e. Use concrete words and phrases and sensory details to convey experiences and events precisely. f. Provide a conclusion that follows the narrated experiences or events. g. With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach. Production and Distribution"},{"code":"C.5.4","subject":"English Language Arts","grade":"5","text":"With limited guidance and support from adults, use DIGITAL RESOURCES to create and publish products as well as to interact and collaborate with others ."},{"code":"C.5.5","subject":"English Language Arts","grade":"5","text":"Conduct short RESEARCH projects that use SEVERAL SOURCES to build knowledge through investigation of different aspects of a topic ."},{"code":"C.5.6","subject":"English Language Arts","grade":"5","text":"Summarize relevant information from experiences, or gather relevant information from multiple print and digital sources ; SUMMARIZE OR PARAPHRASE applicable information in notes and finished work, and provide a list of sources ."},{"code":"C.5.7","subject":"English Language Arts","grade":"5","text":"Compose routinely over extended time frames and shorter time frames for a variety of tasks, purposes and audiences ."},{"code":"L.5.1","subject":"English Language Arts","grade":"5","text":"When writing or speaking , demonstrate command of the conventions of General American English grammar and usage . a. Explain the function of CONJUNCTIONS, PREPOSITIONS AND INTERJECTIONS in a GRADE-LEVEL TEXT . b. Use the PERFECT VERB TENSES . c. Use VERB TENSE to convey various times, sequences, states and conditions . d. Produce COMPLETE SENTENCES recognizing and correcting inappropriate shifts in verb tense . e. Use CORRELATIVE CONJUNCTIONS ."},{"code":"L.5.2","subject":"English Language Arts","grade":"5","text":"When writing : a. Use PUNCTUATION TO SEPARATE ITEMS IN A SERIES . b. Use a COMMA TO SEPARATE AN INTRODUCTORY ELEMENT FROM THE REST OF THE SENTENCE . c. Use a COMMA TO SET OFF THE WORDS YES AND NO, TO SET OFF A TAG QUESTION FROM THE REST OF THE SENTENCE AND TO INDICATE DIRECT ADDRESS . d. Use UNDERLINING, QUOTATION MARKS OR ITALICS TO INDICATE TITLES OF WORKS . e. Use strategies and resources (print and electronic) to identify and correct spelling errors ."},{"code":"L.5.3","subject":"English Language Arts","grade":"5","text":"Use knowledge of language and its conventions when writing, speaking, reading or listening . a. Expand, combine and reduce sentences for meaning, reader/listener interest and style . b. Compare and contrast the VARIETIES OF ENGLISH (e.g., dialects, registers, slang) used in stories, dramas or poems ."},{"code":"L.5.4","subject":"English Language Arts","grade":"5","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grade 5 reading and content, choosing flexibly from an array of strategies . a. Use context (e.g., CAUSE/EFFECT RELATIONSHIPS AND COMPARISONS in text) as a clue to the meaning of a word or phrase . b. Use common AFFIXES AND ROOTS as clues to the meaning of a word . c. Consult print and digital reference materials to find the pronunciation and determine or clarify the precise meaning of key words and phrases . d. Acquire and use accurately GRADE-APPROPRIATE GENERAL ACADEMIC AND DOMAIN-SPECIFIC words and phrases, including THOSE THAT SIGNAL CONTRAST, ADDITION AND OTHER LOGICAL RELATIONSHIPS ."},{"code":"L.5.5","subject":"English Language Arts","grade":"5","text":"Demonstrate understanding of figurative language, word relationships and nuances in word meanings . a. Interpret figurative language , including SIMILES AND METAPHORS , in context . b. Recognize and explain the meaning of common IDIOMS, ADAGES AND PROVERBS . c. Demonstrate understanding of words by relating them to their SYNONYMS and ANTONYMS ."},{"code":"RF.5.3","subject":"English Language Arts","grade":"5","text":"Know and apply grade-level phonics and word analysis skills in decoding and encoding words. a. Use combined knowledge of all phoneme-grapheme correspondences, syllabication patterns and morphology to accurately decode and encode unfamiliar multisyllabic words. Fluency"},{"code":"RF.5.4","subject":"English Language Arts","grade":"5","text":"Read fluently (accuracy, speed and prosody) on grade-level texts to support comprehension. a. Read grade-level text with purpose and understanding. b. Fluently read grade-level prose and poetry orally on successive readings. c. Use context to confirm or self-correct word recognition and understanding, rereading as necessary."},{"code":"RI.5.1","subject":"English Language Arts","grade":"5","text":"QUOTE ACCURATELY FROM A TEXT when explaining what the text says explicitly and when drawing inferences from the text."},{"code":"RI.5.10","subject":"English Language Arts","grade":"5","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT independently ."},{"code":"RI.5.2","subject":"English Language Arts","grade":"5","text":"Analyze how the CENTRAL IDEAS are reflected in a text, and cite relevant implicit and explicit evidence to support thinking ."},{"code":"RI.5.3","subject":"English Language Arts","grade":"5","text":"Explain the relationships or interactions between INDIVIDUALS, EVENTS, IDEAS OR CONCEPTS IN A HISTORICAL, SCIENTIFIC OR TECHNICAL TEXT based on specific information over the course of a text ."},{"code":"RI.5.4","subject":"English Language Arts","grade":"5","text":"Determine the meaning of GENERAL ACADEMIC AND DOMAIN-SPECIFIC words or phrases in a GRADE-LEVEL TEXT , and analyze how those words and phrases shape meaning ."},{"code":"RI.5.5","subject":"English Language Arts","grade":"5","text":"Compare and contrast the overall STRUCTURE of events, ideas, concepts or information in TWO OR MORE TEXTS ."},{"code":"RI.5.6","subject":"English Language Arts","grade":"5","text":"Analyze MULTIPLE ACCOUNTS of the same event or topic , noting important similarities and differences in the PERSPECTIVE they represent ."},{"code":"RI.5.7","subject":"English Language Arts","grade":"5","text":"Analyze information from MULTIPLE PRINT AND NON-PRINT FORMATS , demonstrating the ability to locate an answer to a question quickly or to solve a problem efficiently ."},{"code":"RI.5.8","subject":"English Language Arts","grade":"5","text":"Explain how an author uses REASONS and EVIDENCE to support particular CLAIMS in a text, identifying which REASONS and EVIDENCE support which CLAIM(S) ."},{"code":"RI.5.9","subject":"English Language Arts","grade":"5","text":"Integrate information from SEVERAL TEXTS ON THE SAME THEME OR TOPIC ."},{"code":"RL.5.1","subject":"English Language Arts","grade":"5","text":"QUOTE ACCURATELY FROM A TEXT when explaining what the text says explicitly and when drawing inferences from the text."},{"code":"RL.5.10","subject":"English Language Arts","grade":"5","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.5.2","subject":"English Language Arts","grade":"5","text":"Analyze how the THEME is reflected in the text, including but not limited to poems, stories and dramas, and cite relevant implicit and explicit evidence to support thinking ."},{"code":"RL.5.3","subject":"English Language Arts","grade":"5","text":"Compare and contrast CHARACTERS, SETTINGS OR EVENTS in a story or drama, using specific details to analyze their interaction over the course of the text ."},{"code":"RL.5.4","subject":"English Language Arts","grade":"5","text":"Determine the meaning of words and phrases as they are used in a text, including FIGURATIVE AND CONNOTATIVE MEANINGS , and analyze how those words and phrases shape meaning ."},{"code":"RL.5.5","subject":"English Language Arts","grade":"5","text":"Compare and contrast the overall STRUCTURE of events, ideas, concepts or information IN TWO OR MORE LITERARY TEXTS (E.G., STORIES, POEMS OR DRAMAS) ."},{"code":"RL.5.6","subject":"English Language Arts","grade":"5","text":"Describe how a narrator\u2019s or speaker\u2019s PERSPECTIVE influences how events are described ."},{"code":"RL.5.7","subject":"English Language Arts","grade":"5","text":"Analyze how VISUAL AND MULTIMEDIA ELEMENTS contribute to the meaning or tone of non-print texts ."},{"code":"RL.5.8","subject":"English Language Arts","grade":"5","text":"Not applicable to literature"},{"code":"RL.5.9","subject":"English Language Arts","grade":"5","text":"Compare and contrast STORIES IN THE SAME GENRE on their approaches to SIMILAR THEMES AND TOPICS ."},{"code":"KY.5.G.1","subject":"Mathematics","grade":"5","text":"Use a pair perpendicular number lines, called axes, to define a coordinate system, with the intersection of the lines (the origin) arranged to coincide with the 0 on each line and a given point in the plane located by using an ordered pair of numbers, called its coordinates. Understand that the first number indicates how far to travel from the origin in the direction of one axis and the second number indicates how far to travel in the direction of the second."},{"code":"KY.5.G.2","subject":"Mathematics","grade":"5","text":"Represent real world and mathematical problems by graphing points in the first quadrant of the coordinate plane and interpret coordinate values of points in the context of the situation."},{"code":"KY.5.G.3","subject":"Mathematics","grade":"5","text":"Understand that attributes belonging to a category of two- dimensional figures also belong to all subcategories of that category."},{"code":"KY.5.G.4","subject":"Mathematics","grade":"5","text":"Classify two-dimensional figures in a hierarchy based on properties."},{"code":"KY.5.MD.1","subject":"Mathematics","grade":"5","text":"Convert among different size measurement units (mass, weight, liquid volume, length, time) within one system of units (metric system, U.S. standard system and time)."},{"code":"KY.5.MD.2","subject":"Mathematics","grade":"5","text":"Identify and gather data for statistical questions focused on both categorical and numerical data. Select an appropriate data display (bar graph, pictograph, dot plot). Make observations from the graph about the questions posed."},{"code":"KY.5.MD.3","subject":"Mathematics","grade":"5","text":"Recognize volume as an attribute of solid figures and understand concepts of volume measurement. a. A cube with side length 1 unit, called a \u201cunit cube,\u201d is said to have \u201cone cubic unit\u201d of volume and can be used to measure volume. b. A solid figure which can be packed without gaps or overlaps using n unit cubes is said to have a volume of n cubic units."},{"code":"KY.5.MD.4","subject":"Mathematics","grade":"5","text":"Measure volumes by counting unit cubic cm, cubic in, cubic ft. and improvised units."},{"code":"KY.5.MD.5","subject":"Mathematics","grade":"5","text":"Relate volume to the operations of multiplication and addition and solve real world and mathematical problems involving volume. a. Find the volume of a right rectangular prism with whole- number side lengths by packing it with unit cubes and show that the volume is the same as would be found by multiplying the edge lengths, equivalently by multiplying the height by the area of the base. Represent threefold whole-number products as volumes. b. Apply the formulas V= l x w x h and V = B x h for rectangular prisms with whole-number edge lengths in the context of solving real world and mathematical problems. c. Recognize volume as additive. Find volumes of solid figures composed of two non-overlapping right rectangular prisms by For example, students determine the volume of concrete needed to build the steps in the diagram below."},{"code":"KY.5.NBT.1","subject":"Mathematics","grade":"5","text":"Recognize that in a multi-digit number, a digit in one place represents 10 times as much as it represents in the place to its right and 1 10 of what it represents in the place to its left."},{"code":"KY.5.NBT.2","subject":"Mathematics","grade":"5","text":"Multiply and divide by powers of 10. \u25cf Explain patterns in the number of zeros of the product when multiplying a number by powers of 10. \u25cf Explain patterns in the placement of the decimal point when a decimal is multiplied or divided by a power of 10. \u25cf Use whole-number exponents to denote powers of 10."},{"code":"KY.5.NBT.3","subject":"Mathematics","grade":"5","text":"Read, write and compare decimals to thousandths. a. Read and write decimals to thousandths using base-ten numerals, number names and expanded form. b. Compare two decimals to thousandths based on meanings of the digits in each place, using >, =, and < symbols to record the results of comparisons."},{"code":"KY.5.NBT.4","subject":"Mathematics","grade":"5","text":"The identified mathematical practices, coherence connections and clarifications are possible suggestions; however, they are not the only pathways."},{"code":"KY.5.NBT.5","subject":"Mathematics","grade":"5","text":"Fluently multiply multi-digit whole numbers (not to exceed four-digit by two-digit multiplication) using an algorithm."},{"code":"KY.5.NBT.6","subject":"Mathematics","grade":"5","text":"Divide up to four-digit dividends by two-digit divisors. a. Find whole-number quotients of whole numbers with up to four-digit dividends and two-digit divisors using\u2026 \u25cf strategies based on place value \u25cf the properties of operations \u25cf the relationship between multiplication and division b. Illustrate and explain the calculation by using equations, rectangular arrays and/or area models."},{"code":"KY.5.NBT.7","subject":"Mathematics","grade":"5","text":"Operations with decimals to hundredths. a. Add, subtract, multiply and divide decimals to hundredths using\u2026 \u25cf concrete models or drawings \u25cf strategies based on place value \u25cf properties of operations \u25cf the relationship between addition and subtraction b. Relate the strategy to a written method and explain the reasoning used."},{"code":"KY.5.NF.1","subject":"Mathematics","grade":"5","text":"Efficiently add and subtract fractions with unlike denominators (including mixed numbers) by\u2026 \u25cf using reasoning strategies, such as counting up on a number line or creating visual fraction models \u25cf finding common denominators"},{"code":"KY.5.NF.2","subject":"Mathematics","grade":"5","text":"Solve word problems involving addition and subtraction of fractions. a. Solve word problems involving addition and subtraction of fractions referring to the same whole, including cases of unlike denominators. b. Use benchmark fractions and number sense of fractions to estimate mentally and assess the reasonableness of answers."},{"code":"KY.5.NF.3","subject":"Mathematics","grade":"5","text":"Interpret a fraction as division of the numerator by the denominator ( \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f = a \u00f7 b). Solve word problems involving division of whole numbers leading to answers in the form of fractions or mixed numbers by using visual fraction models or equations to represent the problem."},{"code":"KY.5.NF.4","subject":"Mathematics","grade":"5","text":"Apply and extend previous understanding of multiplication to multiply a fraction or whole number by a fraction. a. Interpret the product ( \ud835\udc4e\ud835\udc4e \ud835\udc4f\ud835\udc4f) x q as a parts of a partition of q into b equal parts; equivalently, as the result of a sequence of operations a x q \u00f7 b. b. Find the area of a rectangle with fractional side lengths by tiling it with squares of the appropriate unit fraction side lengths and show that the area is the same as would be found by multiplying the side lengths. Multiply fractional side lengths to find areas of rectangles and represent fraction products as rectangular areas."},{"code":"KY.5.NF.5","subject":"Mathematics","grade":"5","text":"Interpret multiplication as scaling (resizing), by: a. Comparing the size of a product to the size of one factor on the basis of the size of the other factor, without performing the indicated multiplication. b. Explaining why multiplying a given number by a fraction greater than 1 results in a product greater than the given number (recognizing multiplication by whole numbers greater than 1 as a familiar case); explaining why multiplying a given number by a 1 4 x 7 is less than 7 because 7 is multiplied by a factor less than 1 so the product must be less than 7. 7 3 4 of 7"},{"code":"KY.5.NF.6","subject":"Mathematics","grade":"5","text":"Solve real world problems involving multiplication of fractions and mixed numbers."},{"code":"KY.5.NF.7","subject":"Mathematics","grade":"5","text":"Apply and extend previous understandings of division to divide unit fractions by whole numbers and whole numbers by unit fractions. a. Interpret division of a unit fraction by a non-zero whole number and compute such quotients. b. Interpret division of a whole number by a unit fraction and compute such quotients. c. Solve real world problems involving division of unit fractions by non-zero whole numbers and division of whole numbers by unit fractions."},{"code":"KY.5.OA.1","subject":"Mathematics","grade":"5","text":"Use parentheses, brackets or braces in numerical expressions and evaluate expressions that include symbols."},{"code":"KY.5.OA.2","subject":"Mathematics","grade":"5","text":"Write simple expressions with numbers and interpret numerical expressions without evaluating them."},{"code":"KY.5.OA.3","subject":"Mathematics","grade":"5","text":"Generate numerical patterns for situations. a. Generate a rule for growing patterns, identifying the relationship between corresponding terms (x, y). b. Generate patterns using one or two given rules (x, y). c. Use tables, ordered pairs and graphs to represent the relationship between the quantities."},{"code":"5-ESS1-1","subject":"Science","grade":"5","text":"Support an argument that differences in the apparent brightness of the sun compared to other stars is due to their relative distances from Earth."},{"code":"5-ESS1-2","subject":"Science","grade":"5","text":"Represent data in graphical displays to reveal patterns of daily changes in the length and direction of shadows, day and night, and the seasonal appearance of some stars in the night sky."},{"code":"5-ESS2-1","subject":"Science","grade":"5","text":"Develop a model using an example to describe ways the geosphere, biosphere, hydrosphere, and/or atmosphere interact."},{"code":"5-ESS2-2","subject":"Science","grade":"5","text":"Describe and graph the amounts and percentages of salt water and fresh water in various reservoirs to provide evidence about the distribution of water on Earth."},{"code":"5-ESS3-1","subject":"Science","grade":"5","text":"Obtain and combine information about solutions individual communities use to protect the Earth\u2019s resources and environment.*"},{"code":"5-LS1-1","subject":"Science","grade":"5","text":"Support an argument that plants get the materials they need for growth chiefly from air and water."},{"code":"5-LS2-1","subject":"Science","grade":"5","text":"Develop a model to describe the movement of matter among plants, animals, decomposers, and the environment."},{"code":"5-PS1-1","subject":"Science","grade":"5","text":"Develop a model to describe that matter is made of particles too small to be seen."},{"code":"5-PS1-2","subject":"Science","grade":"5","text":"Measure and graph quantities to provide evidence that regardless of the type of change that occurs when heating, cooling, or mixing substances, the total weight of matter is conserved."},{"code":"5-PS1-3","subject":"Science","grade":"5","text":"Make observations and measurements to identify materials based on their properties."},{"code":"5-PS1-4","subject":"Science","grade":"5","text":"Conduct an investigation to determine whether the mixing of two or more substances results in new substances."},{"code":"5-PS2-1","subject":"Science","grade":"5","text":"Support an argument that the gravitational force exerted by Earth on objects is directed down."},{"code":"5-PS3-1","subject":"Science","grade":"5","text":"Use models to describe that energy in animals\u2019 food (used for body repair, growth, motion, and to maintain body warmth) was once energy from the sun."},{"code":"5.C.CP.1","subject":"Social Studies","grade":"5","text":"Analyze the development and establishment of the U.S. federal government."},{"code":"5.C.CP.2","subject":"Social Studies","grade":"5","text":"Analyze the structure of the U.S. government, including separation of power and its system of checks and balances."},{"code":"5.C.CP.3","subject":"Social Studies","grade":"5","text":"Describe how the Constitution of the United States upholds popular sovereignty, ensures rule of law and establishes a federal system."},{"code":"5.C.CV.1","subject":"Social Studies","grade":"5","text":"Describe the democratic principles of equality before the law, inalienable rights, consent of the governed and right to alter or abolish the government."},{"code":"5.C.KGO.1","subject":"Social Studies","grade":"5","text":"Explain the roles and responsibilities of a Kentucky citizen."},{"code":"5.C.PR.1","subject":"Social Studies","grade":"5","text":"Evaluate whether various rules and laws promote the general welfare, using historical and contemporary examples."},{"code":"5.C.RR.1","subject":"Social Studies","grade":"5","text":"Analyze responsibilities of U.S. citizens by explaining and demonstrating ways to show good citizenship."},{"code":"5.C.RR.2","subject":"Social Studies","grade":"5","text":"Analyze the personal rights conferred by citizenship, and find examples of citizenship, using a variety of sources."},{"code":"5.E.IC.1","subject":"Social Studies","grade":"5","text":"Analyze how incentives and opportunity costs impact decision making, using examples from history."},{"code":"5.E.KE.1","subject":"Social Studies","grade":"5","text":"Analyze how incentives and opportunity costs impact decision making, using examples from Kentucky history."},{"code":"5.E.MA.1","subject":"Social Studies","grade":"5","text":"Describe why the government collects taxes and what goods and services it provides society."},{"code":"5.E.MA.2","subject":"Social Studies","grade":"5","text":"Explain how the United States developed into a market economy."},{"code":"5.E.MI.1","subject":"Social Studies","grade":"5","text":"Explain the relationship between supply and demand."},{"code":"5.E.ST.1","subject":"Social Studies","grade":"5","text":"Explain how specialization, comparative advantage and competition influence the production and exchange of goods and services in an interdependent economy."},{"code":"5.G.GR.1","subject":"Social Studies","grade":"5","text":"Use a variety o f maps, satellite images and other models to explain the relationships between the location of places and regions and their human and environmental characteristics."},{"code":"5.G.HE.1","subject":"Social Studies","grade":"5","text":"Explain how c ultural and environmental changes impact population distribution and influence how people modify and adapt to their environments."},{"code":"5.G.HI.1","subject":"Social Studies","grade":"5","text":"Describe th e traditions diverse cultural groups brought with them when they moved to and within the United States."},{"code":"5.G.HI.2","subject":"Social Studies","grade":"5","text":"Analyze how and why cultural characteristics diffuse and blend with migration and settlement."},{"code":"5.G.KGE.1","subject":"Social Studies","grade":"5","text":"Compare the lives of Kentucky settlers to those living in other areas during the early years of the United States."},{"code":"5.G.MM.1","subject":"Social Studies","grade":"5","text":"Analyze how c ultural, economic and environmental factors encouraged and restricted the movement of people, ideas and goods to and within the United States."},{"code":"5.H.CE.1","subject":"Social Studies","grade":"5","text":"Analyze the causes of the American Revolution and the effects individuals and groups had on the conflict."},{"code":"5.H.CE.2","subject":"Social Studies","grade":"5","text":"Analyze the role religion played in early colonial society."},{"code":"5.H.CE.3","subject":"Social Studies","grade":"5","text":"Describe the social and economic impact of the slave trade on diverse groups."},{"code":"5.H.CH.1","subject":"Social Studies","grade":"5","text":"Describe the i mpact of fundamental documents on the development of the United States."},{"code":"5.H.CH.2","subject":"Social Studies","grade":"5","text":"Analyze the impact innovation and human ingenuity had on the development of the United States from Colonization to the Constitution of the United States."},{"code":"5.H.CO.1","subject":"Social Studies","grade":"5","text":"Analyze the ro le conflict and collaboration played in the founding of the United States."},{"code":"5.H.KH.1","subject":"Social Studies","grade":"5","text":"Describe the role of Kentucky settlers in the American Revolution."},{"code":"5.I.CC.1","subject":"Social Studies","grade":"5","text":"Construct explanatory products, using reasoning, correct sequence, examples and details with relevant information and data, to convey the diverse perspectives that impacted the founding of the United States."},{"code":"5.I.CC.2","subject":"Social Studies","grade":"5","text":"Construct arguments using claims and evidence from multiple sources on how a founding principle(s) is applicable today."},{"code":"5.I.CC.3","subject":"Social Studies","grade":"5","text":"Explain different approaches people can take to address local, regional and global problems, using examples from U.S. history."},{"code":"5.I.CC.4","subject":"Social Studies","grade":"5","text":"Use a range of deliberative and democratic procedures to identify strategies on how to address a current issue."},{"code":"5.I.Q.1","subject":"Social Studies","grade":"5","text":"Ask compelling questions about the founding of the United States. \u201cWhat unites Americans?\u201d Teachers can pose this question to students to facilitate exploration about why this standard applies to the founding of the United States."},{"code":"5.I.Q.2","subject":"Social Studies","grade":"5","text":"Generate supporting questions to answer compelling questions about the founding of the United States."},{"code":"5.I.Q.3","subject":"Social Studies","grade":"5","text":"Identify the types of supporting questions each of the social studies disciplines uses to answer compelling and supporting questions."},{"code":"5.I.UE.1","subject":"Social Studies","grade":"5","text":"Use evidence to develop claims in response to compelling and supporting questions."},{"code":"5.I.UE.2","subject":"Social Studies","grade":"5","text":"Analyze primary and secondary sources on the same event or topic, noting key similarities and differences in the perspective they represent."},{"code":"5.I.UE.3","subject":"Social Studies","grade":"5","text":"Integrate evidence that draws information from multiple sources to answer compelling and supporting questions."},{"code":"C.6.1","subject":"English Language Arts","grade":"6","text":"Compose ARGUMENTS to support claims with clear reasons and relevant evidence . a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience . b. Introduce claim(s), acknowledge opposing claims and organize the reasons and evidence clearly . c. Support claim(s) with clear reasons and relevant evidence, using credible sources and demonstrating an understanding of the topic or text . d. Use words, phrases and clauses to clarify the relationships among claim(s) and reasons . e. Establish and maintain a formal style . f. Provide a concluding statement or section that follows from the argument presented . g. With some guidance, develop and strengthen writing as needed by planning, revising , editing , rewriting or trying a new approach ."},{"code":"C.6.2","subject":"English Language Arts","grade":"6","text":"Compose informative and/or explanatory texts to examine a topic and convey ideas, concepts and information through the selection, organization and analysis of relevant content. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce a topic, previewing what is to follow; organize ideas, concepts and information, using strategies such as definition, classification, comparison/contrast and cause/effect; include formatting, graphics and multimedia when useful to aiding comprehension. c. Develop the topic with relevant facts, definitions, concrete details, quotations or other information and examples. d. Use appropriate transitions to clarify the relationships among ideas and concepts. e. Use precise language and domain-specific vocabulary to inform about or explain the topic. f. Establish and maintain a formal style. g. Provide a concluding statement or section that follows from the information or explanation presented. h. With some guidance, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on how well purpose and audience have been addressed."},{"code":"C.6.3","subject":"English Language Arts","grade":"6","text":"Compose narratives to develop real or imagined experiences or multiple events, memories or ideas, using effective technique, relevant descriptive details and well-structured event sequences. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Engage the reader by establishing a context and introducing a narrator and/or characters; organize an event sequence that unfolds naturally and logically. c. Use narrative techniques, such as dialogue, pacing and description, to develop experiences, events and/or characters. d. Use a variety of transition words to convey sequence and signal shifts from one time frame or setting to another. e. Use precise words and phrases, relevant descriptive details and sensory language to convey experiences and events. f. Provide a conclusion that follows from the narrated experiences or events. g. With guidance, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach. Production and Distribution"},{"code":"C.6.4","subject":"English Language Arts","grade":"6","text":"Use DIGITAL RESOURCES to create and publish products as well as to interact and collaborate with others ; cite sources using MLA or APA format ."},{"code":"C.6.5","subject":"English Language Arts","grade":"6","text":"Conduct short RESEARCH projects to answer a question , drawing on several sources ."},{"code":"C.6.6","subject":"English Language Arts","grade":"6","text":"Gather relevant information from multiple print and digital sources ; assess the credibility of each source; and, in order to reflect or interpret , QUOTE OR PARAPHRASE DATA AND CONCLUSIONS OF OTHERS , avoiding plagiarism by providing in-text and bibliographic MLA or APA citation ."},{"code":"C.6.7","subject":"English Language Arts","grade":"6","text":"Compose routinely over extended time frames and shorter time frames for a variety of tasks, purposes and audiences ."},{"code":"L.6.1","subject":"English Language Arts","grade":"6","text":"In both written and oral expression : a. Recognize vague pronouns and correct pronoun errors , including but not limited to SUBJECTIVE, OBJECTIVE, POSSESSIVE AND INTENSIVE PRONOUNS . b. Recognize and correct inappropriate shifts in PRONOUN number and person . c. Recognize VARIATIONS FROM GENERAL AMERICAN ENGLISH and implement strategies to improve expression in conventional language ."},{"code":"L.6.2","subject":"English Language Arts","grade":"6","text":"When writing : a. Demonstrate appropriate use of PUNCTUATION (COMMAS, PARENTHESES, DASHES) TO SET OFF NONRESTRICTIVE/PARENTHETICAL ELEMENTS . b. Demonstrate appropriate use of strategies to identify and correct spelling errors ."},{"code":"L.6.3","subject":"English Language Arts","grade":"6","text":"Use knowledge of language and its conventions when writing, speaking, reading or listening . a. Vary sentence patterns for meaning, reader/listener interest and style . b. Maintain consistency in style and tone ."},{"code":"L.6.4","subject":"English Language Arts","grade":"6","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grade 6 reading and content, choosing flexibly from an array of strategies . a. Use context (e.g., the overall meaning of a sentence or paragraph; a word\u2019s position or function in a sentence) as a clue to the meaning of a word or phrase . b. Use GREEK AND LATIN AFFIXES AND ROOTS as clues to the meaning of a word . c. Consult print and digital reference materials to find the pronunciation and determine or clarify the precise meaning of key words and phrases . d. Acquire and use accurately grade-appropriate general academic and domain-specific words and phrases; gather vocabulary knowledge when considering a word or phrase important to comprehension or expression ."},{"code":"L.6.5","subject":"English Language Arts","grade":"6","text":"Demonstrate understanding of figurative language, word relationships and nuances in word meanings . a. Interpret FIGURATIVE LANGUAGE , including but not limited to PERSONIFICATION , in context . b. Use the relationship between particular words to better understand each of the words . c. Distinguish among the CONNOTATIONS OF WORDS WITH SIMILAR DENOTATIONS ."},{"code":"RI.6.1","subject":"English Language Arts","grade":"6","text":"CITE TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RI.6.10","subject":"English Language Arts","grade":"6","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT independently ."},{"code":"RI.6.2","subject":"English Language Arts","grade":"6","text":"Analyze how the CENTRAL IDEAS are reflected in the text by citing particular details and/or providing an objective summary ."},{"code":"RI.6.3","subject":"English Language Arts","grade":"6","text":"Analyze in detail how an author develops a KEY INDIVIDUAL, EVENT OR IDEA over the course of a text ."},{"code":"RI.6.4","subject":"English Language Arts","grade":"6","text":"Determine the meaning of words and phrases as they are used in a text, including figurative, connotative and technical meanings; analyze the impact of a specific WORD CHOICE on meaning and TONE ."},{"code":"RI.6.5","subject":"English Language Arts","grade":"6","text":"Analyze how a particular sentence, paragraph, chapter or section fits into the overall structure of a text and contributes to the development of the IDEAS ."},{"code":"RI.6.6","subject":"English Language Arts","grade":"6","text":"Determine an author\u2019s PERSPECTIVE and PURPOSE in a text and explain how it is conveyed in a text."},{"code":"RI.6.7","subject":"English Language Arts","grade":"6","text":"Integrate information presented in PRINT AND NON-PRINT FORMATS to develop a coherent understanding of a topic or issue ."},{"code":"RI.6.8","subject":"English Language Arts","grade":"6","text":"Identify and evaluate the ARGUMENT and specific CLAIMS in a text , distinguishing CLAIMS that are supported by REASONS and EVIDENCE from unsupported CLAIMS ."},{"code":"RI.6.9","subject":"English Language Arts","grade":"6","text":"Compare and contrast how TWO OR MORE AUTHORS present SIMILAR EVENTS ."},{"code":"RL.6.1","subject":"English Language Arts","grade":"6","text":"CITE TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RL.6.10","subject":"English Language Arts","grade":"6","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.6.2","subject":"English Language Arts","grade":"6","text":"Analyze how the text reflects the THEME by citing textual evidence, using direct quoting and summarizing ."},{"code":"RL.6.3","subject":"English Language Arts","grade":"6","text":"Describe how a particular STORY\u2019S OR DRAMA\u2019S PLOT unfolds in a series of episodes and determine how the characters respond or change as the plot moves toward a RESOLUTION ."},{"code":"RL.6.4","subject":"English Language Arts","grade":"6","text":"Determine the meaning of words and phrases as they are used in a text, including figurative and connotative meanings; analyze the impact of a specific WORD CHOICE on meaning and TONE ."},{"code":"RL.6.5","subject":"English Language Arts","grade":"6","text":"Analyze how a particular sentence, paragraph, chapter, scene or stanza fits into the overall STRUCTURE OF THE TEXT ."},{"code":"RL.6.6","subject":"English Language Arts","grade":"6","text":"Explain how an author develops the PERSPECTIVE of the narrator or speaker in a text."},{"code":"RL.6.7","subject":"English Language Arts","grade":"6","text":"Compare and contrast reading a PRINT TEXT and viewing its VISUAL/ORAL PRESENTATION ."},{"code":"RL.6.8","subject":"English Language Arts","grade":"6","text":"Not applicable to literature"},{"code":"RL.6.9","subject":"English Language Arts","grade":"6","text":"Compare and contrast how VARIOUS FORMS OR GENRES OF TEXTS approach a SIMILAR THEME OR TOPIC ."},{"code":"KY.6.EE.1","subject":"Mathematics","grade":"6","text":"Write and evaluate numerical expressions involving whole- number exponents."},{"code":"KY.6.EE.2","subject":"Mathematics","grade":"6","text":"Write, read and evaluate expressions in which letters stand for numbers. a. Write expressions that record operations with numbers and with letters standing for numbers. b. Identify parts of an expression using mathematical terms (sums, term, product, factor, quotient, coefficient); view one or more parts of an expression in a single entity. c. Evaluate expressions for specific values of their variables, including values that are non-negative rational numbers. Include expressions that arise from formulas used in real-world problems. Perform arithmetic operations, including whole-number exponents, in the conventional order when there are no parentheses to specify a particular order (Order of Operations)."},{"code":"KY.6.EE.3","subject":"Mathematics","grade":"6","text":"Apply the properties of operations to generate equivalent expressions."},{"code":"KY.6.EE.4","subject":"Mathematics","grade":"6","text":"Identify when two expressions are equivalent when the two expressions name the same number regardless of which value is substituted into them."},{"code":"KY.6.EE.5","subject":"Mathematics","grade":"6","text":"Understand solving an equation or inequality as a process of answering a question: which values from a specified set, if any, make the equation or inequality true? Use substitution to determine whether a given number in a specified set makes an equation or inequality true."},{"code":"KY.6.EE.6","subject":"Mathematics","grade":"6","text":"Use variables to represent numbers and write expressions when solving a real-world or mathematical problem; understand that a variable can represent an unknown number, or depending on the purpose at hand, any number in a specified set."},{"code":"KY.6.EE.7","subject":"Mathematics","grade":"6","text":"Solve real-world and mathematical problems by writing and solving equations of the form x + p = q and px = q for cases in which p, q and x are all nonnegative rational numbers."},{"code":"KY.6.EE.8","subject":"Mathematics","grade":"6","text":"Write an inequality of the form \ud835\udc65\ud835\udc65> \ud835\udc50\ud835\udc50, \ud835\udc65\ud835\udc65< \ud835\udc50\ud835\udc50, \ud835\udc65\ud835\udc65\u2265 \ud835\udc50\ud835\udc50, or \ud835\udc65\ud835\udc65\u2264 \ud835\udc50\ud835\udc50 to represent a constraint or condition in a real-world or mathematical problem. Recognize that inequalities of these forms have infinitely many solutions; represent solutions of such inequalities on vertical and horizontal number lines."},{"code":"KY.6.EE.9","subject":"Mathematics","grade":"6","text":"Use variables to represent two quantities in a real-world problem that changes in relationship to one another; a. Appropriately recognize one quantity as the dependent variable and the other as the independent variable. b. Write an equation to express one quantity, thought of as the dependent variable, in terms of the other quantity, thought of as the independent variable. c. Analyze the relationship between the dependent and independent variables using graphs and tables and relate these to the question."},{"code":"KY.6.G.1","subject":"Mathematics","grade":"6","text":"Find the area of right triangles, other triangles, special quadrilaterals and polygons by composing into rectangles or decomposing into triangles and quadrilaterals; apply these techniques in the context of solving real-world and mathematical problems."},{"code":"KY.6.G.2","subject":"Mathematics","grade":"6","text":"Find the volume of a right rectangular prism with rational number edge lengths. Apply the formulas V = lwh and V = Bh to find volumes of right rectangular prisms with rational number edge lengths in the context of solving real-world and mathematical problems."},{"code":"KY.6.G.3","subject":"Mathematics","grade":"6","text":"Draw polygons in the coordinate plane given coordinates for the vertices; use coordinates to find the length of a side joining points with the same first coordinate or the same second coordinate. Apply these techniques in the context of solving real-world and mathematical problems."},{"code":"KY.6.G.4","subject":"Mathematics","grade":"6","text":"Classify three-dimensional figures including cubes, prisms, pyramids, cones and spheres."},{"code":"KY.6.NS.1","subject":"Mathematics","grade":"6","text":"Interpret and compute quotients of fractions and solve word problems involving division of fractions by fractions."},{"code":"KY.6.NS.2","subject":"Mathematics","grade":"6","text":"Fluently divide multi-digit numbers using an algorithm. a. Convert a rational number to a decimal using long division. b. Know that the decimal form of a rational number terminates in 0s or eventually repeats."},{"code":"KY.6.NS.3","subject":"Mathematics","grade":"6","text":"Fluently add, subtract, multiply and divide multi-digit decimals using an algorithm for each operation."},{"code":"KY.6.NS.4","subject":"Mathematics","grade":"6","text":"Use the distributive property to express a sum of two whole numbers 1 \u2013 100 with a common factor as a multiple of a sum of two whole numbers with no common factor."},{"code":"KY.6.NS.5","subject":"Mathematics","grade":"6","text":"Understand that positive and negative numbers are used together to describe quantities having opposite directions or values; use positive and negative numbers to represent quantities in real- world contexts, explaining the meaning of 0 in each situation."},{"code":"KY.6.NS.6","subject":"Mathematics","grade":"6","text":"Understand a rational number as a point on the number line. Extend number line diagrams and coordinate axes, using appropriate range and intervals, to represent points on the line and in the plane, that include negative numbers and coordinates. a. Recognize opposite signs of numbers as indicating locations on opposite sides of 0 on the number line; recognize 0 is its own opposite and the opposite of a positive number is a negative, and the opposite of a negative number is a positive, such as \u2212(\u22123) = 3. b. Find and position integers and other rational numbers on a horizontal or vertical number line diagram; find and position pairs of integers and other rational numbers on a coordinate plane. c. Understand signs of numbers in ordered pairs as indicating locations in quadrants of the coordinate plane; recognize the similarity between whole numbers, their negative opposites and their positions on a number line, ordered pairs differ only by signs and their locations on one or both axes."},{"code":"KY.6.NS.7","subject":"Mathematics","grade":"6","text":"Understand ordering and absolute value of rational numbers. a. Interpret statements of inequality as statements about the relative position of two numbers on a number line diagram. b. Write, interpret and explain statements of order for rational numbers in real-world contexts. c. Understand the absolute value of a rational number as its distance from 0 on the number line; interpret absolute value as magnitude for a positive or negative quantity in a real-world situation. d. Distinguish comparisons of absolute value from statements about order."},{"code":"KY.6.NS.8","subject":"Mathematics","grade":"6","text":"Solve real-world and mathematical problems by graphing points in all four quadrants of the coordinate plane. Include use of coordinates and absolute value to find distances between points with the same first coordinate or the same second coordinate."},{"code":"KY.6.RP.1","subject":"Mathematics","grade":"6","text":"Understand the concept of a ratio and use ratio language to describe a ratio relationship between two quantities."},{"code":"KY.6.RP.2","subject":"Mathematics","grade":"6","text":"Understand the concept of a unit rate a/b associated with a ratio a:b with B \u2260 0 and use rate language in the context of a ratio relationship."},{"code":"KY.6.RP.3","subject":"Mathematics","grade":"6","text":"Use ratio and rate reasoning to solve real-world and mathematical problems. a. Make tables of equivalent ratios relating quantities with whole- number measurements, find missing values in the tables and plot the pairs of values on the coordinate plane. Use tables to compare ratios. b. Solve rate problems including those involving unit pricing and constant speed. c. Use ratio reasoning to convert measurement units; manipulate and transform units appropriately when multiplying or dividing quantities."},{"code":"KY.6.SP.0","subject":"Mathematics","grade":"6","text":"Apply the four-step investigative process for statistical reasoning. a. Formulate Questions: Formulate a statistical question as one that anticipates variability and can be answered with data. b. Collect Data: Design and use a plan to collect appropriate data to answer a statistical question. c. Analyze Data: Select appropriate graphical methods and numerical measures to analyze data by displaying variability within a group, comparing individual to individual and comparing individual to group. d. Interpret Results: Draw logical conclusions and make generalizations from the data based on the original question."},{"code":"KY.6.SP.1","subject":"Mathematics","grade":"6","text":"Recognize a statistical question as one that anticipates variability in the data related to the question and accounts for it in the answers."},{"code":"KY.6.SP.2","subject":"Mathematics","grade":"6","text":"Understand that a set of numerical data collected to answer a statistical question has a distribution which can be described by its center, spread and overall shape."},{"code":"KY.6.SP.3","subject":"Mathematics","grade":"6","text":"Recognize that a measure of center for a numerical data set summarizes all of its values with a single number to describe a typical value, while a measure of variation describes how the values in the distribution vary."},{"code":"KY.6.SP.4","subject":"Mathematics","grade":"6","text":"Display the distribution of numerical data in plots on a number line, including dot plots, histograms and box plots."},{"code":"KY.6.SP.5","subject":"Mathematics","grade":"6","text":"Summarize numerical data sets in relation to their context, such as by: a. Reporting the number of observations. b. Describing the nature of the attribute under investigation, including how it was measured and its units of measurement. c. Determining quantitative measures of center (median and/or mean) to describe distribution of numerical data. d. Describing distributions of numerical data qualitatively relating to shape (using terms such as cluster, mode(s), gap, symmetric, uniform, skewed-left, skewed-right and the presence of outliers) and quantitatively relating to spread/variability (using terms such as range and interquartile range). e. Relating the choice of measures of center and variability to the shape of the data distribution."},{"code":"6-ESS1-1","subject":"Science","grade":"6","text":"Develop and use a model of the Earth- sun-moon system to describe the cyclic patterns of lunar phases, eclipses of the sun and moon, and seasons."},{"code":"6-ESS1-2","subject":"Science","grade":"6","text":"Develop and use a model to describe the role of gravity in the motions within galaxies and the solar system."},{"code":"6-ESS1-3","subject":"Science","grade":"6","text":"Analyze and interpret data to determine scale properties of objects in the solar system."},{"code":"6-ESS2-1","subject":"Science","grade":"6","text":"Develop a model to describe the cycling of Earth\u2019s materials and the flow of energy that drives this process."},{"code":"6-ESS2-2","subject":"Science","grade":"6","text":"Construct an explanation based on evidence for how biological and geoscience processes have changed Earth\u2019 s surface at varying time and spatial scales."},{"code":"6-ESS2-3","subject":"Science","grade":"6","text":"Analyze and interpret data on the distribution of fossils and rocks, continental shapes, and seafloor structures to provide evidence of past plate motions."},{"code":"6-ESS2-4","subject":"Science","grade":"6","text":"Develop a model to describe the cycling of water through Earth\u2019s systems driven by energy from the sun and the force of gravity."},{"code":"6-ESS2-5","subject":"Science","grade":"6","text":"Collect data to provide evidence for how the motions and complex interactions of air masses result in changes in weather conditions."},{"code":"6-ESS2-6","subject":"Science","grade":"6","text":"Develop and use a model to describe how unequal heating and rotation of the Earth cause patterns of atmospheric and oceanic circulation that determine regional climates."},{"code":"6-LS1-6","subject":"Science","grade":"6","text":"Construct a scientific explanation based on evidence for the role of photosynthesis in the cycling of matter and flow of energy into and out of organisms."},{"code":"6-LS2-1","subject":"Science","grade":"6","text":"Analyze and interpret data to provide evidence for the effects of resource availability on organisms and populations of organisms in an ecosystem."},{"code":"6-LS2-2","subject":"Science","grade":"6","text":"Construct an explanation that predicts patterns of interaction among organisms across multiple ecosystems."},{"code":"6-LS2-3","subject":"Science","grade":"6","text":"Develop a model to describe the cycling of matter and flow of energy among living and non-living parts of an ecosystem."},{"code":"6-PS1-1","subject":"Science","grade":"6","text":"Develop models to describe the atomic composition of simple molecules and extended structures."},{"code":"6-PS1-4","subject":"Science","grade":"6","text":"Develop a model that predicts and describes changes in particle motion, temperature, and state of a pure substance when thermal energy is added or removed."},{"code":"6-PS2-1","subject":"Science","grade":"6","text":"Apply Newton\u2019s third law to design a solution to a problem involving the motion of two colliding objects. *"},{"code":"6-PS2-4","subject":"Science","grade":"6","text":"Construct and present arguments using evidence to support the claim that gravitational interactions are attractive and depend on the masses of interacting objects."},{"code":"6.C.CP.1","subject":"Social Studies","grade":"6","text":"Explain the origins, functions and structures of governments in River Valley Civilizations and Classical Period Empires between 3500 BCE-600 CE."},{"code":"6.C.CP.2","subject":"Social Studies","grade":"6","text":"Explain connections between government and religion in River Valley Civilizations and Classical Period Empires between 3500 BCE- 600 CE."},{"code":"6.C.CP.3","subject":"Social Studies","grade":"6","text":"Describe the political institutions of monarchy, democracy, republic, empire and theocracy in River Valley Civilizations and Classical Empires between 3500 BCE-600 CE."},{"code":"6.C.CV.1","subject":"Social Studies","grade":"6","text":"Analyze how histo rical, economic, geographic and cultural characteristics influence social and government structures in River Valley Civilizations and Classical Empires between 3500 BCE-600 CE."},{"code":"6.C.PR.1","subject":"Social Studies","grade":"6","text":"Analyze the purpos es and effects of laws in River Valley Civilizations and Classical Empires between 3500 BCE-600 CE."},{"code":"6.C.RR.1","subject":"Social Studies","grade":"6","text":"Evaluate the rights, roles, responsibilities and limitations of the concept of citizen in Classical Greece and Rome."},{"code":"6.E.IC.1","subject":"Social Studies","grade":"6","text":"Analyze the e conomic choices of individuals, societies and governments."},{"code":"6.E.MA.1","subject":"Social Studies","grade":"6","text":"Describe ho w civilizations used bartering to establish mediums of exchange to meet their wants."},{"code":"6.E.MA.2","subject":"Social Studies","grade":"6","text":"Explain how market conditions and economic activity affected the growth of River Valley Civilizations and Classical Empires between 3500 BCE-600 CE."},{"code":"6.E.MI.1","subject":"Social Studies","grade":"6","text":"Trace the c hain of supply for a needed product."},{"code":"6.E.MI.2","subject":"Social Studies","grade":"6","text":"Predict and analyze unintended costs and benefits of economic decisions. 6.E.M1.3 Explain how markets exist whenever there is an exchange of goods and services. 6.E.M1.4 Compare the markets of River Valley Civilizations and Classical Empires between 3500 BCE-600 CE."},{"code":"6.E.MI.3","subject":"Social Studies","grade":"6","text":"Explain how markets exist whenever there is an exchange of goods and services."},{"code":"6.E.MI.4","subject":"Social Studies","grade":"6","text":"Compare the markets of River Valley Civilizations and Classical Empires between 3500 BCE-600 CE."},{"code":"6.E.ST.1","subject":"Social Studies","grade":"6","text":"Compare specialization in two or more civilizations or empires. (see \u201ccontinued\u201d) After the development of agriculture, people were able to settle in one area and, because farmers were creating a food surplus, not all people needed to be involved in procuring food."},{"code":"6.E.ST.2","subject":"Social Studies","grade":"6","text":"Examine how new knowledge, technology and specialization increase productivity."},{"code":"6.G.GR.1","subject":"Social Studies","grade":"6","text":"Use maps and other geographic representations, geospatial technologies, and spatial thinking to determine similarities and differences among River Valley Civilizations and Classical Empires between 3500 BCE- 600 CE."},{"code":"6.G.HE.1","subject":"Social Studies","grade":"6","text":"Analyze how physical environments shaped the development of River Valley Civilizations and Classical Period Empires between 3500 BCE-600 CE."},{"code":"6.G.HE.2","subject":"Social Studies","grade":"6","text":"Analyze how River Valley Civilizations and Classical Empires impacted the environment, both positively and negatively, between 3500 BCE-600 CE."},{"code":"6.G.HI.1","subject":"Social Studies","grade":"6","text":"Explain how population changes in River Valley Civilizations and Classical Empires affected land use between 3500 BCE-600 CE."},{"code":"6.G.HI.2","subject":"Social Studies","grade":"6","text":"Analyze the impact of interactions between various River Valley Civilizations and between various Classical Empires between 3500 BCE-600 CE."},{"code":"6.G.MM.1","subject":"Social Studies","grade":"6","text":"Compare how human and environmental characteristics of a region influenced the movement of people, goods and ideas during the rise of River Valley Civilizations and Classical Empires between 3500 BCE-600 CE."},{"code":"6.H.CE.1","subject":"Social Studies","grade":"6","text":"Analyze the cau ses and effects of the rise of River Valley Civilizations."},{"code":"6.H.CH.1","subject":"Social Studies","grade":"6","text":"Describe how River Valley Civilizations transitioned to empires between 3500 BCE- 600 CE."},{"code":"6.H.CH.2","subject":"Social Studies","grade":"6","text":"Compare the origins and development of early world religions from River Valley Civilizations to Classical Empires 3500 BCE- 600 CE."},{"code":"6.H.CO.1","subject":"Social Studies","grade":"6","text":"Explain the r ole conflict played in the development and expansion of Classical Empires between 3500 BCE-600 CE."},{"code":"6.H.CO.2","subject":"Social Studies","grade":"6","text":"Analyze the impact trade networks had on interactions among various human societies between 3500 BCE-600 CE."},{"code":"6.H.KH.1","subject":"Social Studies","grade":"6","text":"Determine the influences of Classical Greece and Rome on the structures of Kentucky\u2019s state government."},{"code":"6.I.CC.1","subject":"Social Studies","grade":"6","text":"Construct explanations, using reasoning, correct sequence, examples and details with relevant information and data, while acknowledging the strengths and weaknesses of the explanations concerning the development of civilizations."},{"code":"6.I.CC.2","subject":"Social Studies","grade":"6","text":"Construct arguments, using claims and evidence from multiple credible sources, while acknowledging the strengths and limitations of the arguments, to address how a specific problem can manifest itself at local, regional and global levels over time."},{"code":"6.I.CC.3","subject":"Social Studies","grade":"6","text":"Evaluate how individuals and groups addressed local, regional and global problems throughout the development of civilizations."},{"code":"6.I.CC.4","subject":"Social Studies","grade":"6","text":"Engage in a range of deliberative and democratic procedures to discuss current local, regional and global issues."},{"code":"6.I.CC.5","subject":"Social Studies","grade":"6","text":"Describe a specific problem from the development of civilizations using each of the social studies disciplines."},{"code":"6.I.Q.1","subject":"Social Studies","grade":"6","text":"Develop compelling questions related to the development of civilizations between 3500 BCE- 600 CE."},{"code":"6.I.Q.2","subject":"Social Studies","grade":"6","text":"Generate supporting questions related to the development of civilizations between 3500 BCE- 600 CE."},{"code":"6.I.Q.3","subject":"Social Studies","grade":"6","text":"Identify the types of supporting questions each of the social studies disciplines uses to answer compelling and supporting questions."},{"code":"6.I.UE.1","subject":"Social Studies","grade":"6","text":"Develop claims, citing relevant evidence, in response to compelling and supporting questions."},{"code":"6.I.UE.2","subject":"Social Studies","grade":"6","text":"Compare evidence from primary and secondary sources to assist in answering compelling and supporting questions."},{"code":"6.I.UE.3","subject":"Social Studies","grade":"6","text":"Gather primary and secondary sources, and determine their relevance and intended use to answer compelling and supporting questions."},{"code":"C.7.1","subject":"English Language Arts","grade":"7","text":"Compose arguments to support claims with clear reasons and relevant evidence. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce claim(s), acknowledge opposing claims and counter/refute them and organize the reasons and evidence logically. c. Support claim(s) with logical reasoning and relevant evidence, using accurate, credible sources and demonstrating an understanding of the topic or text. d. Use transitions to create cohesion and clarify the relationships among claims. e. Establish and maintain a task-appropriate writing style. f. Provide a concluding statement or section that supports the argument presented. g. With some guidance, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on how well purpose and audience have been addressed."},{"code":"C.7.2","subject":"English Language Arts","grade":"7","text":"Compose informative and/or explanatory texts to examine a topic and convey ideas, concepts and information through the selection, organization and analysis of relevant content. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce a topic clearly; organize ideas, concepts and information, using strategies such as definition, classification, comparison/contrast and cause/effect; include formatting, graphics and multimedia when useful to aiding comprehension. c. Develop the topic with relevant facts, definitions, concrete details, quotations or other information and examples. d. Use appropriate transitions to create cohesion and clarify the relationships among ideas and concepts. e. Use precise language and domain-specific vocabulary to inform about or explain the topic. f. Establish and maintain a formal style. g. Provide a concluding statement or section that follows from and supports the information or explanation presented. h. With some guidance, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on how well purpose and audience have been addressed."},{"code":"C.7.3","subject":"English Language Arts","grade":"7","text":"Compose narratives to develop real or imagined experiences or multiple events, memories or ideas using effective technique, relevant descriptive details and well-structured event sequences. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Engage the reader by establishing a context and point of view and introducing a narrator and/or characters; organize an event sequence that unfolds naturally and logically. c. Use narrative techniques, such as dialogue, pacing and description, to develop experiences, events and/or characters. d. Use a variety of transition words to convey sequence and signal shifts from one time frame or setting to another. e. Use precise words, relevant descriptive details and sensory language to capture the action and convey experiences and events. f. Provide a conclusion that follows from and reflects on the narrated experiences or events. g. With guidance, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach. Production and Distribution"},{"code":"C.7.4","subject":"English Language Arts","grade":"7","text":"Use DIGITAL RESOURCES to create and publish products as well as to interact and collaborate with others ; cite sources using MLA or APA format ."},{"code":"C.7.5","subject":"English Language Arts","grade":"7","text":"Conduct short RESEARCH projects to answer a question , drawing on several sources and generating additional related, focused questions for further research and investigation ."},{"code":"C.7.6","subject":"English Language Arts","grade":"7","text":"Gather relevant information from multiple print and digital sources, using search terms effectively ; assess the credibility and accuracy of each source; and, in order to engage in reflection or analysis , QUOTE OR PARAPHRASE DATA AND CONCLUSIONS OF OTHERS , avoiding plagiarism by providing in-text and bibliographic MLA or APA citation ."},{"code":"C.7.7","subject":"English Language Arts","grade":"7","text":"Compose routinely over extended time frames and shorter time frames for a variety of tasks, purposes and audiences ."},{"code":"L.7.1","subject":"English Language Arts","grade":"7","text":"In both written and oral expression : a. Create sentences using correctly placed CLAUSES AND PHRASES . b. Demonstrate appropriate use of SIMPLE, COMPOUND, COMPLEX AND COMPOUND-COMPLEX SENTENCES to signal differing relationships among ideas ."},{"code":"L.7.2","subject":"English Language Arts","grade":"7","text":"When writing : a. Demonstrate appropriate use of a COMMA TO SEPARATE COORDINATE ADJECTIVES . b. Demonstrate appropriate use of strategies and resources (print and electronic) to identify and correct spelling errors ."},{"code":"L.7.3","subject":"English Language Arts","grade":"7","text":"Use knowledge of language and its conventions when writing, speaking, reading or listening . a. Choose language that expresses ideas precisely and concisely , recognizing and eliminating wordiness and redundancy ."},{"code":"L.7.4","subject":"English Language Arts","grade":"7","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grade 7 reading and content, choosing flexibly from an array of strategies . a. Use context (e.g., the overall meaning of a sentence or paragraph; a word\u2019s position or function in a sentence) as a clue to the meaning of a word or phrase . b. Use GREEK AND LATIN AFFIXES AND ROOTS as clues to the meaning of a word . c. Consult print and digital reference materials to find the pronunciation and determine or clarify the precise meaning of key words and phrases . d. Acquire and use accurately grade-appropriate general academic and domain-specific words and phrases; gather vocabulary knowledge when considering a word or phrase important to comprehension or expression ."},{"code":"L.7.5","subject":"English Language Arts","grade":"7","text":"Demonstrate understanding of; figurative language, word relationships and nuances in word meanings . a. Interpret figurative language , including but not limited to ALLUSIONS , in context . b. Use the relationship between particular words to improve understanding . c. Distinguish among the CONNOTATIONS of words with similar DENOTATIONS ."},{"code":"RI.7.1","subject":"English Language Arts","grade":"7","text":"CITE SEVERAL PIECES OF TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RI.7.10","subject":"English Language Arts","grade":"7","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT independently ."},{"code":"RI.7.2","subject":"English Language Arts","grade":"7","text":"Determine CENTRAL IDEAS of a text and analyze their development through citing textual evidence, paraphrasing or summarizing ."},{"code":"RI.7.3","subject":"English Language Arts","grade":"7","text":"Analyze the INTERACTIONS BETWEEN INDIVIDUALS, EVENTS AND IDEAS over the course of a text ."},{"code":"RI.7.4","subject":"English Language Arts","grade":"7","text":"Determine the meaning of words and phrases as they are used in a text, including figurative, connotative and technical meanings; analyze the impact of WORD CHOICES on meaning and TONE ."},{"code":"RI.7.5","subject":"English Language Arts","grade":"7","text":"Analyze the STRUCTURE an author uses to organize a text, including how the different sections contribute to the whole and to the development of the ideas ."},{"code":"RI.7.6","subject":"English Language Arts","grade":"7","text":"Determine an author\u2019s PERSPECTIVE and PURPOSE in a text, and analyze how the author distinguishes his or her position from that of others ."},{"code":"RI.7.7","subject":"English Language Arts","grade":"7","text":"Compare and contrast a print to a non-print version of a text, analyzing each media's PORTRAYAL OF THE SUBJECT and its impact on the audience ."},{"code":"RI.7.8","subject":"English Language Arts","grade":"7","text":"Identify and evaluate the ARGUMENT and specific CLAIMS in a text, assessing whether the reasoning is sound and the EVIDENCE is relevant and sufficient to support the CLAIMS ."},{"code":"RI.7.9","subject":"English Language Arts","grade":"7","text":"Analyze how TWO OR MORE AUTHORS WRITING ABOUT THE SAME TOPIC present key information by emphasizing different evidence or advancing different interpretations of facts ."},{"code":"RL.7.1","subject":"English Language Arts","grade":"7","text":"CITE SEVERAL PIECES OF TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RL.7.10","subject":"English Language Arts","grade":"7","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.7.2","subject":"English Language Arts","grade":"7","text":"Determine THEMES of a text and analyze their development through citing textual evidence, paraphrasing or summarizing ."},{"code":"RL.7.3","subject":"English Language Arts","grade":"7","text":"Analyze how particular ELEMENTS OF A STORY OR DRAMA influence one another ."},{"code":"RL.7.4","subject":"English Language Arts","grade":"7","text":"Determine the meaning of words and phrases as they are used in a text, including figurative and connotative meanings; analyze the impact of RHYMES AND OTHER REPETITIONS OF SOUNDS on a passage."},{"code":"RL.7.5","subject":"English Language Arts","grade":"7","text":"Analyze how the form or STRUCTURE of a drama, poem or prose text contributes to its meaning ."},{"code":"RL.7.6","subject":"English Language Arts","grade":"7","text":"Analyze how an author develops and contrasts the PERSPECTIVE of different characters or narrators in a text."},{"code":"RL.7.7","subject":"English Language Arts","grade":"7","text":"Compare and contrast reading a print text and viewing its visual/oral presentation , analyzing the effects of TECHNIQUES UNIQUE TO EACH MEDIUM ."},{"code":"RL.7.8","subject":"English Language Arts","grade":"7","text":"Not applicable to literature"},{"code":"RL.7.9","subject":"English Language Arts","grade":"7","text":"Compare and contrast a FICTIONAL PORTRAYAL and A HISTORICAL ACCOUNT OF THE SAME PERIOD as a means to understand how authors use history ."},{"code":"KY.7.EE.1","subject":"Mathematics","grade":"7","text":"Apply properties of operations as strategies to add, subtract, factor and expand linear expressions with rational coefficients."},{"code":"KY.7.EE.2","subject":"Mathematics","grade":"7","text":"Understand that rewriting an expression in different forms in a problem context can clarify the problem and how the quantities in it are related."},{"code":"KY.7.EE.3","subject":"Mathematics","grade":"7","text":"Solve real-life and mathematical problems posed with positive and negative rational numbers in any form, using tools strategically. Apply properties of operations to calculate with numbers in any form; convert between forms as appropriate; and assess the reasonableness of answers using mental computation and estimation strategies."},{"code":"KY.7.EE.4","subject":"Mathematics","grade":"7","text":"Use variables to represent quantities in a real-world or mathematical problem and construct equations and inequalities to solve problems by reasoning about the quantities. a. Solve word problems leading to equations of the form \ud835\udc5d\ud835\udc5d\ud835\udc65\ud835\udc65 + \ud835\udc5e\ud835\udc5e = \ud835\udc5f\ud835\udc5f and \ud835\udc5d\ud835\udc5d(\ud835\udc65\ud835\udc65 + \ud835\udc5e\ud835\udc5e) = \ud835\udc5f\ud835\udc5f, where p, q and r are specific rational numbers. Solve equations of these forms. Graph the solution set of the equality and interpret it in context of the problem. b. Solve word problems leading to inequalities of the form \ud835\udc5d\ud835\udc5d\ud835\udc65\ud835\udc65+ \ud835\udc5e\ud835\udc5e > \ud835\udc5f\ud835\udc5f, \ud835\udc5d\ud835\udc5d\ud835\udc65\ud835\udc65 + \ud835\udc5e\ud835\udc5e < \ud835\udc5f\ud835\udc5f, \ud835\udc5d\ud835\udc5d\ud835\udc65\ud835\udc65+ \ud835\udc5e\ud835\udc5e\u2265 \ud835\udc5f\ud835\udc5f, \ud835\udc5d\ud835\udc5d\ud835\udc65\ud835\udc65+ \ud835\udc5e\ud835\udc5e\u2264 \ud835\udc5f\ud835\udc5f; where p, q and r are specific rational numbers. Graph the solution set of the inequality and interpret it in context of the problem."},{"code":"KY.7.G.1","subject":"Mathematics","grade":"7","text":"Solve problems involving scale drawings of geometric figures, including computing actual lengths and areas from a scale drawing and reproducing a scale drawing at a different scale."},{"code":"KY.7.G.2","subject":"Mathematics","grade":"7","text":"Draw (freehand, with ruler and protractor and with technology) geometric shapes with given conditions. Focus on constructing triangles from three measures of angles or sides, noticing when the conditions determine a unique triangle, more than one triangle, or no triangle."},{"code":"KY.7.G.3","subject":"Mathematics","grade":"7","text":"Describe the two-dimensional figures that result from slicing three-dimensional figures, as in plane sections of right rectangular prisms and right rectangular pyramids."},{"code":"KY.7.G.4","subject":"Mathematics","grade":"7","text":"Use formulas for area and circumference of circles and their relationships. a. Apply the formulas for the area and circumference of a circle to solve real-world and mathematical problems. b. Explore and understand the relationship between the radius, diameter, circumference and area of a circle."},{"code":"KY.7.G.5","subject":"Mathematics","grade":"7","text":"Apply properties of supplementary, complementary, vertical and adjacent angles in a multi-step problem to write and solve simple equations for an unknown angle in a figure."},{"code":"KY.7.G.6","subject":"Mathematics","grade":"7","text":"Solve problems involving area of two-dimensional objects and surface area and volume of three-dimensional objects. a. Solve real-world and mathematical problems involving area of two-dimensional objects composed of triangles, quadrilaterals and other polygons. a. Emphasis is on finding the area of composite figures composed of convex polygons. b. Students understand volume and surface area are two different quantities used to describe the same three-dimensional figure. Building upon their understanding of area, students use nets of three dimensional objects to conceptualize surface area."},{"code":"KY.7.NS.1","subject":"Mathematics","grade":"7","text":"Apply and extend previous understandings of addition and subtraction to add and subtract rational numbers; represent addition and subtraction on a horizontal or vertical number line diagram. a. Describe situations in which opposite quantities combine to make 0. b. Understand \ud835\udc5d\ud835\udc5d + \ud835\udc5e\ud835\udc5e as the number located a distance |\ud835\udc5e\ud835\udc5e| from p, in the positive or negative direction depending on whether q is positive or negative. Show that a number and its opposite have a sum of 0 (are additive inverses). Interpret sums of rational numbers by describing real-world contexts. c. Understand subtraction of rational numbers as adding the additive inverse, \ud835\udc5d\ud835\udc5d \u2013 \ud835\udc5e\ud835\udc5e = \ud835\udc5d\ud835\udc5d + (\u2013 \ud835\udc5e\ud835\udc5e). Show that the distance between two rational numbers on the number line is the absolute value of their difference and apply this principle in real-world contexts. d. Apply properties of operations as strategies to add and subtract rational numbers."},{"code":"KY.7.NS.2","subject":"Mathematics","grade":"7","text":"Apply and extend previous understandings of multiplication and division and of fractions to multiply and divide rational numbers. a. Understand that multiplication is extended from fractions to rational numbers by requiring that operations continue to satisfy the properties of operations, particularly the distributive property, leading to products such as (\u20131)(\u20131) = 1 and the rules a. Emphasis is on exploring and understanding how the rules for multiplying and dividing with negative numbers are connected to properties for the operations, rather than to think of them as arbitrary rules. They explain 4 times (-3) could be four days of golfing 3 under par and therefore, having an overall score of -12. The remaining operations are based on applying properties."},{"code":"KY.7.NS.2c","subject":"Mathematics","grade":"7","text":"Apply properties of operations as strategies to add and subtract rational numbers. Apply properties of operations as strategies to multiply and divide rational numbers. 8"},{"code":"KY.7.NS.3","subject":"Mathematics","grade":"7","text":"Solve real-world and mathematical problems involving the four operations with rational numbers."},{"code":"KY.7.RP.1","subject":"Mathematics","grade":"7","text":"Compute unit rates associated with ratios of fractions, including ratios of lengths, areas and other quantities measured in like or different units."},{"code":"KY.7.RP.2","subject":"Mathematics","grade":"7","text":"Recognize and represent proportional relationships between quantities. a. Decide whether two quantities represent a proportional relationship. b. Identify the constant of proportionality (unit rate) in tables, graphs, equations, diagrams and verbal descriptions of proportional relationships. c. Represent proportional relationships by equations. d. Explain what a point (x, y) on the graph of a proportional relationship means in terms of the situation, with special attention to the points (0, 0) and (1, r) where r is the unit rate."},{"code":"KY.7.RP.3","subject":"Mathematics","grade":"7","text":"Use percents to solve mathematical and real-world problems. a. Find a percent of a quantity as a rate per 100; solve problems involving finding the whole, a part and a percent, given two of these. b. Use proportional relationships to solve multistep ratio and percent problems."},{"code":"KY.7.SP.0","subject":"Mathematics","grade":"7","text":"Create displays, including circle graphs (pie charts), scaled pictographs and bar graphs, to compare and analyze distributions of categorical data from both matching and different-sized samples."},{"code":"KY.7.SP.1","subject":"Mathematics","grade":"7","text":"Understand that statistics can be used to gain information about a population by examining a sample of the population; generalizations about a population from a sample are valid only if the sample is representative of that population. Understand that random Recognize what makes a valid and non-valid sample of a population. Recognize the size of the sample holds importance to the accuracy of the sample."},{"code":"KY.7.SP.2","subject":"Mathematics","grade":"7","text":"Use data from a random sample to draw inferences about a population with an unknown characteristic of interest. a. Generate multiple samples of categorical data of the same size to gauge the variation in estimates or predictions. b. Generate multiple samples (or simulated samples) of numerical data to gauge the variation in estimates or predictions. c. Gauge how far off an estimate or prediction might be related to a population character of interest."},{"code":"KY.7.SP.3","subject":"Mathematics","grade":"7","text":"Describe the degree of visual overlap (and separation) from the graphical representations of two numerical data distributions (box plots, dot plots) with similar variabilities with similar contexts (same variable), measuring the difference between the centers (medians or means) by expressing this difference as a multiple of a measure of variability (interquartile range when comparing medians or the mean absolute deviation when comparing means)."},{"code":"KY.7.SP.4","subject":"Mathematics","grade":"7","text":"Calculate and use measures of center (mean and median) and measures of variability (interquartile range when comparing medians and mean absolute deviation when comparing means) for numerical data from random samples to draw informal comparative inferences about two populations."},{"code":"KY.7.SP.5","subject":"Mathematics","grade":"7","text":"Describe the probability of a chance event is a number between 0 and 1, which tells how likely the event is, from impossible (0) to certain (1). A probability near 0 indicates an unlikely event, a probability around 1/2 indicates an event that is neither unlikely nor likely and a probability near 1 indicates a likely event."},{"code":"KY.7.SP.6","subject":"Mathematics","grade":"7","text":"Approximate the probability of a chance event by collecting data on the chance process that produces it and observing its long-run relative frequency and predict the approximate relative frequency given the probability."},{"code":"KY.7.SP.7","subject":"Mathematics","grade":"7","text":"Develop a probability model and use it to find probabilities of events. Compare probabilities from a model to observed frequencies; if the agreement is not good, explain possible sources of the discrepancy. a. Develop a uniform probability model by assigning equal probability to all outcomes and use the model to determine probabilities of events. b. Develop a probability model (which may not be uniform) by observing frequencies in data generated from a chance process."},{"code":"KY.7.SP.8","subject":"Mathematics","grade":"7","text":"Find probabilities of compound events using organized lists, tables, tree diagrams and simulation. Example: a. If the probability of heads occurring on a coin is \u00bd, then the probability of three heads in a row is \u00bd \u22c5\u00bd \u22c5\u00bd = \u215b."},{"code":"7-LS1-1","subject":"Science","grade":"7","text":"Conduct an investigation to provide evidence that living things are made of cells; either one cell or many different numbers and types of cells."},{"code":"7-LS1-2","subject":"Science","grade":"7","text":"Develop and use a model to describe the function of a cell as a whole and ways the parts of cells contribute to the function."},{"code":"7-LS1-3","subject":"Science","grade":"7","text":"Use argument supported by evidence for how the body is a system of interacting subsystems composed of groups of cells."},{"code":"7-LS1-7","subject":"Science","grade":"7","text":"Develop a model to describe how food is rearranged through chemical reactions forming new molecules that support growth and/or release energy as this matter moves through an organism."},{"code":"7-LS1-8","subject":"Science","grade":"7","text":"Gather and synthesize information that sensory receptors respond to stimuli by sending messages to the brain for immediate behavior or storage as memories."},{"code":"7-PS1-2","subject":"Science","grade":"7","text":"Analyze and interpret data on the properties of substances before and after the substances interact to determine if a chemical reaction has occurred."},{"code":"7-PS1-5","subject":"Science","grade":"7","text":"Develop and use a model to describe how the total number of atoms does not change in a chemical reaction and thus mass is conserved."},{"code":"7-PS1-6","subject":"Science","grade":"7","text":"Undertake a design project to construct, test, and modify a device that either releases or absorbs thermal energy.*"},{"code":"7-PS2-2","subject":"Science","grade":"7","text":"Plan an investigation to provide evidence that the change in an object\u2019s motion depends on the sum of the forces on the object and the mass of the object."},{"code":"7-PS2-3","subject":"Science","grade":"7","text":"Ask questions about data to determine the factors that affect the strength of electric and magnetic forces."},{"code":"7-PS2-5","subject":"Science","grade":"7","text":"Conduct an investigation and evaluate the experimental design to provide evidence that fields exist between objects exerting forces on each other even though the objects are not in contact."},{"code":"7-PS3-1","subject":"Science","grade":"7","text":"Construct and interpret graphical displays of data to describe the relationships of kinetic energy to the mass of an object and to the speed of an object."},{"code":"7-PS3-2","subject":"Science","grade":"7","text":"Develop a model to describe that when the arrangement of objects interacting at a distance changes, different amounts of potential energy are stored in the system."},{"code":"7-PS3-3","subject":"Science","grade":"7","text":"Apply scientific principles to design, construct, and test a device that either minimizes or maximizes thermal energy transfer.*"},{"code":"7-PS3-4","subject":"Science","grade":"7","text":"Plan an investigation to determine the relationships among the energy transferred, the type of matter, the mass, and the change in the average kinetic energy of the particles as measured by the temperature of the sample."},{"code":"7-PS3-5","subject":"Science","grade":"7","text":"Construct, use, and present arguments to support the claim that when the kinetic energy of an object changes, energy is transferred to or from the object."},{"code":"7-PS4-1","subject":"Science","grade":"7","text":"Use mathematical representations to describe a simple model for waves that includes how the amplitude of a wave is related to the energy in a wave."},{"code":"7-PS4-2","subject":"Science","grade":"7","text":"Develop and use a model to describe that waves are reflected, absorbed, or transmitted through various materials."},{"code":"7-PS4-3","subject":"Science","grade":"7","text":"Integrate qualitative scientific and technical information to support the claim that designed technologies can transmit digital information as wave pulses."},{"code":"7.C.CP.1","subject":"Social Studies","grade":"7","text":"Compare political institutions and their impacts on people in empires between 600- 1600."},{"code":"7.C.CV.1","subject":"Social Studies","grade":"7","text":"Describe the metho ds used by non-democratic governments to create order, establish justice and meet the needs of their subjects between 600-1600."},{"code":"7.C.PR.1","subject":"Social Studies","grade":"7","text":"Assess the effectiv eness of law codes to create order, establish justice and meet the needs of their subjects between 600-1600."},{"code":"7.C.RR.1","subject":"Social Studies","grade":"7","text":"Compare rights, role s, responsibilities and limitations of subjects in empires between 600- 1600 with those of citizens in modern countries."},{"code":"7.E.IC.1","subject":"Social Studies","grade":"7","text":"Analyze how econ omic choices were made based on scarcity."},{"code":"7.E.IC.2","subject":"Social Studies","grade":"7","text":"Analyze the impact of growth and expansion on the allocation of resources and economic incentives."},{"code":"7.E.MA.1","subject":"Social Studies","grade":"7","text":"Compare the economic development of traditional and market economies."},{"code":"7.E.MA.2","subject":"Social Studies","grade":"7","text":"Compare how different economic systems choose to allocate the production, distribution and consumption of resources."},{"code":"7.E.MI.1","subject":"Social Studies","grade":"7","text":"Analyze the role of cons umers and producers in product markets."},{"code":"7.E.MI.2","subject":"Social Studies","grade":"7","text":"Analyze the relationship between supply and demand."},{"code":"7.E.MI.3","subject":"Social Studies","grade":"7","text":"Categorize the four factors of production and how they are combined to make goods and deliver services."},{"code":"7.E.ST.1","subject":"Social Studies","grade":"7","text":"Explain the i mpact of supply and demand on the emergence of global markets."},{"code":"7.E.ST.2","subject":"Social Studies","grade":"7","text":"Analyze the impact of specialization upon trade and the cost of goods and services."},{"code":"7.E.ST.3","subject":"Social Studies","grade":"7","text":"Explain how growing interdependence and advances in technology improve standards of living."},{"code":"7.E.ST.4","subject":"Social Studies","grade":"7","text":"Analyze the interregional trading systems of the Americas, Africa, Asia and Europe between 600-1450."},{"code":"7.G.GR.1","subject":"Social Studies","grade":"7","text":"Analyze the spat ial organization of people, places and environments found in the societies and empires of Afro-Eurasia and the Americas between 600-1600."},{"code":"7.G.GR.2","subject":"Social Studies","grade":"7","text":"Use maps and other geographic representations, geospatial technologies, and spatial thinking to interpret the relationships between humans and their environment."},{"code":"7.G.HE.1","subject":"Social Studies","grade":"7","text":"Examine how physical geography influenced the societies and empires of Afro-Eurasia and the Americas between 600-1600."},{"code":"7.G.HE.2","subject":"Social Studies","grade":"7","text":"Explain how societies and empires of Afro- Eurasia and the Americas between 600-1600 impacted the environment in a variety of ways."},{"code":"7.G.HI.1","subject":"Social Studies","grade":"7","text":"Distinguish ho w cooperation and conflict within and among the societies and empires of Afro-Eurasia and the Americas between 600-1600 influenced the division and control of land and resources."},{"code":"7.G.HI.2","subject":"Social Studies","grade":"7","text":"Examine ways in which one culture can both positively and negatively influence another through cultural diffusion, trade relationships, expansion and exploration."},{"code":"7.G.MM.1","subject":"Social Studies","grade":"7","text":"Analyze the push and pull factors that influenced movement, voluntary migration and forced migration in the societies and empires of Afro-Eurasia and the Americas between 600-1600."},{"code":"7.H.CE.1","subject":"Social Studies","grade":"7","text":"Analyze the causes and effects of the Renaissance, Scientific Revolution and the Enlightenment."},{"code":"7.H.CE.2","subject":"Social Studies","grade":"7","text":"Evaluate the political, geographic, economic and social impact of the expansion of empires between 600-1600."},{"code":"7.H.CH.1","subject":"Social Studies","grade":"7","text":"Indicate changes resulting from increased interactions and connections between Afro- Eurasia and the Americas between 1450-1600."},{"code":"7.H.CO.1","subject":"Social Studies","grade":"7","text":"Explain how religion influenced state- building, trade and cultural interactions between 600-1600."},{"code":"7.H.CO.2","subject":"Social Studies","grade":"7","text":"Evaluate various motives for expansion among multiple empires between 600-1600."},{"code":"7.I.CC.1","subject":"Social Studies","grade":"7","text":"Construct explanations, using reasoning, correct sequence, examples and details with relevant information and data, while acknowledging the strengths and weaknesses of the explanations concerning the growth and expansion of civilizations."},{"code":"7.I.CC.2","subject":"Social Studies","grade":"7","text":"Construct arguments by drawing on multiple disciplinary lenses to analyze how a specific problem can manifest itself at local, regional and global levels over time, identifying its characteristics and causes and the challenges and opportunities faced by those trying to address the problem."},{"code":"7.I.CC.3","subject":"Social Studies","grade":"7","text":"Evaluate how individuals and groups addressed local, regional and global problems throughout the growth and expansion of civilizations."},{"code":"7.I.CC.4","subject":"Social Studies","grade":"7","text":"Use a range of deliberative and democratic procedures to discuss current local, regional and global issues."},{"code":"7.I.CC.5","subject":"Social Studies","grade":"7","text":"Analyze a specific problem from the growth and expansion of civilizations using each of the social studies disciplines."},{"code":"7.I.Q.1","subject":"Social Studies","grade":"7","text":"Develop compelling questions, focusing on the growth and expansion of civilizations from 600-1600."},{"code":"7.I.Q.2","subject":"Social Studies","grade":"7","text":"Generate supporting questions, using the disciplines of social studies, to help answer compelling questions related to the growth and expansion of civilizations between 600-1600."},{"code":"7.I.Q.3","subject":"Social Studies","grade":"7","text":"Compare the types of supporting questions each of the social studies disciplines uses to answer compelling and supporting questions."},{"code":"7.I.UE.1","subject":"Social Studies","grade":"7","text":"Use multiple sources to develop claims in response to compelling and supporting questions."},{"code":"7.I.UE.2","subject":"Social Studies","grade":"7","text":"Analyze evidence from multiple perspectives and sources to support claims and refute opposing claims, noting evidentiary limitations to answer compelling and supporting questions."},{"code":"7.I.UE.3","subject":"Social Studies","grade":"7","text":"Gather relevant information from multiple sources while using the origin, authority, structure and context of the sources to guide the selection to answer compelling and supporting questions."},{"code":"C.8.1","subject":"English Language Arts","grade":"8","text":"Compose arguments to support claims with clear reasons and relevant evidence. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce claim(s), acknowledge and distinguish opposing claim(s) and counter/refute them and organize the reasons and evidence logically. c. Support claim(s) with logical reasoning and relevant evidence, using accurate, credible sources and demonstrating an understanding of the topic or text. d. Use transitions to create cohesion and clarify the relationships among claim(s), counterclaims, reasons and evidence. e. Establish and maintain a task-appropriate writing style. f. Provide a concluding statement or section that supports the argument presented. g. With some guidance, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on how well purpose and audience have been addressed."},{"code":"C.8.2","subject":"English Language Arts","grade":"8","text":"Compose informative and/or explanatory texts to examine a topic and convey ideas, concepts and information through the selection, organization and analysis of relevant content. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce a topic clearly; organize ideas, concepts and information into broader categories; include formatting, graphics and multimedia when useful to aiding comprehension. c. Develop the topic with relevant, well-chosen facts, definitions, concrete details, quotations or other information and examples. d. Use appropriate and varied transitions to create cohesion and clarify the relationships among ideas and concepts. e. Use precise language and domain-specific vocabulary to inform about or explain the topic. f. Establish and maintain a formal style. g. Provide a concluding statement or section that follows from and supports the information or explanation presented. h. With some guidance, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on how well purpose and audience have been addressed."},{"code":"C.8.3","subject":"English Language Arts","grade":"8","text":"Use narratives strategically in other modes of writing, utilizing effective technique, well-chosen details and well-structured sequences for an intended purpose. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Engage the reader by setting out a problem, situation or observation, establishing a point of view and introducing a narrator and/or characters; create a smooth progression of experiences or events. c. Use narrative techniques, such as dialogue, pacing, description and reflection, to develop experiences, events and/or characters. d. Use a variety of transitions to convey sequence, signal shifts from one time frame or setting to another and show the relationships among experiences and events. e. Use precise words and phrases, relevant descriptive details and sensory language to capture the action and convey experiences and events. f. Provide a conclusion that connects the narrative\u2019s relevance to the intended purpose of the writing. g. With guidance, develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach. Production and Distribution"},{"code":"C.8.4","subject":"English Language Arts","grade":"8","text":"Use DIGITAL RESOURCES to create and publish products as well as to interact and collaborate with others ; cite sources using MLA or APA format ."},{"code":"C.8.5","subject":"English Language Arts","grade":"8","text":"Conduct short RESEARCH projects to answer a question (including a self-generated question) , drawing on several sources and generating new avenues for inquiry ."},{"code":"C.8.6","subject":"English Language Arts","grade":"8","text":"Gather relevant information from multiple print and digital sources, using search terms effectively ; assess the credibility and accuracy of each source; and, in order to reflect, analyze or complete short research projects , QUOTE OR PARAPHRASE THE DATA AND CONCLUSIONS OF OTHERS , while avoiding plagiarism by providing in-text and bibliographic MLA or APA citation ."},{"code":"C.8.7","subject":"English Language Arts","grade":"8","text":"Compose routinely over extended time frames and shorter time frames for a variety of tasks, purposes and audiences ."},{"code":"L.8.1","subject":"English Language Arts","grade":"8","text":"In both written and oral expression : a. Identify VERBALS correctly based on their intended function . b. Demonstrate appropriate use of VERBS IN THE ACTIVE AND PASSIVE VOICE . c. Demonstrate appropriate use of VERBS IN THE INDICATIVE, IMPERATIVE, INTERROGATIVE, CONDITIONAL AND SUBJUNCTIVE MOOD , while recognizing and correcting inappropriate shifts ."},{"code":"L.8.2","subject":"English Language Arts","grade":"8","text":"When writing : a. Demonstrate appropriate use of PUNCTUATION TO INDICATE A PAUSE OR BREAK . b. Demonstrate appropriate use of an ELLIPSIS TO INDICATE AN OMISSION . c. Demonstrate appropriate use of strategies and resources (print and electronic) to identify and correct spelling errors ."},{"code":"L.8.3","subject":"English Language Arts","grade":"8","text":"Use knowledge of language and its conventions when writing, speaking, reading or listening . a. Use VERBS IN THE ACTIVE AND PASSIVE VOICE AND IN THE CONDITIONAL AND SUBJUNCTIVE MOOD to achieve particular effects (e.g., emphasizing the actor or the action, expressing uncertainty or describing a state contrary to fact) ."},{"code":"L.8.4","subject":"English Language Arts","grade":"8","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grade 8 reading and content, choosing flexibly from an array of strategies . a. Use context (e.g., the overall meaning of a sentence or paragraph; a word\u2019s position or function in a sentence) as a clue to the meaning of a word or phrase . b. Use GREEK AND LATIN AFFIXES AND ROOTS as clues to the meaning of a word . c. Consult print and digital reference materials to find the pronunciation and determine or clarify the precise meaning of key words and phrases . d. Acquire and use accurately grade-appropriate general academic and domain-specific words and phrases; gather vocabulary knowledge when considering a word or phrase important to comprehension or expression ."},{"code":"L.8.5","subject":"English Language Arts","grade":"8","text":"Demonstrate understanding of figurative language, word relationships and nuances in word meanings . a. Interpret figurative language , including but not limited to IRONY , in context . b. Use the relationship between particular words to better understand each of the words . c. Distinguish among the CONNOTATIONS of words with similar DENOTATIONS ."},{"code":"RI.8.1","subject":"English Language Arts","grade":"8","text":"CITE RELEVANT TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RI.8.10","subject":"English Language Arts","grade":"8","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT independently ."},{"code":"RI.8.2","subject":"English Language Arts","grade":"8","text":"Determine CENTRAL IDEAS of a text, and analyze how they are developed through relationships of key details, citing textual evidence, paraphrasing or summarizing ."},{"code":"RI.8.3","subject":"English Language Arts","grade":"8","text":"Analyze how an author uses COMPARISONS, ANALOGIES OR CATEGORIES to make connections among and distinctions between ideas over the course of a text ."},{"code":"RI.8.4","subject":"English Language Arts","grade":"8","text":"Determine the meaning of words and phrases as they are used in text, including figurative, connotative and technical meanings; analyze the impact of specific WORD CHOICES on meaning and TONE ."},{"code":"RI.8.5","subject":"English Language Arts","grade":"8","text":"Analyze in detail the STRUCTURE OF A SPECIFIC PARAGRAPH in a text, including the role of particular sentences in developing and refining a key concept ."},{"code":"RI.8.6","subject":"English Language Arts","grade":"8","text":"Determine an author\u2019s PERSPECTIVE and PURPOSE in a text, and analyze how the author acknowledges and responds to conflicting evidence or viewpoints ."},{"code":"RI.8.7","subject":"English Language Arts","grade":"8","text":"Evaluate the advantages and disadvantages of using PRINT AND NON-PRINT FORMATS for presenting particular topics or ideas ."},{"code":"RI.8.8","subject":"English Language Arts","grade":"8","text":"Identify and evaluate the ARGUMENT and specific CLAIMS in a text, assessing whether the reasoning is sound and the EVIDENCE is relevant and sufficient ; recognize when irrelevant evidence is introduced ."},{"code":"RI.8.9","subject":"English Language Arts","grade":"8","text":"Analyze TWO OR MORE TEXTS WITH CONFLICTING INFORMATION ON THE SAME TOPIC , and identify where the texts disagree in fact or interpretation ."},{"code":"RL.8.1","subject":"English Language Arts","grade":"8","text":"CITE RELEVANT TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RL.8.10","subject":"English Language Arts","grade":"8","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.8.2","subject":"English Language Arts","grade":"8","text":"Determine THEMES of a text, and analyze how they are developed through relationships of characters, setting and plot , citing textual evidence, paraphrasing or summarizing ."},{"code":"RL.8.3","subject":"English Language Arts","grade":"8","text":"Analyze how particular LINES OF DIALOGUE OR INCIDENTS IN A STORY OR DRAMA propel the action, reveal aspects of a character or provoke a decision ."},{"code":"RL.8.4","subject":"English Language Arts","grade":"8","text":"Determine the meaning of words and phrases as they are used in a text, including figurative and connotative meanings; analyze the impact of specific WORD CHOICES on meaning and TONE , including but not limited to ANALOGIES or ALLUSIONS to other texts."},{"code":"RL.8.5","subject":"English Language Arts","grade":"8","text":"Compare and contrast the structure of two or more texts and analyze how the differing STRUCTURE OF EACH TEXT contributes to its meaning and style ."},{"code":"RL.8.6","subject":"English Language Arts","grade":"8","text":"Analyze characters\u2019 and readers\u2019 PERSPECTIVES and how the differences create effects , including but not limited to SUSPENSE, HUMOR AND EMPATHY ."},{"code":"RL.8.7","subject":"English Language Arts","grade":"8","text":"Analyze the extent to which a FILMED/LIVE PRODUCTION OF A STORY OR DRAMA stays faithful to or departs from the text or script , evaluating choices made by the director or actors ."},{"code":"RL.8.8","subject":"English Language Arts","grade":"8","text":"Not applicable to literature"},{"code":"RL.8.9","subject":"English Language Arts","grade":"8","text":"Analyze how a MODERN WORK OF FICTION draws on THEMES, PATTERNS OF EVENTS OR CHARACTER TYPES from MYTHS, TRADITIONAL STORIES OR RELIGIOUS WORKS , including describing how the material is rendered new ."},{"code":"KY.8.EE.1","subject":"Mathematics","grade":"8","text":"Know and apply the properties of integer exponents to generate equivalent numerical expressions."},{"code":"KY.8.EE.2","subject":"Mathematics","grade":"8","text":"Use square root and cube root symbols to represent solutions to equations of the form x2 = p and x3 = p, where p is a positive rational number. Evaluate square roots of small perfect squares and cube roots of small perfect cubes. Know that perfect squares and perfect cubes are rational."},{"code":"KY.8.EE.3","subject":"Mathematics","grade":"8","text":"Use numbers expressed in the form of a single digit times an integer power of 10 (Scientific Notation) to estimate very large or very small quantities and express how many times larger or smaller one is than the other."},{"code":"KY.8.EE.4","subject":"Mathematics","grade":"8","text":"Perform operations with numbers expressed in scientific notation, including problems where both decimal and scientific notation are used. Use scientific notation and choose units of appropriate size for measurements of very large or very small quantities. Interpret scientific notation that has been generated by technology."},{"code":"KY.8.EE.5","subject":"Mathematics","grade":"8","text":"d. Students describe points (x, y) in terms of the labels of the x- and y-axes; students understand in a proportional relationship (0, 0) is a valid point and (1, r) represents the unit rate and the constant of proportionality for the relationship between the quantities."},{"code":"KY.8.EE.6","subject":"Mathematics","grade":"8","text":"Use similar triangles to explain why the slope, m, is the same between any two distinct points on a non-vertical line in the coordinate plane; know the equation y = mx for a line through the origin and the equation y = mx + b for a line intercepting the vertical axis at b."},{"code":"KY.8.EE.7","subject":"Mathematics","grade":"8","text":"Solve linear equations in one variable. a. Give examples of linear equations in one variable with one solution, infinitely many solutions, or no solutions. Show which of these possibilities is the case by successively transforming the given equation into simpler forms, until an equivalent equation of the form \ud835\udc65\ud835\udc65 = \ud835\udc4e\ud835\udc4e, \ud835\udc4e\ud835\udc4e = \ud835\udc4e\ud835\udc4e, or \ud835\udc4e\ud835\udc4e = b results (where a and b are different numbers). b. Solve linear equations with rational number coefficients, including equations whose solutions require expanding expressions using the distributive property and combining like terms."},{"code":"KY.8.EE.8","subject":"Mathematics","grade":"8","text":"Analyze and solve a system of two linear equations. a. Understand that solutions to a system of two linear equations in two variables correspond to points of intersection of their graphs, because points of intersection satisfy both equations simultaneously; understand that a system of two linear equations may have one solution, no solution, or infinitely many solutions. b. Solve systems of two linear equations in two variables algebraically by using substitution where at least one equation contains at least one variable whose coefficient is 1 and by inspection for simple cases c. Solve real-world and mathematical problems leading to two linear equations in two variables. a. Examples are both mathematical and real-life contexts. Emphasis is on determining what types of contexts lead to having no solutions or infinitely many solutions. Students use tables, graphs and equations to explain why a graphed system has infinitely many or no solutions. b. Elimination and/or matrices are not required for grade 8. Emphasis is on choosing a method. Students solve simple cases by inspection, for example, 3\ud835\udc65\ud835\udc65 + 2\ud835\udc66\ud835\udc66 = 5 and 3\ud835\udc65\ud835\udc65 + 2\ud835\udc66\ud835\udc66 = 6 have no solution because 3\ud835\udc65\ud835\udc65 + 2\ud835\udc66\ud835\udc66 cannot simultaneously be 5 and 6 and select from the other approaches, based on the numbers in the problem. Solving systems algebraically will be"},{"code":"KY.8.F.1","subject":"Mathematics","grade":"8","text":"Understand that a function is a rule that assigns to each input exactly one output. The graph of a function is the set of ordered pairs consisting of an input and the corresponding output."},{"code":"KY.8.F.2","subject":"Mathematics","grade":"8","text":"Compare properties of two functions each represented in a different way (algebraically, graphically, numerically in tables, or by verbal descriptions)."},{"code":"KY.8.F.3","subject":"Mathematics","grade":"8","text":"Understand properties of linear functions. a. Interpret the equation y = mx + b as defining a linear function, whose graph is a straight line. b. Identify and give examples of functions that are not linear."},{"code":"KY.8.F.4","subject":"Mathematics","grade":"8","text":"Construct a function to model a linear relationship between two quantities. a. Determine the rate of change and initial value of the function from a description of a relationship or from two (x, y) values, including reading these from a table or from a graph. b. Interpret the rate of change and initial value of a linear function in terms of the situation it models and in terms of its graph or a table of values."},{"code":"KY.8.F.5","subject":"Mathematics","grade":"8","text":"Use graphs to represent functions. a. Describe qualitatively the functional relationship between two quantities by analyzing a graph. b. Sketch a graph that exhibits the qualitative features of a function that has been described verbally."},{"code":"KY.8.G.1","subject":"Mathematics","grade":"8","text":"Verify experimentally the properties of rotations, reflections and translations: \u25cf Lines are congruent to lines. \u25cf Line segments are congruent to line segments of the same length. \u25cf Angles are congruent to angles of the same measure. \u25cf Parallel lines are congruent to parallel lines."},{"code":"KY.8.G.2","subject":"Mathematics","grade":"8","text":"Understand that a two-dimensional figure is congruent to another if the second can be obtained from the first by a sequence of rotations, reflections and translations. Given two congruent figures, describe a sequence that exhibits the congruence between them."},{"code":"KY.8.G.3","subject":"Mathematics","grade":"8","text":"Describe the effect of dilations, translations, rotations and reflections on two-dimensional figures using coordinates."},{"code":"KY.8.G.4","subject":"Mathematics","grade":"8","text":"Understand that a two-dimensional figure is similar to another if the second can be obtained from the first by a sequence of rotations, reflections, translations and dilations. Given two similar two- dimensional figures, describe a sequence that exhibits the similarity between them."},{"code":"KY.8.G.5","subject":"Mathematics","grade":"8","text":"Use informal arguments to establish facts about the angle sum and exterior angle of triangles, about the angles created when parallel lines are cut by a transversal and the angle-angle criterion for similarity of triangles."},{"code":"KY.8.G.6","subject":"Mathematics","grade":"8","text":"Explain a proof of the Pythagorean Theorem and its converse."},{"code":"KY.8.G.7","subject":"Mathematics","grade":"8","text":"Apply the Pythagorean Theorem to determine unknown side lengths in right triangles in real-world and mathematical problems in two and three dimensions."},{"code":"KY.8.G.8","subject":"Mathematics","grade":"8","text":"Apply the Pythagorean Theorem to find the distance between two points in a coordinate system."},{"code":"KY.8.G.9","subject":"Mathematics","grade":"8","text":"Apply the formulas for the volumes and surface areas of cones, cylinders and spheres and use them to solve real-world and mathematical problems."},{"code":"KY.8.NS.1","subject":"Mathematics","grade":"8","text":"Understand informally that every number has a decimal expansion; the rational numbers are those with decimal expansions that terminate in 0s or eventually repeat. Know that other numbers are called irrational."},{"code":"KY.8.NS.2","subject":"Mathematics","grade":"8","text":"Use rational approximations of irrational numbers to compare the size of irrational numbers, locate them approximately on a number line diagram and estimate the value of expressions."},{"code":"KY.8.SP.1","subject":"Mathematics","grade":"8","text":"Construct and interpret scatter plots for bivariate numerical data to investigate patterns of association between two quantities. Describe patterns such as clustering, outliers, positive or negative association, linear association and nonlinear association."},{"code":"KY.8.SP.2","subject":"Mathematics","grade":"8","text":"Know that lines are widely used to model relationships between two quantitative variables. For scatter plots that suggest a linear association, informally fit a line and informally assess the model fit by judging the closeness of the data points to the line."},{"code":"KY.8.SP.3","subject":"Mathematics","grade":"8","text":"Use the equation of a linear model to solve problems in the context of bivariate numerical data, interpreting the slope and intercept."},{"code":"8-ESS1-4","subject":"Science","grade":"8","text":"Construct a scientific explanation based on evidence from rock strata for how the geologic time scale is used to organize Earth\u2019s 4.6-billion-year-old history."},{"code":"8-ESS3-1","subject":"Science","grade":"8","text":"Construct a scientific explanation based on evidence for how the uneven distributions of Earth\u2019s mineral, energy, and groundwater resources are the result of past and current geoscience processes."},{"code":"8-ESS3-2","subject":"Science","grade":"8","text":"Analyze and interpret data to forecast future catastrophic events to inform the development of technologies to mitigate the effects of natural hazards."},{"code":"8-ESS3-3","subject":"Science","grade":"8","text":"Apply scientific principles to design a method for monitoring and minimizing a human impact on the environment.*"},{"code":"8-ESS3-4","subject":"Science","grade":"8","text":"Construct an argument supported by evidence for how increases in human population and per-capita consumption of natural resources impact Earth\u2019s systems."},{"code":"8-ESS3-5","subject":"Science","grade":"8","text":"Ask questions to clarify evidence of the factors that have caused the rise in global temperatures over the past century."},{"code":"8-LS1-4","subject":"Science","grade":"8","text":"Use argument based on empirical evidence and scientific reasoning to support an explanation for how characteristic animal behaviors and specialized plant structures affect the probability of successful reproduction of animals and plants respectively."},{"code":"8-LS1-5","subject":"Science","grade":"8","text":"Construct a scientific explanation based on evidence for how environmental and genetic factors influence the growth of organisms."},{"code":"8-LS2-4","subject":"Science","grade":"8","text":"Construct an argument supported by empirical evidence that changes to physical or biological components of an ecosystem affect populations."},{"code":"8-LS2-5","subject":"Science","grade":"8","text":"Evaluate competing design solutions for maintaining biodiversity and ecosystem services.*"},{"code":"8-LS3-1","subject":"Science","grade":"8","text":"Develop and use a model to describe why structural changes to genes (mutations) located on chromosomes may affect proteins and may result in harmful, beneficial, or neutral effects to the structure and function of the organism."},{"code":"8-LS3-2","subject":"Science","grade":"8","text":"Develop and use a model to describe why asexual reproduction results in offspring with identical genetic information and sexual reproduction results in offspring with genetic variation."},{"code":"8-LS4-1","subject":"Science","grade":"8","text":"Analyze and interpret data for patterns in the fossil record that document the existence, diversity, extinction, and change of life forms throughout the history of life on Earth under the assumption that natural laws operate today as in the past."},{"code":"8-LS4-2","subject":"Science","grade":"8","text":"Apply scientific ideas to construct an explanation for the anatomical similarities and differences among modern organisms and between modern and fossil organisms to infer evolutionary relationships."},{"code":"8-LS4-3","subject":"Science","grade":"8","text":"Analyze data to compare patterns in the embryological development across multiple species to identify relationships not evident in the fully formed adult anatomy."},{"code":"8-LS4-4","subject":"Science","grade":"8","text":"Construct an explanation based on evidence that describes how genetic variations of traits in a population increase some individuals\u2019 probability of surviving and reproducing in a specific environment."},{"code":"8-LS4-5","subject":"Science","grade":"8","text":"Gather and synthesize information about technologies that have changed the way humans influence the inheritance of desired traits in organisms."},{"code":"8-LS4-6","subject":"Science","grade":"8","text":"Use mathematical representations to support explanations of how natural selection may lead to increases and decreases of specific traits in populations over time."},{"code":"8-PS1-3","subject":"Science","grade":"8","text":"Gather and make sense of information to describe that synthetic materials come from natural resources and impact society."},{"code":"8.C.CP.1","subject":"Social Studies","grade":"8","text":"Analyze the origin and purposes of rule of law, popular sovereignty, federalism, separation of powers and checks and balances."},{"code":"8.C.CP.2","subject":"Social Studies","grade":"8","text":"Explain the origins, functions and structure of government, with reference to the Mayflower Compact, the Declaration of Independence, Articles of Confederation, the Federalist No. 1 (Alexander Hamilton), the Federalist Nos. 10 and 51 (James Madison), the Constitution of the United States, the first ten (10) amendments to the Constitution of the United States, also known as the Bill of Rights and other fundamental documents, and their impacts on citizens."},{"code":"8.C.CP.3","subject":"Social Studies","grade":"8","text":"Explain how a system of checks and balances is intended to prevent a concentration of power in one branch."},{"code":"8.C.CV.1","subject":"Social Studies","grade":"8","text":"Analyze the impact of the democratic principles of equality before the law, inalienable rights, consent of the governed and the right to alter or abolish the government in the United States from the Colonial Era to Reconstruction from 1600- 1877."},{"code":"8.C.KGO.1","subject":"Social Studies","grade":"8","text":"Examine the role of Kentucky and Kentuckians within national politics between 1792- 1877."},{"code":"8.C.PR.1","subject":"Social Studies","grade":"8","text":"Explain the relationship between federalism and local, state and national governments."},{"code":"8.C.PR.2","subject":"Social Studies","grade":"8","text":"Explain how the Constitution of the United States was interpreted and amended through the amendment process, legislative processes, judicial review, executive actions and Supreme Court Cases between 1789- 1877."},{"code":"8.C.RR.1","subject":"Social Studies","grade":"8","text":"Analyze the r ole of citizens in the U.S. political system, with attention to the definition of who is a citizen, expansion of that definition over time and changes in participation over time."},{"code":"8.C.RR.2","subject":"Social Studies","grade":"8","text":"Analyze expansion of and restriction on citizenship and voting rights on diverse groups in the United States from the Colonial Era to Reconstruction from 1600-1877."},{"code":"8.C.RR.3","subject":"Social Studies","grade":"8","text":"Analyze how groups in the United States have challenged Constitutional provisions, laws and court rulings denying them the rights of citizens."},{"code":"8.E.IC.1","subject":"Social Studies","grade":"8","text":"Evaluate eco nomic decisions based on scarcity, opportunity costs and incentives."},{"code":"8.E.IC.2","subject":"Social Studies","grade":"8","text":"Assess the impact of growth and expansion on the allocation of resources and economic incentives."},{"code":"8.E.KE.1","subject":"Social Studies","grade":"8","text":"Explain how regional trends and policies impacted Kentucky\u2019s economy prior to the Civil War."},{"code":"8.E.KE.2","subject":"Social Studies","grade":"8","text":"Explain how the availability of resources in Kentucky led people to make economic choices from the Colonial Era to Reconstruction from 1600-1877."},{"code":"8.E.MA.1","subject":"Social Studies","grade":"8","text":"Analyze differi ng perspectives regarding the role of government in the economy, including the role of money and banking."},{"code":"8.E.MA.2","subject":"Social Studies","grade":"8","text":"Assess how regions of the United States specialized based on supply and demand due to their geographic locations."},{"code":"8.E.MA.3","subject":"Social Studies","grade":"8","text":"Analyze the purpose of taxation and its impact on government spending."},{"code":"8.E.MA.4","subject":"Social Studies","grade":"8","text":"Analyze how property rights are defined, protected, enforced and limited by government."},{"code":"8.E.MI.1","subject":"Social Studies","grade":"8","text":"Describe the impact of supply and demand on equilibrium prices and quantities produced in the United States from the Colonial Era to Reconstruction from 1600-1877."},{"code":"8.E.MI.2","subject":"Social Studies","grade":"8","text":"Assess the ways factors of production are combined in innovative ways resulting in economic growth and increased standards of living."},{"code":"8.E.ST.1","subject":"Social Studies","grade":"8","text":"Analyze why economic interdependence existed between the regions of the United States between 1783-1877."},{"code":"8.G.GR.1","subject":"Social Studies","grade":"8","text":"Use maps and other geographic representations, geospatial technologies, and spatial thinking to analyze settlement patterns in the United States from the Colonial Era to Reconstruction from 1600-1877."},{"code":"8.G.HE.1","subject":"Social Studies","grade":"8","text":"Analyze how cultural and technological changes influenced how people interacted with their environments in the United States from the Colonial Era to Reconstruction from 1600- 1877."},{"code":"8.G.HI.1","subject":"Social Studies","grade":"8","text":"Explain how global interconnections impacted culture, land use and trade in the United States during Colonial Era through Reconstruction from 1600-1877."},{"code":"8.G.KGE.1","subject":"Social Studies","grade":"8","text":"Analyze Kentucky\u2019s role in the early nation through Reconstruction based on its physical geography and location."},{"code":"8.G.MM.1","subject":"Social Studies","grade":"8","text":"Interpret how political, environmental, social and economic factors led to both forced and voluntary migration in the United States from the Colonial Era to Reconstruction from 1600-1877."},{"code":"8.H.CE.1","subject":"Social Studies","grade":"8","text":"Analyze how the political, geographic, social and economic choices of the Colonial Era impacted the Revolutionary Period and Early Republic Period."},{"code":"8.H.CE.2","subject":"Social Studies","grade":"8","text":"Analyze the cause and effect of Westward Expansion, the Civil War and Reconstruction on the diverse populations of the United States."},{"code":"8.H.CH.1","subject":"Social Studies","grade":"8","text":"E xplain the role changing political, social and economic perspectives had on the lives of diverse groups of people in the Colonial Era."},{"code":"8.H.CH.2","subject":"Social Studies","grade":"8","text":"Analyze how social and ideological philosophies impacted various movements in the United States from the Colonial Era to Reconstruction from 1600-1877."},{"code":"8.H.CH.3","subject":"Social Studies","grade":"8","text":"Explain how political, social and economic perspectives in the United States led to the rise in sectionalism between 1840- 1860."},{"code":"8.H.CH.4","subject":"Social Studies","grade":"8","text":"Evaluate the impact technological innovations made on agriculture, trade and commerce in the years leading up to the Civil War between 1840-1860."},{"code":"8.H.CH.5","subject":"Social Studies","grade":"8","text":"Explain examples of political, geographic, social and economic changes and consistencies in the different regions of the United States between 1860-1877."},{"code":"8.H.CH.6","subject":"Social Studies","grade":"8","text":"Analyze the impact of fundamental documents and speeches on the development of the United States from 1600-1877 that shall include but are not limited to: \u2022 The Mayflower Compact; \u2022 The Declaration of Independence; \u2022 The Constitution of the United States; \u2022 The Federalist No. 1 (Alexander Hamilton); \u2022 The Federalist Nos. 10 and 51 (James Madison); \u2022 The June 8, 1789 speech on amendments to the Constitution of the United States by James Madison; \u2022 The first ten (10) amendments to the Constitution of the United States, also known as the Bill of Rights; \u2022 The 1796 Farewell Address by George Washington; \u2022 The United States Supreme Court opinion in Marbury v."},{"code":"8.H.CO.1","subject":"Social Studies","grade":"8","text":"Explain how colonial resistance to British control led to the Revolutionary War."},{"code":"8.H.CO.2","subject":"Social Studies","grade":"8","text":"Describe the conflicts and compromises that shaped the development of the U.S. government between 1783-1877."},{"code":"8.H.CO.3","subject":"Social Studies","grade":"8","text":"Analyze how economic, social, ideological and political changes led to sectional and national tensions, inspiring reform movements between 1840-1860."},{"code":"8.H.CO.4","subject":"Social Studies","grade":"8","text":"Explain how sectionalism and the institution of slavery within the United States led to conflicts between 1820- 1877."},{"code":"8.H.KH.1","subject":"Social Studies","grade":"8","text":"Articulate Ke ntucky\u2019s role in early American history from the earliest colonial settlement to 1877."},{"code":"8.H.KH.2","subject":"Social Studies","grade":"8","text":"Examine patterns of collaboration and conflict between immigrants to Kentucky and those already in residence from 1775 to 1877."},{"code":"8.I.CC.1","subject":"Social Studies","grade":"8","text":"Construct explanations, using reasoning, correct sequence, examples and details with relevant information and data, while acknowledging the strengths and weaknesses of the explanations related to the development of the United States."},{"code":"8.I.CC.2","subject":"Social Studies","grade":"8","text":"Construct arguments by drawing on multiple disciplinary lenses to analyze how multiple perspectives, diversity and conflict and compromise impacted the development of the United States."},{"code":"8.I.CC.3","subject":"Social Studies","grade":"8","text":"Evaluate how individuals and groups addressed local, regional and global problems concerning the development of the United States."},{"code":"8.I.CC.4","subject":"Social Studies","grade":"8","text":"Apply a range of deliberative and democratic procedures to make decisions about ways to take action on current local, regional and global issues."},{"code":"8.I.CC.5","subject":"Social Studies","grade":"8","text":"Evaluate a specific problem concerning the development of the United States using each of the social studies disciplines."},{"code":"8.I.Q.1","subject":"Social Studies","grade":"8","text":"Develop compelling questions related to the development of the United States between 1600\u20131877."},{"code":"8.I.Q.2","subject":"Social Studies","grade":"8","text":"Generate supporting questions, using the disciplines of social studies, to help answer compelling questions in U.S. history between 1600-1877."},{"code":"8.I.Q.3","subject":"Social Studies","grade":"8","text":"Evaluate the types of supporting questions each of the social studies disciplines uses to answer compelling and supporting questions."},{"code":"8.I.UE.1","subject":"Social Studies","grade":"8","text":"Use multiple sources to develop claims in response to compelling and supporting questions."},{"code":"8.I.UE.2","subject":"Social Studies","grade":"8","text":"Gather relevant information from multiple sources while using the origin, authority, structure, context and corroborative value of the sources to guide the selection to answer compelling and supporting questions."},{"code":"8.I.UE.3","subject":"Social Studies","grade":"8","text":"Gather relevant information from multiple sources while using the origin, authority, structure, context and corroborative value of the sources to guide the selection to answer compelling and supporting questions."},{"code":"C.9-10.1","subject":"English Language Arts","grade":"9","text":"Compose arguments to support claims in an analysis of substantive topics or texts, using valid reasoning and relevant and sufficient evidence. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce precise claim(s), distinguish the claim(s) from alternate or opposing claims and create an organization that establishes clear relationships among claim(s), counterclaims, reasons and evidence. c. Develop claim(s) and counterclaims fairly, supplying evidence for each while pointing out the strengths and limitations of both in a manner that anticipates the audience\u2019s knowledge level and concerns. d. Link the major sections of the text cohesively, and clarify the relationships among claim(s), counterclaims, reasons and evidence. e. Establish and maintain a task-appropriate writing style. f. Provide a concluding statement or section that follows and supports the argument presented. g. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience."},{"code":"C.9-10.1a","subject":"English Language Arts","grade":"9","text":"Composition, Grades 9-10, Standard 1, Substandard a Language L"},{"code":"C.9-10.2","subject":"English Language Arts","grade":"9","text":"Compose informative and/or explanatory texts to examine and convey complex ideas, concepts and information clearly and accurately through the effective selection, organization and analysis of content. a. Produce writing in which the development and organization are appropriate to task and purpose. b. Introduce a topic; organize complex ideas, concepts and information to make important connections and distinctions; include formatting, graphics and multimedia when useful to aiding comprehension. c. Develop the topic with well-chosen, relevant and sufficient facts, extended definitions, concrete details, quotations or other information and examples appropriate to the audience\u2019s knowledge of the topic. d. Use appropriate and varied transitions to link the major sections of the text, create cohesion and clarify the relationships among complex ideas and concepts. e. Use precise language and domain-specific vocabulary to manage the complexity of the topic. f. Establish and maintain a formal style and objective tone while attending to the norms and conventions of the discipline in which they are writing. g. Provide a concluding statement or section that follows from and supports the information or explanation presented. h. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience."},{"code":"C.9-10.3","subject":"English Language Arts","grade":"9","text":"Use narratives strategically in other modes of writing, utilizing effective technique, well-chosen details and well-structured sequences for an intended purpose, including but not limited to introducing an idea and/or supporting a claim. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task and purpose. b. Engage and orient the reader by setting out a problem, situation or observation, establishing one or multiple point(s) of view and introducing a narrator and/or characters; create a smooth progression of experiences or events. c. Use narrative techniques, such as dialogue, pacing, description, reflection and multiple plot lines, to develop experiences, events and/or characters. d. Use a variety of techniques to sequence events so that they build on one another to create a coherent whole. e. Use precise words and phrases, telling details f. sensory language to convey a vivid picture of the experiences, events, setting and/or characters. g. Provide a conclusion that explicitly connects the narrative\u2019s relevance to the intended purpose of the writing. h. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience. Production and Distribution"},{"code":"C.9-10.4","subject":"English Language Arts","grade":"9","text":"Use DIGITAL RESOURCES to create, publish and update individual or shared products , taking advantage of technology\u2019s capacity to link to other information and to display information flexibly and dynamically. Use a variety of formats to cite sources ."},{"code":"C.9-10.5","subject":"English Language Arts","grade":"9","text":"Conduct short as well as more sustained RESEARCH projects to answer a question (including a self-generated question) or solve a problem; narrow or broaden the inquiry when appropriate; synthesize multiple sources on the subject , demonstrating understanding of the subject under investigation ."},{"code":"C.9-10.6","subject":"English Language Arts","grade":"9","text":"Gather relevant information from multiple authoritative print and digital sources, using advanced searches effectively ; assess the usefulness of each source in answering the research question; integrate information into the text selectively to maintain the flow of ideas , avoiding plagiarism and following a standard format for citation ."},{"code":"C.9-10.7","subject":"English Language Arts","grade":"9","text":"Compose routinely over extended time frames and shorter time frames for a variety of tasks, purposes and audiences ."},{"code":"L.9-10.1","subject":"English Language Arts","grade":"9","text":"In both written and oral expression : a. Demonstrate appropriate use of PARALLEL STRUCTURE . b. Demonstrate task-appropriate use of PHRASES and CLAUSES to communicate purpose, develop structure and add variety ."},{"code":"L.9-10.2","subject":"English Language Arts","grade":"9","text":"When writing : a. Demonstrate appropriate use of a SEMICOLON WITH AND WITHOUT A CONJUNCTIVE ADVERB TO LINK TWO OR MORE CLOSELY RELATED INDEPENDENT CLAUSES . b. Demonstrate appropriate use of a COLON TO INTRODUCE A LIST OR QUOTATION . c. Demonstrate appropriate use of strategies and resources (print and electronic) to identify and correct spelling errors ."},{"code":"L.9-10.3","subject":"English Language Arts","grade":"9","text":"Apply knowledge of language to understand how language functions in different contexts, to make effective choices for meaning or style and to comprehend more fully when reading or listening . a. Write and edit work so that it conforms to the guidelines in a style manual appropriate for the discipline and writing type ."},{"code":"L.9-10.4","subject":"English Language Arts","grade":"9","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grades 9-10 reading and content, choosing flexibly from an array of strategies . a. Use context (e.g., the overall meaning of a sentence, paragraph or text; a word\u2019s position or function in a sentence) as a clue to the meaning of a word or phrase . b. Identify and correctly use patterns of word changes that indicate different meanings or parts of speech . c. Consult general and specialized reference materials to find the pronunciation of a word or determine or clarify its precise meaning or its part of speech . d. Acquire and use accurately general academic and domain-specific words and phrases, sufficient for reading, writing, speaking and listening in order to be postsecondary ready; demonstrate independence in gathering vocabulary knowledge when considering a word or phrase important to comprehension or expression ."},{"code":"L.9-10.5","subject":"English Language Arts","grade":"9","text":"Demonstrate understanding of figurative language, word relationships and nuances in word meanings . a. Interpret FIGURES OF SPEECH in context , including but not limited to EUPHEMISM and OXYMORON , and analyze their rhetorical function in the text. b. Analyze nuances in the meaning of words with similar denotations ."},{"code":"RI.9-10.1","subject":"English Language Arts","grade":"9","text":"CITE RELEVANT AND THOROUGH TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RI.9-10.10","subject":"English Language Arts","grade":"9","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT independently ."},{"code":"RI.9-10.2","subject":"English Language Arts","grade":"9","text":"Determine CENTRAL IDEAS of a text and analyze in detail their development over the course of the text , including how they emerge and are shaped and refined by specific details ."},{"code":"RI.9-10.3","subject":"English Language Arts","grade":"9","text":"Analyze how the author unfolds AN ANALYSIS OR SERIES OF IDEAS OR EVENTS over the course of a text, including the order in which the points are made , how they are introduced and developed and the connections that are drawn between them ."},{"code":"RI.9-10.4","subject":"English Language Arts","grade":"9","text":"Determine the meaning of words and phrases as they are used in a text, including figurative, connotative and technical meanings; analyze the cumulative impact of specific WORD CHOICES on meaning and TONE ."},{"code":"RI.9-10.5","subject":"English Language Arts","grade":"9","text":"Analyze in detail how an author\u2019s IDEAS OR CLAIMS are developed and refined by particular sentences, paragraphs or larger portions of a text ."},{"code":"RI.9-10.6","subject":"English Language Arts","grade":"9","text":"Determine an author\u2019s POINT OF VIEW, PERSPECTIVE and PURPOSE in a text, and analyze how an author uses RHETORIC to advance that point of view or purpose ."},{"code":"RI.9-10.7","subject":"English Language Arts","grade":"9","text":"Analyze various accounts of A SUBJECT PRESENTED IN DIFFERENT PRINT AND NON-PRINT FORMATS , determining which details are emphasized in each account ."},{"code":"RI.9-10.8","subject":"English Language Arts","grade":"9","text":"Evaluate the ARGUMENT , specific CLAIMS and EVIDENCE in a text, assessing the validity, reasoning, relevancy and sufficiency of the evidence ; identify false statements and FALLACIOUS REASONING ."},{"code":"RI.9-10.9","subject":"English Language Arts","grade":"9","text":"Analyze DOCUMENTS OF HISTORICAL AND LITERARY SIGNIFICANCE , including how they address related THEMES and concepts ."},{"code":"RL.9-10.1","subject":"English Language Arts","grade":"9","text":"CITE RELEVANT AND THOROUGH TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RL.9-10.10","subject":"English Language Arts","grade":"9","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.9-10.2","subject":"English Language Arts","grade":"9","text":"Determine a THEME OR CENTRAL IDEA of a text and analyze in detail its development over the course of the text , including how it emerges and is shaped and refined by specific details ."},{"code":"RL.9-10.3","subject":"English Language Arts","grade":"9","text":"Analyze how COMPLEX CHARACTERS develop over the course of a text , interact with other characters and advance the plot or develop themes ."},{"code":"RL.9-10.4","subject":"English Language Arts","grade":"9","text":"Determine the meaning of words and phrases as they are used in the text, including figurative and connotative meanings; analyze the cumulative impact of specific WORD CHOICES on meaning and TONE ."},{"code":"RL.9-10.5","subject":"English Language Arts","grade":"9","text":"Analyze how an author\u2019s choices concerning text STRUCTURE, ORDER OF DETAILS, SEQUENCE AND MANIPULATION OF TIME (E.G., FLASHBACK, PACING) create effects (e.g., emotional impact, character development) ."},{"code":"RL.9-10.6","subject":"English Language Arts","grade":"9","text":"Analyze how authors\u2019 PERSPECTIVES OR CULTURAL EXPERIENCES are reflected in works of world literature from various historical contexts ."},{"code":"RL.9-10.7","subject":"English Language Arts","grade":"9","text":"Analyze the impact of the REPRESENTATION OF A SUBJECT OR A KEY SCENE IN DIFFERENT PRINT AND NON-PRINT MEDIUMS and evaluate what is emphasized or omitted in each treatment ."},{"code":"RL.9-10.8","subject":"English Language Arts","grade":"9","text":"Not applicable to literature"},{"code":"RL.9-10.9","subject":"English Language Arts","grade":"9","text":"Analyze TWO OR MORE TEXTS from different time periods to evaluate the impact of authors\u2019 approaches to similar themes and topics ."},{"code":"KY.HS.A.1","subject":"Mathematics","grade":"9","text":"Interpret expressions that represent a quantity in terms of its context. \u2605 a. Interpret parts of an expression, such as terms, factors and coefficients. b. Interpret complicated expressions, given a context, by viewing one or more of their parts as a single entity."},{"code":"KY.HS.A.10","subject":"Mathematics","grade":"9","text":"Rewrite simple rational expressions in different forms."},{"code":"KY.HS.A.11","subject":"Mathematics","grade":"9","text":"Add, subtract, multiply and divide rational algebraic expressions."},{"code":"KY.HS.A.12","subject":"Mathematics","grade":"9","text":"Create equations and inequalities in one variable and use them to solve problems."},{"code":"KY.HS.A.13","subject":"Mathematics","grade":"9","text":"Create equations in two or more variables to represent relationships between quantities; graph equations on coordinate axes with labels and scales."},{"code":"KY.HS.A.14","subject":"Mathematics","grade":"9","text":"Create a system of equations or inequalities to represent constraints within a modeling context. Interpret the solution(s) to the corresponding system as viable or nonviable options within the context."},{"code":"KY.HS.A.15","subject":"Mathematics","grade":"9","text":"Rearrange formulas to solve a literal equation, highlighting a quantity of interest, using the same reasoning as in solving equations."},{"code":"KY.HS.A.16","subject":"Mathematics","grade":"9","text":"Understand each step in solving a simple equation as following from the equality of numbers asserted at the previous step, starting from the assumption that the original equation has a solution. Construct a viable argument to justify a solution method."},{"code":"KY.HS.A.17","subject":"Mathematics","grade":"9","text":"Solve and justify equations in one variable. Justify the solutions and give examples showing how extraneous solutions may arise. a. Solve rational equations written as proportions in one variable. b. Solve radical equations in one variable."},{"code":"KY.HS.A.18","subject":"Mathematics","grade":"9","text":"Solve linear equations and inequalities in one variable, including literal equations with coefficients represented by letters."},{"code":"KY.HS.A.19","subject":"Mathematics","grade":"9","text":"Solve quadratic equations in one variable. a. Solve quadratic equations by taking square roots, the quadratic formula and factoring, as appropriate to the initial form of the equation. Recognize when the quadratic formula gives complex solutions and write them as a \u00b1 bi for real numbers a and b. b. (+) Use the method of completing the square to transform any quadratic equation in x into an equation of the form (x \u2013 p)2 = q that has the same solutions. Derive the quadratic formula from this form. c. (+) Solve quadratic equations by completing the square."},{"code":"KY.HS.A.2","subject":"Mathematics","grade":"9","text":"Use the structure of an expression to identify ways to rewrite it and consistently look for opportunities to rewrite expressions in equivalent forms."},{"code":"KY.HS.A.20","subject":"Mathematics","grade":"9","text":"Solve systems of linear equations in two variables. a. Understand a system of two equations in two variables has the same solution as a new system formed by replacing one of the original equations with an equivalent equation. b. Solve systems of linear equations with graphs, substitution and elimination, focusing on pairs of linear equations in two variables."},{"code":"KY.HS.A.21","subject":"Mathematics","grade":"9","text":"Solve a simple system consisting of a linear equation and a quadratic equation in two variables algebraically and graphically."},{"code":"KY.HS.A.22","subject":"Mathematics","grade":"9","text":"Use matrices to solve a system of equations. a. Represent a system of linear equations as a single matrix equation in a vector variable. b. Find the inverse of a matrix if it exists. c. Use matrices to solve systems of linear equations (using technology for matrices of dimension 3 \u00d7 3 or greater)."},{"code":"KY.HS.A.23","subject":"Mathematics","grade":"9","text":"Understand that the graph of an equation in two variables is the set of all its solutions plotted in the coordinate plane."},{"code":"KY.HS.A.24","subject":"Mathematics","grade":"9","text":"Justify that the solutions of the equations f(x) = g(x) are the x-coordinates of the points where the graphs of y = f(x) and y = g(x) intersect. Find the approximate solutions graphically, using technology or tables. \u2605"},{"code":"KY.HS.A.25","subject":"Mathematics","grade":"9","text":"Graph linear inequalities in two variables. a. Graph the solutions to a linear inequality as a half-plane (excluding the boundary in the case of a strict inequality). b. Graph the solution set to a system of linear inequalities as the intersection of the corresponding half-planes."},{"code":"KY.HS.A.3","subject":"Mathematics","grade":"9","text":"Choose and produce an equivalent form of an expression to reveal and explain properties of the quantity represented by the expression. \u2605 a. Write the standard form of a given polynomial and identify the terms, coefficients, degree, leading coefficient and constant term. b. Factor a quadratic expression to reveal the zeros of the function it defines. c. Use the properties of exponents to rewrite exponential expressions. d. (+) Complete the square in a quadratic expression to reveal the maximum or minimum value of the function it defines."},{"code":"KY.HS.A.3b","subject":"Mathematics","grade":"9","text":"Students recognize the connection between the zero product property and solving a quadratic in one variable by setting factored expressions equal to zero."},{"code":"KY.HS.A.3d","subject":"Mathematics","grade":"9","text":"Students recognize being able to complete the square allows them to identify the coordinates of the maximum or minimum value more easily than when the quadratic is in standard form and there are pros and cons of each equivalent form."},{"code":"KY.HS.A.4","subject":"Mathematics","grade":"9","text":"Derive the formula for the sum of a finite geometric series (when the common ratio is not 1) and use the formula to solve problems. \u2605"},{"code":"KY.HS.A.5","subject":"Mathematics","grade":"9","text":"Add, subtract and multiply polynomials."},{"code":"KY.HS.A.6","subject":"Mathematics","grade":"9","text":"Know and apply the Remainder Theorem."},{"code":"KY.HS.A.7","subject":"Mathematics","grade":"9","text":"Identify roots of polynomials when suitable factorizations are available. Know these roots become the zeros (x-intercepts) for the corresponding polynomial function."},{"code":"KY.HS.A.8","subject":"Mathematics","grade":"9","text":"Prove polynomial identities and use them to describe numerical relationships."},{"code":"KY.HS.A.9","subject":"Mathematics","grade":"9","text":"Know and apply the Binomial Theorem for the expansion of (x + y )n in powers of x and y for a positive integer n, where x and y are any numbers, with coefficients determined for example by Pascal\u2019s Triangle."},{"code":"KY.HS.C.1","subject":"Mathematics","grade":"9","text":"Understand limits. a. Apply limits to a variety of functions, including piecewise functions. b. (++) Prove that the limit of a function exists, based upon the definition of a limit."},{"code":"KY.HS.C.10","subject":"Mathematics","grade":"9","text":"Communicate an understanding of continuity using precise mathematical symbols and language."},{"code":"KY.HS.C.11","subject":"Mathematics","grade":"9","text":"Define derivatives. a. Define the derivative of a function as the limit of the difference quotient. b. Understand this limit of the difference quotient can be interpreted as an instantaneous rate of change or the slope of a tangent line."},{"code":"KY.HS.C.12","subject":"Mathematics","grade":"9","text":"Use average rate of change to estimate the derivative from a table of values or a graph."},{"code":"KY.HS.C.13","subject":"Mathematics","grade":"9","text":"Understand the derivative as a function."},{"code":"KY.HS.C.15","subject":"Mathematics","grade":"9","text":"Explain why differentiability implies continuity yet continuity does not imply differentiability."},{"code":"KY.HS.C.16","subject":"Mathematics","grade":"9","text":"Understand and apply the Mean Value Theorem, including numerical, graphical and algebraic representations."},{"code":"KY.HS.C.17","subject":"Mathematics","grade":"9","text":"Understand the relationship between the concavity of a function and the sign of the second derivative."},{"code":"KY.HS.C.18","subject":"Mathematics","grade":"9","text":"Understand Rolle\u2019s Theorem as a special case of the Mean Value Theorem."},{"code":"KY.HS.C.19","subject":"Mathematics","grade":"9","text":"Efficiently find derivatives of functions with and without technology."},{"code":"KY.HS.C.2","subject":"Mathematics","grade":"9","text":"Demonstrate an understanding of limits by estimating and finding the limit of a function at a point graphically, numerically and algebraically."},{"code":"KY.HS.C.20","subject":"Mathematics","grade":"9","text":"Understand and use derivative rules for sums, differences, products and quotients of two functions and calculate the derivative of a composite function using the chain rule. MP2,"},{"code":"KY.HS.C.21","subject":"Mathematics","grade":"9","text":"Use implicit differentiation to find a derivative in an equation of two variables."},{"code":"KY.HS.C.22","subject":"Mathematics","grade":"9","text":"Use implicit differentiation to find the derivative of the inverse of a function."},{"code":"KY.HS.C.23","subject":"Mathematics","grade":"9","text":"Understand the relationship between the increasing and decreasing behavior of a function and the sign of the first derivative of the function."},{"code":"KY.HS.C.24","subject":"Mathematics","grade":"9","text":"Use the first derivative to analyze curves and identify relative extrema."},{"code":"KY.HS.C.25","subject":"Mathematics","grade":"9","text":"Understand the relationship of concavity to the second derivative."},{"code":"KY.HS.C.26","subject":"Mathematics","grade":"9","text":"Use the second derivative to find points of inflection."},{"code":"KY.HS.C.27","subject":"Mathematics","grade":"9","text":"Use the second derivative to analytically locate intervals on which a function is concave up, concave down or neither."},{"code":"KY.HS.C.28","subject":"Mathematics","grade":"9","text":"Describe how graphical characteristics of a given function, the first derivative of that function and the second derivative of that function interrelate."},{"code":"KY.HS.C.29","subject":"Mathematics","grade":"9","text":"Use derivatives to express rate of change in a variety of contexts."},{"code":"KY.HS.C.3","subject":"Mathematics","grade":"9","text":"Apply properties and theorems of limits, including limits of indeterminate forms."},{"code":"KY.HS.C.30","subject":"Mathematics","grade":"9","text":"Use derivatives to solve a variety of problems including related rates, optimization, tangent line approximations and growth and decay models."},{"code":"KY.HS.C.31","subject":"Mathematics","grade":"9","text":"Use differentiation to solve problems involving velocity, speed and acceleration."},{"code":"KY.HS.C.32","subject":"Mathematics","grade":"9","text":"Understand and apply differential equations. a. Verify solutions to differential equations and use them to model real-world problems with and without technology. b. Solve separable differential equations and use them in modeling real-world problems with and without technology."},{"code":"KY.HS.C.33","subject":"Mathematics","grade":"9","text":"Understand the definite integral of a function over an interval. Interpret a definite integral as a limit of Riemann Sums and as net accumulation of change."},{"code":"KY.HS.C.34","subject":"Mathematics","grade":"9","text":"Write a Riemann sum that represents the definition of a definite integral."},{"code":"KY.HS.C.35","subject":"Mathematics","grade":"9","text":"Calculate the values of Riemann Sums over equal subdivisions to approximate definite integrals of functions represented graphically and numerically (using tables). Use left-hand sums, right- hand sums, midpoint sums and trapezoidal sums."},{"code":"KY.HS.C.36","subject":"Mathematics","grade":"9","text":"Recognize differentiation and integration as inverse operations."},{"code":"KY.HS.C.37","subject":"Mathematics","grade":"9","text":"Understand how the Fundamental Theorem of Calculus connects differentiation and integration and use it to evaluate definite and indefinite integrals and to represent particular antiderivatives."},{"code":"KY.HS.C.38","subject":"Mathematics","grade":"9","text":"Perform analytical and graphical analysis of functions using the Fundamental Theorem of Calculus."},{"code":"KY.HS.C.39","subject":"Mathematics","grade":"9","text":"Understand and use the definite integral of a function over an interval and understand its use as a mathematical tool."},{"code":"KY.HS.C.4","subject":"Mathematics","grade":"9","text":"Communicate understanding of limits using precise mathematical symbols and language."},{"code":"KY.HS.C.40","subject":"Mathematics","grade":"9","text":"Find antiderivatives of a variety of basic functions including power, exponential, logarithmic and trigonometric and apply basic properties of definite integrals."},{"code":"KY.HS.C.41","subject":"Mathematics","grade":"9","text":"Use substitution techniques and change of limits of integration to find antiderivatives."},{"code":"KY.HS.C.42","subject":"Mathematics","grade":"9","text":"Find particular antiderivatives given initial conditions."},{"code":"KY.HS.C.43","subject":"Mathematics","grade":"9","text":"Model, solve and interpret applications of antiderivatives including finding area, velocity, acceleration and volume of a solid."},{"code":"KY.HS.C.44","subject":"Mathematics","grade":"9","text":"Apply integration to solve problems including particle motion and exponential growth and decay."},{"code":"KY.HS.C.45","subject":"Mathematics","grade":"9","text":"Describe the application of integration to a variety of problems using precise mathematical language and notation."},{"code":"KY.HS.C.5","subject":"Mathematics","grade":"9","text":"Describe asymptotic behavior (analytically and graphically) in terms of infinite limits and limits at infinity."},{"code":"KY.HS.C.6","subject":"Mathematics","grade":"9","text":"Discuss the end behavior of functions; identify representative functions for each type of end behavior using precise mathematical symbols and language."},{"code":"KY.HS.C.7","subject":"Mathematics","grade":"9","text":"Understand and use the limit definition of continuity to determine whether a given function is continuous at a specific point."},{"code":"KY.HS.C.8","subject":"Mathematics","grade":"9","text":"Define and identify different types of discontinuity \u2013 removable (hole) or non-removable (jump, asymptote) \u2013 in terms of limits."},{"code":"KY.HS.C.9","subject":"Mathematics","grade":"9","text":"Understand and apply continuous function theorems. a. Apply the Intermediate Value Theorem to continuous functions. b. Apply the Extreme Value Theorem to continuous functions."},{"code":"KY.HS.F.1","subject":"Mathematics","grade":"9","text":"Understand properties and key features of functions and the different ways functions can be represented. a. Understand that a function from one set (called the domain) to another set (called the range) assigns to each element of the domain exactly one element of the range. If f is a function and x is an element of its domain, then f(x) denotes the output of f corresponding to the input x. b. Using appropriate function notation, evaluate functions for inputs in their domains and interpret statements that use function notation in terms of a context. c. For a function that models a relationship between two quantities, interpret key features of graphs and tables in terms of the quantities and sketch graphs showing key features given a verbal description of the relationship. d. Relate the domain of a function to its graph and, where applicable, to the quantitative relationship it describes. e. Compare properties of two functions each represented in a different way (algebraically, graphically, numerically in tables, or by verbal descriptions)."},{"code":"KY.HS.F.10","subject":"Mathematics","grade":"9","text":"Understand the inverse relationship between exponents and logarithms and use this relationship to solve problems involving logarithms and exponents with the use of technology."},{"code":"KY.HS.F.11","subject":"Mathematics","grade":"9","text":"Distinguish between situations that can be modeled with linear functions and with exponential functions. a. Recognize and justify that linear functions grow by equal differences over equal intervals and that exponential functions grow by equal factors over equal intervals. b. Recognize situations in which one quantity changes at a constant rate per unit interval relative to another. c. Recognize situations in which a quantity grows or decays by a constant percent rate per unit interval relative to another."},{"code":"KY.HS.F.12","subject":"Mathematics","grade":"9","text":"Construct linear and exponential functions, including arithmetic and geometric sequences, given a graph, a description of a relationship, or two input-output pairs (include reading these from a table)."},{"code":"KY.HS.F.13","subject":"Mathematics","grade":"9","text":"Observe using graphs and tables that a quantity increasing exponentially eventually exceeds a quantity increasing linearly, quadratically, or (more generally) as a polynomial function."},{"code":"KY.HS.F.14","subject":"Mathematics","grade":"9","text":"Interpret the parameters in a linear or exponential function in terms of a context."},{"code":"KY.HS.F.15","subject":"Mathematics","grade":"9","text":"Understand the relationship of radian measure of an angle to its arc length."},{"code":"KY.HS.F.16","subject":"Mathematics","grade":"9","text":"Understand and use the unit circle. a. Explain how the unit circle in the coordinate plane enables the extension of trigonometric functions to all real numbers, interpreted as radian measures of angles traversed counterclockwise around the unit circle. b. Use special triangles to determine geometrically the values of sine, cosine, tangent for \u03c0/3, \u03c0 /4 and \u03c0 /6 and use the unit circle to express the values of sine, cosine and tangent for \u03c0 \u2013x, \u03c0 +x and 2 \u03c0 \u2013x in terms of their values for x, where x is any real number. c. Use the unit circle to explain symmetry (odd and even) and periodicity of trigonometric functions."},{"code":"KY.HS.F.17","subject":"Mathematics","grade":"9","text":"Choose trigonometric functions to model periodic phenomena with specified period, midline and amplitude. \u2605"},{"code":"KY.HS.F.18","subject":"Mathematics","grade":"9","text":"Understand that restricting a trigonometric function to a domain on which it is always increasing or always decreasing allows its inverse to be constructed."},{"code":"KY.HS.F.19","subject":"Mathematics","grade":"9","text":"Use inverse functions to solve trigonometric equations that arise in modeling contexts; evaluate the solutions using technology and interpret them in terms of the context. \u2605"},{"code":"KY.HS.F.2","subject":"Mathematics","grade":"9","text":"Recognize that arithmetic and geometric sequences are functions, sometimes defined recursively, whose domain is a subset of the integers."},{"code":"KY.HS.F.20","subject":"Mathematics","grade":"9","text":"Proving identities and formulas within the context of trigonometry. a. Prove the Pythagorean identity and use it to find sin(\u03b8), cos(\u03b8), or tan(\u03b8) given sin(\u03b8), cos(\u03b8), or tan(\u03b8) and the quadrant of the angle. b. Prove the addition and subtraction formulas for sine, cosine and tangent and use them to solve problems."},{"code":"KY.HS.F.3","subject":"Mathematics","grade":"9","text":"Understand average rate of change of a function over an interval. a. Calculate and interpret the average rate of change of a function (presented symbolically or as a table) over a specified interval. b. Estimate the rate of change from a graph. \u2605"},{"code":"KY.HS.F.4","subject":"Mathematics","grade":"9","text":"Graph functions expressed symbolically and show key features of the graph, with and without using technology (computer, graphing calculator). \u2605 a. Graph linear and quadratic functions and show intercepts, maxima and minima. b. Graph square root, cube root and absolute value functions. c. Graph polynomial functions, identifying zeros when suitable factorizations are available and showing end behavior. d. Graph exponential and logarithmic functions, showing intercepts and end behavior. e. (+) Graph trigonometric functions, showing period, midline and amplitude. f. (+) Graph piecewise functions, including step functions. g. (+) Graph rational functions, identifying zeros and asymptotes when suitable factorizations are available and showing end behavior."},{"code":"KY.HS.F.5","subject":"Mathematics","grade":"9","text":"Write a function defined by an expression in different but equivalent forms to reveal and explain different properties of the function. a. Identify zeros, extreme values and symmetry of the graph within the context of a quadratic function. a. Quadratic functions provide a rich playground for developing this ability, since the three principal forms for a quadratic expression (expanded, factored and completed square) each give insight into different aspects of the function. b. Students examine real-world situations with constant multiplicative change, represented as expressions, such as growth or decay."},{"code":"KY.HS.F.6","subject":"Mathematics","grade":"9","text":"Write a function that describes a relationship between two quantities. \u2605 a. Determine an explicit expression, a recursive process, or steps for calculation from a context. b. Combine standard function types using arithmetic operations. c. (+) Compose functions."},{"code":"KY.HS.F.7","subject":"Mathematics","grade":"9","text":"Use arithmetic and geometric sequences to model situations and scenarios. a. Use formulas (explicit and recursive) to generate terms for arithmetic and geometric sequences. b. Write formulas to model arithmetic and geometric sequences and apply those formulas in realistic situations. \u2605 c. (+) Translate between recursive and explicit formulas."},{"code":"KY.HS.F.8","subject":"Mathematics","grade":"9","text":"Understand the effects of transformations on the graph of a function. a. Identify the effect on the graph of replacing f(x) by f(x) + k, k f(x), f(kx) and f(x + k) for specific values of k (both positive and negative); find the value of k given the graphs. b. Experiment with cases and illustrate an explanation of the effects on the graph using technology."},{"code":"KY.HS.F.9","subject":"Mathematics","grade":"9","text":"Find inverse functions. a. Given the equation of an invertible function, find the inverse. b. (+) Verify by composition that one function is the inverse of another. c. (+) Read values of an inverse function from a graph or a table, given that the function has an inverse. d. (+) Produce an invertible function from a non-invertible function by restricting the domain."},{"code":"KY.HS.G.1","subject":"Mathematics","grade":"9","text":"Know and apply precise definitions of the language of Geometry: a. Understand properties of line segments, angles and circle. b. Understand properties of and differences between perpendicular and parallel lines."},{"code":"KY.HS.G.10","subject":"Mathematics","grade":"9","text":"Apply the properties of similarity transformations to establish the AA criterion for two triangles to be similar."},{"code":"KY.HS.G.11","subject":"Mathematics","grade":"9","text":"Understand theorems about triangles. a. Apply theorems about triangles. b. (+) Prove theorems about triangles. c. Use similarity criteria for triangles to solve problems and to prove relationships in geometric figures."},{"code":"KY.HS.G.12","subject":"Mathematics","grade":"9","text":"Understand properties of right triangles. a. Understand that by similarity, side ratios in right triangles are properties of the angles in the triangle, leading to definitions of trigonometric ratios for acute angles (sine, cosine and tangent). b. Explain and use the relationship between the sine and cosine of complementary angles. c. Use trigonometric ratios and the Pythagorean Theorem to solve right triangles in applied problems. \u2605"},{"code":"KY.HS.G.12c","subject":"Mathematics","grade":"9","text":"Use coordinates to justify and prove simple geometric theorems algebraically. Use similarity criteria for triangles to solve problems in geometric figures. Use trigonometric ratios and the Pythagorean Theorem to solve right triangles in applied problems.\u2605"},{"code":"KY.HS.G.13","subject":"Mathematics","grade":"9","text":"Derive the formula A = 1/2 ab sin(C) for the area of a triangle by drawing an auxiliary line from a vertex perpendicular to the opposite side."},{"code":"KY.HS.G.14","subject":"Mathematics","grade":"9","text":"Understand and apply the Law of Sines and the Law of Cosines. a. Use the Law of Sines and Cosines to find unknown measurements in right and non-right triangles. b. Prove the Laws of Sines and Cosines and use them to solve problems."},{"code":"KY.HS.G.15","subject":"Mathematics","grade":"9","text":"Verify using dilations that all circles are similar."},{"code":"KY.HS.G.16","subject":"Mathematics","grade":"9","text":"Identify and describe relationships among angles and segments within the context of circles involving: a. Recognize differences between and properties of inscribed, central and circumscribed angles. b. Understand relationships between inscribed angles and the diameter of a circle. c. Understand the relationship between the radius of a circle and the line drawn through the point of tangency on that radius."},{"code":"KY.HS.G.17","subject":"Mathematics","grade":"9","text":"Apply basic construction procedures within the context of a circle. a. Construct the inscribed and circumscribed circles of a triangle. b. Construct a tangent line from a point outside a given circle to the circle."},{"code":"KY.HS.G.18","subject":"Mathematics","grade":"9","text":"Understand the relationship between an intercepted arc length within a circle and the radius of the circle. a. Derive using similarity the fact that the length of the arc intercepted by an angle is proportional to the radius. Derive the formula for the area of a sector. b. Define the radian measure of the angle as the measure of a central angle that intercepts an arc equal in length to the radius of the circle."},{"code":"KY.HS.G.19","subject":"Mathematics","grade":"9","text":"Understand the relationship between the algebraic form and the geometric representation of a circle. a. Write the equation of a circle of given center and radius using the Pythagorean Theorem. b. (+) Derive and write the equation of a circle of given center and radius using the Pythagorean Theorem. c. (+) Complete the square to find the center and radius of a circle given by an equation."},{"code":"KY.HS.G.2","subject":"Mathematics","grade":"9","text":"Representing transformations in the plane. a. Describe transformations as functions that take points in the plane as inputs and give other points as outputs b. Compare transformations that preserve distance and angle measures to those that do not. c. Given a rectangle, parallelogram, trapezoid, or regular polygon, formally describe the rotations and reflections that carry it onto itself, using properties of these figures."},{"code":"KY.HS.G.20","subject":"Mathematics","grade":"9","text":"Derive the equations of conic sections. a. Derive the equation of a parabola given a focus and directrix. b. Derive the equations of ellipses and hyperbolas given the foci, using the fact that the sum or difference of distances from the foci is constant."},{"code":"KY.HS.G.21","subject":"Mathematics","grade":"9","text":"Use coordinates to justify and prove simple geometric theorems algebraically."},{"code":"KY.HS.G.22","subject":"Mathematics","grade":"9","text":"Justify and apply the slope criteria for parallel and perpendicular lines and use them to solve geometric problems."},{"code":"KY.HS.G.23","subject":"Mathematics","grade":"9","text":"Find measurements among points within the coordinate plane. a. Use points from the coordinate plane to find the coordinates of a midpoint of a line segment and the distance between the endpoints of a line segment. b. Find the point on a directed line segment between two given points that partitions the segment in a given ratio."},{"code":"KY.HS.G.24","subject":"Mathematics","grade":"9","text":"Use coordinates within the coordinate plane to calculate measurements of two dimensional figures. a. Compute the perimeters of various polygons. b. Compute the areas of triangles, rectangles and other quadrilaterals.\u2605"},{"code":"KY.HS.G.25","subject":"Mathematics","grade":"9","text":"Analyze and determine the validity of arguments for the formulas for the various figures and shapes. a. Finding the circumference and area of a circle. b. Finding the volume of a sphere, prism, cylinder, pyramid and cone."},{"code":"KY.HS.G.26","subject":"Mathematics","grade":"9","text":"Give an informal argument using Cavalieri\u2019s principle for the formulas for the volume of a sphere and other solid figures."},{"code":"KY.HS.G.27","subject":"Mathematics","grade":"9","text":"Use volume formulas to solve problems for cylinders, pyramids, cones, spheres, prisms \u2605"},{"code":"KY.HS.G.28","subject":"Mathematics","grade":"9","text":"Identify the shapes of two-dimensional cross-sections of three-dimensional objects and identify three-dimensional objects generated by rotations of two-dimensional objects."},{"code":"KY.HS.G.29","subject":"Mathematics","grade":"9","text":"Use geometric shapes, their measures and their properties to describe objects in real world settings."},{"code":"KY.HS.G.3","subject":"Mathematics","grade":"9","text":"Develop formal definitions of rotations, reflections and translations in terms of angles, circles, perpendicular lines, parallel lines and line segments."},{"code":"KY.HS.G.30","subject":"Mathematics","grade":"9","text":"Apply concepts of density based on area and volume in modeling situations, using appropriate units of measurement."},{"code":"KY.HS.G.31","subject":"Mathematics","grade":"9","text":"Apply geometric methods to solve design problems. \u2605"},{"code":"KY.HS.G.4","subject":"Mathematics","grade":"9","text":"Understand the effects of transformations of geometric figures. a. Given a geometric figure and a rotation, reflection, or translation, draw the transformed figure. b. Specify a sequence of transformations that will carry a given figure onto another. c. Use geometric descriptions of rigid motions to transform figures and to predict the effect of a given rigid motion on a given figure. Given two figures, use the definition of congruence in terms of rigid motions to decide if they are congruent."},{"code":"KY.HS.G.5","subject":"Mathematics","grade":"9","text":"Know and apply the concepts of triangle congruence: a. Use the definition of congruence in terms of rigid motions to show that two triangles are congruent if and only if corresponding pairs of sides and corresponding pairs of angles are congruent. b. Explain how the criteria for triangle congruence (ASA, SAS and SSS) follow from the definition of congruence in terms of rigid motions."},{"code":"KY.HS.G.6","subject":"Mathematics","grade":"9","text":"Apply theorems for lines, angles, triangles, parallelograms."},{"code":"KY.HS.G.7","subject":"Mathematics","grade":"9","text":"Prove theorems about geometric figures. a. Construct formal proofs to justify theorems for lines, angles and triangles. b. (+) Construct formal proofs to justify theorems for parallelograms."},{"code":"KY.HS.G.8","subject":"Mathematics","grade":"9","text":"Create and apply geometric constructions. a. Make formal geometric constructions with a variety of tools and methods. b. Apply basic construction procedures to construct more complex figures."},{"code":"KY.HS.G.9","subject":"Mathematics","grade":"9","text":"Understand properties of dilations. a. Verify the properties that result from that dilations given by a center and a scale factor. b. Verify that a dilation produces an image that is similar to the pre-image."},{"code":"KY.HS.N.1","subject":"Mathematics","grade":"9","text":"by extending student understanding to situations where the numerator is not one. For example, students understand that defining 4m/n is the same as \u221a4 \ud835\udc5b\ud835\udc5b m and ( \u221a4 \ud835\udc5b\ud835\udc5b )m. Include contextual examples, such as rewriting the volume of a sphere to identify the radius as a function of volume."},{"code":"KY.HS.N.10","subject":"Mathematics","grade":"9","text":"Extend polynomial identities to the complex numbers."},{"code":"KY.HS.N.11","subject":"Mathematics","grade":"9","text":"Know the Fundamental Theorem of Algebra; show that it is true for quadratic polynomials."},{"code":"KY.HS.N.12","subject":"Mathematics","grade":"9","text":"Understand and apply properties of vectors. a. Recognize vector quantities as having both magnitude and direction. Represent vector quantities by directed line segments and use appropriate symbols for vectors and their magnitudes. b. Find the components of a vector by subtracting the coordinates of an initial point from the coordinates of a terminal point. c. Solve problems involving velocity and other quantities that can be represented by vectors."},{"code":"KY.HS.N.13","subject":"Mathematics","grade":"9","text":"Perform operations with vectors (addition, subtraction and multiplication by a scalar). a. Add vectors end-to-end, component-wise and by the parallelogram rule. Understand that the magnitude of a sum of two vectors is typically not the sum of the magnitudes. b. Given two vectors in magnitude and direction form, determine the magnitude and direction of their sum. c. Understand vector subtraction v \u2013 w as v + (\u2013w), where \u2013w is the additive inverse of w, with the same magnitude as w and pointing in the opposite direction. Represent vector subtraction graphically by connecting the tips in the appropriate order and perform vector subtraction component-wise. d. Represent scalar multiplication graphically by scaling vectors and possibly reversing their direction; perform scalar multiplication component-wise. e. b. Compute the magnitude of a scalar multiple cv using ||cv|| = |c|v. Compute the direction of cv knowing that when |c|v \u2260 0, the direction of cv is either along v (for c > 0) or against v (for c < 0)."},{"code":"KY.HS.N.14","subject":"Mathematics","grade":"9","text":"Use matrices to represent and manipulate data."},{"code":"KY.HS.N.15","subject":"Mathematics","grade":"9","text":"Perform operations with matrices. a. Add, subtract and multiply matrices of appropriate dimensions. b. Multiply matrices by scalars to produce new matrices."},{"code":"KY.HS.N.16","subject":"Mathematics","grade":"9","text":"Understand properties of square and identity matrices. a. Understand that, unlike multiplication of numbers, matrix multiplication for square matrices is not a commutative operation, but still satisfies the associative and distributive properties. b. Understand that the zero and identity matrices play a role in matrix addition and multiplication similar to the role of 0 and 1 in the real numbers. The determinant of a square matrix is nonzero if and only if the matrix has a multiplicative inverse. c. Work with 2 \u00d7 2 matrices as transformations of the plane and interpret the absolute value of the determinant in terms of area."},{"code":"KY.HS.N.17","subject":"Mathematics","grade":"9","text":"Multiply a vector (regarded as a matrix with one column) by a matrix of suitable dimensions to produce another vector. Work with matrices as transformations of vectors."},{"code":"KY.HS.N.2","subject":"Mathematics","grade":"9","text":"Rewrite expressions involving radicals and rational exponents using the properties of exponents."},{"code":"KY.HS.N.3","subject":"Mathematics","grade":"9","text":"Justify why the sum or product of two rational numbers is rational; that the sum of a rational number and an irrational number is irrational; and that the product of a nonzero rational number and an irrational number is irrational."},{"code":"KY.HS.N.4","subject":"Mathematics","grade":"9","text":"Use units in context as a way to understand problems and to guide the solution of multi-step problems; \u2605 a. Choose and interpret units consistently in formulas; b. Choose and interpret the scale and the origin in graphs and data displays."},{"code":"KY.HS.N.5","subject":"Mathematics","grade":"9","text":"Define appropriate units in context for the purpose of descriptive modeling. \u2605"},{"code":"KY.HS.N.6","subject":"Mathematics","grade":"9","text":"does not require a formal discussion or use of significant digits in the scientific sense, students understand a level of precision. For example, when using the Pythagorean Theorem with measurements given in tenths of an inch, it is appropriate for students to express answers to the nearest tenth, but not to the nearest hundredth because that level of precision was not used in the original measures."},{"code":"KY.HS.N.7","subject":"Mathematics","grade":"9","text":"Understanding properties of complex numbers. a. Know there is a complex number i such that i2 = \u20131 and every complex number has the form a + bi with a and b real. b. Use the relation i2 = \u20131 and the commutative, associative and distributive properties to add, subtract and multiply complex numbers. c. (+) Find the conjugate of a complex number and use it to find the quotient of complex numbers."},{"code":"KY.HS.N.8","subject":"Mathematics","grade":"9","text":"Understanding representations of complex numbers using the complex plane. a. Represent complex numbers on the complex plane in rectangular and polar form (including real and imaginary numbers) and explain why the rectangular and polar forms of a given complex number represent the same number. b. Represent addition, subtraction, multiplication, modulus and conjugation of complex numbers geometrically on the complex plane; use properties of this representation for computation. c. Calculate the distance between numbers in the complex plane as the modulus of the difference and the midpoint of a segment as the average of the numbers at its endpoints."},{"code":"KY.HS.N.9","subject":"Mathematics","grade":"9","text":"Solve quadratic equations with real coefficients that have complex solutions."},{"code":"KY.HS.SP.1","subject":"Mathematics","grade":"9","text":"Represent the distribution of data with plots on the real number line (stem plots, dot plots, histograms and box plots)."},{"code":"KY.HS.SP.10","subject":"Mathematics","grade":"9","text":"Decide if a specified model is consistent with the results from a simulation."},{"code":"KY.HS.SP.11","subject":"Mathematics","grade":"9","text":"Recognize the purposes of and differences among sample surveys, experiments and observational studies; explain how randomization relates to each."},{"code":"KY.HS.SP.12","subject":"Mathematics","grade":"9","text":"Use data from a sample survey to estimate a population mean or proportion and explain how bias may be involved in the process."},{"code":"KY.HS.SP.13","subject":"Mathematics","grade":"9","text":"Use data from a randomized experiment to compare two treatments; use simulations to decide if differences between estimates or statistics are significant."},{"code":"KY.HS.SP.14","subject":"Mathematics","grade":"9","text":"Describe events as subsets of a sample space. Use characteristics (or categories) of the outcomes, such as, \u2022 as unions, \u201cA or B,\u201d that are mutually exclusive events and \u2022 as unions, \u201cA or B,\u201d that are non-mutually exclusive events and \u2022 as intersections, \u201cA and B,\u201d and \u2022 as complements of other events, \u201cnot A.\u201d to calculate basic probabilities."},{"code":"KY.HS.SP.15","subject":"Mathematics","grade":"9","text":"Understand the concept of independence. a. Understand that two events A and B are independent if the probability of A and B occurring together is the product of their individual probabilities, P(A) x P(B) b. (+) Determine whether two events are independent and provide a justification to support the decision. c. Recognize and explain the concept of independence in everyday language and everyday situations."},{"code":"KY.HS.SP.16","subject":"Mathematics","grade":"9","text":"Understand the concept of conditional probability. a. Understand the conditional probability of A given B as P(A and B)/P(B). b. (+) Interpret independence of A and B as saying that the conditional probability of A given B is the same as the probability of A and the conditional probability of B given A is the same as the probability of B. a. For any two events A and B, P(A given B) = \ud835\udc43\ud835\udc43(\ud835\udc34\ud835\udc34 \ud835\udc4e\ud835\udc4e\ud835\udc5b\ud835\udc5b\ud835\udc51\ud835\udc51 \ud835\udc35\ud835\udc35) \ud835\udc43\ud835\udc43(\ud835\udc35\ud835\udc35)."},{"code":"KY.HS.SP.17","subject":"Mathematics","grade":"9","text":"Construct and interpret two-way frequency tables of data when two categories are associated with each object being classified. Use the two-way table as a sample space to decide whether events are independent and to approximate conditional probabilities."},{"code":"KY.HS.SP.18","subject":"Mathematics","grade":"9","text":"Apply the General Multiplication Rule, P(A and B) = P(A)P(B|A) = P(B)P(A|B), in a uniform probability model and interpret the answer in terms of the model."},{"code":"KY.HS.SP.19","subject":"Mathematics","grade":"9","text":"Use permutations and combinations to compute probabilities. a. Distinguish between situations that can be modeled using counting techniques, including Fundamental Counting Principle, permutations and combinations. b. Perform calculations using the appropriate counting technique, including simple probabilities. c. (+) Use permutations and combinations to compute probabilities of compound events and solve problems."},{"code":"KY.HS.SP.2","subject":"Mathematics","grade":"9","text":"Use statistics appropriate to the shape of the numerical data distribution to compare center (median, mean) and spread (interquartile range when comparing medians and standard deviation when comparing means) of different data distributions."},{"code":"KY.HS.SP.20","subject":"Mathematics","grade":"9","text":"Define a random variable for a quantity of interest by assigning a numerical value to each event in a sample space; graph the corresponding probability distribution using the same appropriate graphical displays as for data distributions."},{"code":"KY.HS.SP.21","subject":"Mathematics","grade":"9","text":"Calculate the expected value of a random variable; interpret it as the mean of the probability distribution and use the value in analyzing decisions."},{"code":"KY.HS.SP.22","subject":"Mathematics","grade":"9","text":"Develop a probability distribution for a random variable. a. Find an expected value based on a sample space in which theoretical probabilities can be calculated. b. Find an expected value based on a sample space in which empirical probabilities can be calculated."},{"code":"KY.HS.SP.23","subject":"Mathematics","grade":"9","text":"Weigh the possible outcomes of a decision by assigning probabilities to payoff values and finding expected values. a. Find the expected payoff for a game of chance. b. Evaluate and compare strategies on the basis of expected values. c. Use calculated expected values to make fair decisions and formulate strategies."},{"code":"KY.HS.SP.3","subject":"Mathematics","grade":"9","text":"Interpret differences in shape, center and spread in the context of the distributions of the numerical data, accounting for the presence and possible effects of extreme data points (outliers)."},{"code":"KY.HS.SP.4","subject":"Mathematics","grade":"9","text":"When appropriate, fit a normal distribution to a numerical data set for given mean and standard deviation and then estimate population percentages using the Empirical Rule and recognize that there are data sets for which such a procedure is not appropriate."},{"code":"KY.HS.SP.5","subject":"Mathematics","grade":"9","text":"Summarize categorical data for two or more categories in frequency tables. Calculate and interpret joint, marginal and conditional relative frequencies (probabilities) in the context of the data, recognizing possible associations and trends in the data."},{"code":"KY.HS.SP.6","subject":"Mathematics","grade":"9","text":"Represent data on two quantitative variables on a scatter plot and describe how the explanatory and response variables are related. a. Calculate an appropriate mathematical model, or use a given mathematical model, for data to solve problems in context. b. Informally assess the fit of a model (through calculating correlation for linear data, plotting, calculating and/or analyzing residuals)."},{"code":"KY.HS.SP.7","subject":"Mathematics","grade":"9","text":"Interpret the slope (rate of change) and the intercept (constant term) of a linear model in the context of the data."},{"code":"KY.HS.SP.8","subject":"Mathematics","grade":"9","text":"Understand the role and purpose of correlation in linear regression. a. Use technology to compute correlation coefficient of a linear fit. b. Interpret the meaning of the correlation within the context of the data. c. Describe the limitations of correlation when establishing causation."},{"code":"KY.HS.SP.9","subject":"Mathematics","grade":"9","text":"in that results from non-random samples (Voluntary Response and Convenience) generate biased results when compared with more appropriate, random samples of the same population."},{"code":"HS-ESS1-1","subject":"Science","grade":"9","text":"Develop a model based on evidence to illustrate the life span of the sun and the role of nuclear fusion in the sun\u2019s core to release energy that eventually reaches Earth in the form of radiation."},{"code":"HS-ESS1-2","subject":"Science","grade":"9","text":"Construct an explanation of the Big Bang theory based on astronomical evidence of light spectra, motion of distant galaxies, and composition of matter in the universe."},{"code":"HS-ESS1-3","subject":"Science","grade":"9","text":"Communicate scientific ideas about the way stars, over their life cycle, produce elements."},{"code":"HS-ESS1-4","subject":"Science","grade":"9","text":"Use mathematical or computational representations to predict the motion of orbiting objects in the solar system."},{"code":"HS-ESS1-5","subject":"Science","grade":"9","text":"Evaluate evidence of the past and current movements of continental and oceanic crust and the theory of plate tectonics to explain the ages of crustal rocks."},{"code":"HS-ESS1-6","subject":"Science","grade":"9","text":"Apply scientific reasoning and evidence from ancient Earth materials, meteorites, and other planetary surfaces to construct an account of Earth\u2019s formation and early history."},{"code":"HS-ESS2-1","subject":"Science","grade":"9","text":"Develop a model to illustrate how Earth\u2019s internal and surface processes operate at different spatial and temporal scales to form continental and ocean-floor features."},{"code":"HS-ESS2-2","subject":"Science","grade":"9","text":"Analyze geoscience data to make the claim that one change to Earth\u2019s surface can create feedbacks that cause changes to other Earth systems."},{"code":"HS-ESS2-3","subject":"Science","grade":"9","text":"Develop a model based on evidence of Earth\u2019s interior to describe the cycling of matter by thermal convection."},{"code":"HS-ESS2-4","subject":"Science","grade":"9","text":"Use a model to describe how variations in the flow of energy into and out of Earth\u2019s systems result in changes in climate."},{"code":"HS-ESS2-5","subject":"Science","grade":"9","text":"Plan and conduct an investigation of the properties of water and its effects on Earth materials and surface processes."},{"code":"HS-ESS2-6","subject":"Science","grade":"9","text":"Develop a quantitative model to describe the cycling of carbon among the hydrosphere, atmosphere, geosphere, and biosphere."},{"code":"HS-ESS2-7","subject":"Science","grade":"9","text":"Construct an argument based on evidence about the simultaneous coevolution of Earth\u2019s systems and life on Earth."},{"code":"HS-ESS3-1","subject":"Science","grade":"9","text":"Construct an explanation based on evidence for how the availability of natural resources, occurrence of natural hazards, and changes in climate have influenced human activity."},{"code":"HS-ESS3-2","subject":"Science","grade":"9","text":"Evaluate competing design solutions for developing, managing, and utilizing energy and mineral resources based on cost- benefit ratios.*"},{"code":"HS-ESS3-3","subject":"Science","grade":"9","text":"Create a computational simulation to illustrate the relationships among the management of natural resources, the sustainability of human populations, and biodiversity."},{"code":"HS-ESS3-4","subject":"Science","grade":"9","text":"Evaluate or refine a technological solution that reduces impacts of human activities on natural systems.*"},{"code":"HS-ESS3-5","subject":"Science","grade":"9","text":"Analyze geoscience data and the results from global climate models to make an evidence-based forecast of the current rate of global or regional climate change and associated future impacts to Earth\u2019s systems."},{"code":"HS-ESS3-6","subject":"Science","grade":"9","text":"Use a computational representation to illustrate the relationships among Earth systems and how those relationships are being modified due to human activity."},{"code":"HS-ETS1-1","subject":"Science","grade":"9","text":"Analyze a major global challenge to specify qualitative and quantitative criteria and constraints for solutions that account for societal needs and wants. *"},{"code":"HS-ETS1-2","subject":"Science","grade":"9","text":"Design a solution to a complex real- world problem by breaking it down into smaller, more manageable problems that can be solved through engineering. *"},{"code":"HS-ETS1-3","subject":"Science","grade":"9","text":"Evaluate a solution to a complex real- world problem based on prioritized criteria and trade-offs that account for a range of constraints, including cost, safety, reliability, and aesthetics, as well as possible social, cultural, and environmental impacts. *"},{"code":"HS-ETS1-4","subject":"Science","grade":"9","text":"Use a computer simulation to model the impact of proposed solutions to a complex real- world problem with numerous criteria and constraints on interactions within and between systems relevant to the problem. *"},{"code":"HS-LS1-1","subject":"Science","grade":"9","text":"Construct an explanation based on evidence for how the structure of DNA determines the structure of proteins, which carry out the essential functions of life through systems of specialized cells."},{"code":"HS-LS1-2","subject":"Science","grade":"9","text":"Develop and use a model to illustrate the hierarchical organization of interacting systems that provide specific functions within multicellular organisms."},{"code":"HS-LS1-3","subject":"Science","grade":"9","text":"Plan and conduct an investigation to provide evidence that feedback mechanisms maintain homeostasis."},{"code":"HS-LS1-4","subject":"Science","grade":"9","text":"Use a model to illustrate the role of cellular division (mitosis) and differentiation in producing and maintaining complex organisms."},{"code":"HS-LS1-5","subject":"Science","grade":"9","text":"Use a model to illustrate how photosynthesis transforms light energy into stored chemical energy."},{"code":"HS-LS1-6","subject":"Science","grade":"9","text":"Construct and revise an explanation based on evidence for how carbon, hydrogen, and oxygen from sugar molecules may combine with other elements to form amino acids and/or other large carbon-based molecules."},{"code":"HS-LS1-7","subject":"Science","grade":"9","text":"Use a model to illustrate that cellular respiration is a chemical process whereby the bonds of food molecules and oxygen molecules are broken and the bonds in new compounds are formed, resulting in a net transfer of energy."},{"code":"HS-LS2-1","subject":"Science","grade":"9","text":"Use mathematical and/or computational representations to support explanations of factors that affect carrying capacity of ecosystems at different scales."},{"code":"HS-LS2-2","subject":"Science","grade":"9","text":"Use mathematical representations to support and revise explanations based on evidence about factors affecting biodiversity and populations in ecosystems of different scales."},{"code":"HS-LS2-3","subject":"Science","grade":"9","text":"Construct and revise an explanation based on evidence for the cycling of matter and flow of energy in aerobic and anaerobic conditions."},{"code":"HS-LS2-4","subject":"Science","grade":"9","text":"Use mathematical representations to support claims for the cycling of matter and flow of energy among organisms in an ecosystem."},{"code":"HS-LS2-5","subject":"Science","grade":"9","text":"Develop a model to illustrate the role of photosynthesis and cellular respiration in the cycling of carbon among the biosphere, atmosphere, hydrosphere, and geosphere."},{"code":"HS-LS2-6","subject":"Science","grade":"9","text":"Evaluate claims, evidence, and reasoning that the complex interactions in ecosystems maintain relatively consistent numbers and types of organisms in stable conditions, but changing conditions may result in a new ecosystem."},{"code":"HS-LS2-7","subject":"Science","grade":"9","text":"Design, evaluate, and refine a solution for reducing the impacts of human activities on the environment and biodiversit y.*"},{"code":"HS-LS2-8","subject":"Science","grade":"9","text":"Evaluate evidence for the role of group behavior on individual and species\u2019 chances to survive and reproduce."},{"code":"HS-LS3-1","subject":"Science","grade":"9","text":"Ask questions to clarify relationships about the role of DNA and chromosomes in coding the instructions for characteristic traits passed from parents to offspring."},{"code":"HS-LS3-2","subject":"Science","grade":"9","text":"Make and defend a claim based on evidence that inheritable genetic variations may result from (1) new genetic combinations through meiosis, (2) viable errors occurring during replication, and/or (3) mutations caused by environmental factors."},{"code":"HS-LS3-3","subject":"Science","grade":"9","text":"Apply concepts of statistics and probability to explain the variation and distribution of expressed traits in a population."},{"code":"HS-LS4-1","subject":"Science","grade":"9","text":"Communicate scientific information that common ancestry and biological evolution are supported by multiple lines of empirical evidence."},{"code":"HS-LS4-2","subject":"Science","grade":"9","text":"Construct an explanation based on evidence that the process of evolution primarily results from four factors: (1) the potential for a species to increase in number, (2) the heritable genetic variation of individuals in a species due to mutation and sexual reproduction, (3) competition for limited resources, and (4) the proliferation of those organisms that are better able to survive and reproduce in the environment."},{"code":"HS-LS4-3","subject":"Science","grade":"9","text":"Apply concepts of statistics and probability to support explanations that organisms with an advantageous heritable trait tend to increase in proportion to organisms lacking this trait."},{"code":"HS-LS4-4","subject":"Science","grade":"9","text":"Construct an explanation based on evidence for how natural selection leads to adaptation of populations."},{"code":"HS-LS4-5","subject":"Science","grade":"9","text":"Evaluate the evidence supporting claims that changes in environmental conditions may result in (1) increases in the number of individuals of some species, (2) the emergence of new species over time, and (3) the extinction of other species."},{"code":"HS-LS4-6","subject":"Science","grade":"9","text":"Create or revise a simulation to test a solution to mitigate adverse impacts of human activity on biodiversit y.*"},{"code":"HS-PS1-1","subject":"Science","grade":"9","text":"Use the periodic table as a model to predict the relative properties of elements based on the patterns of electrons in the outermost energy level of atoms."},{"code":"HS-PS1-2","subject":"Science","grade":"9","text":"Construct and revise an explanation for the outcome of a simple chemical reaction based on the outermost electron states of atoms, trends in the periodic table, and knowledge of the patterns of chemical properties."},{"code":"HS-PS1-3","subject":"Science","grade":"9","text":"Plan and conduct an investigation to gather evidence to compare the structure of substances at the macro and micro scale to infer the strength of electrical forces between particles."},{"code":"HS-PS1-4","subject":"Science","grade":"9","text":"Develop a model to illustrate that the release or absorption of energy from a chemical reaction system depends upon the changes in total bond energy."},{"code":"HS-PS1-5","subject":"Science","grade":"9","text":"Apply scientific principles and evidence to provide an explanation about the effects of changing the temperature or concentration of the reacting particles on the rate at which a reaction occurs."},{"code":"HS-PS1-6","subject":"Science","grade":"9","text":"Refine the design of a chemical system by specifying a change in conditions that would produce increased amounts of products at equilibrium.*"},{"code":"HS-PS1-7","subject":"Science","grade":"9","text":"Use mathematical representations to support the claim that atoms, and therefore mass, are conserved during a chemical reaction."},{"code":"HS-PS1-8","subject":"Science","grade":"9","text":"Develop models to illustrate the changes in the composition of the nucleus of the atom and the energy released during the processes of fission, fusion, and radioactive decay."},{"code":"HS-PS2-1","subject":"Science","grade":"9","text":"Analyze data to support the claim that Newton\u2019s second law of motion describes the mathematical relationship among the net force on a macroscopic object, its mass, and its acceleration."},{"code":"HS-PS2-2","subject":"Science","grade":"9","text":"Use mathematical representations to support the claim that the total momentum of a system of objects is conserved when there is no net force on the system."},{"code":"HS-PS2-3","subject":"Science","grade":"9","text":"Apply scientific and engineering ideas to design, evaluate, and refine a device that minimizes the force on a macroscopic object during a collision.*"},{"code":"HS-PS2-4","subject":"Science","grade":"9","text":"Use mathematical representations of Newton\u2019s law of gravitation and Coulomb\u2019s law to describe and predict the gravitational and electrostatic forces between objects."},{"code":"HS-PS2-5","subject":"Science","grade":"9","text":"Plan and conduct an investigation to provide evidence that an electric current can produce a magnetic field and that a changing magnetic field can produce an electric current."},{"code":"HS-PS2-6","subject":"Science","grade":"9","text":"Communicate scientific and technical information about why the molecular-level structure is important in the functioning of designed materials.*"},{"code":"HS-PS3-1","subject":"Science","grade":"9","text":"Create a computational model to calculate the change in the energy of one component in a system when the change in energy of the other component(s) and energy flows in and out of the system are known."},{"code":"HS-PS3-2","subject":"Science","grade":"9","text":"Develop and use models to illustrate that energy at the macroscopic scale can be accounted for as a combination of energy associated with the motion of particles (objects) and energy associated with the relative position of particles (objects)."},{"code":"HS-PS3-3","subject":"Science","grade":"9","text":"Design, build, and refine a device that works within given constraints to convert one form of energy into another form of energy.*"},{"code":"HS-PS3-4","subject":"Science","grade":"9","text":"Plan and conduct an investigation to provide evidence that the transfer of thermal energy when two components of different temperature are combined within a closed system results in a more uniform energy distribution among the components in the system (second law of thermodynamics)."},{"code":"HS-PS3-5","subject":"Science","grade":"9","text":"Develop and use a model of two objects interacting through electric or magnetic fields to illustrate the forces between objects and the changes in energy of the objects due to the interaction."},{"code":"HS-PS4-1","subject":"Science","grade":"9","text":"Use mathematical representations to support a claim regarding relationships among the frequency, wavelength, and speed of waves traveling in various media."},{"code":"HS-PS4-2","subject":"Science","grade":"9","text":"Evaluate questions about the advantages of using digital transmission and storage of information."},{"code":"HS-PS4-3","subject":"Science","grade":"9","text":"Evaluate the claims, evidence, and reasoning behind the idea that electromagnetic radiation can be described either by a wave model or a particle model, and that for some situations one model is more useful than the other."},{"code":"HS-PS4-4","subject":"Science","grade":"9","text":"Evaluate the validity and reliability of claims in published materials of the effects that different frequencies of electromagnetic radiation have when absorbed by matter."},{"code":"HS-PS4-5","subject":"Science","grade":"9","text":"Communicate technical information about how some technological devices use the principles of wave behavior and wave interactions with matter to transmit and capture information and energy.*"},{"code":"HS.C.CP.1","subject":"Social Studies","grade":"9","text":"Explain how the Cons titution of the United States embodies the principles of rule of law, popular sovereignty, republicanism, federalism, separation of powers and checks and balances to promote general welfare."},{"code":"HS.C.CP.2","subject":"Social Studies","grade":"9","text":"Analyze legislative, executive and judicial branch decisions in terms of constitutionality and impact on citizens and states."},{"code":"HS.C.CP.3","subject":"Social Studies","grade":"9","text":"Compare various forms of government and how each maintains order, upholds human rights and interacts within the international community."},{"code":"HS.C.CP.4","subject":"Social Studies","grade":"9","text":"Evaluate how the U.S. judicial system is designed to uphold equality before the law, due process and inalienable rights."},{"code":"HS.C.CV.1","subject":"Social Studies","grade":"9","text":"Explain how classic al republicanism, natural rights philosophy and English common law influenced the thinking and actions of the American Founders."},{"code":"HS.C.CV.2","subject":"Social Studies","grade":"9","text":"Assess how the expansion of civic virtues, democratic principles, constitutional rights and human rights influence the thoughts and actions of individuals and groups."},{"code":"HS.C.CV.3","subject":"Social Studies","grade":"9","text":"Analyze the impact of the e fforts of individuals and reform movements on the expansion of civil rights and liberties locally, nationally and internationally."},{"code":"HS.C.KGO.1","subject":"Social Studies","grade":"9","text":"Explain how the Ke ntucky Constitution embodies the principles of rule of law, popular sovereignty, separation of powers and checks and balances."},{"code":"HS.C.KGO.2","subject":"Social Studies","grade":"9","text":"Compare Kentucky\u2019s government to other states and to the federal government."},{"code":"HS.C.KGO.3","subject":"Social Studies","grade":"9","text":"Describe how active citizens can affect change in their communities and Kentucky Informed and engaged citizenship is a crucial part of the successful functioning of Kentucky."},{"code":"HS.C.PR.1","subject":"Social Studies","grade":"9","text":"Analyze the role of the thre e branches of government in the lawmaking process."},{"code":"HS.C.PR.2","subject":"Social Studies","grade":"9","text":"Analyze the role of elections, bureaucracy, political parties, interest groups and media in shaping public policy."},{"code":"HS.C.PR.3","subject":"Social Studies","grade":"9","text":"Evaluate intended and unintended consequences of public policies locally, nationally and internationally."},{"code":"HS.C.PR.4","subject":"Social Studies","grade":"9","text":"Compare the domestic and foreign policies of the United States and other countries."},{"code":"HS.C.RR.1","subject":"Social Studies","grade":"9","text":"Evaluate the civic r esponsibilities of individuals within a society."},{"code":"HS.C.RR.2","subject":"Social Studies","grade":"9","text":"Explain how active citizens can affect the lawmaking process locally, nationally and internationally. internationally engaged citizens are critical to positively evolving societies."},{"code":"HS.E.IC.1","subject":"Social Studies","grade":"9","text":"Predict the way scarcity causes individuals, organizations and governments to evaluate tradeoffs, make choices and incur opportunity costs."},{"code":"HS.E.IC.2","subject":"Social Studies","grade":"9","text":"Evaluate how individuals, organizations and governments respond to incentives in the decision- making process."},{"code":"HS.E.IC.3","subject":"Social Studies","grade":"9","text":"Perform a cost-benefit analysis on a real-world situation, using economic thinking to describe the marginal costs and benefits of a particular situation."},{"code":"HS.E.IC.4","subject":"Social Studies","grade":"9","text":"Evaluate how incentives determine what is produced and distributed in a competitive market system."},{"code":"HS.E.KE.1","subject":"Social Studies","grade":"9","text":"Analyze how national and international trends and policies impact Kentucky\u2019s state and local economies."},{"code":"HS.E.KE.2","subject":"Social Studies","grade":"9","text":"Analyze how national and international trends and policies impact Kentucky\u2019s state and local economies."},{"code":"HS.E.KE.3","subject":"Social Studies","grade":"9","text":"Analyze how the four components of Gross Domestic Product (GDP) are combined to assess the health of Kentucky\u2019s economy."},{"code":"HS.E.MA.1","subject":"Social Studies","grade":"9","text":"Evaluate how valu es and beliefs like economic freedom, equity, full employment, price stability, security, efficiency and growth help to form different types of economic systems."},{"code":"HS.E.MA.2","subject":"Social Studies","grade":"9","text":"Analyze ways in which competition and government regulation influence what is produced and allocated in an economy."},{"code":"HS.E.MA.3","subject":"Social Studies","grade":"9","text":"Describe the externalities of government attempts to remedy market failure and improve market outcomes through fiscal policy."},{"code":"HS.E.MA.4","subject":"Social Studies","grade":"9","text":"Analyze the impact of fiscal policies, various government taxation and spending policies on the economy."},{"code":"HS.E.MA.5","subject":"Social Studies","grade":"9","text":"Assess how interest rates influence borrowing and investing."},{"code":"HS.E.MA.6","subject":"Social Studies","grade":"9","text":"Assess the effectiveness of rules and laws that protect both consumers and producers."},{"code":"HS.E.MA.7","subject":"Social Studies","grade":"9","text":"Explain how the Federal Reserve uses monetary policy to promote price stability, employment and economic growth."},{"code":"HS.E.MI.1","subject":"Social Studies","grade":"9","text":"Compare per fect competition, monopolistic competition, oligopoly and monopoly and how the extent of competition within various markets affects price, quantity and variety in production."},{"code":"HS.E.MI.2","subject":"Social Studies","grade":"9","text":"Analyze and graph the impact of supply and demand shifts on equilibrium price and quantities produced."},{"code":"HS.E.MI.3","subject":"Social Studies","grade":"9","text":"Analyze the roles of product and factor markets."},{"code":"HS.E.MI.4","subject":"Social Studies","grade":"9","text":"Compare the roles of consumers and producers in the product, labor and financial markets and the economy as a whole."},{"code":"HS.E.ST.1","subject":"Social Studies","grade":"9","text":"Draw conclusions regarding the effect of specialization and trade on production, distribution and consumption of goods and services for individuals, businesses and societies."},{"code":"HS.E.ST.2","subject":"Social Studies","grade":"9","text":"Analyze the role of comparative advantage in international trade of goods and services."},{"code":"HS.E.ST.3","subject":"Social Studies","grade":"9","text":"Explain how international economic trends and policies affect political, social and economic conditions in various nations. (see \u201ccontinued\u201d) Nations in the modern world are affected by the interconnectedness of economies, which causes ripple effects across borders."},{"code":"HS.G.GR.1","subject":"Social Studies","grade":"9","text":"Interpret the relationships among human and physical patterns and processes at local, national and global scales."},{"code":"HS.G.GR.2","subject":"Social Studies","grade":"9","text":"Analyze how environmental factors influence population distributions from place to place."},{"code":"HS.G.HE.1","subject":"Social Studies","grade":"9","text":"Assess the reciproc al relationship between physical environment and culture within local, national and global scales."},{"code":"HS.G.HE.2","subject":"Social Studies","grade":"9","text":"Analyze how human settlements are influenced by or influence the relationship between people and the environment."},{"code":"HS.G.HI.1","subject":"Social Studies","grade":"9","text":"Analyze how the forces of cooperation and conflict within and among people, nations and empires influence the division and control of Earth\u2019s surface and resources."},{"code":"HS.G.HI.2","subject":"Social Studies","grade":"9","text":"Analyze how cultural and economic decisions influence the characteristics of various places."},{"code":"HS.G.HI.3","subject":"Social Studies","grade":"9","text":"Explain how people create natural and cultural regions to interpret Earth\u2019s complexity."},{"code":"HS.G.KGE.1","subject":"Social Studies","grade":"9","text":"Explain how Kentuckians view sense of place differently based on cultural and environmental characteristics of varying regions of the state."},{"code":"HS.G.KGE.2","subject":"Social Studies","grade":"9","text":"Explain how the geography of Kentucky influences the development of the state."},{"code":"HS.G.MM.1","subject":"Social Studies","grade":"9","text":"Analyze how cult ural, economic and environmental factors contribute to migration patterns and population distribution at multiple scales."},{"code":"HS.G.MM.2","subject":"Social Studies","grade":"9","text":"Evaluate reasons for the spatial distribution of human populations at different scales on Earth\u2019s surface."},{"code":"C.9-10.1","subject":"English Language Arts","grade":"10","text":"Compose arguments to support claims in an analysis of substantive topics or texts, using valid reasoning and relevant and sufficient evidence. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce precise claim(s), distinguish the claim(s) from alternate or opposing claims and create an organization that establishes clear relationships among claim(s), counterclaims, reasons and evidence. c. Develop claim(s) and counterclaims fairly, supplying evidence for each while pointing out the strengths and limitations of both in a manner that anticipates the audience\u2019s knowledge level and concerns. d. Link the major sections of the text cohesively, and clarify the relationships among claim(s), counterclaims, reasons and evidence. e. Establish and maintain a task-appropriate writing style. f. Provide a concluding statement or section that follows and supports the argument presented. g. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience."},{"code":"C.9-10.1a","subject":"English Language Arts","grade":"10","text":"Composition, Grades 9-10, Standard 1, Substandard a Language L"},{"code":"C.9-10.2","subject":"English Language Arts","grade":"10","text":"Compose informative and/or explanatory texts to examine and convey complex ideas, concepts and information clearly and accurately through the effective selection, organization and analysis of content. a. Produce writing in which the development and organization are appropriate to task and purpose. b. Introduce a topic; organize complex ideas, concepts and information to make important connections and distinctions; include formatting, graphics and multimedia when useful to aiding comprehension. c. Develop the topic with well-chosen, relevant and sufficient facts, extended definitions, concrete details, quotations or other information and examples appropriate to the audience\u2019s knowledge of the topic. d. Use appropriate and varied transitions to link the major sections of the text, create cohesion and clarify the relationships among complex ideas and concepts. e. Use precise language and domain-specific vocabulary to manage the complexity of the topic. f. Establish and maintain a formal style and objective tone while attending to the norms and conventions of the discipline in which they are writing. g. Provide a concluding statement or section that follows from and supports the information or explanation presented. h. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience."},{"code":"C.9-10.3","subject":"English Language Arts","grade":"10","text":"Use narratives strategically in other modes of writing, utilizing effective technique, well-chosen details and well-structured sequences for an intended purpose, including but not limited to introducing an idea and/or supporting a claim. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task and purpose. b. Engage and orient the reader by setting out a problem, situation or observation, establishing one or multiple point(s) of view and introducing a narrator and/or characters; create a smooth progression of experiences or events. c. Use narrative techniques, such as dialogue, pacing, description, reflection and multiple plot lines, to develop experiences, events and/or characters. d. Use a variety of techniques to sequence events so that they build on one another to create a coherent whole. e. Use precise words and phrases, telling details f. sensory language to convey a vivid picture of the experiences, events, setting and/or characters. g. Provide a conclusion that explicitly connects the narrative\u2019s relevance to the intended purpose of the writing. h. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience. Production and Distribution"},{"code":"C.9-10.4","subject":"English Language Arts","grade":"10","text":"Use DIGITAL RESOURCES to create, publish and update individual or shared products , taking advantage of technology\u2019s capacity to link to other information and to display information flexibly and dynamically. Use a variety of formats to cite sources ."},{"code":"C.9-10.5","subject":"English Language Arts","grade":"10","text":"Conduct short as well as more sustained RESEARCH projects to answer a question (including a self-generated question) or solve a problem; narrow or broaden the inquiry when appropriate; synthesize multiple sources on the subject , demonstrating understanding of the subject under investigation ."},{"code":"C.9-10.6","subject":"English Language Arts","grade":"10","text":"Gather relevant information from multiple authoritative print and digital sources, using advanced searches effectively ; assess the usefulness of each source in answering the research question; integrate information into the text selectively to maintain the flow of ideas , avoiding plagiarism and following a standard format for citation ."},{"code":"C.9-10.7","subject":"English Language Arts","grade":"10","text":"Compose routinely over extended time frames and shorter time frames for a variety of tasks, purposes and audiences ."},{"code":"L.9-10.1","subject":"English Language Arts","grade":"10","text":"In both written and oral expression : a. Demonstrate appropriate use of PARALLEL STRUCTURE . b. Demonstrate task-appropriate use of PHRASES and CLAUSES to communicate purpose, develop structure and add variety ."},{"code":"L.9-10.2","subject":"English Language Arts","grade":"10","text":"When writing : a. Demonstrate appropriate use of a SEMICOLON WITH AND WITHOUT A CONJUNCTIVE ADVERB TO LINK TWO OR MORE CLOSELY RELATED INDEPENDENT CLAUSES . b. Demonstrate appropriate use of a COLON TO INTRODUCE A LIST OR QUOTATION . c. Demonstrate appropriate use of strategies and resources (print and electronic) to identify and correct spelling errors ."},{"code":"L.9-10.3","subject":"English Language Arts","grade":"10","text":"Apply knowledge of language to understand how language functions in different contexts, to make effective choices for meaning or style and to comprehend more fully when reading or listening . a. Write and edit work so that it conforms to the guidelines in a style manual appropriate for the discipline and writing type ."},{"code":"L.9-10.4","subject":"English Language Arts","grade":"10","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grades 9-10 reading and content, choosing flexibly from an array of strategies . a. Use context (e.g., the overall meaning of a sentence, paragraph or text; a word\u2019s position or function in a sentence) as a clue to the meaning of a word or phrase . b. Identify and correctly use patterns of word changes that indicate different meanings or parts of speech . c. Consult general and specialized reference materials to find the pronunciation of a word or determine or clarify its precise meaning or its part of speech . d. Acquire and use accurately general academic and domain-specific words and phrases, sufficient for reading, writing, speaking and listening in order to be postsecondary ready; demonstrate independence in gathering vocabulary knowledge when considering a word or phrase important to comprehension or expression ."},{"code":"L.9-10.5","subject":"English Language Arts","grade":"10","text":"Demonstrate understanding of figurative language, word relationships and nuances in word meanings . a. Interpret FIGURES OF SPEECH in context , including but not limited to EUPHEMISM and OXYMORON , and analyze their rhetorical function in the text. b. Analyze nuances in the meaning of words with similar denotations ."},{"code":"RI.9-10.1","subject":"English Language Arts","grade":"10","text":"CITE RELEVANT AND THOROUGH TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RI.9-10.10","subject":"English Language Arts","grade":"10","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX INFORMATIONAL TEXT independently ."},{"code":"RI.9-10.2","subject":"English Language Arts","grade":"10","text":"Determine CENTRAL IDEAS of a text and analyze in detail their development over the course of the text , including how they emerge and are shaped and refined by specific details ."},{"code":"RI.9-10.3","subject":"English Language Arts","grade":"10","text":"Analyze how the author unfolds AN ANALYSIS OR SERIES OF IDEAS OR EVENTS over the course of a text, including the order in which the points are made , how they are introduced and developed and the connections that are drawn between them ."},{"code":"RI.9-10.4","subject":"English Language Arts","grade":"10","text":"Determine the meaning of words and phrases as they are used in a text, including figurative, connotative and technical meanings; analyze the cumulative impact of specific WORD CHOICES on meaning and TONE ."},{"code":"RI.9-10.5","subject":"English Language Arts","grade":"10","text":"Analyze in detail how an author\u2019s IDEAS OR CLAIMS are developed and refined by particular sentences, paragraphs or larger portions of a text ."},{"code":"RI.9-10.6","subject":"English Language Arts","grade":"10","text":"Determine an author\u2019s POINT OF VIEW, PERSPECTIVE and PURPOSE in a text, and analyze how an author uses RHETORIC to advance that point of view or purpose ."},{"code":"RI.9-10.7","subject":"English Language Arts","grade":"10","text":"Analyze various accounts of A SUBJECT PRESENTED IN DIFFERENT PRINT AND NON-PRINT FORMATS , determining which details are emphasized in each account ."},{"code":"RI.9-10.8","subject":"English Language Arts","grade":"10","text":"Evaluate the ARGUMENT , specific CLAIMS and EVIDENCE in a text, assessing the validity, reasoning, relevancy and sufficiency of the evidence ; identify false statements and FALLACIOUS REASONING ."},{"code":"RI.9-10.9","subject":"English Language Arts","grade":"10","text":"Analyze DOCUMENTS OF HISTORICAL AND LITERARY SIGNIFICANCE , including how they address related THEMES and concepts ."},{"code":"RL.9-10.1","subject":"English Language Arts","grade":"10","text":"CITE RELEVANT AND THOROUGH TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RL.9-10.10","subject":"English Language Arts","grade":"10","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.9-10.2","subject":"English Language Arts","grade":"10","text":"Determine a THEME OR CENTRAL IDEA of a text and analyze in detail its development over the course of the text , including how it emerges and is shaped and refined by specific details ."},{"code":"RL.9-10.3","subject":"English Language Arts","grade":"10","text":"Analyze how COMPLEX CHARACTERS develop over the course of a text , interact with other characters and advance the plot or develop themes ."},{"code":"RL.9-10.4","subject":"English Language Arts","grade":"10","text":"Determine the meaning of words and phrases as they are used in the text, including figurative and connotative meanings; analyze the cumulative impact of specific WORD CHOICES on meaning and TONE ."},{"code":"RL.9-10.5","subject":"English Language Arts","grade":"10","text":"Analyze how an author\u2019s choices concerning text STRUCTURE, ORDER OF DETAILS, SEQUENCE AND MANIPULATION OF TIME (E.G., FLASHBACK, PACING) create effects (e.g., emotional impact, character development) ."},{"code":"RL.9-10.6","subject":"English Language Arts","grade":"10","text":"Analyze how authors\u2019 PERSPECTIVES OR CULTURAL EXPERIENCES are reflected in works of world literature from various historical contexts ."},{"code":"RL.9-10.7","subject":"English Language Arts","grade":"10","text":"Analyze the impact of the REPRESENTATION OF A SUBJECT OR A KEY SCENE IN DIFFERENT PRINT AND NON-PRINT MEDIUMS and evaluate what is emphasized or omitted in each treatment ."},{"code":"RL.9-10.8","subject":"English Language Arts","grade":"10","text":"Not applicable to literature"},{"code":"RL.9-10.9","subject":"English Language Arts","grade":"10","text":"Analyze TWO OR MORE TEXTS from different time periods to evaluate the impact of authors\u2019 approaches to similar themes and topics ."},{"code":"KY.HS.A.1","subject":"Mathematics","grade":"10","text":"Interpret expressions that represent a quantity in terms of its context. \u2605 a. Interpret parts of an expression, such as terms, factors and coefficients. b. Interpret complicated expressions, given a context, by viewing one or more of their parts as a single entity."},{"code":"KY.HS.A.10","subject":"Mathematics","grade":"10","text":"Rewrite simple rational expressions in different forms."},{"code":"KY.HS.A.11","subject":"Mathematics","grade":"10","text":"Add, subtract, multiply and divide rational algebraic expressions."},{"code":"KY.HS.A.12","subject":"Mathematics","grade":"10","text":"Create equations and inequalities in one variable and use them to solve problems."},{"code":"KY.HS.A.13","subject":"Mathematics","grade":"10","text":"Create equations in two or more variables to represent relationships between quantities; graph equations on coordinate axes with labels and scales."},{"code":"KY.HS.A.14","subject":"Mathematics","grade":"10","text":"Create a system of equations or inequalities to represent constraints within a modeling context. Interpret the solution(s) to the corresponding system as viable or nonviable options within the context."},{"code":"KY.HS.A.15","subject":"Mathematics","grade":"10","text":"Rearrange formulas to solve a literal equation, highlighting a quantity of interest, using the same reasoning as in solving equations."},{"code":"KY.HS.A.16","subject":"Mathematics","grade":"10","text":"Understand each step in solving a simple equation as following from the equality of numbers asserted at the previous step, starting from the assumption that the original equation has a solution. Construct a viable argument to justify a solution method."},{"code":"KY.HS.A.17","subject":"Mathematics","grade":"10","text":"Solve and justify equations in one variable. Justify the solutions and give examples showing how extraneous solutions may arise. a. Solve rational equations written as proportions in one variable. b. Solve radical equations in one variable."},{"code":"KY.HS.A.18","subject":"Mathematics","grade":"10","text":"Solve linear equations and inequalities in one variable, including literal equations with coefficients represented by letters."},{"code":"KY.HS.A.19","subject":"Mathematics","grade":"10","text":"Solve quadratic equations in one variable. a. Solve quadratic equations by taking square roots, the quadratic formula and factoring, as appropriate to the initial form of the equation. Recognize when the quadratic formula gives complex solutions and write them as a \u00b1 bi for real numbers a and b. b. (+) Use the method of completing the square to transform any quadratic equation in x into an equation of the form (x \u2013 p)2 = q that has the same solutions. Derive the quadratic formula from this form. c. (+) Solve quadratic equations by completing the square."},{"code":"KY.HS.A.2","subject":"Mathematics","grade":"10","text":"Use the structure of an expression to identify ways to rewrite it and consistently look for opportunities to rewrite expressions in equivalent forms."},{"code":"KY.HS.A.20","subject":"Mathematics","grade":"10","text":"Solve systems of linear equations in two variables. a. Understand a system of two equations in two variables has the same solution as a new system formed by replacing one of the original equations with an equivalent equation. b. Solve systems of linear equations with graphs, substitution and elimination, focusing on pairs of linear equations in two variables."},{"code":"KY.HS.A.21","subject":"Mathematics","grade":"10","text":"Solve a simple system consisting of a linear equation and a quadratic equation in two variables algebraically and graphically."},{"code":"KY.HS.A.22","subject":"Mathematics","grade":"10","text":"Use matrices to solve a system of equations. a. Represent a system of linear equations as a single matrix equation in a vector variable. b. Find the inverse of a matrix if it exists. c. Use matrices to solve systems of linear equations (using technology for matrices of dimension 3 \u00d7 3 or greater)."},{"code":"KY.HS.A.23","subject":"Mathematics","grade":"10","text":"Understand that the graph of an equation in two variables is the set of all its solutions plotted in the coordinate plane."},{"code":"KY.HS.A.24","subject":"Mathematics","grade":"10","text":"Justify that the solutions of the equations f(x) = g(x) are the x-coordinates of the points where the graphs of y = f(x) and y = g(x) intersect. Find the approximate solutions graphically, using technology or tables. \u2605"},{"code":"KY.HS.A.25","subject":"Mathematics","grade":"10","text":"Graph linear inequalities in two variables. a. Graph the solutions to a linear inequality as a half-plane (excluding the boundary in the case of a strict inequality). b. Graph the solution set to a system of linear inequalities as the intersection of the corresponding half-planes."},{"code":"KY.HS.A.3","subject":"Mathematics","grade":"10","text":"Choose and produce an equivalent form of an expression to reveal and explain properties of the quantity represented by the expression. \u2605 a. Write the standard form of a given polynomial and identify the terms, coefficients, degree, leading coefficient and constant term. b. Factor a quadratic expression to reveal the zeros of the function it defines. c. Use the properties of exponents to rewrite exponential expressions. d. (+) Complete the square in a quadratic expression to reveal the maximum or minimum value of the function it defines."},{"code":"KY.HS.A.3b","subject":"Mathematics","grade":"10","text":"Students recognize the connection between the zero product property and solving a quadratic in one variable by setting factored expressions equal to zero."},{"code":"KY.HS.A.3d","subject":"Mathematics","grade":"10","text":"Students recognize being able to complete the square allows them to identify the coordinates of the maximum or minimum value more easily than when the quadratic is in standard form and there are pros and cons of each equivalent form."},{"code":"KY.HS.A.4","subject":"Mathematics","grade":"10","text":"Derive the formula for the sum of a finite geometric series (when the common ratio is not 1) and use the formula to solve problems. \u2605"},{"code":"KY.HS.A.5","subject":"Mathematics","grade":"10","text":"Add, subtract and multiply polynomials."},{"code":"KY.HS.A.6","subject":"Mathematics","grade":"10","text":"Know and apply the Remainder Theorem."},{"code":"KY.HS.A.7","subject":"Mathematics","grade":"10","text":"Identify roots of polynomials when suitable factorizations are available. Know these roots become the zeros (x-intercepts) for the corresponding polynomial function."},{"code":"KY.HS.A.8","subject":"Mathematics","grade":"10","text":"Prove polynomial identities and use them to describe numerical relationships."},{"code":"KY.HS.A.9","subject":"Mathematics","grade":"10","text":"Know and apply the Binomial Theorem for the expansion of (x + y )n in powers of x and y for a positive integer n, where x and y are any numbers, with coefficients determined for example by Pascal\u2019s Triangle."},{"code":"KY.HS.C.1","subject":"Mathematics","grade":"10","text":"Understand limits. a. Apply limits to a variety of functions, including piecewise functions. b. (++) Prove that the limit of a function exists, based upon the definition of a limit."},{"code":"KY.HS.C.10","subject":"Mathematics","grade":"10","text":"Communicate an understanding of continuity using precise mathematical symbols and language."},{"code":"KY.HS.C.11","subject":"Mathematics","grade":"10","text":"Define derivatives. a. Define the derivative of a function as the limit of the difference quotient. b. Understand this limit of the difference quotient can be interpreted as an instantaneous rate of change or the slope of a tangent line."},{"code":"KY.HS.C.12","subject":"Mathematics","grade":"10","text":"Use average rate of change to estimate the derivative from a table of values or a graph."},{"code":"KY.HS.C.13","subject":"Mathematics","grade":"10","text":"Understand the derivative as a function."},{"code":"KY.HS.C.15","subject":"Mathematics","grade":"10","text":"Explain why differentiability implies continuity yet continuity does not imply differentiability."},{"code":"KY.HS.C.16","subject":"Mathematics","grade":"10","text":"Understand and apply the Mean Value Theorem, including numerical, graphical and algebraic representations."},{"code":"KY.HS.C.17","subject":"Mathematics","grade":"10","text":"Understand the relationship between the concavity of a function and the sign of the second derivative."},{"code":"KY.HS.C.18","subject":"Mathematics","grade":"10","text":"Understand Rolle\u2019s Theorem as a special case of the Mean Value Theorem."},{"code":"KY.HS.C.19","subject":"Mathematics","grade":"10","text":"Efficiently find derivatives of functions with and without technology."},{"code":"KY.HS.C.2","subject":"Mathematics","grade":"10","text":"Demonstrate an understanding of limits by estimating and finding the limit of a function at a point graphically, numerically and algebraically."},{"code":"KY.HS.C.20","subject":"Mathematics","grade":"10","text":"Understand and use derivative rules for sums, differences, products and quotients of two functions and calculate the derivative of a composite function using the chain rule. MP2,"},{"code":"KY.HS.C.21","subject":"Mathematics","grade":"10","text":"Use implicit differentiation to find a derivative in an equation of two variables."},{"code":"KY.HS.C.22","subject":"Mathematics","grade":"10","text":"Use implicit differentiation to find the derivative of the inverse of a function."},{"code":"KY.HS.C.23","subject":"Mathematics","grade":"10","text":"Understand the relationship between the increasing and decreasing behavior of a function and the sign of the first derivative of the function."},{"code":"KY.HS.C.24","subject":"Mathematics","grade":"10","text":"Use the first derivative to analyze curves and identify relative extrema."},{"code":"KY.HS.C.25","subject":"Mathematics","grade":"10","text":"Understand the relationship of concavity to the second derivative."},{"code":"KY.HS.C.26","subject":"Mathematics","grade":"10","text":"Use the second derivative to find points of inflection."},{"code":"KY.HS.C.27","subject":"Mathematics","grade":"10","text":"Use the second derivative to analytically locate intervals on which a function is concave up, concave down or neither."},{"code":"KY.HS.C.28","subject":"Mathematics","grade":"10","text":"Describe how graphical characteristics of a given function, the first derivative of that function and the second derivative of that function interrelate."},{"code":"KY.HS.C.29","subject":"Mathematics","grade":"10","text":"Use derivatives to express rate of change in a variety of contexts."},{"code":"KY.HS.C.3","subject":"Mathematics","grade":"10","text":"Apply properties and theorems of limits, including limits of indeterminate forms."},{"code":"KY.HS.C.30","subject":"Mathematics","grade":"10","text":"Use derivatives to solve a variety of problems including related rates, optimization, tangent line approximations and growth and decay models."},{"code":"KY.HS.C.31","subject":"Mathematics","grade":"10","text":"Use differentiation to solve problems involving velocity, speed and acceleration."},{"code":"KY.HS.C.32","subject":"Mathematics","grade":"10","text":"Understand and apply differential equations. a. Verify solutions to differential equations and use them to model real-world problems with and without technology. b. Solve separable differential equations and use them in modeling real-world problems with and without technology."},{"code":"KY.HS.C.33","subject":"Mathematics","grade":"10","text":"Understand the definite integral of a function over an interval. Interpret a definite integral as a limit of Riemann Sums and as net accumulation of change."},{"code":"KY.HS.C.34","subject":"Mathematics","grade":"10","text":"Write a Riemann sum that represents the definition of a definite integral."},{"code":"KY.HS.C.35","subject":"Mathematics","grade":"10","text":"Calculate the values of Riemann Sums over equal subdivisions to approximate definite integrals of functions represented graphically and numerically (using tables). Use left-hand sums, right- hand sums, midpoint sums and trapezoidal sums."},{"code":"KY.HS.C.36","subject":"Mathematics","grade":"10","text":"Recognize differentiation and integration as inverse operations."},{"code":"KY.HS.C.37","subject":"Mathematics","grade":"10","text":"Understand how the Fundamental Theorem of Calculus connects differentiation and integration and use it to evaluate definite and indefinite integrals and to represent particular antiderivatives."},{"code":"KY.HS.C.38","subject":"Mathematics","grade":"10","text":"Perform analytical and graphical analysis of functions using the Fundamental Theorem of Calculus."},{"code":"KY.HS.C.39","subject":"Mathematics","grade":"10","text":"Understand and use the definite integral of a function over an interval and understand its use as a mathematical tool."},{"code":"KY.HS.C.4","subject":"Mathematics","grade":"10","text":"Communicate understanding of limits using precise mathematical symbols and language."},{"code":"KY.HS.C.40","subject":"Mathematics","grade":"10","text":"Find antiderivatives of a variety of basic functions including power, exponential, logarithmic and trigonometric and apply basic properties of definite integrals."},{"code":"KY.HS.C.41","subject":"Mathematics","grade":"10","text":"Use substitution techniques and change of limits of integration to find antiderivatives."},{"code":"KY.HS.C.42","subject":"Mathematics","grade":"10","text":"Find particular antiderivatives given initial conditions."},{"code":"KY.HS.C.43","subject":"Mathematics","grade":"10","text":"Model, solve and interpret applications of antiderivatives including finding area, velocity, acceleration and volume of a solid."},{"code":"KY.HS.C.44","subject":"Mathematics","grade":"10","text":"Apply integration to solve problems including particle motion and exponential growth and decay."},{"code":"KY.HS.C.45","subject":"Mathematics","grade":"10","text":"Describe the application of integration to a variety of problems using precise mathematical language and notation."},{"code":"KY.HS.C.5","subject":"Mathematics","grade":"10","text":"Describe asymptotic behavior (analytically and graphically) in terms of infinite limits and limits at infinity."},{"code":"KY.HS.C.6","subject":"Mathematics","grade":"10","text":"Discuss the end behavior of functions; identify representative functions for each type of end behavior using precise mathematical symbols and language."},{"code":"KY.HS.C.7","subject":"Mathematics","grade":"10","text":"Understand and use the limit definition of continuity to determine whether a given function is continuous at a specific point."},{"code":"KY.HS.C.8","subject":"Mathematics","grade":"10","text":"Define and identify different types of discontinuity \u2013 removable (hole) or non-removable (jump, asymptote) \u2013 in terms of limits."},{"code":"KY.HS.C.9","subject":"Mathematics","grade":"10","text":"Understand and apply continuous function theorems. a. Apply the Intermediate Value Theorem to continuous functions. b. Apply the Extreme Value Theorem to continuous functions."},{"code":"KY.HS.F.1","subject":"Mathematics","grade":"10","text":"Understand properties and key features of functions and the different ways functions can be represented. a. Understand that a function from one set (called the domain) to another set (called the range) assigns to each element of the domain exactly one element of the range. If f is a function and x is an element of its domain, then f(x) denotes the output of f corresponding to the input x. b. Using appropriate function notation, evaluate functions for inputs in their domains and interpret statements that use function notation in terms of a context. c. For a function that models a relationship between two quantities, interpret key features of graphs and tables in terms of the quantities and sketch graphs showing key features given a verbal description of the relationship. d. Relate the domain of a function to its graph and, where applicable, to the quantitative relationship it describes. e. Compare properties of two functions each represented in a different way (algebraically, graphically, numerically in tables, or by verbal descriptions)."},{"code":"KY.HS.F.10","subject":"Mathematics","grade":"10","text":"Understand the inverse relationship between exponents and logarithms and use this relationship to solve problems involving logarithms and exponents with the use of technology."},{"code":"KY.HS.F.11","subject":"Mathematics","grade":"10","text":"Distinguish between situations that can be modeled with linear functions and with exponential functions. a. Recognize and justify that linear functions grow by equal differences over equal intervals and that exponential functions grow by equal factors over equal intervals. b. Recognize situations in which one quantity changes at a constant rate per unit interval relative to another. c. Recognize situations in which a quantity grows or decays by a constant percent rate per unit interval relative to another."},{"code":"KY.HS.F.12","subject":"Mathematics","grade":"10","text":"Construct linear and exponential functions, including arithmetic and geometric sequences, given a graph, a description of a relationship, or two input-output pairs (include reading these from a table)."},{"code":"KY.HS.F.13","subject":"Mathematics","grade":"10","text":"Observe using graphs and tables that a quantity increasing exponentially eventually exceeds a quantity increasing linearly, quadratically, or (more generally) as a polynomial function."},{"code":"KY.HS.F.14","subject":"Mathematics","grade":"10","text":"Interpret the parameters in a linear or exponential function in terms of a context."},{"code":"KY.HS.F.15","subject":"Mathematics","grade":"10","text":"Understand the relationship of radian measure of an angle to its arc length."},{"code":"KY.HS.F.16","subject":"Mathematics","grade":"10","text":"Understand and use the unit circle. a. Explain how the unit circle in the coordinate plane enables the extension of trigonometric functions to all real numbers, interpreted as radian measures of angles traversed counterclockwise around the unit circle. b. Use special triangles to determine geometrically the values of sine, cosine, tangent for \u03c0/3, \u03c0 /4 and \u03c0 /6 and use the unit circle to express the values of sine, cosine and tangent for \u03c0 \u2013x, \u03c0 +x and 2 \u03c0 \u2013x in terms of their values for x, where x is any real number. c. Use the unit circle to explain symmetry (odd and even) and periodicity of trigonometric functions."},{"code":"KY.HS.F.17","subject":"Mathematics","grade":"10","text":"Choose trigonometric functions to model periodic phenomena with specified period, midline and amplitude. \u2605"},{"code":"KY.HS.F.18","subject":"Mathematics","grade":"10","text":"Understand that restricting a trigonometric function to a domain on which it is always increasing or always decreasing allows its inverse to be constructed."},{"code":"KY.HS.F.19","subject":"Mathematics","grade":"10","text":"Use inverse functions to solve trigonometric equations that arise in modeling contexts; evaluate the solutions using technology and interpret them in terms of the context. \u2605"},{"code":"KY.HS.F.2","subject":"Mathematics","grade":"10","text":"Recognize that arithmetic and geometric sequences are functions, sometimes defined recursively, whose domain is a subset of the integers."},{"code":"KY.HS.F.20","subject":"Mathematics","grade":"10","text":"Proving identities and formulas within the context of trigonometry. a. Prove the Pythagorean identity and use it to find sin(\u03b8), cos(\u03b8), or tan(\u03b8) given sin(\u03b8), cos(\u03b8), or tan(\u03b8) and the quadrant of the angle. b. Prove the addition and subtraction formulas for sine, cosine and tangent and use them to solve problems."},{"code":"KY.HS.F.3","subject":"Mathematics","grade":"10","text":"Understand average rate of change of a function over an interval. a. Calculate and interpret the average rate of change of a function (presented symbolically or as a table) over a specified interval. b. Estimate the rate of change from a graph. \u2605"},{"code":"KY.HS.F.4","subject":"Mathematics","grade":"10","text":"Graph functions expressed symbolically and show key features of the graph, with and without using technology (computer, graphing calculator). \u2605 a. Graph linear and quadratic functions and show intercepts, maxima and minima. b. Graph square root, cube root and absolute value functions. c. Graph polynomial functions, identifying zeros when suitable factorizations are available and showing end behavior. d. Graph exponential and logarithmic functions, showing intercepts and end behavior. e. (+) Graph trigonometric functions, showing period, midline and amplitude. f. (+) Graph piecewise functions, including step functions. g. (+) Graph rational functions, identifying zeros and asymptotes when suitable factorizations are available and showing end behavior."},{"code":"KY.HS.F.5","subject":"Mathematics","grade":"10","text":"Write a function defined by an expression in different but equivalent forms to reveal and explain different properties of the function. a. Identify zeros, extreme values and symmetry of the graph within the context of a quadratic function. a. Quadratic functions provide a rich playground for developing this ability, since the three principal forms for a quadratic expression (expanded, factored and completed square) each give insight into different aspects of the function. b. Students examine real-world situations with constant multiplicative change, represented as expressions, such as growth or decay."},{"code":"KY.HS.F.6","subject":"Mathematics","grade":"10","text":"Write a function that describes a relationship between two quantities. \u2605 a. Determine an explicit expression, a recursive process, or steps for calculation from a context. b. Combine standard function types using arithmetic operations. c. (+) Compose functions."},{"code":"KY.HS.F.7","subject":"Mathematics","grade":"10","text":"Use arithmetic and geometric sequences to model situations and scenarios. a. Use formulas (explicit and recursive) to generate terms for arithmetic and geometric sequences. b. Write formulas to model arithmetic and geometric sequences and apply those formulas in realistic situations. \u2605 c. (+) Translate between recursive and explicit formulas."},{"code":"KY.HS.F.8","subject":"Mathematics","grade":"10","text":"Understand the effects of transformations on the graph of a function. a. Identify the effect on the graph of replacing f(x) by f(x) + k, k f(x), f(kx) and f(x + k) for specific values of k (both positive and negative); find the value of k given the graphs. b. Experiment with cases and illustrate an explanation of the effects on the graph using technology."},{"code":"KY.HS.F.9","subject":"Mathematics","grade":"10","text":"Find inverse functions. a. Given the equation of an invertible function, find the inverse. b. (+) Verify by composition that one function is the inverse of another. c. (+) Read values of an inverse function from a graph or a table, given that the function has an inverse. d. (+) Produce an invertible function from a non-invertible function by restricting the domain."},{"code":"KY.HS.G.1","subject":"Mathematics","grade":"10","text":"Know and apply precise definitions of the language of Geometry: a. Understand properties of line segments, angles and circle. b. Understand properties of and differences between perpendicular and parallel lines."},{"code":"KY.HS.G.10","subject":"Mathematics","grade":"10","text":"Apply the properties of similarity transformations to establish the AA criterion for two triangles to be similar."},{"code":"KY.HS.G.11","subject":"Mathematics","grade":"10","text":"Understand theorems about triangles. a. Apply theorems about triangles. b. (+) Prove theorems about triangles. c. Use similarity criteria for triangles to solve problems and to prove relationships in geometric figures."},{"code":"KY.HS.G.12","subject":"Mathematics","grade":"10","text":"Understand properties of right triangles. a. Understand that by similarity, side ratios in right triangles are properties of the angles in the triangle, leading to definitions of trigonometric ratios for acute angles (sine, cosine and tangent). b. Explain and use the relationship between the sine and cosine of complementary angles. c. Use trigonometric ratios and the Pythagorean Theorem to solve right triangles in applied problems. \u2605"},{"code":"KY.HS.G.12c","subject":"Mathematics","grade":"10","text":"Use coordinates to justify and prove simple geometric theorems algebraically. Use similarity criteria for triangles to solve problems in geometric figures. Use trigonometric ratios and the Pythagorean Theorem to solve right triangles in applied problems.\u2605"},{"code":"KY.HS.G.13","subject":"Mathematics","grade":"10","text":"Derive the formula A = 1/2 ab sin(C) for the area of a triangle by drawing an auxiliary line from a vertex perpendicular to the opposite side."},{"code":"KY.HS.G.14","subject":"Mathematics","grade":"10","text":"Understand and apply the Law of Sines and the Law of Cosines. a. Use the Law of Sines and Cosines to find unknown measurements in right and non-right triangles. b. Prove the Laws of Sines and Cosines and use them to solve problems."},{"code":"KY.HS.G.15","subject":"Mathematics","grade":"10","text":"Verify using dilations that all circles are similar."},{"code":"KY.HS.G.16","subject":"Mathematics","grade":"10","text":"Identify and describe relationships among angles and segments within the context of circles involving: a. Recognize differences between and properties of inscribed, central and circumscribed angles. b. Understand relationships between inscribed angles and the diameter of a circle. c. Understand the relationship between the radius of a circle and the line drawn through the point of tangency on that radius."},{"code":"KY.HS.G.17","subject":"Mathematics","grade":"10","text":"Apply basic construction procedures within the context of a circle. a. Construct the inscribed and circumscribed circles of a triangle. b. Construct a tangent line from a point outside a given circle to the circle."},{"code":"KY.HS.G.18","subject":"Mathematics","grade":"10","text":"Understand the relationship between an intercepted arc length within a circle and the radius of the circle. a. Derive using similarity the fact that the length of the arc intercepted by an angle is proportional to the radius. Derive the formula for the area of a sector. b. Define the radian measure of the angle as the measure of a central angle that intercepts an arc equal in length to the radius of the circle."},{"code":"KY.HS.G.19","subject":"Mathematics","grade":"10","text":"Understand the relationship between the algebraic form and the geometric representation of a circle. a. Write the equation of a circle of given center and radius using the Pythagorean Theorem. b. (+) Derive and write the equation of a circle of given center and radius using the Pythagorean Theorem. c. (+) Complete the square to find the center and radius of a circle given by an equation."},{"code":"KY.HS.G.2","subject":"Mathematics","grade":"10","text":"Representing transformations in the plane. a. Describe transformations as functions that take points in the plane as inputs and give other points as outputs b. Compare transformations that preserve distance and angle measures to those that do not. c. Given a rectangle, parallelogram, trapezoid, or regular polygon, formally describe the rotations and reflections that carry it onto itself, using properties of these figures."},{"code":"KY.HS.G.20","subject":"Mathematics","grade":"10","text":"Derive the equations of conic sections. a. Derive the equation of a parabola given a focus and directrix. b. Derive the equations of ellipses and hyperbolas given the foci, using the fact that the sum or difference of distances from the foci is constant."},{"code":"KY.HS.G.21","subject":"Mathematics","grade":"10","text":"Use coordinates to justify and prove simple geometric theorems algebraically."},{"code":"KY.HS.G.22","subject":"Mathematics","grade":"10","text":"Justify and apply the slope criteria for parallel and perpendicular lines and use them to solve geometric problems."},{"code":"KY.HS.G.23","subject":"Mathematics","grade":"10","text":"Find measurements among points within the coordinate plane. a. Use points from the coordinate plane to find the coordinates of a midpoint of a line segment and the distance between the endpoints of a line segment. b. Find the point on a directed line segment between two given points that partitions the segment in a given ratio."},{"code":"KY.HS.G.24","subject":"Mathematics","grade":"10","text":"Use coordinates within the coordinate plane to calculate measurements of two dimensional figures. a. Compute the perimeters of various polygons. b. Compute the areas of triangles, rectangles and other quadrilaterals.\u2605"},{"code":"KY.HS.G.25","subject":"Mathematics","grade":"10","text":"Analyze and determine the validity of arguments for the formulas for the various figures and shapes. a. Finding the circumference and area of a circle. b. Finding the volume of a sphere, prism, cylinder, pyramid and cone."},{"code":"KY.HS.G.26","subject":"Mathematics","grade":"10","text":"Give an informal argument using Cavalieri\u2019s principle for the formulas for the volume of a sphere and other solid figures."},{"code":"KY.HS.G.27","subject":"Mathematics","grade":"10","text":"Use volume formulas to solve problems for cylinders, pyramids, cones, spheres, prisms \u2605"},{"code":"KY.HS.G.28","subject":"Mathematics","grade":"10","text":"Identify the shapes of two-dimensional cross-sections of three-dimensional objects and identify three-dimensional objects generated by rotations of two-dimensional objects."},{"code":"KY.HS.G.29","subject":"Mathematics","grade":"10","text":"Use geometric shapes, their measures and their properties to describe objects in real world settings."},{"code":"KY.HS.G.3","subject":"Mathematics","grade":"10","text":"Develop formal definitions of rotations, reflections and translations in terms of angles, circles, perpendicular lines, parallel lines and line segments."},{"code":"KY.HS.G.30","subject":"Mathematics","grade":"10","text":"Apply concepts of density based on area and volume in modeling situations, using appropriate units of measurement."},{"code":"KY.HS.G.31","subject":"Mathematics","grade":"10","text":"Apply geometric methods to solve design problems. \u2605"},{"code":"KY.HS.G.4","subject":"Mathematics","grade":"10","text":"Understand the effects of transformations of geometric figures. a. Given a geometric figure and a rotation, reflection, or translation, draw the transformed figure. b. Specify a sequence of transformations that will carry a given figure onto another. c. Use geometric descriptions of rigid motions to transform figures and to predict the effect of a given rigid motion on a given figure. Given two figures, use the definition of congruence in terms of rigid motions to decide if they are congruent."},{"code":"KY.HS.G.5","subject":"Mathematics","grade":"10","text":"Know and apply the concepts of triangle congruence: a. Use the definition of congruence in terms of rigid motions to show that two triangles are congruent if and only if corresponding pairs of sides and corresponding pairs of angles are congruent. b. Explain how the criteria for triangle congruence (ASA, SAS and SSS) follow from the definition of congruence in terms of rigid motions."},{"code":"KY.HS.G.6","subject":"Mathematics","grade":"10","text":"Apply theorems for lines, angles, triangles, parallelograms."},{"code":"KY.HS.G.7","subject":"Mathematics","grade":"10","text":"Prove theorems about geometric figures. a. Construct formal proofs to justify theorems for lines, angles and triangles. b. (+) Construct formal proofs to justify theorems for parallelograms."},{"code":"KY.HS.G.8","subject":"Mathematics","grade":"10","text":"Create and apply geometric constructions. a. Make formal geometric constructions with a variety of tools and methods. b. Apply basic construction procedures to construct more complex figures."},{"code":"KY.HS.G.9","subject":"Mathematics","grade":"10","text":"Understand properties of dilations. a. Verify the properties that result from that dilations given by a center and a scale factor. b. Verify that a dilation produces an image that is similar to the pre-image."},{"code":"KY.HS.N.1","subject":"Mathematics","grade":"10","text":"by extending student understanding to situations where the numerator is not one. For example, students understand that defining 4m/n is the same as \u221a4 \ud835\udc5b\ud835\udc5b m and ( \u221a4 \ud835\udc5b\ud835\udc5b )m. Include contextual examples, such as rewriting the volume of a sphere to identify the radius as a function of volume."},{"code":"KY.HS.N.10","subject":"Mathematics","grade":"10","text":"Extend polynomial identities to the complex numbers."},{"code":"KY.HS.N.11","subject":"Mathematics","grade":"10","text":"Know the Fundamental Theorem of Algebra; show that it is true for quadratic polynomials."},{"code":"KY.HS.N.12","subject":"Mathematics","grade":"10","text":"Understand and apply properties of vectors. a. Recognize vector quantities as having both magnitude and direction. Represent vector quantities by directed line segments and use appropriate symbols for vectors and their magnitudes. b. Find the components of a vector by subtracting the coordinates of an initial point from the coordinates of a terminal point. c. Solve problems involving velocity and other quantities that can be represented by vectors."},{"code":"KY.HS.N.13","subject":"Mathematics","grade":"10","text":"Perform operations with vectors (addition, subtraction and multiplication by a scalar). a. Add vectors end-to-end, component-wise and by the parallelogram rule. Understand that the magnitude of a sum of two vectors is typically not the sum of the magnitudes. b. Given two vectors in magnitude and direction form, determine the magnitude and direction of their sum. c. Understand vector subtraction v \u2013 w as v + (\u2013w), where \u2013w is the additive inverse of w, with the same magnitude as w and pointing in the opposite direction. Represent vector subtraction graphically by connecting the tips in the appropriate order and perform vector subtraction component-wise. d. Represent scalar multiplication graphically by scaling vectors and possibly reversing their direction; perform scalar multiplication component-wise. e. b. Compute the magnitude of a scalar multiple cv using ||cv|| = |c|v. Compute the direction of cv knowing that when |c|v \u2260 0, the direction of cv is either along v (for c > 0) or against v (for c < 0)."},{"code":"KY.HS.N.14","subject":"Mathematics","grade":"10","text":"Use matrices to represent and manipulate data."},{"code":"KY.HS.N.15","subject":"Mathematics","grade":"10","text":"Perform operations with matrices. a. Add, subtract and multiply matrices of appropriate dimensions. b. Multiply matrices by scalars to produce new matrices."},{"code":"KY.HS.N.16","subject":"Mathematics","grade":"10","text":"Understand properties of square and identity matrices. a. Understand that, unlike multiplication of numbers, matrix multiplication for square matrices is not a commutative operation, but still satisfies the associative and distributive properties. b. Understand that the zero and identity matrices play a role in matrix addition and multiplication similar to the role of 0 and 1 in the real numbers. The determinant of a square matrix is nonzero if and only if the matrix has a multiplicative inverse. c. Work with 2 \u00d7 2 matrices as transformations of the plane and interpret the absolute value of the determinant in terms of area."},{"code":"KY.HS.N.17","subject":"Mathematics","grade":"10","text":"Multiply a vector (regarded as a matrix with one column) by a matrix of suitable dimensions to produce another vector. Work with matrices as transformations of vectors."},{"code":"KY.HS.N.2","subject":"Mathematics","grade":"10","text":"Rewrite expressions involving radicals and rational exponents using the properties of exponents."},{"code":"KY.HS.N.3","subject":"Mathematics","grade":"10","text":"Justify why the sum or product of two rational numbers is rational; that the sum of a rational number and an irrational number is irrational; and that the product of a nonzero rational number and an irrational number is irrational."},{"code":"KY.HS.N.4","subject":"Mathematics","grade":"10","text":"Use units in context as a way to understand problems and to guide the solution of multi-step problems; \u2605 a. Choose and interpret units consistently in formulas; b. Choose and interpret the scale and the origin in graphs and data displays."},{"code":"KY.HS.N.5","subject":"Mathematics","grade":"10","text":"Define appropriate units in context for the purpose of descriptive modeling. \u2605"},{"code":"KY.HS.N.6","subject":"Mathematics","grade":"10","text":"does not require a formal discussion or use of significant digits in the scientific sense, students understand a level of precision. For example, when using the Pythagorean Theorem with measurements given in tenths of an inch, it is appropriate for students to express answers to the nearest tenth, but not to the nearest hundredth because that level of precision was not used in the original measures."},{"code":"KY.HS.N.7","subject":"Mathematics","grade":"10","text":"Understanding properties of complex numbers. a. Know there is a complex number i such that i2 = \u20131 and every complex number has the form a + bi with a and b real. b. Use the relation i2 = \u20131 and the commutative, associative and distributive properties to add, subtract and multiply complex numbers. c. (+) Find the conjugate of a complex number and use it to find the quotient of complex numbers."},{"code":"KY.HS.N.8","subject":"Mathematics","grade":"10","text":"Understanding representations of complex numbers using the complex plane. a. Represent complex numbers on the complex plane in rectangular and polar form (including real and imaginary numbers) and explain why the rectangular and polar forms of a given complex number represent the same number. b. Represent addition, subtraction, multiplication, modulus and conjugation of complex numbers geometrically on the complex plane; use properties of this representation for computation. c. Calculate the distance between numbers in the complex plane as the modulus of the difference and the midpoint of a segment as the average of the numbers at its endpoints."},{"code":"KY.HS.N.9","subject":"Mathematics","grade":"10","text":"Solve quadratic equations with real coefficients that have complex solutions."},{"code":"KY.HS.SP.1","subject":"Mathematics","grade":"10","text":"Represent the distribution of data with plots on the real number line (stem plots, dot plots, histograms and box plots)."},{"code":"KY.HS.SP.10","subject":"Mathematics","grade":"10","text":"Decide if a specified model is consistent with the results from a simulation."},{"code":"KY.HS.SP.11","subject":"Mathematics","grade":"10","text":"Recognize the purposes of and differences among sample surveys, experiments and observational studies; explain how randomization relates to each."},{"code":"KY.HS.SP.12","subject":"Mathematics","grade":"10","text":"Use data from a sample survey to estimate a population mean or proportion and explain how bias may be involved in the process."},{"code":"KY.HS.SP.13","subject":"Mathematics","grade":"10","text":"Use data from a randomized experiment to compare two treatments; use simulations to decide if differences between estimates or statistics are significant."},{"code":"KY.HS.SP.14","subject":"Mathematics","grade":"10","text":"Describe events as subsets of a sample space. Use characteristics (or categories) of the outcomes, such as, \u2022 as unions, \u201cA or B,\u201d that are mutually exclusive events and \u2022 as unions, \u201cA or B,\u201d that are non-mutually exclusive events and \u2022 as intersections, \u201cA and B,\u201d and \u2022 as complements of other events, \u201cnot A.\u201d to calculate basic probabilities."},{"code":"KY.HS.SP.15","subject":"Mathematics","grade":"10","text":"Understand the concept of independence. a. Understand that two events A and B are independent if the probability of A and B occurring together is the product of their individual probabilities, P(A) x P(B) b. (+) Determine whether two events are independent and provide a justification to support the decision. c. Recognize and explain the concept of independence in everyday language and everyday situations."},{"code":"KY.HS.SP.16","subject":"Mathematics","grade":"10","text":"Understand the concept of conditional probability. a. Understand the conditional probability of A given B as P(A and B)/P(B). b. (+) Interpret independence of A and B as saying that the conditional probability of A given B is the same as the probability of A and the conditional probability of B given A is the same as the probability of B. a. For any two events A and B, P(A given B) = \ud835\udc43\ud835\udc43(\ud835\udc34\ud835\udc34 \ud835\udc4e\ud835\udc4e\ud835\udc5b\ud835\udc5b\ud835\udc51\ud835\udc51 \ud835\udc35\ud835\udc35) \ud835\udc43\ud835\udc43(\ud835\udc35\ud835\udc35)."},{"code":"KY.HS.SP.17","subject":"Mathematics","grade":"10","text":"Construct and interpret two-way frequency tables of data when two categories are associated with each object being classified. Use the two-way table as a sample space to decide whether events are independent and to approximate conditional probabilities."},{"code":"KY.HS.SP.18","subject":"Mathematics","grade":"10","text":"Apply the General Multiplication Rule, P(A and B) = P(A)P(B|A) = P(B)P(A|B), in a uniform probability model and interpret the answer in terms of the model."},{"code":"KY.HS.SP.19","subject":"Mathematics","grade":"10","text":"Use permutations and combinations to compute probabilities. a. Distinguish between situations that can be modeled using counting techniques, including Fundamental Counting Principle, permutations and combinations. b. Perform calculations using the appropriate counting technique, including simple probabilities. c. (+) Use permutations and combinations to compute probabilities of compound events and solve problems."},{"code":"KY.HS.SP.2","subject":"Mathematics","grade":"10","text":"Use statistics appropriate to the shape of the numerical data distribution to compare center (median, mean) and spread (interquartile range when comparing medians and standard deviation when comparing means) of different data distributions."},{"code":"KY.HS.SP.20","subject":"Mathematics","grade":"10","text":"Define a random variable for a quantity of interest by assigning a numerical value to each event in a sample space; graph the corresponding probability distribution using the same appropriate graphical displays as for data distributions."},{"code":"KY.HS.SP.21","subject":"Mathematics","grade":"10","text":"Calculate the expected value of a random variable; interpret it as the mean of the probability distribution and use the value in analyzing decisions."},{"code":"KY.HS.SP.22","subject":"Mathematics","grade":"10","text":"Develop a probability distribution for a random variable. a. Find an expected value based on a sample space in which theoretical probabilities can be calculated. b. Find an expected value based on a sample space in which empirical probabilities can be calculated."},{"code":"KY.HS.SP.23","subject":"Mathematics","grade":"10","text":"Weigh the possible outcomes of a decision by assigning probabilities to payoff values and finding expected values. a. Find the expected payoff for a game of chance. b. Evaluate and compare strategies on the basis of expected values. c. Use calculated expected values to make fair decisions and formulate strategies."},{"code":"KY.HS.SP.3","subject":"Mathematics","grade":"10","text":"Interpret differences in shape, center and spread in the context of the distributions of the numerical data, accounting for the presence and possible effects of extreme data points (outliers)."},{"code":"KY.HS.SP.4","subject":"Mathematics","grade":"10","text":"When appropriate, fit a normal distribution to a numerical data set for given mean and standard deviation and then estimate population percentages using the Empirical Rule and recognize that there are data sets for which such a procedure is not appropriate."},{"code":"KY.HS.SP.5","subject":"Mathematics","grade":"10","text":"Summarize categorical data for two or more categories in frequency tables. Calculate and interpret joint, marginal and conditional relative frequencies (probabilities) in the context of the data, recognizing possible associations and trends in the data."},{"code":"KY.HS.SP.6","subject":"Mathematics","grade":"10","text":"Represent data on two quantitative variables on a scatter plot and describe how the explanatory and response variables are related. a. Calculate an appropriate mathematical model, or use a given mathematical model, for data to solve problems in context. b. Informally assess the fit of a model (through calculating correlation for linear data, plotting, calculating and/or analyzing residuals)."},{"code":"KY.HS.SP.7","subject":"Mathematics","grade":"10","text":"Interpret the slope (rate of change) and the intercept (constant term) of a linear model in the context of the data."},{"code":"KY.HS.SP.8","subject":"Mathematics","grade":"10","text":"Understand the role and purpose of correlation in linear regression. a. Use technology to compute correlation coefficient of a linear fit. b. Interpret the meaning of the correlation within the context of the data. c. Describe the limitations of correlation when establishing causation."},{"code":"KY.HS.SP.9","subject":"Mathematics","grade":"10","text":"in that results from non-random samples (Voluntary Response and Convenience) generate biased results when compared with more appropriate, random samples of the same population."},{"code":"HS-ESS1-1","subject":"Science","grade":"10","text":"Develop a model based on evidence to illustrate the life span of the sun and the role of nuclear fusion in the sun\u2019s core to release energy that eventually reaches Earth in the form of radiation."},{"code":"HS-ESS1-2","subject":"Science","grade":"10","text":"Construct an explanation of the Big Bang theory based on astronomical evidence of light spectra, motion of distant galaxies, and composition of matter in the universe."},{"code":"HS-ESS1-3","subject":"Science","grade":"10","text":"Communicate scientific ideas about the way stars, over their life cycle, produce elements."},{"code":"HS-ESS1-4","subject":"Science","grade":"10","text":"Use mathematical or computational representations to predict the motion of orbiting objects in the solar system."},{"code":"HS-ESS1-5","subject":"Science","grade":"10","text":"Evaluate evidence of the past and current movements of continental and oceanic crust and the theory of plate tectonics to explain the ages of crustal rocks."},{"code":"HS-ESS1-6","subject":"Science","grade":"10","text":"Apply scientific reasoning and evidence from ancient Earth materials, meteorites, and other planetary surfaces to construct an account of Earth\u2019s formation and early history."},{"code":"HS-ESS2-1","subject":"Science","grade":"10","text":"Develop a model to illustrate how Earth\u2019s internal and surface processes operate at different spatial and temporal scales to form continental and ocean-floor features."},{"code":"HS-ESS2-2","subject":"Science","grade":"10","text":"Analyze geoscience data to make the claim that one change to Earth\u2019s surface can create feedbacks that cause changes to other Earth systems."},{"code":"HS-ESS2-3","subject":"Science","grade":"10","text":"Develop a model based on evidence of Earth\u2019s interior to describe the cycling of matter by thermal convection."},{"code":"HS-ESS2-4","subject":"Science","grade":"10","text":"Use a model to describe how variations in the flow of energy into and out of Earth\u2019s systems result in changes in climate."},{"code":"HS-ESS2-5","subject":"Science","grade":"10","text":"Plan and conduct an investigation of the properties of water and its effects on Earth materials and surface processes."},{"code":"HS-ESS2-6","subject":"Science","grade":"10","text":"Develop a quantitative model to describe the cycling of carbon among the hydrosphere, atmosphere, geosphere, and biosphere."},{"code":"HS-ESS2-7","subject":"Science","grade":"10","text":"Construct an argument based on evidence about the simultaneous coevolution of Earth\u2019s systems and life on Earth."},{"code":"HS-ESS3-1","subject":"Science","grade":"10","text":"Construct an explanation based on evidence for how the availability of natural resources, occurrence of natural hazards, and changes in climate have influenced human activity."},{"code":"HS-ESS3-2","subject":"Science","grade":"10","text":"Evaluate competing design solutions for developing, managing, and utilizing energy and mineral resources based on cost- benefit ratios.*"},{"code":"HS-ESS3-3","subject":"Science","grade":"10","text":"Create a computational simulation to illustrate the relationships among the management of natural resources, the sustainability of human populations, and biodiversity."},{"code":"HS-ESS3-4","subject":"Science","grade":"10","text":"Evaluate or refine a technological solution that reduces impacts of human activities on natural systems.*"},{"code":"HS-ESS3-5","subject":"Science","grade":"10","text":"Analyze geoscience data and the results from global climate models to make an evidence-based forecast of the current rate of global or regional climate change and associated future impacts to Earth\u2019s systems."},{"code":"HS-ESS3-6","subject":"Science","grade":"10","text":"Use a computational representation to illustrate the relationships among Earth systems and how those relationships are being modified due to human activity."},{"code":"HS-ETS1-1","subject":"Science","grade":"10","text":"Analyze a major global challenge to specify qualitative and quantitative criteria and constraints for solutions that account for societal needs and wants. *"},{"code":"HS-ETS1-2","subject":"Science","grade":"10","text":"Design a solution to a complex real- world problem by breaking it down into smaller, more manageable problems that can be solved through engineering. *"},{"code":"HS-ETS1-3","subject":"Science","grade":"10","text":"Evaluate a solution to a complex real- world problem based on prioritized criteria and trade-offs that account for a range of constraints, including cost, safety, reliability, and aesthetics, as well as possible social, cultural, and environmental impacts. *"},{"code":"HS-ETS1-4","subject":"Science","grade":"10","text":"Use a computer simulation to model the impact of proposed solutions to a complex real- world problem with numerous criteria and constraints on interactions within and between systems relevant to the problem. *"},{"code":"HS-LS1-1","subject":"Science","grade":"10","text":"Construct an explanation based on evidence for how the structure of DNA determines the structure of proteins, which carry out the essential functions of life through systems of specialized cells."},{"code":"HS-LS1-2","subject":"Science","grade":"10","text":"Develop and use a model to illustrate the hierarchical organization of interacting systems that provide specific functions within multicellular organisms."},{"code":"HS-LS1-3","subject":"Science","grade":"10","text":"Plan and conduct an investigation to provide evidence that feedback mechanisms maintain homeostasis."},{"code":"HS-LS1-4","subject":"Science","grade":"10","text":"Use a model to illustrate the role of cellular division (mitosis) and differentiation in producing and maintaining complex organisms."},{"code":"HS-LS1-5","subject":"Science","grade":"10","text":"Use a model to illustrate how photosynthesis transforms light energy into stored chemical energy."},{"code":"HS-LS1-6","subject":"Science","grade":"10","text":"Construct and revise an explanation based on evidence for how carbon, hydrogen, and oxygen from sugar molecules may combine with other elements to form amino acids and/or other large carbon-based molecules."},{"code":"HS-LS1-7","subject":"Science","grade":"10","text":"Use a model to illustrate that cellular respiration is a chemical process whereby the bonds of food molecules and oxygen molecules are broken and the bonds in new compounds are formed, resulting in a net transfer of energy."},{"code":"HS-LS2-1","subject":"Science","grade":"10","text":"Use mathematical and/or computational representations to support explanations of factors that affect carrying capacity of ecosystems at different scales."},{"code":"HS-LS2-2","subject":"Science","grade":"10","text":"Use mathematical representations to support and revise explanations based on evidence about factors affecting biodiversity and populations in ecosystems of different scales."},{"code":"HS-LS2-3","subject":"Science","grade":"10","text":"Construct and revise an explanation based on evidence for the cycling of matter and flow of energy in aerobic and anaerobic conditions."},{"code":"HS-LS2-4","subject":"Science","grade":"10","text":"Use mathematical representations to support claims for the cycling of matter and flow of energy among organisms in an ecosystem."},{"code":"HS-LS2-5","subject":"Science","grade":"10","text":"Develop a model to illustrate the role of photosynthesis and cellular respiration in the cycling of carbon among the biosphere, atmosphere, hydrosphere, and geosphere."},{"code":"HS-LS2-6","subject":"Science","grade":"10","text":"Evaluate claims, evidence, and reasoning that the complex interactions in ecosystems maintain relatively consistent numbers and types of organisms in stable conditions, but changing conditions may result in a new ecosystem."},{"code":"HS-LS2-7","subject":"Science","grade":"10","text":"Design, evaluate, and refine a solution for reducing the impacts of human activities on the environment and biodiversit y.*"},{"code":"HS-LS2-8","subject":"Science","grade":"10","text":"Evaluate evidence for the role of group behavior on individual and species\u2019 chances to survive and reproduce."},{"code":"HS-LS3-1","subject":"Science","grade":"10","text":"Ask questions to clarify relationships about the role of DNA and chromosomes in coding the instructions for characteristic traits passed from parents to offspring."},{"code":"HS-LS3-2","subject":"Science","grade":"10","text":"Make and defend a claim based on evidence that inheritable genetic variations may result from (1) new genetic combinations through meiosis, (2) viable errors occurring during replication, and/or (3) mutations caused by environmental factors."},{"code":"HS-LS3-3","subject":"Science","grade":"10","text":"Apply concepts of statistics and probability to explain the variation and distribution of expressed traits in a population."},{"code":"HS-LS4-1","subject":"Science","grade":"10","text":"Communicate scientific information that common ancestry and biological evolution are supported by multiple lines of empirical evidence."},{"code":"HS-LS4-2","subject":"Science","grade":"10","text":"Construct an explanation based on evidence that the process of evolution primarily results from four factors: (1) the potential for a species to increase in number, (2) the heritable genetic variation of individuals in a species due to mutation and sexual reproduction, (3) competition for limited resources, and (4) the proliferation of those organisms that are better able to survive and reproduce in the environment."},{"code":"HS-LS4-3","subject":"Science","grade":"10","text":"Apply concepts of statistics and probability to support explanations that organisms with an advantageous heritable trait tend to increase in proportion to organisms lacking this trait."},{"code":"HS-LS4-4","subject":"Science","grade":"10","text":"Construct an explanation based on evidence for how natural selection leads to adaptation of populations."},{"code":"HS-LS4-5","subject":"Science","grade":"10","text":"Evaluate the evidence supporting claims that changes in environmental conditions may result in (1) increases in the number of individuals of some species, (2) the emergence of new species over time, and (3) the extinction of other species."},{"code":"HS-LS4-6","subject":"Science","grade":"10","text":"Create or revise a simulation to test a solution to mitigate adverse impacts of human activity on biodiversit y.*"},{"code":"HS-PS1-1","subject":"Science","grade":"10","text":"Use the periodic table as a model to predict the relative properties of elements based on the patterns of electrons in the outermost energy level of atoms."},{"code":"HS-PS1-2","subject":"Science","grade":"10","text":"Construct and revise an explanation for the outcome of a simple chemical reaction based on the outermost electron states of atoms, trends in the periodic table, and knowledge of the patterns of chemical properties."},{"code":"HS-PS1-3","subject":"Science","grade":"10","text":"Plan and conduct an investigation to gather evidence to compare the structure of substances at the macro and micro scale to infer the strength of electrical forces between particles."},{"code":"HS-PS1-4","subject":"Science","grade":"10","text":"Develop a model to illustrate that the release or absorption of energy from a chemical reaction system depends upon the changes in total bond energy."},{"code":"HS-PS1-5","subject":"Science","grade":"10","text":"Apply scientific principles and evidence to provide an explanation about the effects of changing the temperature or concentration of the reacting particles on the rate at which a reaction occurs."},{"code":"HS-PS1-6","subject":"Science","grade":"10","text":"Refine the design of a chemical system by specifying a change in conditions that would produce increased amounts of products at equilibrium.*"},{"code":"HS-PS1-7","subject":"Science","grade":"10","text":"Use mathematical representations to support the claim that atoms, and therefore mass, are conserved during a chemical reaction."},{"code":"HS-PS1-8","subject":"Science","grade":"10","text":"Develop models to illustrate the changes in the composition of the nucleus of the atom and the energy released during the processes of fission, fusion, and radioactive decay."},{"code":"HS-PS2-1","subject":"Science","grade":"10","text":"Analyze data to support the claim that Newton\u2019s second law of motion describes the mathematical relationship among the net force on a macroscopic object, its mass, and its acceleration."},{"code":"HS-PS2-2","subject":"Science","grade":"10","text":"Use mathematical representations to support the claim that the total momentum of a system of objects is conserved when there is no net force on the system."},{"code":"HS-PS2-3","subject":"Science","grade":"10","text":"Apply scientific and engineering ideas to design, evaluate, and refine a device that minimizes the force on a macroscopic object during a collision.*"},{"code":"HS-PS2-4","subject":"Science","grade":"10","text":"Use mathematical representations of Newton\u2019s law of gravitation and Coulomb\u2019s law to describe and predict the gravitational and electrostatic forces between objects."},{"code":"HS-PS2-5","subject":"Science","grade":"10","text":"Plan and conduct an investigation to provide evidence that an electric current can produce a magnetic field and that a changing magnetic field can produce an electric current."},{"code":"HS-PS2-6","subject":"Science","grade":"10","text":"Communicate scientific and technical information about why the molecular-level structure is important in the functioning of designed materials.*"},{"code":"HS-PS3-1","subject":"Science","grade":"10","text":"Create a computational model to calculate the change in the energy of one component in a system when the change in energy of the other component(s) and energy flows in and out of the system are known."},{"code":"HS-PS3-2","subject":"Science","grade":"10","text":"Develop and use models to illustrate that energy at the macroscopic scale can be accounted for as a combination of energy associated with the motion of particles (objects) and energy associated with the relative position of particles (objects)."},{"code":"HS-PS3-3","subject":"Science","grade":"10","text":"Design, build, and refine a device that works within given constraints to convert one form of energy into another form of energy.*"},{"code":"HS-PS3-4","subject":"Science","grade":"10","text":"Plan and conduct an investigation to provide evidence that the transfer of thermal energy when two components of different temperature are combined within a closed system results in a more uniform energy distribution among the components in the system (second law of thermodynamics)."},{"code":"HS-PS3-5","subject":"Science","grade":"10","text":"Develop and use a model of two objects interacting through electric or magnetic fields to illustrate the forces between objects and the changes in energy of the objects due to the interaction."},{"code":"HS-PS4-1","subject":"Science","grade":"10","text":"Use mathematical representations to support a claim regarding relationships among the frequency, wavelength, and speed of waves traveling in various media."},{"code":"HS-PS4-2","subject":"Science","grade":"10","text":"Evaluate questions about the advantages of using digital transmission and storage of information."},{"code":"HS-PS4-3","subject":"Science","grade":"10","text":"Evaluate the claims, evidence, and reasoning behind the idea that electromagnetic radiation can be described either by a wave model or a particle model, and that for some situations one model is more useful than the other."},{"code":"HS-PS4-4","subject":"Science","grade":"10","text":"Evaluate the validity and reliability of claims in published materials of the effects that different frequencies of electromagnetic radiation have when absorbed by matter."},{"code":"HS-PS4-5","subject":"Science","grade":"10","text":"Communicate technical information about how some technological devices use the principles of wave behavior and wave interactions with matter to transmit and capture information and energy.*"},{"code":"HS.C.CP.1","subject":"Social Studies","grade":"10","text":"Explain how the Cons titution of the United States embodies the principles of rule of law, popular sovereignty, republicanism, federalism, separation of powers and checks and balances to promote general welfare."},{"code":"HS.C.CP.2","subject":"Social Studies","grade":"10","text":"Analyze legislative, executive and judicial branch decisions in terms of constitutionality and impact on citizens and states."},{"code":"HS.C.CP.3","subject":"Social Studies","grade":"10","text":"Compare various forms of government and how each maintains order, upholds human rights and interacts within the international community."},{"code":"HS.C.CP.4","subject":"Social Studies","grade":"10","text":"Evaluate how the U.S. judicial system is designed to uphold equality before the law, due process and inalienable rights."},{"code":"HS.C.CV.1","subject":"Social Studies","grade":"10","text":"Explain how classic al republicanism, natural rights philosophy and English common law influenced the thinking and actions of the American Founders."},{"code":"HS.C.CV.2","subject":"Social Studies","grade":"10","text":"Assess how the expansion of civic virtues, democratic principles, constitutional rights and human rights influence the thoughts and actions of individuals and groups."},{"code":"HS.C.CV.3","subject":"Social Studies","grade":"10","text":"Analyze the impact of the e fforts of individuals and reform movements on the expansion of civil rights and liberties locally, nationally and internationally."},{"code":"HS.C.KGO.1","subject":"Social Studies","grade":"10","text":"Explain how the Ke ntucky Constitution embodies the principles of rule of law, popular sovereignty, separation of powers and checks and balances."},{"code":"HS.C.KGO.2","subject":"Social Studies","grade":"10","text":"Compare Kentucky\u2019s government to other states and to the federal government."},{"code":"HS.C.KGO.3","subject":"Social Studies","grade":"10","text":"Describe how active citizens can affect change in their communities and Kentucky Informed and engaged citizenship is a crucial part of the successful functioning of Kentucky."},{"code":"HS.C.PR.1","subject":"Social Studies","grade":"10","text":"Analyze the role of the thre e branches of government in the lawmaking process."},{"code":"HS.C.PR.2","subject":"Social Studies","grade":"10","text":"Analyze the role of elections, bureaucracy, political parties, interest groups and media in shaping public policy."},{"code":"HS.C.PR.3","subject":"Social Studies","grade":"10","text":"Evaluate intended and unintended consequences of public policies locally, nationally and internationally."},{"code":"HS.C.PR.4","subject":"Social Studies","grade":"10","text":"Compare the domestic and foreign policies of the United States and other countries."},{"code":"HS.C.RR.1","subject":"Social Studies","grade":"10","text":"Evaluate the civic r esponsibilities of individuals within a society."},{"code":"HS.C.RR.2","subject":"Social Studies","grade":"10","text":"Explain how active citizens can affect the lawmaking process locally, nationally and internationally. internationally engaged citizens are critical to positively evolving societies."},{"code":"HS.E.IC.1","subject":"Social Studies","grade":"10","text":"Predict the way scarcity causes individuals, organizations and governments to evaluate tradeoffs, make choices and incur opportunity costs."},{"code":"HS.E.IC.2","subject":"Social Studies","grade":"10","text":"Evaluate how individuals, organizations and governments respond to incentives in the decision- making process."},{"code":"HS.E.IC.3","subject":"Social Studies","grade":"10","text":"Perform a cost-benefit analysis on a real-world situation, using economic thinking to describe the marginal costs and benefits of a particular situation."},{"code":"HS.E.IC.4","subject":"Social Studies","grade":"10","text":"Evaluate how incentives determine what is produced and distributed in a competitive market system."},{"code":"HS.E.KE.1","subject":"Social Studies","grade":"10","text":"Analyze how national and international trends and policies impact Kentucky\u2019s state and local economies."},{"code":"HS.E.KE.2","subject":"Social Studies","grade":"10","text":"Analyze how national and international trends and policies impact Kentucky\u2019s state and local economies."},{"code":"HS.E.KE.3","subject":"Social Studies","grade":"10","text":"Analyze how the four components of Gross Domestic Product (GDP) are combined to assess the health of Kentucky\u2019s economy."},{"code":"HS.E.MA.1","subject":"Social Studies","grade":"10","text":"Evaluate how valu es and beliefs like economic freedom, equity, full employment, price stability, security, efficiency and growth help to form different types of economic systems."},{"code":"HS.E.MA.2","subject":"Social Studies","grade":"10","text":"Analyze ways in which competition and government regulation influence what is produced and allocated in an economy."},{"code":"HS.E.MA.3","subject":"Social Studies","grade":"10","text":"Describe the externalities of government attempts to remedy market failure and improve market outcomes through fiscal policy."},{"code":"HS.E.MA.4","subject":"Social Studies","grade":"10","text":"Analyze the impact of fiscal policies, various government taxation and spending policies on the economy."},{"code":"HS.E.MA.5","subject":"Social Studies","grade":"10","text":"Assess how interest rates influence borrowing and investing."},{"code":"HS.E.MA.6","subject":"Social Studies","grade":"10","text":"Assess the effectiveness of rules and laws that protect both consumers and producers."},{"code":"HS.E.MA.7","subject":"Social Studies","grade":"10","text":"Explain how the Federal Reserve uses monetary policy to promote price stability, employment and economic growth."},{"code":"HS.E.MI.1","subject":"Social Studies","grade":"10","text":"Compare per fect competition, monopolistic competition, oligopoly and monopoly and how the extent of competition within various markets affects price, quantity and variety in production."},{"code":"HS.E.MI.2","subject":"Social Studies","grade":"10","text":"Analyze and graph the impact of supply and demand shifts on equilibrium price and quantities produced."},{"code":"HS.E.MI.3","subject":"Social Studies","grade":"10","text":"Analyze the roles of product and factor markets."},{"code":"HS.E.MI.4","subject":"Social Studies","grade":"10","text":"Compare the roles of consumers and producers in the product, labor and financial markets and the economy as a whole."},{"code":"HS.E.ST.1","subject":"Social Studies","grade":"10","text":"Draw conclusions regarding the effect of specialization and trade on production, distribution and consumption of goods and services for individuals, businesses and societies."},{"code":"HS.E.ST.2","subject":"Social Studies","grade":"10","text":"Analyze the role of comparative advantage in international trade of goods and services."},{"code":"HS.E.ST.3","subject":"Social Studies","grade":"10","text":"Explain how international economic trends and policies affect political, social and economic conditions in various nations. (see \u201ccontinued\u201d) Nations in the modern world are affected by the interconnectedness of economies, which causes ripple effects across borders."},{"code":"HS.G.GR.1","subject":"Social Studies","grade":"10","text":"Interpret the relationships among human and physical patterns and processes at local, national and global scales."},{"code":"HS.G.GR.2","subject":"Social Studies","grade":"10","text":"Analyze how environmental factors influence population distributions from place to place."},{"code":"HS.G.HE.1","subject":"Social Studies","grade":"10","text":"Assess the reciproc al relationship between physical environment and culture within local, national and global scales."},{"code":"HS.G.HE.2","subject":"Social Studies","grade":"10","text":"Analyze how human settlements are influenced by or influence the relationship between people and the environment."},{"code":"HS.G.HI.1","subject":"Social Studies","grade":"10","text":"Analyze how the forces of cooperation and conflict within and among people, nations and empires influence the division and control of Earth\u2019s surface and resources."},{"code":"HS.G.HI.2","subject":"Social Studies","grade":"10","text":"Analyze how cultural and economic decisions influence the characteristics of various places."},{"code":"HS.G.HI.3","subject":"Social Studies","grade":"10","text":"Explain how people create natural and cultural regions to interpret Earth\u2019s complexity."},{"code":"HS.G.KGE.1","subject":"Social Studies","grade":"10","text":"Explain how Kentuckians view sense of place differently based on cultural and environmental characteristics of varying regions of the state."},{"code":"HS.G.KGE.2","subject":"Social Studies","grade":"10","text":"Explain how the geography of Kentucky influences the development of the state."},{"code":"HS.G.MM.1","subject":"Social Studies","grade":"10","text":"Analyze how cult ural, economic and environmental factors contribute to migration patterns and population distribution at multiple scales."},{"code":"HS.G.MM.2","subject":"Social Studies","grade":"10","text":"Evaluate reasons for the spatial distribution of human populations at different scales on Earth\u2019s surface."},{"code":"C.11-12.1","subject":"English Language Arts","grade":"11","text":"Compose arguments to support claims in an analysis of substantive topics or texts, using valid reasoning and relevant and sufficient evidence. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce precise, knowledgeable claim(s), establish the significance of the claim(s), distinguish the claim(s) from alternate or opposing claims and create an organization that logically sequences claim(s), counterclaims, reasons and evidence. c. Develop claim(s) and opposing claims fairly and thoroughly, supplying the most relevant evidence for each while pointing out the strengths and limitations of both in a manner that anticipates the audience\u2019s knowledge level, concerns, values and possible biases. d. Use words, phrases and clauses as well as varied syntax to link the major sections of the text, create cohesion and clarify the relationships between claim(s) and reasons, between reasons and evidence and between claim(s) and opposing claims. e. Establish and maintain a task-appropriate writing style. f. Provide a concluding statement or section that follows from and supports the argument presented. g. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience."},{"code":"C.11-12.2","subject":"English Language Arts","grade":"11","text":"Compose informative/explanatory texts to examine and/or convey complex ideas, concepts and information clearly and accurately through the effective selection, organization and analysis of content. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce a topic; organize complex ideas, concepts and information so that each new element builds on that which precedes it to create a unified whole; include formatting, graphics and multimedia when useful to aiding comprehension. c. Develop the topic thoroughly by selecting the most significant and relevant facts, extended definitions, concrete details, quotations or other information and examples appropriate to the audience\u2019s knowledge of the topic. d. Use appropriate and varied transitions and syntax to link the major sections of the text, create cohesion and clarify the relationships among complex ideas and concepts. e. Use precise language, domain-specific vocabulary and techniques such as metaphor, simile and analogy to manage the complexity of the topic. f. Establish and maintain a formal style and objective tone while attending to the norms and conventions of the discipline in which they are writing. g. Provide a concluding statement or section that follows from and supports the information or explanation presented. h. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience."},{"code":"C.11-12.3","subject":"English Language Arts","grade":"11","text":"Use narratives strategically in other modes of writing utilizing effective technique, well-chosen details and well-structured sequences for an intended purpose, including but not limited to introducing an issue and/or supporting a claim. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Engage and orient the reader by setting up a problem, situation or observation and its significance, establishing one or multiple point(s) of view and introducing a narrator and/or characters; create a smooth progression of experiences or events. c. Use narrative techniques, such as dialogue, pacing, description, reflection and multiple plot lines, to develop experiences, events and/or characters. d. Use a variety of techniques to sequence events so that they build on one another to create a coherent whole and build toward a particular tone and outcome. e. Use precise words and phrases, telling details and sensory language to convey a vivid picture of the experiences, events, setting and/or characters. f. Provide a conclusion that explicitly connects the narrative\u2019s relevance to the intended purpose of the writing. g. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience. Production and Distribution"},{"code":"C.11-12.4","subject":"English Language Arts","grade":"11","text":"Use DIGITAL RESOURCES to create, publish and update individual or shared products , taking advantage of technology\u2019s capacity to link to other information and to display information flexibly and dynamically. Use a variety of formats to cite sources ."},{"code":"C.11-12.5","subject":"English Language Arts","grade":"11","text":"Conduct short as well as more sustained RESEARCH projects to answer a question (including a self-generated question) or solve a problem; narrow or broaden the inquiry when appropriate; synthesize multiple sources on the subject , demonstrating understanding of the subject under investigation ."},{"code":"C.11-12.6","subject":"English Language Arts","grade":"11","text":"Gather relevant information from multiple authoritative print and digital sources, using advanced searches effectively ; assess the strengths and limitations of each source in terms of the task, purpose and audience; integrate information into the text selectively to maintain the flow of ideas, avoiding plagiarism and overreliance on any one source and following a standard format for citation ."},{"code":"C.11-12.7","subject":"English Language Arts","grade":"11","text":"Compose routinely over extended time frames and shorter time frames for a variety of task, purposes and audiences ."},{"code":"L.11-12.1","subject":"English Language Arts","grade":"11","text":"In both written and oral expression : a. Demonstrate the understanding that usage is a matter of convention , can change over time and may be contested . b. Resolve issues of complex or contested usage , consulting references as needed ."},{"code":"L.11-12.2","subject":"English Language Arts","grade":"11","text":"When writing : a. Demonstrate command of the CONVENTIONS OF GENERAL AMERICAN ENGLISH CAPITALIZATION, PUNCTUATION AND SPELLING ."},{"code":"L.11-12.3","subject":"English Language Arts","grade":"11","text":"Apply knowledge of language to understand how language functions in different contexts, to make effective choices for meaning or style and to comprehend more fully when reading or listening . a. Apply an understanding of syntax to the study of complex texts when reading . b. Vary syntax for effect in writing and speaking , consulting references for guidance as needed ."},{"code":"L.11-12.4","subject":"English Language Arts","grade":"11","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grades 11-12 reading and content, choosing flexibly from an array of strategies . a. Use context (e.g., the overall meaning of a sentence, paragraph or text; a word\u2019s position or function in a sentence) as a clue to the meaning of a word or phrase . b. Identify and correctly use patterns of word changes that indicate different meanings or parts of speech . c. Consult general and specialized reference materials to find the pronunciation of a word or determine or clarify its precise meaning or its part of speech . d. Acquire and use accurately general academic and domain-specific words and phrases, sufficient for reading, writing, speaking and listening at the postsecondary readiness level; demonstrate independence in gathering vocabulary knowledge when considering a word or phrase important to comprehension or expression ."},{"code":"L.11-12.5","subject":"English Language Arts","grade":"11","text":"Demonstrate understanding of figurative language, word relationships and nuances in word meanings . a. Interpret FIGURES OF SPEECH in context , including but not limited to HYPERBOLE and PARADOX , and analyze their rhetorical function in the text . b. Analyze nuances in the meaning of words with similar denotations ."},{"code":"L.11-12.5b","subject":"English Language Arts","grade":"11","text":"Language, Grades 11-12, Standard 5, Substandard b Reading Foundational Skills RF"},{"code":"RI.11-12.1","subject":"English Language Arts","grade":"11","text":"CITE RELEVANT AND THOROUGH TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RI.11-12.10","subject":"English Language Arts","grade":"11","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RI.11-12.2","subject":"English Language Arts","grade":"11","text":"Determine TWO OR MORE CENTRAL IDEAS OF A TEXT and analyze their development over the course of the text , including how they interact and build on one another to produce a complex account ."},{"code":"RI.11-12.3","subject":"English Language Arts","grade":"11","text":"Analyze a COMPLEX SET OF IDEAS OR SEQUENCE OF EVENTS and explain how specific individuals, ideas or events interact and develop over the course of the text ."},{"code":"RI.11-12.4","subject":"English Language Arts","grade":"11","text":"Determine the meaning of words and phrases as they are used in a text, including figurative, connotative, and technical meanings; analyze how an author uses and refines THE MEANING OF A KEY TERM OR TERMS over the course of a text ."},{"code":"RI.11-12.5","subject":"English Language Arts","grade":"11","text":"Analyze and evaluate the effectiveness of the structure an author uses in his or her EXPOSITION or ARGUMENT ."},{"code":"RI.11-12.6","subject":"English Language Arts","grade":"11","text":"Determine an author\u2019s POINT OF VIEW, PERSPECTIVE and PURPOSE in a text in which the RHETORIC is particularly effective, analyzing how style and content contribute to the effectiveness of the text ."},{"code":"RI.11-12.7","subject":"English Language Arts","grade":"11","text":"Integrate and evaluate MULTIPLE SOURCES OF INFORMATION presented in different print and non-print formats in order to address a question or solve a problem ."},{"code":"RI.11-12.8","subject":"English Language Arts","grade":"11","text":"Evaluate the ARGUMENT , specific CLAIMS and EVIDENCE in a text, assessing the validity, reasoning, relevance and sufficiency; analyze false statements and FALLACIOUS REASONING ."},{"code":"RI.11-12.9","subject":"English Language Arts","grade":"11","text":"Analyze DOCUMENTS OF HISTORICAL AND LITERARY SIGNIFICANCE for their themes, purposes and rhetorical features ."},{"code":"RL.11-12.1","subject":"English Language Arts","grade":"11","text":"CITE RELEVANT AND THOROUGH TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RL.11-12.10","subject":"English Language Arts","grade":"11","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.11-12.2","subject":"English Language Arts","grade":"11","text":"Determine TWO OR MORE THEMES OR CENTRAL IDEAS of a text and analyze their development over the course of the text , including how they interact and build on one another to produce a complex account ."},{"code":"RL.11-12.3","subject":"English Language Arts","grade":"11","text":"Analyze the IMPACT OF THE AUTHOR\u2019S CHOICES over the course of a text regarding how to develop and relate elements of a story or drama ."},{"code":"RL.11-12.4","subject":"English Language Arts","grade":"11","text":"Determine the meaning of words and phrases as they are used in the text, including figurative and connotative meanings; analyze the cumulative impact of specific WORD CHOICES on meaning and TONE and on the text as a whole ."},{"code":"RL.11-12.5","subject":"English Language Arts","grade":"11","text":"Analyze how an author\u2019s choices concerning how to STRUCTURE SPECIFIC PARTS OF A TEXT contribute to its overall structure and meaning as well as its aesthetic impact ."},{"code":"RL.11-12.6","subject":"English Language Arts","grade":"11","text":"Analyze how POINT OF VIEW AND PERSPECTIVE are used to manipulate the reader for a specific purpose or effect , including but not limited to SATIRE, SARCASM, IRONY AND UNDERSTATEMENT ."},{"code":"RL.11-12.7","subject":"English Language Arts","grade":"11","text":"Analyze DIVERSE MEDIA INTERPRETATIONS OF A STORY, DRAMA OR POEM , evaluating how each version interprets the source text ."},{"code":"RL.11-12.8","subject":"English Language Arts","grade":"11","text":"Not applicable to literature"},{"code":"RL.11-12.9","subject":"English Language Arts","grade":"11","text":"Demonstrate knowledge of various time periods to analyze how TWO OR MORE TEXTS FROM THE SAME PERIOD treat similar themes or topics ."},{"code":"KY.HS.A.1","subject":"Mathematics","grade":"11","text":"Interpret expressions that represent a quantity in terms of its context. \u2605 a. Interpret parts of an expression, such as terms, factors and coefficients. b. Interpret complicated expressions, given a context, by viewing one or more of their parts as a single entity."},{"code":"KY.HS.A.10","subject":"Mathematics","grade":"11","text":"Rewrite simple rational expressions in different forms."},{"code":"KY.HS.A.11","subject":"Mathematics","grade":"11","text":"Add, subtract, multiply and divide rational algebraic expressions."},{"code":"KY.HS.A.12","subject":"Mathematics","grade":"11","text":"Create equations and inequalities in one variable and use them to solve problems."},{"code":"KY.HS.A.13","subject":"Mathematics","grade":"11","text":"Create equations in two or more variables to represent relationships between quantities; graph equations on coordinate axes with labels and scales."},{"code":"KY.HS.A.14","subject":"Mathematics","grade":"11","text":"Create a system of equations or inequalities to represent constraints within a modeling context. Interpret the solution(s) to the corresponding system as viable or nonviable options within the context."},{"code":"KY.HS.A.15","subject":"Mathematics","grade":"11","text":"Rearrange formulas to solve a literal equation, highlighting a quantity of interest, using the same reasoning as in solving equations."},{"code":"KY.HS.A.16","subject":"Mathematics","grade":"11","text":"Understand each step in solving a simple equation as following from the equality of numbers asserted at the previous step, starting from the assumption that the original equation has a solution. Construct a viable argument to justify a solution method."},{"code":"KY.HS.A.17","subject":"Mathematics","grade":"11","text":"Solve and justify equations in one variable. Justify the solutions and give examples showing how extraneous solutions may arise. a. Solve rational equations written as proportions in one variable. b. Solve radical equations in one variable."},{"code":"KY.HS.A.18","subject":"Mathematics","grade":"11","text":"Solve linear equations and inequalities in one variable, including literal equations with coefficients represented by letters."},{"code":"KY.HS.A.19","subject":"Mathematics","grade":"11","text":"Solve quadratic equations in one variable. a. Solve quadratic equations by taking square roots, the quadratic formula and factoring, as appropriate to the initial form of the equation. Recognize when the quadratic formula gives complex solutions and write them as a \u00b1 bi for real numbers a and b. b. (+) Use the method of completing the square to transform any quadratic equation in x into an equation of the form (x \u2013 p)2 = q that has the same solutions. Derive the quadratic formula from this form. c. (+) Solve quadratic equations by completing the square."},{"code":"KY.HS.A.2","subject":"Mathematics","grade":"11","text":"Use the structure of an expression to identify ways to rewrite it and consistently look for opportunities to rewrite expressions in equivalent forms."},{"code":"KY.HS.A.20","subject":"Mathematics","grade":"11","text":"Solve systems of linear equations in two variables. a. Understand a system of two equations in two variables has the same solution as a new system formed by replacing one of the original equations with an equivalent equation. b. Solve systems of linear equations with graphs, substitution and elimination, focusing on pairs of linear equations in two variables."},{"code":"KY.HS.A.21","subject":"Mathematics","grade":"11","text":"Solve a simple system consisting of a linear equation and a quadratic equation in two variables algebraically and graphically."},{"code":"KY.HS.A.22","subject":"Mathematics","grade":"11","text":"Use matrices to solve a system of equations. a. Represent a system of linear equations as a single matrix equation in a vector variable. b. Find the inverse of a matrix if it exists. c. Use matrices to solve systems of linear equations (using technology for matrices of dimension 3 \u00d7 3 or greater)."},{"code":"KY.HS.A.23","subject":"Mathematics","grade":"11","text":"Understand that the graph of an equation in two variables is the set of all its solutions plotted in the coordinate plane."},{"code":"KY.HS.A.24","subject":"Mathematics","grade":"11","text":"Justify that the solutions of the equations f(x) = g(x) are the x-coordinates of the points where the graphs of y = f(x) and y = g(x) intersect. Find the approximate solutions graphically, using technology or tables. \u2605"},{"code":"KY.HS.A.25","subject":"Mathematics","grade":"11","text":"Graph linear inequalities in two variables. a. Graph the solutions to a linear inequality as a half-plane (excluding the boundary in the case of a strict inequality). b. Graph the solution set to a system of linear inequalities as the intersection of the corresponding half-planes."},{"code":"KY.HS.A.3","subject":"Mathematics","grade":"11","text":"Choose and produce an equivalent form of an expression to reveal and explain properties of the quantity represented by the expression. \u2605 a. Write the standard form of a given polynomial and identify the terms, coefficients, degree, leading coefficient and constant term. b. Factor a quadratic expression to reveal the zeros of the function it defines. c. Use the properties of exponents to rewrite exponential expressions. d. (+) Complete the square in a quadratic expression to reveal the maximum or minimum value of the function it defines."},{"code":"KY.HS.A.3b","subject":"Mathematics","grade":"11","text":"Students recognize the connection between the zero product property and solving a quadratic in one variable by setting factored expressions equal to zero."},{"code":"KY.HS.A.3d","subject":"Mathematics","grade":"11","text":"Students recognize being able to complete the square allows them to identify the coordinates of the maximum or minimum value more easily than when the quadratic is in standard form and there are pros and cons of each equivalent form."},{"code":"KY.HS.A.4","subject":"Mathematics","grade":"11","text":"Derive the formula for the sum of a finite geometric series (when the common ratio is not 1) and use the formula to solve problems. \u2605"},{"code":"KY.HS.A.5","subject":"Mathematics","grade":"11","text":"Add, subtract and multiply polynomials."},{"code":"KY.HS.A.6","subject":"Mathematics","grade":"11","text":"Know and apply the Remainder Theorem."},{"code":"KY.HS.A.7","subject":"Mathematics","grade":"11","text":"Identify roots of polynomials when suitable factorizations are available. Know these roots become the zeros (x-intercepts) for the corresponding polynomial function."},{"code":"KY.HS.A.8","subject":"Mathematics","grade":"11","text":"Prove polynomial identities and use them to describe numerical relationships."},{"code":"KY.HS.A.9","subject":"Mathematics","grade":"11","text":"Know and apply the Binomial Theorem for the expansion of (x + y )n in powers of x and y for a positive integer n, where x and y are any numbers, with coefficients determined for example by Pascal\u2019s Triangle."},{"code":"KY.HS.C.1","subject":"Mathematics","grade":"11","text":"Understand limits. a. Apply limits to a variety of functions, including piecewise functions. b. (++) Prove that the limit of a function exists, based upon the definition of a limit."},{"code":"KY.HS.C.10","subject":"Mathematics","grade":"11","text":"Communicate an understanding of continuity using precise mathematical symbols and language."},{"code":"KY.HS.C.11","subject":"Mathematics","grade":"11","text":"Define derivatives. a. Define the derivative of a function as the limit of the difference quotient. b. Understand this limit of the difference quotient can be interpreted as an instantaneous rate of change or the slope of a tangent line."},{"code":"KY.HS.C.12","subject":"Mathematics","grade":"11","text":"Use average rate of change to estimate the derivative from a table of values or a graph."},{"code":"KY.HS.C.13","subject":"Mathematics","grade":"11","text":"Understand the derivative as a function."},{"code":"KY.HS.C.15","subject":"Mathematics","grade":"11","text":"Explain why differentiability implies continuity yet continuity does not imply differentiability."},{"code":"KY.HS.C.16","subject":"Mathematics","grade":"11","text":"Understand and apply the Mean Value Theorem, including numerical, graphical and algebraic representations."},{"code":"KY.HS.C.17","subject":"Mathematics","grade":"11","text":"Understand the relationship between the concavity of a function and the sign of the second derivative."},{"code":"KY.HS.C.18","subject":"Mathematics","grade":"11","text":"Understand Rolle\u2019s Theorem as a special case of the Mean Value Theorem."},{"code":"KY.HS.C.19","subject":"Mathematics","grade":"11","text":"Efficiently find derivatives of functions with and without technology."},{"code":"KY.HS.C.2","subject":"Mathematics","grade":"11","text":"Demonstrate an understanding of limits by estimating and finding the limit of a function at a point graphically, numerically and algebraically."},{"code":"KY.HS.C.20","subject":"Mathematics","grade":"11","text":"Understand and use derivative rules for sums, differences, products and quotients of two functions and calculate the derivative of a composite function using the chain rule. MP2,"},{"code":"KY.HS.C.21","subject":"Mathematics","grade":"11","text":"Use implicit differentiation to find a derivative in an equation of two variables."},{"code":"KY.HS.C.22","subject":"Mathematics","grade":"11","text":"Use implicit differentiation to find the derivative of the inverse of a function."},{"code":"KY.HS.C.23","subject":"Mathematics","grade":"11","text":"Understand the relationship between the increasing and decreasing behavior of a function and the sign of the first derivative of the function."},{"code":"KY.HS.C.24","subject":"Mathematics","grade":"11","text":"Use the first derivative to analyze curves and identify relative extrema."},{"code":"KY.HS.C.25","subject":"Mathematics","grade":"11","text":"Understand the relationship of concavity to the second derivative."},{"code":"KY.HS.C.26","subject":"Mathematics","grade":"11","text":"Use the second derivative to find points of inflection."},{"code":"KY.HS.C.27","subject":"Mathematics","grade":"11","text":"Use the second derivative to analytically locate intervals on which a function is concave up, concave down or neither."},{"code":"KY.HS.C.28","subject":"Mathematics","grade":"11","text":"Describe how graphical characteristics of a given function, the first derivative of that function and the second derivative of that function interrelate."},{"code":"KY.HS.C.29","subject":"Mathematics","grade":"11","text":"Use derivatives to express rate of change in a variety of contexts."},{"code":"KY.HS.C.3","subject":"Mathematics","grade":"11","text":"Apply properties and theorems of limits, including limits of indeterminate forms."},{"code":"KY.HS.C.30","subject":"Mathematics","grade":"11","text":"Use derivatives to solve a variety of problems including related rates, optimization, tangent line approximations and growth and decay models."},{"code":"KY.HS.C.31","subject":"Mathematics","grade":"11","text":"Use differentiation to solve problems involving velocity, speed and acceleration."},{"code":"KY.HS.C.32","subject":"Mathematics","grade":"11","text":"Understand and apply differential equations. a. Verify solutions to differential equations and use them to model real-world problems with and without technology. b. Solve separable differential equations and use them in modeling real-world problems with and without technology."},{"code":"KY.HS.C.33","subject":"Mathematics","grade":"11","text":"Understand the definite integral of a function over an interval. Interpret a definite integral as a limit of Riemann Sums and as net accumulation of change."},{"code":"KY.HS.C.34","subject":"Mathematics","grade":"11","text":"Write a Riemann sum that represents the definition of a definite integral."},{"code":"KY.HS.C.35","subject":"Mathematics","grade":"11","text":"Calculate the values of Riemann Sums over equal subdivisions to approximate definite integrals of functions represented graphically and numerically (using tables). Use left-hand sums, right- hand sums, midpoint sums and trapezoidal sums."},{"code":"KY.HS.C.36","subject":"Mathematics","grade":"11","text":"Recognize differentiation and integration as inverse operations."},{"code":"KY.HS.C.37","subject":"Mathematics","grade":"11","text":"Understand how the Fundamental Theorem of Calculus connects differentiation and integration and use it to evaluate definite and indefinite integrals and to represent particular antiderivatives."},{"code":"KY.HS.C.38","subject":"Mathematics","grade":"11","text":"Perform analytical and graphical analysis of functions using the Fundamental Theorem of Calculus."},{"code":"KY.HS.C.39","subject":"Mathematics","grade":"11","text":"Understand and use the definite integral of a function over an interval and understand its use as a mathematical tool."},{"code":"KY.HS.C.4","subject":"Mathematics","grade":"11","text":"Communicate understanding of limits using precise mathematical symbols and language."},{"code":"KY.HS.C.40","subject":"Mathematics","grade":"11","text":"Find antiderivatives of a variety of basic functions including power, exponential, logarithmic and trigonometric and apply basic properties of definite integrals."},{"code":"KY.HS.C.41","subject":"Mathematics","grade":"11","text":"Use substitution techniques and change of limits of integration to find antiderivatives."},{"code":"KY.HS.C.42","subject":"Mathematics","grade":"11","text":"Find particular antiderivatives given initial conditions."},{"code":"KY.HS.C.43","subject":"Mathematics","grade":"11","text":"Model, solve and interpret applications of antiderivatives including finding area, velocity, acceleration and volume of a solid."},{"code":"KY.HS.C.44","subject":"Mathematics","grade":"11","text":"Apply integration to solve problems including particle motion and exponential growth and decay."},{"code":"KY.HS.C.45","subject":"Mathematics","grade":"11","text":"Describe the application of integration to a variety of problems using precise mathematical language and notation."},{"code":"KY.HS.C.5","subject":"Mathematics","grade":"11","text":"Describe asymptotic behavior (analytically and graphically) in terms of infinite limits and limits at infinity."},{"code":"KY.HS.C.6","subject":"Mathematics","grade":"11","text":"Discuss the end behavior of functions; identify representative functions for each type of end behavior using precise mathematical symbols and language."},{"code":"KY.HS.C.7","subject":"Mathematics","grade":"11","text":"Understand and use the limit definition of continuity to determine whether a given function is continuous at a specific point."},{"code":"KY.HS.C.8","subject":"Mathematics","grade":"11","text":"Define and identify different types of discontinuity \u2013 removable (hole) or non-removable (jump, asymptote) \u2013 in terms of limits."},{"code":"KY.HS.C.9","subject":"Mathematics","grade":"11","text":"Understand and apply continuous function theorems. a. Apply the Intermediate Value Theorem to continuous functions. b. Apply the Extreme Value Theorem to continuous functions."},{"code":"KY.HS.F.1","subject":"Mathematics","grade":"11","text":"Understand properties and key features of functions and the different ways functions can be represented. a. Understand that a function from one set (called the domain) to another set (called the range) assigns to each element of the domain exactly one element of the range. If f is a function and x is an element of its domain, then f(x) denotes the output of f corresponding to the input x. b. Using appropriate function notation, evaluate functions for inputs in their domains and interpret statements that use function notation in terms of a context. c. For a function that models a relationship between two quantities, interpret key features of graphs and tables in terms of the quantities and sketch graphs showing key features given a verbal description of the relationship. d. Relate the domain of a function to its graph and, where applicable, to the quantitative relationship it describes. e. Compare properties of two functions each represented in a different way (algebraically, graphically, numerically in tables, or by verbal descriptions)."},{"code":"KY.HS.F.10","subject":"Mathematics","grade":"11","text":"Understand the inverse relationship between exponents and logarithms and use this relationship to solve problems involving logarithms and exponents with the use of technology."},{"code":"KY.HS.F.11","subject":"Mathematics","grade":"11","text":"Distinguish between situations that can be modeled with linear functions and with exponential functions. a. Recognize and justify that linear functions grow by equal differences over equal intervals and that exponential functions grow by equal factors over equal intervals. b. Recognize situations in which one quantity changes at a constant rate per unit interval relative to another. c. Recognize situations in which a quantity grows or decays by a constant percent rate per unit interval relative to another."},{"code":"KY.HS.F.12","subject":"Mathematics","grade":"11","text":"Construct linear and exponential functions, including arithmetic and geometric sequences, given a graph, a description of a relationship, or two input-output pairs (include reading these from a table)."},{"code":"KY.HS.F.13","subject":"Mathematics","grade":"11","text":"Observe using graphs and tables that a quantity increasing exponentially eventually exceeds a quantity increasing linearly, quadratically, or (more generally) as a polynomial function."},{"code":"KY.HS.F.14","subject":"Mathematics","grade":"11","text":"Interpret the parameters in a linear or exponential function in terms of a context."},{"code":"KY.HS.F.15","subject":"Mathematics","grade":"11","text":"Understand the relationship of radian measure of an angle to its arc length."},{"code":"KY.HS.F.16","subject":"Mathematics","grade":"11","text":"Understand and use the unit circle. a. Explain how the unit circle in the coordinate plane enables the extension of trigonometric functions to all real numbers, interpreted as radian measures of angles traversed counterclockwise around the unit circle. b. Use special triangles to determine geometrically the values of sine, cosine, tangent for \u03c0/3, \u03c0 /4 and \u03c0 /6 and use the unit circle to express the values of sine, cosine and tangent for \u03c0 \u2013x, \u03c0 +x and 2 \u03c0 \u2013x in terms of their values for x, where x is any real number. c. Use the unit circle to explain symmetry (odd and even) and periodicity of trigonometric functions."},{"code":"KY.HS.F.17","subject":"Mathematics","grade":"11","text":"Choose trigonometric functions to model periodic phenomena with specified period, midline and amplitude. \u2605"},{"code":"KY.HS.F.18","subject":"Mathematics","grade":"11","text":"Understand that restricting a trigonometric function to a domain on which it is always increasing or always decreasing allows its inverse to be constructed."},{"code":"KY.HS.F.19","subject":"Mathematics","grade":"11","text":"Use inverse functions to solve trigonometric equations that arise in modeling contexts; evaluate the solutions using technology and interpret them in terms of the context. \u2605"},{"code":"KY.HS.F.2","subject":"Mathematics","grade":"11","text":"Recognize that arithmetic and geometric sequences are functions, sometimes defined recursively, whose domain is a subset of the integers."},{"code":"KY.HS.F.20","subject":"Mathematics","grade":"11","text":"Proving identities and formulas within the context of trigonometry. a. Prove the Pythagorean identity and use it to find sin(\u03b8), cos(\u03b8), or tan(\u03b8) given sin(\u03b8), cos(\u03b8), or tan(\u03b8) and the quadrant of the angle. b. Prove the addition and subtraction formulas for sine, cosine and tangent and use them to solve problems."},{"code":"KY.HS.F.3","subject":"Mathematics","grade":"11","text":"Understand average rate of change of a function over an interval. a. Calculate and interpret the average rate of change of a function (presented symbolically or as a table) over a specified interval. b. Estimate the rate of change from a graph. \u2605"},{"code":"KY.HS.F.4","subject":"Mathematics","grade":"11","text":"Graph functions expressed symbolically and show key features of the graph, with and without using technology (computer, graphing calculator). \u2605 a. Graph linear and quadratic functions and show intercepts, maxima and minima. b. Graph square root, cube root and absolute value functions. c. Graph polynomial functions, identifying zeros when suitable factorizations are available and showing end behavior. d. Graph exponential and logarithmic functions, showing intercepts and end behavior. e. (+) Graph trigonometric functions, showing period, midline and amplitude. f. (+) Graph piecewise functions, including step functions. g. (+) Graph rational functions, identifying zeros and asymptotes when suitable factorizations are available and showing end behavior."},{"code":"KY.HS.F.5","subject":"Mathematics","grade":"11","text":"Write a function defined by an expression in different but equivalent forms to reveal and explain different properties of the function. a. Identify zeros, extreme values and symmetry of the graph within the context of a quadratic function. a. Quadratic functions provide a rich playground for developing this ability, since the three principal forms for a quadratic expression (expanded, factored and completed square) each give insight into different aspects of the function. b. Students examine real-world situations with constant multiplicative change, represented as expressions, such as growth or decay."},{"code":"KY.HS.F.6","subject":"Mathematics","grade":"11","text":"Write a function that describes a relationship between two quantities. \u2605 a. Determine an explicit expression, a recursive process, or steps for calculation from a context. b. Combine standard function types using arithmetic operations. c. (+) Compose functions."},{"code":"KY.HS.F.7","subject":"Mathematics","grade":"11","text":"Use arithmetic and geometric sequences to model situations and scenarios. a. Use formulas (explicit and recursive) to generate terms for arithmetic and geometric sequences. b. Write formulas to model arithmetic and geometric sequences and apply those formulas in realistic situations. \u2605 c. (+) Translate between recursive and explicit formulas."},{"code":"KY.HS.F.8","subject":"Mathematics","grade":"11","text":"Understand the effects of transformations on the graph of a function. a. Identify the effect on the graph of replacing f(x) by f(x) + k, k f(x), f(kx) and f(x + k) for specific values of k (both positive and negative); find the value of k given the graphs. b. Experiment with cases and illustrate an explanation of the effects on the graph using technology."},{"code":"KY.HS.F.9","subject":"Mathematics","grade":"11","text":"Find inverse functions. a. Given the equation of an invertible function, find the inverse. b. (+) Verify by composition that one function is the inverse of another. c. (+) Read values of an inverse function from a graph or a table, given that the function has an inverse. d. (+) Produce an invertible function from a non-invertible function by restricting the domain."},{"code":"KY.HS.G.1","subject":"Mathematics","grade":"11","text":"Know and apply precise definitions of the language of Geometry: a. Understand properties of line segments, angles and circle. b. Understand properties of and differences between perpendicular and parallel lines."},{"code":"KY.HS.G.10","subject":"Mathematics","grade":"11","text":"Apply the properties of similarity transformations to establish the AA criterion for two triangles to be similar."},{"code":"KY.HS.G.11","subject":"Mathematics","grade":"11","text":"Understand theorems about triangles. a. Apply theorems about triangles. b. (+) Prove theorems about triangles. c. Use similarity criteria for triangles to solve problems and to prove relationships in geometric figures."},{"code":"KY.HS.G.12","subject":"Mathematics","grade":"11","text":"Understand properties of right triangles. a. Understand that by similarity, side ratios in right triangles are properties of the angles in the triangle, leading to definitions of trigonometric ratios for acute angles (sine, cosine and tangent). b. Explain and use the relationship between the sine and cosine of complementary angles. c. Use trigonometric ratios and the Pythagorean Theorem to solve right triangles in applied problems. \u2605"},{"code":"KY.HS.G.12c","subject":"Mathematics","grade":"11","text":"Use coordinates to justify and prove simple geometric theorems algebraically. Use similarity criteria for triangles to solve problems in geometric figures. Use trigonometric ratios and the Pythagorean Theorem to solve right triangles in applied problems.\u2605"},{"code":"KY.HS.G.13","subject":"Mathematics","grade":"11","text":"Derive the formula A = 1/2 ab sin(C) for the area of a triangle by drawing an auxiliary line from a vertex perpendicular to the opposite side."},{"code":"KY.HS.G.14","subject":"Mathematics","grade":"11","text":"Understand and apply the Law of Sines and the Law of Cosines. a. Use the Law of Sines and Cosines to find unknown measurements in right and non-right triangles. b. Prove the Laws of Sines and Cosines and use them to solve problems."},{"code":"KY.HS.G.15","subject":"Mathematics","grade":"11","text":"Verify using dilations that all circles are similar."},{"code":"KY.HS.G.16","subject":"Mathematics","grade":"11","text":"Identify and describe relationships among angles and segments within the context of circles involving: a. Recognize differences between and properties of inscribed, central and circumscribed angles. b. Understand relationships between inscribed angles and the diameter of a circle. c. Understand the relationship between the radius of a circle and the line drawn through the point of tangency on that radius."},{"code":"KY.HS.G.17","subject":"Mathematics","grade":"11","text":"Apply basic construction procedures within the context of a circle. a. Construct the inscribed and circumscribed circles of a triangle. b. Construct a tangent line from a point outside a given circle to the circle."},{"code":"KY.HS.G.18","subject":"Mathematics","grade":"11","text":"Understand the relationship between an intercepted arc length within a circle and the radius of the circle. a. Derive using similarity the fact that the length of the arc intercepted by an angle is proportional to the radius. Derive the formula for the area of a sector. b. Define the radian measure of the angle as the measure of a central angle that intercepts an arc equal in length to the radius of the circle."},{"code":"KY.HS.G.19","subject":"Mathematics","grade":"11","text":"Understand the relationship between the algebraic form and the geometric representation of a circle. a. Write the equation of a circle of given center and radius using the Pythagorean Theorem. b. (+) Derive and write the equation of a circle of given center and radius using the Pythagorean Theorem. c. (+) Complete the square to find the center and radius of a circle given by an equation."},{"code":"KY.HS.G.2","subject":"Mathematics","grade":"11","text":"Representing transformations in the plane. a. Describe transformations as functions that take points in the plane as inputs and give other points as outputs b. Compare transformations that preserve distance and angle measures to those that do not. c. Given a rectangle, parallelogram, trapezoid, or regular polygon, formally describe the rotations and reflections that carry it onto itself, using properties of these figures."},{"code":"KY.HS.G.20","subject":"Mathematics","grade":"11","text":"Derive the equations of conic sections. a. Derive the equation of a parabola given a focus and directrix. b. Derive the equations of ellipses and hyperbolas given the foci, using the fact that the sum or difference of distances from the foci is constant."},{"code":"KY.HS.G.21","subject":"Mathematics","grade":"11","text":"Use coordinates to justify and prove simple geometric theorems algebraically."},{"code":"KY.HS.G.22","subject":"Mathematics","grade":"11","text":"Justify and apply the slope criteria for parallel and perpendicular lines and use them to solve geometric problems."},{"code":"KY.HS.G.23","subject":"Mathematics","grade":"11","text":"Find measurements among points within the coordinate plane. a. Use points from the coordinate plane to find the coordinates of a midpoint of a line segment and the distance between the endpoints of a line segment. b. Find the point on a directed line segment between two given points that partitions the segment in a given ratio."},{"code":"KY.HS.G.24","subject":"Mathematics","grade":"11","text":"Use coordinates within the coordinate plane to calculate measurements of two dimensional figures. a. Compute the perimeters of various polygons. b. Compute the areas of triangles, rectangles and other quadrilaterals.\u2605"},{"code":"KY.HS.G.25","subject":"Mathematics","grade":"11","text":"Analyze and determine the validity of arguments for the formulas for the various figures and shapes. a. Finding the circumference and area of a circle. b. Finding the volume of a sphere, prism, cylinder, pyramid and cone."},{"code":"KY.HS.G.26","subject":"Mathematics","grade":"11","text":"Give an informal argument using Cavalieri\u2019s principle for the formulas for the volume of a sphere and other solid figures."},{"code":"KY.HS.G.27","subject":"Mathematics","grade":"11","text":"Use volume formulas to solve problems for cylinders, pyramids, cones, spheres, prisms \u2605"},{"code":"KY.HS.G.28","subject":"Mathematics","grade":"11","text":"Identify the shapes of two-dimensional cross-sections of three-dimensional objects and identify three-dimensional objects generated by rotations of two-dimensional objects."},{"code":"KY.HS.G.29","subject":"Mathematics","grade":"11","text":"Use geometric shapes, their measures and their properties to describe objects in real world settings."},{"code":"KY.HS.G.3","subject":"Mathematics","grade":"11","text":"Develop formal definitions of rotations, reflections and translations in terms of angles, circles, perpendicular lines, parallel lines and line segments."},{"code":"KY.HS.G.30","subject":"Mathematics","grade":"11","text":"Apply concepts of density based on area and volume in modeling situations, using appropriate units of measurement."},{"code":"KY.HS.G.31","subject":"Mathematics","grade":"11","text":"Apply geometric methods to solve design problems. \u2605"},{"code":"KY.HS.G.4","subject":"Mathematics","grade":"11","text":"Understand the effects of transformations of geometric figures. a. Given a geometric figure and a rotation, reflection, or translation, draw the transformed figure. b. Specify a sequence of transformations that will carry a given figure onto another. c. Use geometric descriptions of rigid motions to transform figures and to predict the effect of a given rigid motion on a given figure. Given two figures, use the definition of congruence in terms of rigid motions to decide if they are congruent."},{"code":"KY.HS.G.5","subject":"Mathematics","grade":"11","text":"Know and apply the concepts of triangle congruence: a. Use the definition of congruence in terms of rigid motions to show that two triangles are congruent if and only if corresponding pairs of sides and corresponding pairs of angles are congruent. b. Explain how the criteria for triangle congruence (ASA, SAS and SSS) follow from the definition of congruence in terms of rigid motions."},{"code":"KY.HS.G.6","subject":"Mathematics","grade":"11","text":"Apply theorems for lines, angles, triangles, parallelograms."},{"code":"KY.HS.G.7","subject":"Mathematics","grade":"11","text":"Prove theorems about geometric figures. a. Construct formal proofs to justify theorems for lines, angles and triangles. b. (+) Construct formal proofs to justify theorems for parallelograms."},{"code":"KY.HS.G.8","subject":"Mathematics","grade":"11","text":"Create and apply geometric constructions. a. Make formal geometric constructions with a variety of tools and methods. b. Apply basic construction procedures to construct more complex figures."},{"code":"KY.HS.G.9","subject":"Mathematics","grade":"11","text":"Understand properties of dilations. a. Verify the properties that result from that dilations given by a center and a scale factor. b. Verify that a dilation produces an image that is similar to the pre-image."},{"code":"KY.HS.N.1","subject":"Mathematics","grade":"11","text":"by extending student understanding to situations where the numerator is not one. For example, students understand that defining 4m/n is the same as \u221a4 \ud835\udc5b\ud835\udc5b m and ( \u221a4 \ud835\udc5b\ud835\udc5b )m. Include contextual examples, such as rewriting the volume of a sphere to identify the radius as a function of volume."},{"code":"KY.HS.N.10","subject":"Mathematics","grade":"11","text":"Extend polynomial identities to the complex numbers."},{"code":"KY.HS.N.11","subject":"Mathematics","grade":"11","text":"Know the Fundamental Theorem of Algebra; show that it is true for quadratic polynomials."},{"code":"KY.HS.N.12","subject":"Mathematics","grade":"11","text":"Understand and apply properties of vectors. a. Recognize vector quantities as having both magnitude and direction. Represent vector quantities by directed line segments and use appropriate symbols for vectors and their magnitudes. b. Find the components of a vector by subtracting the coordinates of an initial point from the coordinates of a terminal point. c. Solve problems involving velocity and other quantities that can be represented by vectors."},{"code":"KY.HS.N.13","subject":"Mathematics","grade":"11","text":"Perform operations with vectors (addition, subtraction and multiplication by a scalar). a. Add vectors end-to-end, component-wise and by the parallelogram rule. Understand that the magnitude of a sum of two vectors is typically not the sum of the magnitudes. b. Given two vectors in magnitude and direction form, determine the magnitude and direction of their sum. c. Understand vector subtraction v \u2013 w as v + (\u2013w), where \u2013w is the additive inverse of w, with the same magnitude as w and pointing in the opposite direction. Represent vector subtraction graphically by connecting the tips in the appropriate order and perform vector subtraction component-wise. d. Represent scalar multiplication graphically by scaling vectors and possibly reversing their direction; perform scalar multiplication component-wise. e. b. Compute the magnitude of a scalar multiple cv using ||cv|| = |c|v. Compute the direction of cv knowing that when |c|v \u2260 0, the direction of cv is either along v (for c > 0) or against v (for c < 0)."},{"code":"KY.HS.N.14","subject":"Mathematics","grade":"11","text":"Use matrices to represent and manipulate data."},{"code":"KY.HS.N.15","subject":"Mathematics","grade":"11","text":"Perform operations with matrices. a. Add, subtract and multiply matrices of appropriate dimensions. b. Multiply matrices by scalars to produce new matrices."},{"code":"KY.HS.N.16","subject":"Mathematics","grade":"11","text":"Understand properties of square and identity matrices. a. Understand that, unlike multiplication of numbers, matrix multiplication for square matrices is not a commutative operation, but still satisfies the associative and distributive properties. b. Understand that the zero and identity matrices play a role in matrix addition and multiplication similar to the role of 0 and 1 in the real numbers. The determinant of a square matrix is nonzero if and only if the matrix has a multiplicative inverse. c. Work with 2 \u00d7 2 matrices as transformations of the plane and interpret the absolute value of the determinant in terms of area."},{"code":"KY.HS.N.17","subject":"Mathematics","grade":"11","text":"Multiply a vector (regarded as a matrix with one column) by a matrix of suitable dimensions to produce another vector. Work with matrices as transformations of vectors."},{"code":"KY.HS.N.2","subject":"Mathematics","grade":"11","text":"Rewrite expressions involving radicals and rational exponents using the properties of exponents."},{"code":"KY.HS.N.3","subject":"Mathematics","grade":"11","text":"Justify why the sum or product of two rational numbers is rational; that the sum of a rational number and an irrational number is irrational; and that the product of a nonzero rational number and an irrational number is irrational."},{"code":"KY.HS.N.4","subject":"Mathematics","grade":"11","text":"Use units in context as a way to understand problems and to guide the solution of multi-step problems; \u2605 a. Choose and interpret units consistently in formulas; b. Choose and interpret the scale and the origin in graphs and data displays."},{"code":"KY.HS.N.5","subject":"Mathematics","grade":"11","text":"Define appropriate units in context for the purpose of descriptive modeling. \u2605"},{"code":"KY.HS.N.6","subject":"Mathematics","grade":"11","text":"does not require a formal discussion or use of significant digits in the scientific sense, students understand a level of precision. For example, when using the Pythagorean Theorem with measurements given in tenths of an inch, it is appropriate for students to express answers to the nearest tenth, but not to the nearest hundredth because that level of precision was not used in the original measures."},{"code":"KY.HS.N.7","subject":"Mathematics","grade":"11","text":"Understanding properties of complex numbers. a. Know there is a complex number i such that i2 = \u20131 and every complex number has the form a + bi with a and b real. b. Use the relation i2 = \u20131 and the commutative, associative and distributive properties to add, subtract and multiply complex numbers. c. (+) Find the conjugate of a complex number and use it to find the quotient of complex numbers."},{"code":"KY.HS.N.8","subject":"Mathematics","grade":"11","text":"Understanding representations of complex numbers using the complex plane. a. Represent complex numbers on the complex plane in rectangular and polar form (including real and imaginary numbers) and explain why the rectangular and polar forms of a given complex number represent the same number. b. Represent addition, subtraction, multiplication, modulus and conjugation of complex numbers geometrically on the complex plane; use properties of this representation for computation. c. Calculate the distance between numbers in the complex plane as the modulus of the difference and the midpoint of a segment as the average of the numbers at its endpoints."},{"code":"KY.HS.N.9","subject":"Mathematics","grade":"11","text":"Solve quadratic equations with real coefficients that have complex solutions."},{"code":"KY.HS.SP.1","subject":"Mathematics","grade":"11","text":"Represent the distribution of data with plots on the real number line (stem plots, dot plots, histograms and box plots)."},{"code":"KY.HS.SP.10","subject":"Mathematics","grade":"11","text":"Decide if a specified model is consistent with the results from a simulation."},{"code":"KY.HS.SP.11","subject":"Mathematics","grade":"11","text":"Recognize the purposes of and differences among sample surveys, experiments and observational studies; explain how randomization relates to each."},{"code":"KY.HS.SP.12","subject":"Mathematics","grade":"11","text":"Use data from a sample survey to estimate a population mean or proportion and explain how bias may be involved in the process."},{"code":"KY.HS.SP.13","subject":"Mathematics","grade":"11","text":"Use data from a randomized experiment to compare two treatments; use simulations to decide if differences between estimates or statistics are significant."},{"code":"KY.HS.SP.14","subject":"Mathematics","grade":"11","text":"Describe events as subsets of a sample space. Use characteristics (or categories) of the outcomes, such as, \u2022 as unions, \u201cA or B,\u201d that are mutually exclusive events and \u2022 as unions, \u201cA or B,\u201d that are non-mutually exclusive events and \u2022 as intersections, \u201cA and B,\u201d and \u2022 as complements of other events, \u201cnot A.\u201d to calculate basic probabilities."},{"code":"KY.HS.SP.15","subject":"Mathematics","grade":"11","text":"Understand the concept of independence. a. Understand that two events A and B are independent if the probability of A and B occurring together is the product of their individual probabilities, P(A) x P(B) b. (+) Determine whether two events are independent and provide a justification to support the decision. c. Recognize and explain the concept of independence in everyday language and everyday situations."},{"code":"KY.HS.SP.16","subject":"Mathematics","grade":"11","text":"Understand the concept of conditional probability. a. Understand the conditional probability of A given B as P(A and B)/P(B). b. (+) Interpret independence of A and B as saying that the conditional probability of A given B is the same as the probability of A and the conditional probability of B given A is the same as the probability of B. a. For any two events A and B, P(A given B) = \ud835\udc43\ud835\udc43(\ud835\udc34\ud835\udc34 \ud835\udc4e\ud835\udc4e\ud835\udc5b\ud835\udc5b\ud835\udc51\ud835\udc51 \ud835\udc35\ud835\udc35) \ud835\udc43\ud835\udc43(\ud835\udc35\ud835\udc35)."},{"code":"KY.HS.SP.17","subject":"Mathematics","grade":"11","text":"Construct and interpret two-way frequency tables of data when two categories are associated with each object being classified. Use the two-way table as a sample space to decide whether events are independent and to approximate conditional probabilities."},{"code":"KY.HS.SP.18","subject":"Mathematics","grade":"11","text":"Apply the General Multiplication Rule, P(A and B) = P(A)P(B|A) = P(B)P(A|B), in a uniform probability model and interpret the answer in terms of the model."},{"code":"KY.HS.SP.19","subject":"Mathematics","grade":"11","text":"Use permutations and combinations to compute probabilities. a. Distinguish between situations that can be modeled using counting techniques, including Fundamental Counting Principle, permutations and combinations. b. Perform calculations using the appropriate counting technique, including simple probabilities. c. (+) Use permutations and combinations to compute probabilities of compound events and solve problems."},{"code":"KY.HS.SP.2","subject":"Mathematics","grade":"11","text":"Use statistics appropriate to the shape of the numerical data distribution to compare center (median, mean) and spread (interquartile range when comparing medians and standard deviation when comparing means) of different data distributions."},{"code":"KY.HS.SP.20","subject":"Mathematics","grade":"11","text":"Define a random variable for a quantity of interest by assigning a numerical value to each event in a sample space; graph the corresponding probability distribution using the same appropriate graphical displays as for data distributions."},{"code":"KY.HS.SP.21","subject":"Mathematics","grade":"11","text":"Calculate the expected value of a random variable; interpret it as the mean of the probability distribution and use the value in analyzing decisions."},{"code":"KY.HS.SP.22","subject":"Mathematics","grade":"11","text":"Develop a probability distribution for a random variable. a. Find an expected value based on a sample space in which theoretical probabilities can be calculated. b. Find an expected value based on a sample space in which empirical probabilities can be calculated."},{"code":"KY.HS.SP.23","subject":"Mathematics","grade":"11","text":"Weigh the possible outcomes of a decision by assigning probabilities to payoff values and finding expected values. a. Find the expected payoff for a game of chance. b. Evaluate and compare strategies on the basis of expected values. c. Use calculated expected values to make fair decisions and formulate strategies."},{"code":"KY.HS.SP.3","subject":"Mathematics","grade":"11","text":"Interpret differences in shape, center and spread in the context of the distributions of the numerical data, accounting for the presence and possible effects of extreme data points (outliers)."},{"code":"KY.HS.SP.4","subject":"Mathematics","grade":"11","text":"When appropriate, fit a normal distribution to a numerical data set for given mean and standard deviation and then estimate population percentages using the Empirical Rule and recognize that there are data sets for which such a procedure is not appropriate."},{"code":"KY.HS.SP.5","subject":"Mathematics","grade":"11","text":"Summarize categorical data for two or more categories in frequency tables. Calculate and interpret joint, marginal and conditional relative frequencies (probabilities) in the context of the data, recognizing possible associations and trends in the data."},{"code":"KY.HS.SP.6","subject":"Mathematics","grade":"11","text":"Represent data on two quantitative variables on a scatter plot and describe how the explanatory and response variables are related. a. Calculate an appropriate mathematical model, or use a given mathematical model, for data to solve problems in context. b. Informally assess the fit of a model (through calculating correlation for linear data, plotting, calculating and/or analyzing residuals)."},{"code":"KY.HS.SP.7","subject":"Mathematics","grade":"11","text":"Interpret the slope (rate of change) and the intercept (constant term) of a linear model in the context of the data."},{"code":"KY.HS.SP.8","subject":"Mathematics","grade":"11","text":"Understand the role and purpose of correlation in linear regression. a. Use technology to compute correlation coefficient of a linear fit. b. Interpret the meaning of the correlation within the context of the data. c. Describe the limitations of correlation when establishing causation."},{"code":"KY.HS.SP.9","subject":"Mathematics","grade":"11","text":"in that results from non-random samples (Voluntary Response and Convenience) generate biased results when compared with more appropriate, random samples of the same population."},{"code":"HS-ESS1-1","subject":"Science","grade":"11","text":"Develop a model based on evidence to illustrate the life span of the sun and the role of nuclear fusion in the sun\u2019s core to release energy that eventually reaches Earth in the form of radiation."},{"code":"HS-ESS1-2","subject":"Science","grade":"11","text":"Construct an explanation of the Big Bang theory based on astronomical evidence of light spectra, motion of distant galaxies, and composition of matter in the universe."},{"code":"HS-ESS1-3","subject":"Science","grade":"11","text":"Communicate scientific ideas about the way stars, over their life cycle, produce elements."},{"code":"HS-ESS1-4","subject":"Science","grade":"11","text":"Use mathematical or computational representations to predict the motion of orbiting objects in the solar system."},{"code":"HS-ESS1-5","subject":"Science","grade":"11","text":"Evaluate evidence of the past and current movements of continental and oceanic crust and the theory of plate tectonics to explain the ages of crustal rocks."},{"code":"HS-ESS1-6","subject":"Science","grade":"11","text":"Apply scientific reasoning and evidence from ancient Earth materials, meteorites, and other planetary surfaces to construct an account of Earth\u2019s formation and early history."},{"code":"HS-ESS2-1","subject":"Science","grade":"11","text":"Develop a model to illustrate how Earth\u2019s internal and surface processes operate at different spatial and temporal scales to form continental and ocean-floor features."},{"code":"HS-ESS2-2","subject":"Science","grade":"11","text":"Analyze geoscience data to make the claim that one change to Earth\u2019s surface can create feedbacks that cause changes to other Earth systems."},{"code":"HS-ESS2-3","subject":"Science","grade":"11","text":"Develop a model based on evidence of Earth\u2019s interior to describe the cycling of matter by thermal convection."},{"code":"HS-ESS2-4","subject":"Science","grade":"11","text":"Use a model to describe how variations in the flow of energy into and out of Earth\u2019s systems result in changes in climate."},{"code":"HS-ESS2-5","subject":"Science","grade":"11","text":"Plan and conduct an investigation of the properties of water and its effects on Earth materials and surface processes."},{"code":"HS-ESS2-6","subject":"Science","grade":"11","text":"Develop a quantitative model to describe the cycling of carbon among the hydrosphere, atmosphere, geosphere, and biosphere."},{"code":"HS-ESS2-7","subject":"Science","grade":"11","text":"Construct an argument based on evidence about the simultaneous coevolution of Earth\u2019s systems and life on Earth."},{"code":"HS-ESS3-1","subject":"Science","grade":"11","text":"Construct an explanation based on evidence for how the availability of natural resources, occurrence of natural hazards, and changes in climate have influenced human activity."},{"code":"HS-ESS3-2","subject":"Science","grade":"11","text":"Evaluate competing design solutions for developing, managing, and utilizing energy and mineral resources based on cost- benefit ratios.*"},{"code":"HS-ESS3-3","subject":"Science","grade":"11","text":"Create a computational simulation to illustrate the relationships among the management of natural resources, the sustainability of human populations, and biodiversity."},{"code":"HS-ESS3-4","subject":"Science","grade":"11","text":"Evaluate or refine a technological solution that reduces impacts of human activities on natural systems.*"},{"code":"HS-ESS3-5","subject":"Science","grade":"11","text":"Analyze geoscience data and the results from global climate models to make an evidence-based forecast of the current rate of global or regional climate change and associated future impacts to Earth\u2019s systems."},{"code":"HS-ESS3-6","subject":"Science","grade":"11","text":"Use a computational representation to illustrate the relationships among Earth systems and how those relationships are being modified due to human activity."},{"code":"HS-ETS1-1","subject":"Science","grade":"11","text":"Analyze a major global challenge to specify qualitative and quantitative criteria and constraints for solutions that account for societal needs and wants. *"},{"code":"HS-ETS1-2","subject":"Science","grade":"11","text":"Design a solution to a complex real- world problem by breaking it down into smaller, more manageable problems that can be solved through engineering. *"},{"code":"HS-ETS1-3","subject":"Science","grade":"11","text":"Evaluate a solution to a complex real- world problem based on prioritized criteria and trade-offs that account for a range of constraints, including cost, safety, reliability, and aesthetics, as well as possible social, cultural, and environmental impacts. *"},{"code":"HS-ETS1-4","subject":"Science","grade":"11","text":"Use a computer simulation to model the impact of proposed solutions to a complex real- world problem with numerous criteria and constraints on interactions within and between systems relevant to the problem. *"},{"code":"HS-LS1-1","subject":"Science","grade":"11","text":"Construct an explanation based on evidence for how the structure of DNA determines the structure of proteins, which carry out the essential functions of life through systems of specialized cells."},{"code":"HS-LS1-2","subject":"Science","grade":"11","text":"Develop and use a model to illustrate the hierarchical organization of interacting systems that provide specific functions within multicellular organisms."},{"code":"HS-LS1-3","subject":"Science","grade":"11","text":"Plan and conduct an investigation to provide evidence that feedback mechanisms maintain homeostasis."},{"code":"HS-LS1-4","subject":"Science","grade":"11","text":"Use a model to illustrate the role of cellular division (mitosis) and differentiation in producing and maintaining complex organisms."},{"code":"HS-LS1-5","subject":"Science","grade":"11","text":"Use a model to illustrate how photosynthesis transforms light energy into stored chemical energy."},{"code":"HS-LS1-6","subject":"Science","grade":"11","text":"Construct and revise an explanation based on evidence for how carbon, hydrogen, and oxygen from sugar molecules may combine with other elements to form amino acids and/or other large carbon-based molecules."},{"code":"HS-LS1-7","subject":"Science","grade":"11","text":"Use a model to illustrate that cellular respiration is a chemical process whereby the bonds of food molecules and oxygen molecules are broken and the bonds in new compounds are formed, resulting in a net transfer of energy."},{"code":"HS-LS2-1","subject":"Science","grade":"11","text":"Use mathematical and/or computational representations to support explanations of factors that affect carrying capacity of ecosystems at different scales."},{"code":"HS-LS2-2","subject":"Science","grade":"11","text":"Use mathematical representations to support and revise explanations based on evidence about factors affecting biodiversity and populations in ecosystems of different scales."},{"code":"HS-LS2-3","subject":"Science","grade":"11","text":"Construct and revise an explanation based on evidence for the cycling of matter and flow of energy in aerobic and anaerobic conditions."},{"code":"HS-LS2-4","subject":"Science","grade":"11","text":"Use mathematical representations to support claims for the cycling of matter and flow of energy among organisms in an ecosystem."},{"code":"HS-LS2-5","subject":"Science","grade":"11","text":"Develop a model to illustrate the role of photosynthesis and cellular respiration in the cycling of carbon among the biosphere, atmosphere, hydrosphere, and geosphere."},{"code":"HS-LS2-6","subject":"Science","grade":"11","text":"Evaluate claims, evidence, and reasoning that the complex interactions in ecosystems maintain relatively consistent numbers and types of organisms in stable conditions, but changing conditions may result in a new ecosystem."},{"code":"HS-LS2-7","subject":"Science","grade":"11","text":"Design, evaluate, and refine a solution for reducing the impacts of human activities on the environment and biodiversit y.*"},{"code":"HS-LS2-8","subject":"Science","grade":"11","text":"Evaluate evidence for the role of group behavior on individual and species\u2019 chances to survive and reproduce."},{"code":"HS-LS3-1","subject":"Science","grade":"11","text":"Ask questions to clarify relationships about the role of DNA and chromosomes in coding the instructions for characteristic traits passed from parents to offspring."},{"code":"HS-LS3-2","subject":"Science","grade":"11","text":"Make and defend a claim based on evidence that inheritable genetic variations may result from (1) new genetic combinations through meiosis, (2) viable errors occurring during replication, and/or (3) mutations caused by environmental factors."},{"code":"HS-LS3-3","subject":"Science","grade":"11","text":"Apply concepts of statistics and probability to explain the variation and distribution of expressed traits in a population."},{"code":"HS-LS4-1","subject":"Science","grade":"11","text":"Communicate scientific information that common ancestry and biological evolution are supported by multiple lines of empirical evidence."},{"code":"HS-LS4-2","subject":"Science","grade":"11","text":"Construct an explanation based on evidence that the process of evolution primarily results from four factors: (1) the potential for a species to increase in number, (2) the heritable genetic variation of individuals in a species due to mutation and sexual reproduction, (3) competition for limited resources, and (4) the proliferation of those organisms that are better able to survive and reproduce in the environment."},{"code":"HS-LS4-3","subject":"Science","grade":"11","text":"Apply concepts of statistics and probability to support explanations that organisms with an advantageous heritable trait tend to increase in proportion to organisms lacking this trait."},{"code":"HS-LS4-4","subject":"Science","grade":"11","text":"Construct an explanation based on evidence for how natural selection leads to adaptation of populations."},{"code":"HS-LS4-5","subject":"Science","grade":"11","text":"Evaluate the evidence supporting claims that changes in environmental conditions may result in (1) increases in the number of individuals of some species, (2) the emergence of new species over time, and (3) the extinction of other species."},{"code":"HS-LS4-6","subject":"Science","grade":"11","text":"Create or revise a simulation to test a solution to mitigate adverse impacts of human activity on biodiversit y.*"},{"code":"HS-PS1-1","subject":"Science","grade":"11","text":"Use the periodic table as a model to predict the relative properties of elements based on the patterns of electrons in the outermost energy level of atoms."},{"code":"HS-PS1-2","subject":"Science","grade":"11","text":"Construct and revise an explanation for the outcome of a simple chemical reaction based on the outermost electron states of atoms, trends in the periodic table, and knowledge of the patterns of chemical properties."},{"code":"HS-PS1-3","subject":"Science","grade":"11","text":"Plan and conduct an investigation to gather evidence to compare the structure of substances at the macro and micro scale to infer the strength of electrical forces between particles."},{"code":"HS-PS1-4","subject":"Science","grade":"11","text":"Develop a model to illustrate that the release or absorption of energy from a chemical reaction system depends upon the changes in total bond energy."},{"code":"HS-PS1-5","subject":"Science","grade":"11","text":"Apply scientific principles and evidence to provide an explanation about the effects of changing the temperature or concentration of the reacting particles on the rate at which a reaction occurs."},{"code":"HS-PS1-6","subject":"Science","grade":"11","text":"Refine the design of a chemical system by specifying a change in conditions that would produce increased amounts of products at equilibrium.*"},{"code":"HS-PS1-7","subject":"Science","grade":"11","text":"Use mathematical representations to support the claim that atoms, and therefore mass, are conserved during a chemical reaction."},{"code":"HS-PS1-8","subject":"Science","grade":"11","text":"Develop models to illustrate the changes in the composition of the nucleus of the atom and the energy released during the processes of fission, fusion, and radioactive decay."},{"code":"HS-PS2-1","subject":"Science","grade":"11","text":"Analyze data to support the claim that Newton\u2019s second law of motion describes the mathematical relationship among the net force on a macroscopic object, its mass, and its acceleration."},{"code":"HS-PS2-2","subject":"Science","grade":"11","text":"Use mathematical representations to support the claim that the total momentum of a system of objects is conserved when there is no net force on the system."},{"code":"HS-PS2-3","subject":"Science","grade":"11","text":"Apply scientific and engineering ideas to design, evaluate, and refine a device that minimizes the force on a macroscopic object during a collision.*"},{"code":"HS-PS2-4","subject":"Science","grade":"11","text":"Use mathematical representations of Newton\u2019s law of gravitation and Coulomb\u2019s law to describe and predict the gravitational and electrostatic forces between objects."},{"code":"HS-PS2-5","subject":"Science","grade":"11","text":"Plan and conduct an investigation to provide evidence that an electric current can produce a magnetic field and that a changing magnetic field can produce an electric current."},{"code":"HS-PS2-6","subject":"Science","grade":"11","text":"Communicate scientific and technical information about why the molecular-level structure is important in the functioning of designed materials.*"},{"code":"HS-PS3-1","subject":"Science","grade":"11","text":"Create a computational model to calculate the change in the energy of one component in a system when the change in energy of the other component(s) and energy flows in and out of the system are known."},{"code":"HS-PS3-2","subject":"Science","grade":"11","text":"Develop and use models to illustrate that energy at the macroscopic scale can be accounted for as a combination of energy associated with the motion of particles (objects) and energy associated with the relative position of particles (objects)."},{"code":"HS-PS3-3","subject":"Science","grade":"11","text":"Design, build, and refine a device that works within given constraints to convert one form of energy into another form of energy.*"},{"code":"HS-PS3-4","subject":"Science","grade":"11","text":"Plan and conduct an investigation to provide evidence that the transfer of thermal energy when two components of different temperature are combined within a closed system results in a more uniform energy distribution among the components in the system (second law of thermodynamics)."},{"code":"HS-PS3-5","subject":"Science","grade":"11","text":"Develop and use a model of two objects interacting through electric or magnetic fields to illustrate the forces between objects and the changes in energy of the objects due to the interaction."},{"code":"HS-PS4-1","subject":"Science","grade":"11","text":"Use mathematical representations to support a claim regarding relationships among the frequency, wavelength, and speed of waves traveling in various media."},{"code":"HS-PS4-2","subject":"Science","grade":"11","text":"Evaluate questions about the advantages of using digital transmission and storage of information."},{"code":"HS-PS4-3","subject":"Science","grade":"11","text":"Evaluate the claims, evidence, and reasoning behind the idea that electromagnetic radiation can be described either by a wave model or a particle model, and that for some situations one model is more useful than the other."},{"code":"HS-PS4-4","subject":"Science","grade":"11","text":"Evaluate the validity and reliability of claims in published materials of the effects that different frequencies of electromagnetic radiation have when absorbed by matter."},{"code":"HS-PS4-5","subject":"Science","grade":"11","text":"Communicate technical information about how some technological devices use the principles of wave behavior and wave interactions with matter to transmit and capture information and energy.*"},{"code":"HS.C.CP.1","subject":"Social Studies","grade":"11","text":"Explain how the Cons titution of the United States embodies the principles of rule of law, popular sovereignty, republicanism, federalism, separation of powers and checks and balances to promote general welfare."},{"code":"HS.C.CP.2","subject":"Social Studies","grade":"11","text":"Analyze legislative, executive and judicial branch decisions in terms of constitutionality and impact on citizens and states."},{"code":"HS.C.CP.3","subject":"Social Studies","grade":"11","text":"Compare various forms of government and how each maintains order, upholds human rights and interacts within the international community."},{"code":"HS.C.CP.4","subject":"Social Studies","grade":"11","text":"Evaluate how the U.S. judicial system is designed to uphold equality before the law, due process and inalienable rights."},{"code":"HS.C.CV.1","subject":"Social Studies","grade":"11","text":"Explain how classic al republicanism, natural rights philosophy and English common law influenced the thinking and actions of the American Founders."},{"code":"HS.C.CV.2","subject":"Social Studies","grade":"11","text":"Assess how the expansion of civic virtues, democratic principles, constitutional rights and human rights influence the thoughts and actions of individuals and groups."},{"code":"HS.C.CV.3","subject":"Social Studies","grade":"11","text":"Analyze the impact of the e fforts of individuals and reform movements on the expansion of civil rights and liberties locally, nationally and internationally."},{"code":"HS.C.KGO.1","subject":"Social Studies","grade":"11","text":"Explain how the Ke ntucky Constitution embodies the principles of rule of law, popular sovereignty, separation of powers and checks and balances."},{"code":"HS.C.KGO.2","subject":"Social Studies","grade":"11","text":"Compare Kentucky\u2019s government to other states and to the federal government."},{"code":"HS.C.KGO.3","subject":"Social Studies","grade":"11","text":"Describe how active citizens can affect change in their communities and Kentucky Informed and engaged citizenship is a crucial part of the successful functioning of Kentucky."},{"code":"HS.C.PR.1","subject":"Social Studies","grade":"11","text":"Analyze the role of the thre e branches of government in the lawmaking process."},{"code":"HS.C.PR.2","subject":"Social Studies","grade":"11","text":"Analyze the role of elections, bureaucracy, political parties, interest groups and media in shaping public policy."},{"code":"HS.C.PR.3","subject":"Social Studies","grade":"11","text":"Evaluate intended and unintended consequences of public policies locally, nationally and internationally."},{"code":"HS.C.PR.4","subject":"Social Studies","grade":"11","text":"Compare the domestic and foreign policies of the United States and other countries."},{"code":"HS.C.RR.1","subject":"Social Studies","grade":"11","text":"Evaluate the civic r esponsibilities of individuals within a society."},{"code":"HS.C.RR.2","subject":"Social Studies","grade":"11","text":"Explain how active citizens can affect the lawmaking process locally, nationally and internationally. internationally engaged citizens are critical to positively evolving societies."},{"code":"HS.E.IC.1","subject":"Social Studies","grade":"11","text":"Predict the way scarcity causes individuals, organizations and governments to evaluate tradeoffs, make choices and incur opportunity costs."},{"code":"HS.E.IC.2","subject":"Social Studies","grade":"11","text":"Evaluate how individuals, organizations and governments respond to incentives in the decision- making process."},{"code":"HS.E.IC.3","subject":"Social Studies","grade":"11","text":"Perform a cost-benefit analysis on a real-world situation, using economic thinking to describe the marginal costs and benefits of a particular situation."},{"code":"HS.E.IC.4","subject":"Social Studies","grade":"11","text":"Evaluate how incentives determine what is produced and distributed in a competitive market system."},{"code":"HS.E.KE.1","subject":"Social Studies","grade":"11","text":"Analyze how national and international trends and policies impact Kentucky\u2019s state and local economies."},{"code":"HS.E.KE.2","subject":"Social Studies","grade":"11","text":"Analyze how national and international trends and policies impact Kentucky\u2019s state and local economies."},{"code":"HS.E.KE.3","subject":"Social Studies","grade":"11","text":"Analyze how the four components of Gross Domestic Product (GDP) are combined to assess the health of Kentucky\u2019s economy."},{"code":"HS.E.MA.1","subject":"Social Studies","grade":"11","text":"Evaluate how valu es and beliefs like economic freedom, equity, full employment, price stability, security, efficiency and growth help to form different types of economic systems."},{"code":"HS.E.MA.2","subject":"Social Studies","grade":"11","text":"Analyze ways in which competition and government regulation influence what is produced and allocated in an economy."},{"code":"HS.E.MA.3","subject":"Social Studies","grade":"11","text":"Describe the externalities of government attempts to remedy market failure and improve market outcomes through fiscal policy."},{"code":"HS.E.MA.4","subject":"Social Studies","grade":"11","text":"Analyze the impact of fiscal policies, various government taxation and spending policies on the economy."},{"code":"HS.E.MA.5","subject":"Social Studies","grade":"11","text":"Assess how interest rates influence borrowing and investing."},{"code":"HS.E.MA.6","subject":"Social Studies","grade":"11","text":"Assess the effectiveness of rules and laws that protect both consumers and producers."},{"code":"HS.E.MA.7","subject":"Social Studies","grade":"11","text":"Explain how the Federal Reserve uses monetary policy to promote price stability, employment and economic growth."},{"code":"HS.E.MI.1","subject":"Social Studies","grade":"11","text":"Compare per fect competition, monopolistic competition, oligopoly and monopoly and how the extent of competition within various markets affects price, quantity and variety in production."},{"code":"HS.E.MI.2","subject":"Social Studies","grade":"11","text":"Analyze and graph the impact of supply and demand shifts on equilibrium price and quantities produced."},{"code":"HS.E.MI.3","subject":"Social Studies","grade":"11","text":"Analyze the roles of product and factor markets."},{"code":"HS.E.MI.4","subject":"Social Studies","grade":"11","text":"Compare the roles of consumers and producers in the product, labor and financial markets and the economy as a whole."},{"code":"HS.E.ST.1","subject":"Social Studies","grade":"11","text":"Draw conclusions regarding the effect of specialization and trade on production, distribution and consumption of goods and services for individuals, businesses and societies."},{"code":"HS.E.ST.2","subject":"Social Studies","grade":"11","text":"Analyze the role of comparative advantage in international trade of goods and services."},{"code":"HS.E.ST.3","subject":"Social Studies","grade":"11","text":"Explain how international economic trends and policies affect political, social and economic conditions in various nations. (see \u201ccontinued\u201d) Nations in the modern world are affected by the interconnectedness of economies, which causes ripple effects across borders."},{"code":"HS.G.GR.1","subject":"Social Studies","grade":"11","text":"Interpret the relationships among human and physical patterns and processes at local, national and global scales."},{"code":"HS.G.GR.2","subject":"Social Studies","grade":"11","text":"Analyze how environmental factors influence population distributions from place to place."},{"code":"HS.G.HE.1","subject":"Social Studies","grade":"11","text":"Assess the reciproc al relationship between physical environment and culture within local, national and global scales."},{"code":"HS.G.HE.2","subject":"Social Studies","grade":"11","text":"Analyze how human settlements are influenced by or influence the relationship between people and the environment."},{"code":"HS.G.HI.1","subject":"Social Studies","grade":"11","text":"Analyze how the forces of cooperation and conflict within and among people, nations and empires influence the division and control of Earth\u2019s surface and resources."},{"code":"HS.G.HI.2","subject":"Social Studies","grade":"11","text":"Analyze how cultural and economic decisions influence the characteristics of various places."},{"code":"HS.G.HI.3","subject":"Social Studies","grade":"11","text":"Explain how people create natural and cultural regions to interpret Earth\u2019s complexity."},{"code":"HS.G.KGE.1","subject":"Social Studies","grade":"11","text":"Explain how Kentuckians view sense of place differently based on cultural and environmental characteristics of varying regions of the state."},{"code":"HS.G.KGE.2","subject":"Social Studies","grade":"11","text":"Explain how the geography of Kentucky influences the development of the state."},{"code":"HS.G.MM.1","subject":"Social Studies","grade":"11","text":"Analyze how cult ural, economic and environmental factors contribute to migration patterns and population distribution at multiple scales."},{"code":"HS.G.MM.2","subject":"Social Studies","grade":"11","text":"Evaluate reasons for the spatial distribution of human populations at different scales on Earth\u2019s surface."},{"code":"C.11-12.1","subject":"English Language Arts","grade":"12","text":"Compose arguments to support claims in an analysis of substantive topics or texts, using valid reasoning and relevant and sufficient evidence. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce precise, knowledgeable claim(s), establish the significance of the claim(s), distinguish the claim(s) from alternate or opposing claims and create an organization that logically sequences claim(s), counterclaims, reasons and evidence. c. Develop claim(s) and opposing claims fairly and thoroughly, supplying the most relevant evidence for each while pointing out the strengths and limitations of both in a manner that anticipates the audience\u2019s knowledge level, concerns, values and possible biases. d. Use words, phrases and clauses as well as varied syntax to link the major sections of the text, create cohesion and clarify the relationships between claim(s) and reasons, between reasons and evidence and between claim(s) and opposing claims. e. Establish and maintain a task-appropriate writing style. f. Provide a concluding statement or section that follows from and supports the argument presented. g. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience."},{"code":"C.11-12.2","subject":"English Language Arts","grade":"12","text":"Compose informative/explanatory texts to examine and/or convey complex ideas, concepts and information clearly and accurately through the effective selection, organization and analysis of content. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Introduce a topic; organize complex ideas, concepts and information so that each new element builds on that which precedes it to create a unified whole; include formatting, graphics and multimedia when useful to aiding comprehension. c. Develop the topic thoroughly by selecting the most significant and relevant facts, extended definitions, concrete details, quotations or other information and examples appropriate to the audience\u2019s knowledge of the topic. d. Use appropriate and varied transitions and syntax to link the major sections of the text, create cohesion and clarify the relationships among complex ideas and concepts. e. Use precise language, domain-specific vocabulary and techniques such as metaphor, simile and analogy to manage the complexity of the topic. f. Establish and maintain a formal style and objective tone while attending to the norms and conventions of the discipline in which they are writing. g. Provide a concluding statement or section that follows from and supports the information or explanation presented. h. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience."},{"code":"C.11-12.3","subject":"English Language Arts","grade":"12","text":"Use narratives strategically in other modes of writing utilizing effective technique, well-chosen details and well-structured sequences for an intended purpose, including but not limited to introducing an issue and/or supporting a claim. a. Produce clear and coherent writing in which the development, organization and style are appropriate to task, purpose and audience. b. Engage and orient the reader by setting up a problem, situation or observation and its significance, establishing one or multiple point(s) of view and introducing a narrator and/or characters; create a smooth progression of experiences or events. c. Use narrative techniques, such as dialogue, pacing, description, reflection and multiple plot lines, to develop experiences, events and/or characters. d. Use a variety of techniques to sequence events so that they build on one another to create a coherent whole and build toward a particular tone and outcome. e. Use precise words and phrases, telling details and sensory language to convey a vivid picture of the experiences, events, setting and/or characters. f. Provide a conclusion that explicitly connects the narrative\u2019s relevance to the intended purpose of the writing. g. Develop and strengthen writing as needed by planning, revising, editing, rewriting or trying a new approach, focusing on addressing what is most significant for a specific purpose and audience. Production and Distribution"},{"code":"C.11-12.4","subject":"English Language Arts","grade":"12","text":"Use DIGITAL RESOURCES to create, publish and update individual or shared products , taking advantage of technology\u2019s capacity to link to other information and to display information flexibly and dynamically. Use a variety of formats to cite sources ."},{"code":"C.11-12.5","subject":"English Language Arts","grade":"12","text":"Conduct short as well as more sustained RESEARCH projects to answer a question (including a self-generated question) or solve a problem; narrow or broaden the inquiry when appropriate; synthesize multiple sources on the subject , demonstrating understanding of the subject under investigation ."},{"code":"C.11-12.6","subject":"English Language Arts","grade":"12","text":"Gather relevant information from multiple authoritative print and digital sources, using advanced searches effectively ; assess the strengths and limitations of each source in terms of the task, purpose and audience; integrate information into the text selectively to maintain the flow of ideas, avoiding plagiarism and overreliance on any one source and following a standard format for citation ."},{"code":"C.11-12.7","subject":"English Language Arts","grade":"12","text":"Compose routinely over extended time frames and shorter time frames for a variety of task, purposes and audiences ."},{"code":"L.11-12.1","subject":"English Language Arts","grade":"12","text":"In both written and oral expression : a. Demonstrate the understanding that usage is a matter of convention , can change over time and may be contested . b. Resolve issues of complex or contested usage , consulting references as needed ."},{"code":"L.11-12.2","subject":"English Language Arts","grade":"12","text":"When writing : a. Demonstrate command of the CONVENTIONS OF GENERAL AMERICAN ENGLISH CAPITALIZATION, PUNCTUATION AND SPELLING ."},{"code":"L.11-12.3","subject":"English Language Arts","grade":"12","text":"Apply knowledge of language to understand how language functions in different contexts, to make effective choices for meaning or style and to comprehend more fully when reading or listening . a. Apply an understanding of syntax to the study of complex texts when reading . b. Vary syntax for effect in writing and speaking , consulting references for guidance as needed ."},{"code":"L.11-12.4","subject":"English Language Arts","grade":"12","text":"Determine or clarify the meaning of unknown and multiple-meaning words and phrases based on grades 11-12 reading and content, choosing flexibly from an array of strategies . a. Use context (e.g., the overall meaning of a sentence, paragraph or text; a word\u2019s position or function in a sentence) as a clue to the meaning of a word or phrase . b. Identify and correctly use patterns of word changes that indicate different meanings or parts of speech . c. Consult general and specialized reference materials to find the pronunciation of a word or determine or clarify its precise meaning or its part of speech . d. Acquire and use accurately general academic and domain-specific words and phrases, sufficient for reading, writing, speaking and listening at the postsecondary readiness level; demonstrate independence in gathering vocabulary knowledge when considering a word or phrase important to comprehension or expression ."},{"code":"L.11-12.5","subject":"English Language Arts","grade":"12","text":"Demonstrate understanding of figurative language, word relationships and nuances in word meanings . a. Interpret FIGURES OF SPEECH in context , including but not limited to HYPERBOLE and PARADOX , and analyze their rhetorical function in the text . b. Analyze nuances in the meaning of words with similar denotations ."},{"code":"L.11-12.5b","subject":"English Language Arts","grade":"12","text":"Language, Grades 11-12, Standard 5, Substandard b Reading Foundational Skills RF"},{"code":"RI.11-12.1","subject":"English Language Arts","grade":"12","text":"CITE RELEVANT AND THOROUGH TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RI.11-12.10","subject":"English Language Arts","grade":"12","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RI.11-12.2","subject":"English Language Arts","grade":"12","text":"Determine TWO OR MORE CENTRAL IDEAS OF A TEXT and analyze their development over the course of the text , including how they interact and build on one another to produce a complex account ."},{"code":"RI.11-12.3","subject":"English Language Arts","grade":"12","text":"Analyze a COMPLEX SET OF IDEAS OR SEQUENCE OF EVENTS and explain how specific individuals, ideas or events interact and develop over the course of the text ."},{"code":"RI.11-12.4","subject":"English Language Arts","grade":"12","text":"Determine the meaning of words and phrases as they are used in a text, including figurative, connotative, and technical meanings; analyze how an author uses and refines THE MEANING OF A KEY TERM OR TERMS over the course of a text ."},{"code":"RI.11-12.5","subject":"English Language Arts","grade":"12","text":"Analyze and evaluate the effectiveness of the structure an author uses in his or her EXPOSITION or ARGUMENT ."},{"code":"RI.11-12.6","subject":"English Language Arts","grade":"12","text":"Determine an author\u2019s POINT OF VIEW, PERSPECTIVE and PURPOSE in a text in which the RHETORIC is particularly effective, analyzing how style and content contribute to the effectiveness of the text ."},{"code":"RI.11-12.7","subject":"English Language Arts","grade":"12","text":"Integrate and evaluate MULTIPLE SOURCES OF INFORMATION presented in different print and non-print formats in order to address a question or solve a problem ."},{"code":"RI.11-12.8","subject":"English Language Arts","grade":"12","text":"Evaluate the ARGUMENT , specific CLAIMS and EVIDENCE in a text, assessing the validity, reasoning, relevance and sufficiency; analyze false statements and FALLACIOUS REASONING ."},{"code":"RI.11-12.9","subject":"English Language Arts","grade":"12","text":"Analyze DOCUMENTS OF HISTORICAL AND LITERARY SIGNIFICANCE for their themes, purposes and rhetorical features ."},{"code":"RL.11-12.1","subject":"English Language Arts","grade":"12","text":"CITE RELEVANT AND THOROUGH TEXTUAL EVIDENCE to support analysis of what the text says explicitly as well as inferences drawn from the text."},{"code":"RL.11-12.10","subject":"English Language Arts","grade":"12","text":"Routinely and flexibly develop and apply background knowledge along with a variety of comprehension strategies to understand and analyze GRADE-APPROPRIATE, COMPLEX LITERARY TEXT independently ."},{"code":"RL.11-12.2","subject":"English Language Arts","grade":"12","text":"Determine TWO OR MORE THEMES OR CENTRAL IDEAS of a text and analyze their development over the course of the text , including how they interact and build on one another to produce a complex account ."},{"code":"RL.11-12.3","subject":"English Language Arts","grade":"12","text":"Analyze the IMPACT OF THE AUTHOR\u2019S CHOICES over the course of a text regarding how to develop and relate elements of a story or drama ."},{"code":"RL.11-12.4","subject":"English Language Arts","grade":"12","text":"Determine the meaning of words and phrases as they are used in the text, including figurative and connotative meanings; analyze the cumulative impact of specific WORD CHOICES on meaning and TONE and on the text as a whole ."},{"code":"RL.11-12.5","subject":"English Language Arts","grade":"12","text":"Analyze how an author\u2019s choices concerning how to STRUCTURE SPECIFIC PARTS OF A TEXT contribute to its overall structure and meaning as well as its aesthetic impact ."},{"code":"RL.11-12.6","subject":"English Language Arts","grade":"12","text":"Analyze how POINT OF VIEW AND PERSPECTIVE are used to manipulate the reader for a specific purpose or effect , including but not limited to SATIRE, SARCASM, IRONY AND UNDERSTATEMENT ."},{"code":"RL.11-12.7","subject":"English Language Arts","grade":"12","text":"Analyze DIVERSE MEDIA INTERPRETATIONS OF A STORY, DRAMA OR POEM , evaluating how each version interprets the source text ."},{"code":"RL.11-12.8","subject":"English Language Arts","grade":"12","text":"Not applicable to literature"},{"code":"RL.11-12.9","subject":"English Language Arts","grade":"12","text":"Demonstrate knowledge of various time periods to analyze how TWO OR MORE TEXTS FROM THE SAME PERIOD treat similar themes or topics ."},{"code":"KY.HS.A.1","subject":"Mathematics","grade":"12","text":"Interpret expressions that represent a quantity in terms of its context. \u2605 a. Interpret parts of an expression, such as terms, factors and coefficients. b. Interpret complicated expressions, given a context, by viewing one or more of their parts as a single entity."},{"code":"KY.HS.A.10","subject":"Mathematics","grade":"12","text":"Rewrite simple rational expressions in different forms."},{"code":"KY.HS.A.11","subject":"Mathematics","grade":"12","text":"Add, subtract, multiply and divide rational algebraic expressions."},{"code":"KY.HS.A.12","subject":"Mathematics","grade":"12","text":"Create equations and inequalities in one variable and use them to solve problems."},{"code":"KY.HS.A.13","subject":"Mathematics","grade":"12","text":"Create equations in two or more variables to represent relationships between quantities; graph equations on coordinate axes with labels and scales."},{"code":"KY.HS.A.14","subject":"Mathematics","grade":"12","text":"Create a system of equations or inequalities to represent constraints within a modeling context. Interpret the solution(s) to the corresponding system as viable or nonviable options within the context."},{"code":"KY.HS.A.15","subject":"Mathematics","grade":"12","text":"Rearrange formulas to solve a literal equation, highlighting a quantity of interest, using the same reasoning as in solving equations."},{"code":"KY.HS.A.16","subject":"Mathematics","grade":"12","text":"Understand each step in solving a simple equation as following from the equality of numbers asserted at the previous step, starting from the assumption that the original equation has a solution. Construct a viable argument to justify a solution method."},{"code":"KY.HS.A.17","subject":"Mathematics","grade":"12","text":"Solve and justify equations in one variable. Justify the solutions and give examples showing how extraneous solutions may arise. a. Solve rational equations written as proportions in one variable. b. Solve radical equations in one variable."},{"code":"KY.HS.A.18","subject":"Mathematics","grade":"12","text":"Solve linear equations and inequalities in one variable, including literal equations with coefficients represented by letters."},{"code":"KY.HS.A.19","subject":"Mathematics","grade":"12","text":"Solve quadratic equations in one variable. a. Solve quadratic equations by taking square roots, the quadratic formula and factoring, as appropriate to the initial form of the equation. Recognize when the quadratic formula gives complex solutions and write them as a \u00b1 bi for real numbers a and b. b. (+) Use the method of completing the square to transform any quadratic equation in x into an equation of the form (x \u2013 p)2 = q that has the same solutions. Derive the quadratic formula from this form. c. (+) Solve quadratic equations by completing the square."},{"code":"KY.HS.A.2","subject":"Mathematics","grade":"12","text":"Use the structure of an expression to identify ways to rewrite it and consistently look for opportunities to rewrite expressions in equivalent forms."},{"code":"KY.HS.A.20","subject":"Mathematics","grade":"12","text":"Solve systems of linear equations in two variables. a. Understand a system of two equations in two variables has the same solution as a new system formed by replacing one of the original equations with an equivalent equation. b. Solve systems of linear equations with graphs, substitution and elimination, focusing on pairs of linear equations in two variables."},{"code":"KY.HS.A.21","subject":"Mathematics","grade":"12","text":"Solve a simple system consisting of a linear equation and a quadratic equation in two variables algebraically and graphically."},{"code":"KY.HS.A.22","subject":"Mathematics","grade":"12","text":"Use matrices to solve a system of equations. a. Represent a system of linear equations as a single matrix equation in a vector variable. b. Find the inverse of a matrix if it exists. c. Use matrices to solve systems of linear equations (using technology for matrices of dimension 3 \u00d7 3 or greater)."},{"code":"KY.HS.A.23","subject":"Mathematics","grade":"12","text":"Understand that the graph of an equation in two variables is the set of all its solutions plotted in the coordinate plane."},{"code":"KY.HS.A.24","subject":"Mathematics","grade":"12","text":"Justify that the solutions of the equations f(x) = g(x) are the x-coordinates of the points where the graphs of y = f(x) and y = g(x) intersect. Find the approximate solutions graphically, using technology or tables. \u2605"},{"code":"KY.HS.A.25","subject":"Mathematics","grade":"12","text":"Graph linear inequalities in two variables. a. Graph the solutions to a linear inequality as a half-plane (excluding the boundary in the case of a strict inequality). b. Graph the solution set to a system of linear inequalities as the intersection of the corresponding half-planes."},{"code":"KY.HS.A.3","subject":"Mathematics","grade":"12","text":"Choose and produce an equivalent form of an expression to reveal and explain properties of the quantity represented by the expression. \u2605 a. Write the standard form of a given polynomial and identify the terms, coefficients, degree, leading coefficient and constant term. b. Factor a quadratic expression to reveal the zeros of the function it defines. c. Use the properties of exponents to rewrite exponential expressions. d. (+) Complete the square in a quadratic expression to reveal the maximum or minimum value of the function it defines."},{"code":"KY.HS.A.3b","subject":"Mathematics","grade":"12","text":"Students recognize the connection between the zero product property and solving a quadratic in one variable by setting factored expressions equal to zero."},{"code":"KY.HS.A.3d","subject":"Mathematics","grade":"12","text":"Students recognize being able to complete the square allows them to identify the coordinates of the maximum or minimum value more easily than when the quadratic is in standard form and there are pros and cons of each equivalent form."},{"code":"KY.HS.A.4","subject":"Mathematics","grade":"12","text":"Derive the formula for the sum of a finite geometric series (when the common ratio is not 1) and use the formula to solve problems. \u2605"},{"code":"KY.HS.A.5","subject":"Mathematics","grade":"12","text":"Add, subtract and multiply polynomials."},{"code":"KY.HS.A.6","subject":"Mathematics","grade":"12","text":"Know and apply the Remainder Theorem."},{"code":"KY.HS.A.7","subject":"Mathematics","grade":"12","text":"Identify roots of polynomials when suitable factorizations are available. Know these roots become the zeros (x-intercepts) for the corresponding polynomial function."},{"code":"KY.HS.A.8","subject":"Mathematics","grade":"12","text":"Prove polynomial identities and use them to describe numerical relationships."},{"code":"KY.HS.A.9","subject":"Mathematics","grade":"12","text":"Know and apply the Binomial Theorem for the expansion of (x + y )n in powers of x and y for a positive integer n, where x and y are any numbers, with coefficients determined for example by Pascal\u2019s Triangle."},{"code":"KY.HS.C.1","subject":"Mathematics","grade":"12","text":"Understand limits. a. Apply limits to a variety of functions, including piecewise functions. b. (++) Prove that the limit of a function exists, based upon the definition of a limit."},{"code":"KY.HS.C.10","subject":"Mathematics","grade":"12","text":"Communicate an understanding of continuity using precise mathematical symbols and language."},{"code":"KY.HS.C.11","subject":"Mathematics","grade":"12","text":"Define derivatives. a. Define the derivative of a function as the limit of the difference quotient. b. Understand this limit of the difference quotient can be interpreted as an instantaneous rate of change or the slope of a tangent line."},{"code":"KY.HS.C.12","subject":"Mathematics","grade":"12","text":"Use average rate of change to estimate the derivative from a table of values or a graph."},{"code":"KY.HS.C.13","subject":"Mathematics","grade":"12","text":"Understand the derivative as a function."},{"code":"KY.HS.C.15","subject":"Mathematics","grade":"12","text":"Explain why differentiability implies continuity yet continuity does not imply differentiability."},{"code":"KY.HS.C.16","subject":"Mathematics","grade":"12","text":"Understand and apply the Mean Value Theorem, including numerical, graphical and algebraic representations."},{"code":"KY.HS.C.17","subject":"Mathematics","grade":"12","text":"Understand the relationship between the concavity of a function and the sign of the second derivative."},{"code":"KY.HS.C.18","subject":"Mathematics","grade":"12","text":"Understand Rolle\u2019s Theorem as a special case of the Mean Value Theorem."},{"code":"KY.HS.C.19","subject":"Mathematics","grade":"12","text":"Efficiently find derivatives of functions with and without technology."},{"code":"KY.HS.C.2","subject":"Mathematics","grade":"12","text":"Demonstrate an understanding of limits by estimating and finding the limit of a function at a point graphically, numerically and algebraically."},{"code":"KY.HS.C.20","subject":"Mathematics","grade":"12","text":"Understand and use derivative rules for sums, differences, products and quotients of two functions and calculate the derivative of a composite function using the chain rule. MP2,"},{"code":"KY.HS.C.21","subject":"Mathematics","grade":"12","text":"Use implicit differentiation to find a derivative in an equation of two variables."},{"code":"KY.HS.C.22","subject":"Mathematics","grade":"12","text":"Use implicit differentiation to find the derivative of the inverse of a function."},{"code":"KY.HS.C.23","subject":"Mathematics","grade":"12","text":"Understand the relationship between the increasing and decreasing behavior of a function and the sign of the first derivative of the function."},{"code":"KY.HS.C.24","subject":"Mathematics","grade":"12","text":"Use the first derivative to analyze curves and identify relative extrema."},{"code":"KY.HS.C.25","subject":"Mathematics","grade":"12","text":"Understand the relationship of concavity to the second derivative."},{"code":"KY.HS.C.26","subject":"Mathematics","grade":"12","text":"Use the second derivative to find points of inflection."},{"code":"KY.HS.C.27","subject":"Mathematics","grade":"12","text":"Use the second derivative to analytically locate intervals on which a function is concave up, concave down or neither."},{"code":"KY.HS.C.28","subject":"Mathematics","grade":"12","text":"Describe how graphical characteristics of a given function, the first derivative of that function and the second derivative of that function interrelate."},{"code":"KY.HS.C.29","subject":"Mathematics","grade":"12","text":"Use derivatives to express rate of change in a variety of contexts."},{"code":"KY.HS.C.3","subject":"Mathematics","grade":"12","text":"Apply properties and theorems of limits, including limits of indeterminate forms."},{"code":"KY.HS.C.30","subject":"Mathematics","grade":"12","text":"Use derivatives to solve a variety of problems including related rates, optimization, tangent line approximations and growth and decay models."},{"code":"KY.HS.C.31","subject":"Mathematics","grade":"12","text":"Use differentiation to solve problems involving velocity, speed and acceleration."},{"code":"KY.HS.C.32","subject":"Mathematics","grade":"12","text":"Understand and apply differential equations. a. Verify solutions to differential equations and use them to model real-world problems with and without technology. b. Solve separable differential equations and use them in modeling real-world problems with and without technology."},{"code":"KY.HS.C.33","subject":"Mathematics","grade":"12","text":"Understand the definite integral of a function over an interval. Interpret a definite integral as a limit of Riemann Sums and as net accumulation of change."},{"code":"KY.HS.C.34","subject":"Mathematics","grade":"12","text":"Write a Riemann sum that represents the definition of a definite integral."},{"code":"KY.HS.C.35","subject":"Mathematics","grade":"12","text":"Calculate the values of Riemann Sums over equal subdivisions to approximate definite integrals of functions represented graphically and numerically (using tables). Use left-hand sums, right- hand sums, midpoint sums and trapezoidal sums."},{"code":"KY.HS.C.36","subject":"Mathematics","grade":"12","text":"Recognize differentiation and integration as inverse operations."},{"code":"KY.HS.C.37","subject":"Mathematics","grade":"12","text":"Understand how the Fundamental Theorem of Calculus connects differentiation and integration and use it to evaluate definite and indefinite integrals and to represent particular antiderivatives."},{"code":"KY.HS.C.38","subject":"Mathematics","grade":"12","text":"Perform analytical and graphical analysis of functions using the Fundamental Theorem of Calculus."},{"code":"KY.HS.C.39","subject":"Mathematics","grade":"12","text":"Understand and use the definite integral of a function over an interval and understand its use as a mathematical tool."},{"code":"KY.HS.C.4","subject":"Mathematics","grade":"12","text":"Communicate understanding of limits using precise mathematical symbols and language."},{"code":"KY.HS.C.40","subject":"Mathematics","grade":"12","text":"Find antiderivatives of a variety of basic functions including power, exponential, logarithmic and trigonometric and apply basic properties of definite integrals."},{"code":"KY.HS.C.41","subject":"Mathematics","grade":"12","text":"Use substitution techniques and change of limits of integration to find antiderivatives."},{"code":"KY.HS.C.42","subject":"Mathematics","grade":"12","text":"Find particular antiderivatives given initial conditions."},{"code":"KY.HS.C.43","subject":"Mathematics","grade":"12","text":"Model, solve and interpret applications of antiderivatives including finding area, velocity, acceleration and volume of a solid."},{"code":"KY.HS.C.44","subject":"Mathematics","grade":"12","text":"Apply integration to solve problems including particle motion and exponential growth and decay."},{"code":"KY.HS.C.45","subject":"Mathematics","grade":"12","text":"Describe the application of integration to a variety of problems using precise mathematical language and notation."},{"code":"KY.HS.C.5","subject":"Mathematics","grade":"12","text":"Describe asymptotic behavior (analytically and graphically) in terms of infinite limits and limits at infinity."},{"code":"KY.HS.C.6","subject":"Mathematics","grade":"12","text":"Discuss the end behavior of functions; identify representative functions for each type of end behavior using precise mathematical symbols and language."},{"code":"KY.HS.C.7","subject":"Mathematics","grade":"12","text":"Understand and use the limit definition of continuity to determine whether a given function is continuous at a specific point."},{"code":"KY.HS.C.8","subject":"Mathematics","grade":"12","text":"Define and identify different types of discontinuity \u2013 removable (hole) or non-removable (jump, asymptote) \u2013 in terms of limits."},{"code":"KY.HS.C.9","subject":"Mathematics","grade":"12","text":"Understand and apply continuous function theorems. a. Apply the Intermediate Value Theorem to continuous functions. b. Apply the Extreme Value Theorem to continuous functions."},{"code":"KY.HS.F.1","subject":"Mathematics","grade":"12","text":"Understand properties and key features of functions and the different ways functions can be represented. a. Understand that a function from one set (called the domain) to another set (called the range) assigns to each element of the domain exactly one element of the range. If f is a function and x is an element of its domain, then f(x) denotes the output of f corresponding to the input x. b. Using appropriate function notation, evaluate functions for inputs in their domains and interpret statements that use function notation in terms of a context. c. For a function that models a relationship between two quantities, interpret key features of graphs and tables in terms of the quantities and sketch graphs showing key features given a verbal description of the relationship. d. Relate the domain of a function to its graph and, where applicable, to the quantitative relationship it describes. e. Compare properties of two functions each represented in a different way (algebraically, graphically, numerically in tables, or by verbal descriptions)."},{"code":"KY.HS.F.10","subject":"Mathematics","grade":"12","text":"Understand the inverse relationship between exponents and logarithms and use this relationship to solve problems involving logarithms and exponents with the use of technology."},{"code":"KY.HS.F.11","subject":"Mathematics","grade":"12","text":"Distinguish between situations that can be modeled with linear functions and with exponential functions. a. Recognize and justify that linear functions grow by equal differences over equal intervals and that exponential functions grow by equal factors over equal intervals. b. Recognize situations in which one quantity changes at a constant rate per unit interval relative to another. c. Recognize situations in which a quantity grows or decays by a constant percent rate per unit interval relative to another."},{"code":"KY.HS.F.12","subject":"Mathematics","grade":"12","text":"Construct linear and exponential functions, including arithmetic and geometric sequences, given a graph, a description of a relationship, or two input-output pairs (include reading these from a table)."},{"code":"KY.HS.F.13","subject":"Mathematics","grade":"12","text":"Observe using graphs and tables that a quantity increasing exponentially eventually exceeds a quantity increasing linearly, quadratically, or (more generally) as a polynomial function."},{"code":"KY.HS.F.14","subject":"Mathematics","grade":"12","text":"Interpret the parameters in a linear or exponential function in terms of a context."},{"code":"KY.HS.F.15","subject":"Mathematics","grade":"12","text":"Understand the relationship of radian measure of an angle to its arc length."},{"code":"KY.HS.F.16","subject":"Mathematics","grade":"12","text":"Understand and use the unit circle. a. Explain how the unit circle in the coordinate plane enables the extension of trigonometric functions to all real numbers, interpreted as radian measures of angles traversed counterclockwise around the unit circle. b. Use special triangles to determine geometrically the values of sine, cosine, tangent for \u03c0/3, \u03c0 /4 and \u03c0 /6 and use the unit circle to express the values of sine, cosine and tangent for \u03c0 \u2013x, \u03c0 +x and 2 \u03c0 \u2013x in terms of their values for x, where x is any real number. c. Use the unit circle to explain symmetry (odd and even) and periodicity of trigonometric functions."},{"code":"KY.HS.F.17","subject":"Mathematics","grade":"12","text":"Choose trigonometric functions to model periodic phenomena with specified period, midline and amplitude. \u2605"},{"code":"KY.HS.F.18","subject":"Mathematics","grade":"12","text":"Understand that restricting a trigonometric function to a domain on which it is always increasing or always decreasing allows its inverse to be constructed."},{"code":"KY.HS.F.19","subject":"Mathematics","grade":"12","text":"Use inverse functions to solve trigonometric equations that arise in modeling contexts; evaluate the solutions using technology and interpret them in terms of the context. \u2605"},{"code":"KY.HS.F.2","subject":"Mathematics","grade":"12","text":"Recognize that arithmetic and geometric sequences are functions, sometimes defined recursively, whose domain is a subset of the integers."},{"code":"KY.HS.F.20","subject":"Mathematics","grade":"12","text":"Proving identities and formulas within the context of trigonometry. a. Prove the Pythagorean identity and use it to find sin(\u03b8), cos(\u03b8), or tan(\u03b8) given sin(\u03b8), cos(\u03b8), or tan(\u03b8) and the quadrant of the angle. b. Prove the addition and subtraction formulas for sine, cosine and tangent and use them to solve problems."},{"code":"KY.HS.F.3","subject":"Mathematics","grade":"12","text":"Understand average rate of change of a function over an interval. a. Calculate and interpret the average rate of change of a function (presented symbolically or as a table) over a specified interval. b. Estimate the rate of change from a graph. \u2605"},{"code":"KY.HS.F.4","subject":"Mathematics","grade":"12","text":"Graph functions expressed symbolically and show key features of the graph, with and without using technology (computer, graphing calculator). \u2605 a. Graph linear and quadratic functions and show intercepts, maxima and minima. b. Graph square root, cube root and absolute value functions. c. Graph polynomial functions, identifying zeros when suitable factorizations are available and showing end behavior. d. Graph exponential and logarithmic functions, showing intercepts and end behavior. e. (+) Graph trigonometric functions, showing period, midline and amplitude. f. (+) Graph piecewise functions, including step functions. g. (+) Graph rational functions, identifying zeros and asymptotes when suitable factorizations are available and showing end behavior."},{"code":"KY.HS.F.5","subject":"Mathematics","grade":"12","text":"Write a function defined by an expression in different but equivalent forms to reveal and explain different properties of the function. a. Identify zeros, extreme values and symmetry of the graph within the context of a quadratic function. a. Quadratic functions provide a rich playground for developing this ability, since the three principal forms for a quadratic expression (expanded, factored and completed square) each give insight into different aspects of the function. b. Students examine real-world situations with constant multiplicative change, represented as expressions, such as growth or decay."},{"code":"KY.HS.F.6","subject":"Mathematics","grade":"12","text":"Write a function that describes a relationship between two quantities. \u2605 a. Determine an explicit expression, a recursive process, or steps for calculation from a context. b. Combine standard function types using arithmetic operations. c. (+) Compose functions."},{"code":"KY.HS.F.7","subject":"Mathematics","grade":"12","text":"Use arithmetic and geometric sequences to model situations and scenarios. a. Use formulas (explicit and recursive) to generate terms for arithmetic and geometric sequences. b. Write formulas to model arithmetic and geometric sequences and apply those formulas in realistic situations. \u2605 c. (+) Translate between recursive and explicit formulas."},{"code":"KY.HS.F.8","subject":"Mathematics","grade":"12","text":"Understand the effects of transformations on the graph of a function. a. Identify the effect on the graph of replacing f(x) by f(x) + k, k f(x), f(kx) and f(x + k) for specific values of k (both positive and negative); find the value of k given the graphs. b. Experiment with cases and illustrate an explanation of the effects on the graph using technology."},{"code":"KY.HS.F.9","subject":"Mathematics","grade":"12","text":"Find inverse functions. a. Given the equation of an invertible function, find the inverse. b. (+) Verify by composition that one function is the inverse of another. c. (+) Read values of an inverse function from a graph or a table, given that the function has an inverse. d. (+) Produce an invertible function from a non-invertible function by restricting the domain."},{"code":"KY.HS.G.1","subject":"Mathematics","grade":"12","text":"Know and apply precise definitions of the language of Geometry: a. Understand properties of line segments, angles and circle. b. Understand properties of and differences between perpendicular and parallel lines."},{"code":"KY.HS.G.10","subject":"Mathematics","grade":"12","text":"Apply the properties of similarity transformations to establish the AA criterion for two triangles to be similar."},{"code":"KY.HS.G.11","subject":"Mathematics","grade":"12","text":"Understand theorems about triangles. a. Apply theorems about triangles. b. (+) Prove theorems about triangles. c. Use similarity criteria for triangles to solve problems and to prove relationships in geometric figures."},{"code":"KY.HS.G.12","subject":"Mathematics","grade":"12","text":"Understand properties of right triangles. a. Understand that by similarity, side ratios in right triangles are properties of the angles in the triangle, leading to definitions of trigonometric ratios for acute angles (sine, cosine and tangent). b. Explain and use the relationship between the sine and cosine of complementary angles. c. Use trigonometric ratios and the Pythagorean Theorem to solve right triangles in applied problems. \u2605"},{"code":"KY.HS.G.12c","subject":"Mathematics","grade":"12","text":"Use coordinates to justify and prove simple geometric theorems algebraically. Use similarity criteria for triangles to solve problems in geometric figures. Use trigonometric ratios and the Pythagorean Theorem to solve right triangles in applied problems.\u2605"},{"code":"KY.HS.G.13","subject":"Mathematics","grade":"12","text":"Derive the formula A = 1/2 ab sin(C) for the area of a triangle by drawing an auxiliary line from a vertex perpendicular to the opposite side."},{"code":"KY.HS.G.14","subject":"Mathematics","grade":"12","text":"Understand and apply the Law of Sines and the Law of Cosines. a. Use the Law of Sines and Cosines to find unknown measurements in right and non-right triangles. b. Prove the Laws of Sines and Cosines and use them to solve problems."},{"code":"KY.HS.G.15","subject":"Mathematics","grade":"12","text":"Verify using dilations that all circles are similar."},{"code":"KY.HS.G.16","subject":"Mathematics","grade":"12","text":"Identify and describe relationships among angles and segments within the context of circles involving: a. Recognize differences between and properties of inscribed, central and circumscribed angles. b. Understand relationships between inscribed angles and the diameter of a circle. c. Understand the relationship between the radius of a circle and the line drawn through the point of tangency on that radius."},{"code":"KY.HS.G.17","subject":"Mathematics","grade":"12","text":"Apply basic construction procedures within the context of a circle. a. Construct the inscribed and circumscribed circles of a triangle. b. Construct a tangent line from a point outside a given circle to the circle."},{"code":"KY.HS.G.18","subject":"Mathematics","grade":"12","text":"Understand the relationship between an intercepted arc length within a circle and the radius of the circle. a. Derive using similarity the fact that the length of the arc intercepted by an angle is proportional to the radius. Derive the formula for the area of a sector. b. Define the radian measure of the angle as the measure of a central angle that intercepts an arc equal in length to the radius of the circle."},{"code":"KY.HS.G.19","subject":"Mathematics","grade":"12","text":"Understand the relationship between the algebraic form and the geometric representation of a circle. a. Write the equation of a circle of given center and radius using the Pythagorean Theorem. b. (+) Derive and write the equation of a circle of given center and radius using the Pythagorean Theorem. c. (+) Complete the square to find the center and radius of a circle given by an equation."},{"code":"KY.HS.G.2","subject":"Mathematics","grade":"12","text":"Representing transformations in the plane. a. Describe transformations as functions that take points in the plane as inputs and give other points as outputs b. Compare transformations that preserve distance and angle measures to those that do not. c. Given a rectangle, parallelogram, trapezoid, or regular polygon, formally describe the rotations and reflections that carry it onto itself, using properties of these figures."},{"code":"KY.HS.G.20","subject":"Mathematics","grade":"12","text":"Derive the equations of conic sections. a. Derive the equation of a parabola given a focus and directrix. b. Derive the equations of ellipses and hyperbolas given the foci, using the fact that the sum or difference of distances from the foci is constant."},{"code":"KY.HS.G.21","subject":"Mathematics","grade":"12","text":"Use coordinates to justify and prove simple geometric theorems algebraically."},{"code":"KY.HS.G.22","subject":"Mathematics","grade":"12","text":"Justify and apply the slope criteria for parallel and perpendicular lines and use them to solve geometric problems."},{"code":"KY.HS.G.23","subject":"Mathematics","grade":"12","text":"Find measurements among points within the coordinate plane. a. Use points from the coordinate plane to find the coordinates of a midpoint of a line segment and the distance between the endpoints of a line segment. b. Find the point on a directed line segment between two given points that partitions the segment in a given ratio."},{"code":"KY.HS.G.24","subject":"Mathematics","grade":"12","text":"Use coordinates within the coordinate plane to calculate measurements of two dimensional figures. a. Compute the perimeters of various polygons. b. Compute the areas of triangles, rectangles and other quadrilaterals.\u2605"},{"code":"KY.HS.G.25","subject":"Mathematics","grade":"12","text":"Analyze and determine the validity of arguments for the formulas for the various figures and shapes. a. Finding the circumference and area of a circle. b. Finding the volume of a sphere, prism, cylinder, pyramid and cone."},{"code":"KY.HS.G.26","subject":"Mathematics","grade":"12","text":"Give an informal argument using Cavalieri\u2019s principle for the formulas for the volume of a sphere and other solid figures."},{"code":"KY.HS.G.27","subject":"Mathematics","grade":"12","text":"Use volume formulas to solve problems for cylinders, pyramids, cones, spheres, prisms \u2605"},{"code":"KY.HS.G.28","subject":"Mathematics","grade":"12","text":"Identify the shapes of two-dimensional cross-sections of three-dimensional objects and identify three-dimensional objects generated by rotations of two-dimensional objects."},{"code":"KY.HS.G.29","subject":"Mathematics","grade":"12","text":"Use geometric shapes, their measures and their properties to describe objects in real world settings."},{"code":"KY.HS.G.3","subject":"Mathematics","grade":"12","text":"Develop formal definitions of rotations, reflections and translations in terms of angles, circles, perpendicular lines, parallel lines and line segments."},{"code":"KY.HS.G.30","subject":"Mathematics","grade":"12","text":"Apply concepts of density based on area and volume in modeling situations, using appropriate units of measurement."},{"code":"KY.HS.G.31","subject":"Mathematics","grade":"12","text":"Apply geometric methods to solve design problems. \u2605"},{"code":"KY.HS.G.4","subject":"Mathematics","grade":"12","text":"Understand the effects of transformations of geometric figures. a. Given a geometric figure and a rotation, reflection, or translation, draw the transformed figure. b. Specify a sequence of transformations that will carry a given figure onto another. c. Use geometric descriptions of rigid motions to transform figures and to predict the effect of a given rigid motion on a given figure. Given two figures, use the definition of congruence in terms of rigid motions to decide if they are congruent."},{"code":"KY.HS.G.5","subject":"Mathematics","grade":"12","text":"Know and apply the concepts of triangle congruence: a. Use the definition of congruence in terms of rigid motions to show that two triangles are congruent if and only if corresponding pairs of sides and corresponding pairs of angles are congruent. b. Explain how the criteria for triangle congruence (ASA, SAS and SSS) follow from the definition of congruence in terms of rigid motions."},{"code":"KY.HS.G.6","subject":"Mathematics","grade":"12","text":"Apply theorems for lines, angles, triangles, parallelograms."},{"code":"KY.HS.G.7","subject":"Mathematics","grade":"12","text":"Prove theorems about geometric figures. a. Construct formal proofs to justify theorems for lines, angles and triangles. b. (+) Construct formal proofs to justify theorems for parallelograms."},{"code":"KY.HS.G.8","subject":"Mathematics","grade":"12","text":"Create and apply geometric constructions. a. Make formal geometric constructions with a variety of tools and methods. b. Apply basic construction procedures to construct more complex figures."},{"code":"KY.HS.G.9","subject":"Mathematics","grade":"12","text":"Understand properties of dilations. a. Verify the properties that result from that dilations given by a center and a scale factor. b. Verify that a dilation produces an image that is similar to the pre-image."},{"code":"KY.HS.N.1","subject":"Mathematics","grade":"12","text":"by extending student understanding to situations where the numerator is not one. For example, students understand that defining 4m/n is the same as \u221a4 \ud835\udc5b\ud835\udc5b m and ( \u221a4 \ud835\udc5b\ud835\udc5b )m. Include contextual examples, such as rewriting the volume of a sphere to identify the radius as a function of volume."},{"code":"KY.HS.N.10","subject":"Mathematics","grade":"12","text":"Extend polynomial identities to the complex numbers."},{"code":"KY.HS.N.11","subject":"Mathematics","grade":"12","text":"Know the Fundamental Theorem of Algebra; show that it is true for quadratic polynomials."},{"code":"KY.HS.N.12","subject":"Mathematics","grade":"12","text":"Understand and apply properties of vectors. a. Recognize vector quantities as having both magnitude and direction. Represent vector quantities by directed line segments and use appropriate symbols for vectors and their magnitudes. b. Find the components of a vector by subtracting the coordinates of an initial point from the coordinates of a terminal point. c. Solve problems involving velocity and other quantities that can be represented by vectors."},{"code":"KY.HS.N.13","subject":"Mathematics","grade":"12","text":"Perform operations with vectors (addition, subtraction and multiplication by a scalar). a. Add vectors end-to-end, component-wise and by the parallelogram rule. Understand that the magnitude of a sum of two vectors is typically not the sum of the magnitudes. b. Given two vectors in magnitude and direction form, determine the magnitude and direction of their sum. c. Understand vector subtraction v \u2013 w as v + (\u2013w), where \u2013w is the additive inverse of w, with the same magnitude as w and pointing in the opposite direction. Represent vector subtraction graphically by connecting the tips in the appropriate order and perform vector subtraction component-wise. d. Represent scalar multiplication graphically by scaling vectors and possibly reversing their direction; perform scalar multiplication component-wise. e. b. Compute the magnitude of a scalar multiple cv using ||cv|| = |c|v. Compute the direction of cv knowing that when |c|v \u2260 0, the direction of cv is either along v (for c > 0) or against v (for c < 0)."},{"code":"KY.HS.N.14","subject":"Mathematics","grade":"12","text":"Use matrices to represent and manipulate data."},{"code":"KY.HS.N.15","subject":"Mathematics","grade":"12","text":"Perform operations with matrices. a. Add, subtract and multiply matrices of appropriate dimensions. b. Multiply matrices by scalars to produce new matrices."},{"code":"KY.HS.N.16","subject":"Mathematics","grade":"12","text":"Understand properties of square and identity matrices. a. Understand that, unlike multiplication of numbers, matrix multiplication for square matrices is not a commutative operation, but still satisfies the associative and distributive properties. b. Understand that the zero and identity matrices play a role in matrix addition and multiplication similar to the role of 0 and 1 in the real numbers. The determinant of a square matrix is nonzero if and only if the matrix has a multiplicative inverse. c. Work with 2 \u00d7 2 matrices as transformations of the plane and interpret the absolute value of the determinant in terms of area."},{"code":"KY.HS.N.17","subject":"Mathematics","grade":"12","text":"Multiply a vector (regarded as a matrix with one column) by a matrix of suitable dimensions to produce another vector. Work with matrices as transformations of vectors."},{"code":"KY.HS.N.2","subject":"Mathematics","grade":"12","text":"Rewrite expressions involving radicals and rational exponents using the properties of exponents."},{"code":"KY.HS.N.3","subject":"Mathematics","grade":"12","text":"Justify why the sum or product of two rational numbers is rational; that the sum of a rational number and an irrational number is irrational; and that the product of a nonzero rational number and an irrational number is irrational."},{"code":"KY.HS.N.4","subject":"Mathematics","grade":"12","text":"Use units in context as a way to understand problems and to guide the solution of multi-step problems; \u2605 a. Choose and interpret units consistently in formulas; b. Choose and interpret the scale and the origin in graphs and data displays."},{"code":"KY.HS.N.5","subject":"Mathematics","grade":"12","text":"Define appropriate units in context for the purpose of descriptive modeling. \u2605"},{"code":"KY.HS.N.6","subject":"Mathematics","grade":"12","text":"does not require a formal discussion or use of significant digits in the scientific sense, students understand a level of precision. For example, when using the Pythagorean Theorem with measurements given in tenths of an inch, it is appropriate for students to express answers to the nearest tenth, but not to the nearest hundredth because that level of precision was not used in the original measures."},{"code":"KY.HS.N.7","subject":"Mathematics","grade":"12","text":"Understanding properties of complex numbers. a. Know there is a complex number i such that i2 = \u20131 and every complex number has the form a + bi with a and b real. b. Use the relation i2 = \u20131 and the commutative, associative and distributive properties to add, subtract and multiply complex numbers. c. (+) Find the conjugate of a complex number and use it to find the quotient of complex numbers."},{"code":"KY.HS.N.8","subject":"Mathematics","grade":"12","text":"Understanding representations of complex numbers using the complex plane. a. Represent complex numbers on the complex plane in rectangular and polar form (including real and imaginary numbers) and explain why the rectangular and polar forms of a given complex number represent the same number. b. Represent addition, subtraction, multiplication, modulus and conjugation of complex numbers geometrically on the complex plane; use properties of this representation for computation. c. Calculate the distance between numbers in the complex plane as the modulus of the difference and the midpoint of a segment as the average of the numbers at its endpoints."},{"code":"KY.HS.N.9","subject":"Mathematics","grade":"12","text":"Solve quadratic equations with real coefficients that have complex solutions."},{"code":"KY.HS.SP.1","subject":"Mathematics","grade":"12","text":"Represent the distribution of data with plots on the real number line (stem plots, dot plots, histograms and box plots)."},{"code":"KY.HS.SP.10","subject":"Mathematics","grade":"12","text":"Decide if a specified model is consistent with the results from a simulation."},{"code":"KY.HS.SP.11","subject":"Mathematics","grade":"12","text":"Recognize the purposes of and differences among sample surveys, experiments and observational studies; explain how randomization relates to each."},{"code":"KY.HS.SP.12","subject":"Mathematics","grade":"12","text":"Use data from a sample survey to estimate a population mean or proportion and explain how bias may be involved in the process."},{"code":"KY.HS.SP.13","subject":"Mathematics","grade":"12","text":"Use data from a randomized experiment to compare two treatments; use simulations to decide if differences between estimates or statistics are significant."},{"code":"KY.HS.SP.14","subject":"Mathematics","grade":"12","text":"Describe events as subsets of a sample space. Use characteristics (or categories) of the outcomes, such as, \u2022 as unions, \u201cA or B,\u201d that are mutually exclusive events and \u2022 as unions, \u201cA or B,\u201d that are non-mutually exclusive events and \u2022 as intersections, \u201cA and B,\u201d and \u2022 as complements of other events, \u201cnot A.\u201d to calculate basic probabilities."},{"code":"KY.HS.SP.15","subject":"Mathematics","grade":"12","text":"Understand the concept of independence. a. Understand that two events A and B are independent if the probability of A and B occurring together is the product of their individual probabilities, P(A) x P(B) b. (+) Determine whether two events are independent and provide a justification to support the decision. c. Recognize and explain the concept of independence in everyday language and everyday situations."},{"code":"KY.HS.SP.16","subject":"Mathematics","grade":"12","text":"Understand the concept of conditional probability. a. Understand the conditional probability of A given B as P(A and B)/P(B). b. (+) Interpret independence of A and B as saying that the conditional probability of A given B is the same as the probability of A and the conditional probability of B given A is the same as the probability of B. a. For any two events A and B, P(A given B) = \ud835\udc43\ud835\udc43(\ud835\udc34\ud835\udc34 \ud835\udc4e\ud835\udc4e\ud835\udc5b\ud835\udc5b\ud835\udc51\ud835\udc51 \ud835\udc35\ud835\udc35) \ud835\udc43\ud835\udc43(\ud835\udc35\ud835\udc35)."},{"code":"KY.HS.SP.17","subject":"Mathematics","grade":"12","text":"Construct and interpret two-way frequency tables of data when two categories are associated with each object being classified. Use the two-way table as a sample space to decide whether events are independent and to approximate conditional probabilities."},{"code":"KY.HS.SP.18","subject":"Mathematics","grade":"12","text":"Apply the General Multiplication Rule, P(A and B) = P(A)P(B|A) = P(B)P(A|B), in a uniform probability model and interpret the answer in terms of the model."},{"code":"KY.HS.SP.19","subject":"Mathematics","grade":"12","text":"Use permutations and combinations to compute probabilities. a. Distinguish between situations that can be modeled using counting techniques, including Fundamental Counting Principle, permutations and combinations. b. Perform calculations using the appropriate counting technique, including simple probabilities. c. (+) Use permutations and combinations to compute probabilities of compound events and solve problems."},{"code":"KY.HS.SP.2","subject":"Mathematics","grade":"12","text":"Use statistics appropriate to the shape of the numerical data distribution to compare center (median, mean) and spread (interquartile range when comparing medians and standard deviation when comparing means) of different data distributions."},{"code":"KY.HS.SP.20","subject":"Mathematics","grade":"12","text":"Define a random variable for a quantity of interest by assigning a numerical value to each event in a sample space; graph the corresponding probability distribution using the same appropriate graphical displays as for data distributions."},{"code":"KY.HS.SP.21","subject":"Mathematics","grade":"12","text":"Calculate the expected value of a random variable; interpret it as the mean of the probability distribution and use the value in analyzing decisions."},{"code":"KY.HS.SP.22","subject":"Mathematics","grade":"12","text":"Develop a probability distribution for a random variable. a. Find an expected value based on a sample space in which theoretical probabilities can be calculated. b. Find an expected value based on a sample space in which empirical probabilities can be calculated."},{"code":"KY.HS.SP.23","subject":"Mathematics","grade":"12","text":"Weigh the possible outcomes of a decision by assigning probabilities to payoff values and finding expected values. a. Find the expected payoff for a game of chance. b. Evaluate and compare strategies on the basis of expected values. c. Use calculated expected values to make fair decisions and formulate strategies."},{"code":"KY.HS.SP.3","subject":"Mathematics","grade":"12","text":"Interpret differences in shape, center and spread in the context of the distributions of the numerical data, accounting for the presence and possible effects of extreme data points (outliers)."},{"code":"KY.HS.SP.4","subject":"Mathematics","grade":"12","text":"When appropriate, fit a normal distribution to a numerical data set for given mean and standard deviation and then estimate population percentages using the Empirical Rule and recognize that there are data sets for which such a procedure is not appropriate."},{"code":"KY.HS.SP.5","subject":"Mathematics","grade":"12","text":"Summarize categorical data for two or more categories in frequency tables. Calculate and interpret joint, marginal and conditional relative frequencies (probabilities) in the context of the data, recognizing possible associations and trends in the data."},{"code":"KY.HS.SP.6","subject":"Mathematics","grade":"12","text":"Represent data on two quantitative variables on a scatter plot and describe how the explanatory and response variables are related. a. Calculate an appropriate mathematical model, or use a given mathematical model, for data to solve problems in context. b. Informally assess the fit of a model (through calculating correlation for linear data, plotting, calculating and/or analyzing residuals)."},{"code":"KY.HS.SP.7","subject":"Mathematics","grade":"12","text":"Interpret the slope (rate of change) and the intercept (constant term) of a linear model in the context of the data."},{"code":"KY.HS.SP.8","subject":"Mathematics","grade":"12","text":"Understand the role and purpose of correlation in linear regression. a. Use technology to compute correlation coefficient of a linear fit. b. Interpret the meaning of the correlation within the context of the data. c. Describe the limitations of correlation when establishing causation."},{"code":"KY.HS.SP.9","subject":"Mathematics","grade":"12","text":"in that results from non-random samples (Voluntary Response and Convenience) generate biased results when compared with more appropriate, random samples of the same population."},{"code":"HS-ESS1-1","subject":"Science","grade":"12","text":"Develop a model based on evidence to illustrate the life span of the sun and the role of nuclear fusion in the sun\u2019s core to release energy that eventually reaches Earth in the form of radiation."},{"code":"HS-ESS1-2","subject":"Science","grade":"12","text":"Construct an explanation of the Big Bang theory based on astronomical evidence of light spectra, motion of distant galaxies, and composition of matter in the universe."},{"code":"HS-ESS1-3","subject":"Science","grade":"12","text":"Communicate scientific ideas about the way stars, over their life cycle, produce elements."},{"code":"HS-ESS1-4","subject":"Science","grade":"12","text":"Use mathematical or computational representations to predict the motion of orbiting objects in the solar system."},{"code":"HS-ESS1-5","subject":"Science","grade":"12","text":"Evaluate evidence of the past and current movements of continental and oceanic crust and the theory of plate tectonics to explain the ages of crustal rocks."},{"code":"HS-ESS1-6","subject":"Science","grade":"12","text":"Apply scientific reasoning and evidence from ancient Earth materials, meteorites, and other planetary surfaces to construct an account of Earth\u2019s formation and early history."},{"code":"HS-ESS2-1","subject":"Science","grade":"12","text":"Develop a model to illustrate how Earth\u2019s internal and surface processes operate at different spatial and temporal scales to form continental and ocean-floor features."},{"code":"HS-ESS2-2","subject":"Science","grade":"12","text":"Analyze geoscience data to make the claim that one change to Earth\u2019s surface can create feedbacks that cause changes to other Earth systems."},{"code":"HS-ESS2-3","subject":"Science","grade":"12","text":"Develop a model based on evidence of Earth\u2019s interior to describe the cycling of matter by thermal convection."},{"code":"HS-ESS2-4","subject":"Science","grade":"12","text":"Use a model to describe how variations in the flow of energy into and out of Earth\u2019s systems result in changes in climate."},{"code":"HS-ESS2-5","subject":"Science","grade":"12","text":"Plan and conduct an investigation of the properties of water and its effects on Earth materials and surface processes."},{"code":"HS-ESS2-6","subject":"Science","grade":"12","text":"Develop a quantitative model to describe the cycling of carbon among the hydrosphere, atmosphere, geosphere, and biosphere."},{"code":"HS-ESS2-7","subject":"Science","grade":"12","text":"Construct an argument based on evidence about the simultaneous coevolution of Earth\u2019s systems and life on Earth."},{"code":"HS-ESS3-1","subject":"Science","grade":"12","text":"Construct an explanation based on evidence for how the availability of natural resources, occurrence of natural hazards, and changes in climate have influenced human activity."},{"code":"HS-ESS3-2","subject":"Science","grade":"12","text":"Evaluate competing design solutions for developing, managing, and utilizing energy and mineral resources based on cost- benefit ratios.*"},{"code":"HS-ESS3-3","subject":"Science","grade":"12","text":"Create a computational simulation to illustrate the relationships among the management of natural resources, the sustainability of human populations, and biodiversity."},{"code":"HS-ESS3-4","subject":"Science","grade":"12","text":"Evaluate or refine a technological solution that reduces impacts of human activities on natural systems.*"},{"code":"HS-ESS3-5","subject":"Science","grade":"12","text":"Analyze geoscience data and the results from global climate models to make an evidence-based forecast of the current rate of global or regional climate change and associated future impacts to Earth\u2019s systems."},{"code":"HS-ESS3-6","subject":"Science","grade":"12","text":"Use a computational representation to illustrate the relationships among Earth systems and how those relationships are being modified due to human activity."},{"code":"HS-ETS1-1","subject":"Science","grade":"12","text":"Analyze a major global challenge to specify qualitative and quantitative criteria and constraints for solutions that account for societal needs and wants. *"},{"code":"HS-ETS1-2","subject":"Science","grade":"12","text":"Design a solution to a complex real- world problem by breaking it down into smaller, more manageable problems that can be solved through engineering. *"},{"code":"HS-ETS1-3","subject":"Science","grade":"12","text":"Evaluate a solution to a complex real- world problem based on prioritized criteria and trade-offs that account for a range of constraints, including cost, safety, reliability, and aesthetics, as well as possible social, cultural, and environmental impacts. *"},{"code":"HS-ETS1-4","subject":"Science","grade":"12","text":"Use a computer simulation to model the impact of proposed solutions to a complex real- world problem with numerous criteria and constraints on interactions within and between systems relevant to the problem. *"},{"code":"HS-LS1-1","subject":"Science","grade":"12","text":"Construct an explanation based on evidence for how the structure of DNA determines the structure of proteins, which carry out the essential functions of life through systems of specialized cells."},{"code":"HS-LS1-2","subject":"Science","grade":"12","text":"Develop and use a model to illustrate the hierarchical organization of interacting systems that provide specific functions within multicellular organisms."},{"code":"HS-LS1-3","subject":"Science","grade":"12","text":"Plan and conduct an investigation to provide evidence that feedback mechanisms maintain homeostasis."},{"code":"HS-LS1-4","subject":"Science","grade":"12","text":"Use a model to illustrate the role of cellular division (mitosis) and differentiation in producing and maintaining complex organisms."},{"code":"HS-LS1-5","subject":"Science","grade":"12","text":"Use a model to illustrate how photosynthesis transforms light energy into stored chemical energy."},{"code":"HS-LS1-6","subject":"Science","grade":"12","text":"Construct and revise an explanation based on evidence for how carbon, hydrogen, and oxygen from sugar molecules may combine with other elements to form amino acids and/or other large carbon-based molecules."},{"code":"HS-LS1-7","subject":"Science","grade":"12","text":"Use a model to illustrate that cellular respiration is a chemical process whereby the bonds of food molecules and oxygen molecules are broken and the bonds in new compounds are formed, resulting in a net transfer of energy."},{"code":"HS-LS2-1","subject":"Science","grade":"12","text":"Use mathematical and/or computational representations to support explanations of factors that affect carrying capacity of ecosystems at different scales."},{"code":"HS-LS2-2","subject":"Science","grade":"12","text":"Use mathematical representations to support and revise explanations based on evidence about factors affecting biodiversity and populations in ecosystems of different scales."},{"code":"HS-LS2-3","subject":"Science","grade":"12","text":"Construct and revise an explanation based on evidence for the cycling of matter and flow of energy in aerobic and anaerobic conditions."},{"code":"HS-LS2-4","subject":"Science","grade":"12","text":"Use mathematical representations to support claims for the cycling of matter and flow of energy among organisms in an ecosystem."},{"code":"HS-LS2-5","subject":"Science","grade":"12","text":"Develop a model to illustrate the role of photosynthesis and cellular respiration in the cycling of carbon among the biosphere, atmosphere, hydrosphere, and geosphere."},{"code":"HS-LS2-6","subject":"Science","grade":"12","text":"Evaluate claims, evidence, and reasoning that the complex interactions in ecosystems maintain relatively consistent numbers and types of organisms in stable conditions, but changing conditions may result in a new ecosystem."},{"code":"HS-LS2-7","subject":"Science","grade":"12","text":"Design, evaluate, and refine a solution for reducing the impacts of human activities on the environment and biodiversit y.*"},{"code":"HS-LS2-8","subject":"Science","grade":"12","text":"Evaluate evidence for the role of group behavior on individual and species\u2019 chances to survive and reproduce."},{"code":"HS-LS3-1","subject":"Science","grade":"12","text":"Ask questions to clarify relationships about the role of DNA and chromosomes in coding the instructions for characteristic traits passed from parents to offspring."},{"code":"HS-LS3-2","subject":"Science","grade":"12","text":"Make and defend a claim based on evidence that inheritable genetic variations may result from (1) new genetic combinations through meiosis, (2) viable errors occurring during replication, and/or (3) mutations caused by environmental factors."},{"code":"HS-LS3-3","subject":"Science","grade":"12","text":"Apply concepts of statistics and probability to explain the variation and distribution of expressed traits in a population."},{"code":"HS-LS4-1","subject":"Science","grade":"12","text":"Communicate scientific information that common ancestry and biological evolution are supported by multiple lines of empirical evidence."},{"code":"HS-LS4-2","subject":"Science","grade":"12","text":"Construct an explanation based on evidence that the process of evolution primarily results from four factors: (1) the potential for a species to increase in number, (2) the heritable genetic variation of individuals in a species due to mutation and sexual reproduction, (3) competition for limited resources, and (4) the proliferation of those organisms that are better able to survive and reproduce in the environment."},{"code":"HS-LS4-3","subject":"Science","grade":"12","text":"Apply concepts of statistics and probability to support explanations that organisms with an advantageous heritable trait tend to increase in proportion to organisms lacking this trait."},{"code":"HS-LS4-4","subject":"Science","grade":"12","text":"Construct an explanation based on evidence for how natural selection leads to adaptation of populations."},{"code":"HS-LS4-5","subject":"Science","grade":"12","text":"Evaluate the evidence supporting claims that changes in environmental conditions may result in (1) increases in the number of individuals of some species, (2) the emergence of new species over time, and (3) the extinction of other species."},{"code":"HS-LS4-6","subject":"Science","grade":"12","text":"Create or revise a simulation to test a solution to mitigate adverse impacts of human activity on biodiversit y.*"},{"code":"HS-PS1-1","subject":"Science","grade":"12","text":"Use the periodic table as a model to predict the relative properties of elements based on the patterns of electrons in the outermost energy level of atoms."},{"code":"HS-PS1-2","subject":"Science","grade":"12","text":"Construct and revise an explanation for the outcome of a simple chemical reaction based on the outermost electron states of atoms, trends in the periodic table, and knowledge of the patterns of chemical properties."},{"code":"HS-PS1-3","subject":"Science","grade":"12","text":"Plan and conduct an investigation to gather evidence to compare the structure of substances at the macro and micro scale to infer the strength of electrical forces between particles."},{"code":"HS-PS1-4","subject":"Science","grade":"12","text":"Develop a model to illustrate that the release or absorption of energy from a chemical reaction system depends upon the changes in total bond energy."},{"code":"HS-PS1-5","subject":"Science","grade":"12","text":"Apply scientific principles and evidence to provide an explanation about the effects of changing the temperature or concentration of the reacting particles on the rate at which a reaction occurs."},{"code":"HS-PS1-6","subject":"Science","grade":"12","text":"Refine the design of a chemical system by specifying a change in conditions that would produce increased amounts of products at equilibrium.*"},{"code":"HS-PS1-7","subject":"Science","grade":"12","text":"Use mathematical representations to support the claim that atoms, and therefore mass, are conserved during a chemical reaction."},{"code":"HS-PS1-8","subject":"Science","grade":"12","text":"Develop models to illustrate the changes in the composition of the nucleus of the atom and the energy released during the processes of fission, fusion, and radioactive decay."},{"code":"HS-PS2-1","subject":"Science","grade":"12","text":"Analyze data to support the claim that Newton\u2019s second law of motion describes the mathematical relationship among the net force on a macroscopic object, its mass, and its acceleration."},{"code":"HS-PS2-2","subject":"Science","grade":"12","text":"Use mathematical representations to support the claim that the total momentum of a system of objects is conserved when there is no net force on the system."},{"code":"HS-PS2-3","subject":"Science","grade":"12","text":"Apply scientific and engineering ideas to design, evaluate, and refine a device that minimizes the force on a macroscopic object during a collision.*"},{"code":"HS-PS2-4","subject":"Science","grade":"12","text":"Use mathematical representations of Newton\u2019s law of gravitation and Coulomb\u2019s law to describe and predict the gravitational and electrostatic forces between objects."},{"code":"HS-PS2-5","subject":"Science","grade":"12","text":"Plan and conduct an investigation to provide evidence that an electric current can produce a magnetic field and that a changing magnetic field can produce an electric current."},{"code":"HS-PS2-6","subject":"Science","grade":"12","text":"Communicate scientific and technical information about why the molecular-level structure is important in the functioning of designed materials.*"},{"code":"HS-PS3-1","subject":"Science","grade":"12","text":"Create a computational model to calculate the change in the energy of one component in a system when the change in energy of the other component(s) and energy flows in and out of the system are known."},{"code":"HS-PS3-2","subject":"Science","grade":"12","text":"Develop and use models to illustrate that energy at the macroscopic scale can be accounted for as a combination of energy associated with the motion of particles (objects) and energy associated with the relative position of particles (objects)."},{"code":"HS-PS3-3","subject":"Science","grade":"12","text":"Design, build, and refine a device that works within given constraints to convert one form of energy into another form of energy.*"},{"code":"HS-PS3-4","subject":"Science","grade":"12","text":"Plan and conduct an investigation to provide evidence that the transfer of thermal energy when two components of different temperature are combined within a closed system results in a more uniform energy distribution among the components in the system (second law of thermodynamics)."},{"code":"HS-PS3-5","subject":"Science","grade":"12","text":"Develop and use a model of two objects interacting through electric or magnetic fields to illustrate the forces between objects and the changes in energy of the objects due to the interaction."},{"code":"HS-PS4-1","subject":"Science","grade":"12","text":"Use mathematical representations to support a claim regarding relationships among the frequency, wavelength, and speed of waves traveling in various media."},{"code":"HS-PS4-2","subject":"Science","grade":"12","text":"Evaluate questions about the advantages of using digital transmission and storage of information."},{"code":"HS-PS4-3","subject":"Science","grade":"12","text":"Evaluate the claims, evidence, and reasoning behind the idea that electromagnetic radiation can be described either by a wave model or a particle model, and that for some situations one model is more useful than the other."},{"code":"HS-PS4-4","subject":"Science","grade":"12","text":"Evaluate the validity and reliability of claims in published materials of the effects that different frequencies of electromagnetic radiation have when absorbed by matter."},{"code":"HS-PS4-5","subject":"Science","grade":"12","text":"Communicate technical information about how some technological devices use the principles of wave behavior and wave interactions with matter to transmit and capture information and energy.*"},{"code":"HS.C.CP.1","subject":"Social Studies","grade":"12","text":"Explain how the Cons titution of the United States embodies the principles of rule of law, popular sovereignty, republicanism, federalism, separation of powers and checks and balances to promote general welfare."},{"code":"HS.C.CP.2","subject":"Social Studies","grade":"12","text":"Analyze legislative, executive and judicial branch decisions in terms of constitutionality and impact on citizens and states."},{"code":"HS.C.CP.3","subject":"Social Studies","grade":"12","text":"Compare various forms of government and how each maintains order, upholds human rights and interacts within the international community."},{"code":"HS.C.CP.4","subject":"Social Studies","grade":"12","text":"Evaluate how the U.S. judicial system is designed to uphold equality before the law, due process and inalienable rights."},{"code":"HS.C.CV.1","subject":"Social Studies","grade":"12","text":"Explain how classic al republicanism, natural rights philosophy and English common law influenced the thinking and actions of the American Founders."},{"code":"HS.C.CV.2","subject":"Social Studies","grade":"12","text":"Assess how the expansion of civic virtues, democratic principles, constitutional rights and human rights influence the thoughts and actions of individuals and groups."},{"code":"HS.C.CV.3","subject":"Social Studies","grade":"12","text":"Analyze the impact of the e fforts of individuals and reform movements on the expansion of civil rights and liberties locally, nationally and internationally."},{"code":"HS.C.KGO.1","subject":"Social Studies","grade":"12","text":"Explain how the Ke ntucky Constitution embodies the principles of rule of law, popular sovereignty, separation of powers and checks and balances."},{"code":"HS.C.KGO.2","subject":"Social Studies","grade":"12","text":"Compare Kentucky\u2019s government to other states and to the federal government."},{"code":"HS.C.KGO.3","subject":"Social Studies","grade":"12","text":"Describe how active citizens can affect change in their communities and Kentucky Informed and engaged citizenship is a crucial part of the successful functioning of Kentucky."},{"code":"HS.C.PR.1","subject":"Social Studies","grade":"12","text":"Analyze the role of the thre e branches of government in the lawmaking process."},{"code":"HS.C.PR.2","subject":"Social Studies","grade":"12","text":"Analyze the role of elections, bureaucracy, political parties, interest groups and media in shaping public policy."},{"code":"HS.C.PR.3","subject":"Social Studies","grade":"12","text":"Evaluate intended and unintended consequences of public policies locally, nationally and internationally."},{"code":"HS.C.PR.4","subject":"Social Studies","grade":"12","text":"Compare the domestic and foreign policies of the United States and other countries."},{"code":"HS.C.RR.1","subject":"Social Studies","grade":"12","text":"Evaluate the civic r esponsibilities of individuals within a society."},{"code":"HS.C.RR.2","subject":"Social Studies","grade":"12","text":"Explain how active citizens can affect the lawmaking process locally, nationally and internationally. internationally engaged citizens are critical to positively evolving societies."},{"code":"HS.E.IC.1","subject":"Social Studies","grade":"12","text":"Predict the way scarcity causes individuals, organizations and governments to evaluate tradeoffs, make choices and incur opportunity costs."},{"code":"HS.E.IC.2","subject":"Social Studies","grade":"12","text":"Evaluate how individuals, organizations and governments respond to incentives in the decision- making process."},{"code":"HS.E.IC.3","subject":"Social Studies","grade":"12","text":"Perform a cost-benefit analysis on a real-world situation, using economic thinking to describe the marginal costs and benefits of a particular situation."},{"code":"HS.E.IC.4","subject":"Social Studies","grade":"12","text":"Evaluate how incentives determine what is produced and distributed in a competitive market system."},{"code":"HS.E.KE.1","subject":"Social Studies","grade":"12","text":"Analyze how national and international trends and policies impact Kentucky\u2019s state and local economies."},{"code":"HS.E.KE.2","subject":"Social Studies","grade":"12","text":"Analyze how national and international trends and policies impact Kentucky\u2019s state and local economies."},{"code":"HS.E.KE.3","subject":"Social Studies","grade":"12","text":"Analyze how the four components of Gross Domestic Product (GDP) are combined to assess the health of Kentucky\u2019s economy."},{"code":"HS.E.MA.1","subject":"Social Studies","grade":"12","text":"Evaluate how valu es and beliefs like economic freedom, equity, full employment, price stability, security, efficiency and growth help to form different types of economic systems."},{"code":"HS.E.MA.2","subject":"Social Studies","grade":"12","text":"Analyze ways in which competition and government regulation influence what is produced and allocated in an economy."},{"code":"HS.E.MA.3","subject":"Social Studies","grade":"12","text":"Describe the externalities of government attempts to remedy market failure and improve market outcomes through fiscal policy."},{"code":"HS.E.MA.4","subject":"Social Studies","grade":"12","text":"Analyze the impact of fiscal policies, various government taxation and spending policies on the economy."},{"code":"HS.E.MA.5","subject":"Social Studies","grade":"12","text":"Assess how interest rates influence borrowing and investing."},{"code":"HS.E.MA.6","subject":"Social Studies","grade":"12","text":"Assess the effectiveness of rules and laws that protect both consumers and producers."},{"code":"HS.E.MA.7","subject":"Social Studies","grade":"12","text":"Explain how the Federal Reserve uses monetary policy to promote price stability, employment and economic growth."},{"code":"HS.E.MI.1","subject":"Social Studies","grade":"12","text":"Compare per fect competition, monopolistic competition, oligopoly and monopoly and how the extent of competition within various markets affects price, quantity and variety in production."},{"code":"HS.E.MI.2","subject":"Social Studies","grade":"12","text":"Analyze and graph the impact of supply and demand shifts on equilibrium price and quantities produced."},{"code":"HS.E.MI.3","subject":"Social Studies","grade":"12","text":"Analyze the roles of product and factor markets."},{"code":"HS.E.MI.4","subject":"Social Studies","grade":"12","text":"Compare the roles of consumers and producers in the product, labor and financial markets and the economy as a whole."},{"code":"HS.E.ST.1","subject":"Social Studies","grade":"12","text":"Draw conclusions regarding the effect of specialization and trade on production, distribution and consumption of goods and services for individuals, businesses and societies."},{"code":"HS.E.ST.2","subject":"Social Studies","grade":"12","text":"Analyze the role of comparative advantage in international trade of goods and services."},{"code":"HS.E.ST.3","subject":"Social Studies","grade":"12","text":"Explain how international economic trends and policies affect political, social and economic conditions in various nations. (see \u201ccontinued\u201d) Nations in the modern world are affected by the interconnectedness of economies, which causes ripple effects across borders."},{"code":"HS.G.GR.1","subject":"Social Studies","grade":"12","text":"Interpret the relationships among human and physical patterns and processes at local, national and global scales."},{"code":"HS.G.GR.2","subject":"Social Studies","grade":"12","text":"Analyze how environmental factors influence population distributions from place to place."},{"code":"HS.G.HE.1","subject":"Social Studies","grade":"12","text":"Assess the reciproc al relationship between physical environment and culture within local, national and global scales."},{"code":"HS.G.HE.2","subject":"Social Studies","grade":"12","text":"Analyze how human settlements are influenced by or influence the relationship between people and the environment."},{"code":"HS.G.HI.1","subject":"Social Studies","grade":"12","text":"Analyze how the forces of cooperation and conflict within and among people, nations and empires influence the division and control of Earth\u2019s surface and resources."},{"code":"HS.G.HI.2","subject":"Social Studies","grade":"12","text":"Analyze how cultural and economic decisions influence the characteristics of various places."},{"code":"HS.G.HI.3","subject":"Social Studies","grade":"12","text":"Explain how people create natural and cultural regions to interpret Earth\u2019s complexity."},{"code":"HS.G.KGE.1","subject":"Social Studies","grade":"12","text":"Explain how Kentuckians view sense of place differently based on cultural and environmental characteristics of varying regions of the state."},{"code":"HS.G.KGE.2","subject":"Social Studies","grade":"12","text":"Explain how the geography of Kentucky influences the development of the state."},{"code":"HS.G.MM.1","subject":"Social Studies","grade":"12","text":"Analyze how cult ural, economic and environmental factors contribute to migration patterns and population distribution at multiple scales."},{"code":"HS.G.MM.2","subject":"Social Studies","grade":"12","text":"Evaluate reasons for the spatial distribution of human populations at different scales on Earth\u2019s surface."}];
